/* isc2 cc :: quizEngine.js  (data bank + assessment engine) */
window.ISC2CC = window.ISC2CC || {};
ISC2CC.questions = [{"id":"D1-001","domain":1,"obj":"1.1","diff":"easy","q":"Which element of the CIA triad ensures that information has not been altered by unauthorized parties?","options":["Integrity","Confidentiality","Availability","Authentication"],"answer":0,"explain":"<strong>Correct.</strong> Integrity ensures data is accurate and has not been modified in an unauthorized or undetected manner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: This protects data from unauthorized disclosure, not from unauthorized alteration.</span><span class='qd'><b>Availability</b>: This ensures data and systems are accessible when needed, not that they are unaltered.</span><span class='qd'><b>Authentication</b>: This verifies identity and is not one of the three CIA triad elements.</span>"},{"id":"D1-002","domain":1,"obj":"1.1","diff":"easy","q":"A user logs in with a password and then enters a code from an app on their phone. What concept does this represent?","options":["Single sign-on","Multi-factor authentication","Non-repudiation","Least privilege"],"answer":1,"explain":"<strong>Correct.</strong> Combining something you know (password) with something you have (phone app code) uses two different factor types, which is multi-factor authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single sign-on</b>: SSO lets one login grant access to many systems; it does not describe using multiple factors.</span><span class='qd'><b>Non-repudiation</b>: This prevents denial of an action and is not about login factors.</span><span class='qd'><b>Least privilege</b>: This limits access rights to the minimum needed, unrelated to authentication factors.</span>"},{"id":"D1-003","domain":1,"obj":"1.1","diff":"easy","q":"Which of the following is an example of the 'something you are' authentication factor?","options":["A hardware token","A PIN","A fingerprint scan","A smart card"],"answer":2,"explain":"<strong>Correct.</strong> A fingerprint is a biometric characteristic, which represents the 'something you are' factor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hardware token</b>: This is 'something you have,' a physical possession factor.</span><span class='qd'><b>A PIN</b>: This is 'something you know,' a knowledge factor.</span><span class='qd'><b>A smart card</b>: This is 'something you have,' a possession factor.</span>"},{"id":"D1-004","domain":1,"obj":"1.1","diff":"medium","q":"An auditor needs to prove that a specific user sent a particular email and cannot later deny it. Which property provides this assurance?","options":["Confidentiality","Availability","Redundancy","Non-repudiation"],"answer":3,"explain":"<strong>Correct.</strong> Non-repudiation ensures that a party cannot deny having performed an action, typically achieved through digital signatures and logging.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: This keeps the email secret but does not prove who sent it.</span><span class='qd'><b>Availability</b>: This ensures access to the email, not proof of its origin.</span><span class='qd'><b>Redundancy</b>: This provides duplicate resources for reliability, not proof of action.</span>"},{"id":"D1-005","domain":1,"obj":"1.1","diff":"medium","q":"The DAD triad describes the opposite of the CIA triad. Which DAD term corresponds to a loss of confidentiality?","options":["Disclosure","Alteration","Destruction","Denial"],"answer":0,"explain":"<strong>Correct.</strong> Disclosure is the unauthorized release of information, which directly undermines confidentiality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Alteration</b>: Alteration is the opposite of integrity, not confidentiality.</span><span class='qd'><b>Destruction</b>: Destruction relates to a loss of availability, not confidentiality.</span><span class='qd'><b>Denial</b>: Denial of access is the opposite of availability, not confidentiality.</span>"},{"id":"D1-006","domain":1,"obj":"1.1","diff":"easy","q":"In the AAA framework, which component determines what an authenticated user is permitted to do?","options":["Authentication","Authorization","Accounting","Assurance"],"answer":1,"explain":"<strong>Correct.</strong> Authorization defines the permissions and resources an authenticated user may access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Authentication</b>: This verifies identity but does not grant specific permissions.</span><span class='qd'><b>Accounting</b>: This tracks and records what a user does, not what they may do.</span><span class='qd'><b>Assurance</b>: This is not one of the three A's in AAA.</span>"},{"id":"D1-007","domain":1,"obj":"1.1","diff":"medium","q":"A hospital must protect patient records so they are accessible to clinicians during an emergency. Which CIA principle is most directly addressed by ensuring uptime and redundancy?","options":["Confidentiality","Integrity","Availability","Non-repudiation"],"answer":2,"explain":"<strong>Correct.</strong> Availability ensures authorized users can access information and systems when needed, which uptime and redundancy support.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: This concerns keeping records private, not ensuring they are reachable.</span><span class='qd'><b>Integrity</b>: This ensures records are accurate, not that they are accessible.</span><span class='qd'><b>Non-repudiation</b>: This proves who took an action and is not part of the CIA triad.</span>"},{"id":"D1-008","domain":1,"obj":"1.1","diff":"easy","q":"Which of the following is considered personally identifiable information (PII)?","options":["A public company stock ticker","A generic product catalog number","A published office address of a corporation","A Social Security number"],"answer":3,"explain":"<strong>Correct.</strong> A Social Security number directly identifies a specific individual and is classic PII.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public company stock ticker</b>: This identifies a company, not an individual, and is public.</span><span class='qd'><b>A published office address of a corporation</b>: This is corporate, public information, not personal identity data.</span><span class='qd'><b>A generic product catalog number</b>: This identifies a product, not a person.</span>"},{"id":"D1-009","domain":1,"obj":"1.1","diff":"medium","q":"An analyst configures a system so that every user action is timestamped and logged to a secure server. Which AAA component does this support?","options":["Accounting","Authorization","Authentication","Authorization creep"],"answer":0,"explain":"<strong>Correct.</strong> Accounting (also called auditing) records user activity, including timestamps and actions, for later review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Authentication</b>: This confirms identity at login and does not log ongoing activity.</span><span class='qd'><b>Authorization</b>: This grants permissions but does not record what users actually do.</span><span class='qd'><b>Authorization creep</b>: This is the accumulation of excess privileges over time, not a logging function.</span>"},{"id":"D1-010","domain":1,"obj":"1.1","diff":"hard","q":"A company wants to ensure that a contract signed electronically is provably tied to the signer and that the document was not changed after signing. Which combination of services best meets this need?","options":["Encryption and availability","Digital signature providing integrity and non-repudiation","Redundancy and load balancing","Anonymization and confidentiality"],"answer":1,"explain":"<strong>Correct.</strong> A digital signature binds the signer to the document and detects any change, delivering both integrity and non-repudiation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption and availability</b>: Encryption protects confidentiality and availability ensures access, but neither proves who signed.</span><span class='qd'><b>Redundancy and load balancing</b>: These support availability only and do nothing to bind a signer to a document.</span><span class='qd'><b>Anonymization and confidentiality</b>: Anonymization removes identity, which is the opposite of binding a signer to the contract.</span>"},{"id":"D1-011","domain":1,"obj":"1.2","diff":"easy","q":"In risk terminology, what is a vulnerability?","options":["A person or thing that may cause harm","The likelihood of a loss occurring","A weakness that can be exploited","The financial impact of an incident"],"answer":2,"explain":"<strong>Correct.</strong> A vulnerability is a weakness or gap in a system that a threat could exploit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A person or thing that may cause harm</b>: That describes a threat or threat actor, not a vulnerability.</span><span class='qd'><b>The likelihood of a loss occurring</b>: That is the probability component of risk, not a vulnerability.</span><span class='qd'><b>The financial impact of an incident</b>: That describes impact, a separate component of risk.</span>"},{"id":"D1-012","domain":1,"obj":"1.2","diff":"easy","q":"Which term best describes a hurricane that could damage a coastal data center?","options":["Vulnerability","Residual risk","Control","Threat"],"answer":3,"explain":"<strong>Correct.</strong> A hurricane is a natural threat, an external event with the potential to cause harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Vulnerability</b>: The weakness would be the data center's lack of protection, not the hurricane itself.</span><span class='qd'><b>Control</b>: A control is a safeguard that reduces risk, not the harmful event.</span><span class='qd'><b>Residual risk</b>: This is risk remaining after controls, not the threat event.</span>"},{"id":"D1-013","domain":1,"obj":"1.2","diff":"medium","q":"A risk analyst calculates that a single flood would cause $200,000 in damage and that floods occur once every 4 years. What is the annualized loss expectancy (ALE)?","options":["$50,000","$800,000","$200,000","$25,000"],"answer":0,"explain":"<strong>Correct.</strong> ALE = SLE x ARO. The SLE is $200,000 and the ARO is 0.25 (once per 4 years), so ALE = 200,000 x 0.25 = $50,000.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$200,000</b>: This is the single loss expectancy, not annualized.</span><span class='qd'><b>$800,000</b>: This incorrectly multiplies by 4 instead of dividing by 4.</span><span class='qd'><b>$25,000</b>: This uses an ARO of 0.125 (once every 8 years), which does not match the scenario.</span>"},{"id":"D1-014","domain":1,"obj":"1.2","diff":"medium","q":"A company decides to purchase cyber insurance to handle the financial impact of a potential breach. Which risk treatment strategy is this?","options":["Risk avoidance","Risk transference","Risk mitigation","Risk acceptance"],"answer":1,"explain":"<strong>Correct.</strong> Buying insurance shifts the financial consequences of a risk to a third party, which is risk transference.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: Avoidance means not engaging in the activity at all, which insurance does not do.</span><span class='qd'><b>Risk mitigation</b>: Mitigation reduces likelihood or impact through controls, not by shifting cost to an insurer.</span><span class='qd'><b>Risk acceptance</b>: Acceptance means taking no action and absorbing the loss, the opposite of transferring it.</span>"},{"id":"D1-015","domain":1,"obj":"1.2","diff":"easy","q":"Which risk treatment option involves taking no further action because the potential loss is within the organization's tolerance?","options":["Risk transference","Risk avoidance","Risk acceptance","Risk mitigation"],"answer":2,"explain":"<strong>Correct.</strong> Risk acceptance is the deliberate decision to take no additional action because the risk falls within tolerance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: Avoidance eliminates the risk by ceasing the activity, which is an action.</span><span class='qd'><b>Risk transference</b>: Transference moves the risk to another party, such as through insurance.</span><span class='qd'><b>Risk mitigation</b>: Mitigation applies controls to reduce the risk, which is an action.</span>"},{"id":"D1-016","domain":1,"obj":"1.2","diff":"medium","q":"After implementing firewalls and patching, an organization still faces some chance of compromise. What is this remaining risk called?","options":["Total risk","Inherent risk","Risk appetite","Residual risk"],"answer":3,"explain":"<strong>Correct.</strong> Residual risk is the risk that remains after controls have been applied.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Inherent risk</b>: Inherent risk is the level of risk before any controls are applied.</span><span class='qd'><b>Total risk</b>: Total risk is the full exposure without controls, similar to inherent risk.</span><span class='qd'><b>Risk appetite</b>: Risk appetite is the amount of risk an organization is willing to pursue, not the leftover risk.</span>"},{"id":"D1-017","domain":1,"obj":"1.2","diff":"hard","q":"An organization uses descriptive ratings such as 'high,' 'medium,' and 'low' to rank risks rather than assigning dollar values. Which assessment approach is being used?","options":["Qualitative risk analysis","Quantitative risk analysis","Annualized loss expectancy","Single loss expectancy"],"answer":0,"explain":"<strong>Correct.</strong> Qualitative analysis uses subjective, descriptive categories like high, medium, and low rather than numeric monetary values.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Quantitative risk analysis</b>: This assigns specific numeric or monetary values, not descriptive ratings.</span><span class='qd'><b>Annualized loss expectancy</b>: ALE is a specific quantitative calculation, not a descriptive ranking.</span><span class='qd'><b>Single loss expectancy</b>: SLE is a quantitative dollar figure for one event, not a qualitative scale.</span>"},{"id":"D1-018","domain":1,"obj":"1.2","diff":"medium","q":"A firm refuses to launch a new product line because the associated regulatory risk is too great. Which risk treatment is this?","options":["Risk acceptance","Risk avoidance","Risk mitigation","Risk transference"],"answer":1,"explain":"<strong>Correct.</strong> Choosing not to engage in the risky activity altogether is risk avoidance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk acceptance</b>: Acceptance would mean launching the product and absorbing the risk, not declining it.</span><span class='qd'><b>Risk mitigation</b>: Mitigation would launch the product while reducing risk with controls.</span><span class='qd'><b>Risk transference</b>: Transference would shift the risk to another party while still proceeding.</span>"},{"id":"D1-019","domain":1,"obj":"1.2","diff":"easy","q":"Which formula correctly expresses the single loss expectancy (SLE)?","options":["Threat x vulnerability","SLE x annualized rate of occurrence","Asset value x exposure factor","Likelihood x risk appetite"],"answer":2,"explain":"<strong>Correct.</strong> SLE equals the asset value multiplied by the exposure factor (the percentage of asset lost in one event).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SLE x annualized rate of occurrence</b>: That is the formula for ALE, not SLE.</span><span class='qd'><b>Threat x vulnerability</b>: This is a conceptual relationship for risk, not the SLE calculation.</span><span class='qd'><b>Likelihood x risk appetite</b>: This is not a recognized loss expectancy formula.</span>"},{"id":"D1-020","domain":1,"obj":"1.2","diff":"hard","q":"A board defines the broad amount of risk it is willing to pursue across the enterprise, while a security team sets specific acceptable deviation levels for individual systems. Which two terms correctly map to these, respectively?","options":["Risk tolerance and risk appetite","Risk transference and risk avoidance","Residual risk and inherent risk","Risk appetite and risk tolerance"],"answer":3,"explain":"<strong>Correct.</strong> Risk appetite is the broad enterprise level of risk an organization will pursue, while risk tolerance is the acceptable variation for specific objectives or systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk tolerance and risk appetite</b>: This reverses the two terms relative to the scenario.</span><span class='qd'><b>Residual risk and inherent risk</b>: These describe risk before and after controls, not appetite and tolerance.</span><span class='qd'><b>Risk transference and risk avoidance</b>: These are treatment strategies, not measures of acceptable risk.</span>"},{"id":"D1-021","domain":1,"obj":"1.3","diff":"easy","q":"A locked door securing a server room is an example of which control category?","options":["Physical control","Administrative control","Technical control","Compensating control"],"answer":0,"explain":"<strong>Correct.</strong> A locked door is a tangible, physical barrier, making it a physical control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Technical control</b>: Technical controls are implemented through technology such as software or hardware logic.</span><span class='qd'><b>Administrative control</b>: Administrative controls are policies and procedures, not physical barriers.</span><span class='qd'><b>Compensating control</b>: This describes a control's function as a substitute, not the category of a locked door by default.</span>"},{"id":"D1-022","domain":1,"obj":"1.3","diff":"easy","q":"A security awareness training policy that all employees must complete annually is an example of which control category?","options":["Physical control","Administrative control","Technical control","Detective control"],"answer":1,"explain":"<strong>Correct.</strong> Policies, procedures, and training are administrative (managerial) controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical control</b>: Physical controls are tangible barriers like locks or fences, not training programs.</span><span class='qd'><b>Technical control</b>: Technical controls are enforced by technology, not by a policy requirement.</span><span class='qd'><b>Detective control</b>: This is a control function, and training is primarily directive rather than detective.</span>"},{"id":"D1-023","domain":1,"obj":"1.3","diff":"medium","q":"A motion-activated camera records footage when someone enters a restricted area. Which control function does the recording capability primarily serve?","options":["Preventive","Corrective","Detective","Directive"],"answer":2,"explain":"<strong>Correct.</strong> Recording activity to identify that an event occurred is a detective control function.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive</b>: Preventive controls stop an event before it happens; recording does not block entry.</span><span class='qd'><b>Corrective</b>: Corrective controls fix or restore after an incident, which a recording does not do.</span><span class='qd'><b>Directive</b>: Directive controls instruct or guide behavior, such as a policy or sign.</span>"},{"id":"D1-024","domain":1,"obj":"1.3","diff":"medium","q":"A 'Beware of Dog' warning sign at a fence is intended to discourage intruders from attempting entry. Which control function does this represent?","options":["Detective","Compensating","Corrective","Deterrent"],"answer":3,"explain":"<strong>Correct.</strong> A warning sign that discourages an attacker from acting is a deterrent control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detective</b>: Detective controls identify events after they occur; a sign does not detect anything.</span><span class='qd'><b>Corrective</b>: Corrective controls remediate after an incident, which a sign does not do.</span><span class='qd'><b>Compensating</b>: Compensating controls substitute for a primary control that cannot be used; a sign is not a substitute here.</span>"},{"id":"D1-025","domain":1,"obj":"1.3","diff":"medium","q":"After a ransomware incident, an organization restores affected systems from clean backups. Which control function is being used?","options":["Corrective","Deterrent","Preventive","Directive"],"answer":0,"explain":"<strong>Correct.</strong> Restoring systems after an incident to return to normal operations is a corrective control function.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive</b>: Preventive controls act before an incident; restoration happens afterward.</span><span class='qd'><b>Deterrent</b>: Deterrent controls discourage attackers, not recover systems.</span><span class='qd'><b>Directive</b>: Directive controls provide instructions or guidance, not system recovery.</span>"},{"id":"D1-026","domain":1,"obj":"1.3","diff":"hard","q":"A legacy application cannot support multi-factor authentication. To address the resulting weakness, the organization restricts access to the application to a hardened jump server on an isolated network. The isolation is best described as which control function?","options":["Detective control","Preventive control that is also compensating","Deterrent control","Directive control"],"answer":1,"explain":"<strong>Correct.</strong> Because it substitutes for the missing MFA requirement while actively reducing the chance of compromise, the isolation acts as a compensating control that is preventive in nature.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detective control</b>: Isolation prevents access rather than merely identifying that an event occurred.</span><span class='qd'><b>Deterrent control</b>: It does not rely on discouraging an attacker; it technically blocks unauthorized paths.</span><span class='qd'><b>Directive control</b>: It enforces restriction technically rather than instructing people on how to behave.</span>"},{"id":"D1-027","domain":1,"obj":"1.3","diff":"easy","q":"Encryption applied to a database to protect data at rest is an example of which control category?","options":["Physical control","Administrative control","Technical control","Deterrent control"],"answer":2,"explain":"<strong>Correct.</strong> Encryption is implemented through technology and logic, making it a technical (logical) control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical control</b>: Physical controls are tangible barriers, not software-based encryption.</span><span class='qd'><b>Administrative control</b>: Administrative controls are policies and procedures, not technical mechanisms.</span><span class='qd'><b>Deterrent control</b>: This names a function, not the technical category that encryption belongs to.</span>"},{"id":"D1-028","domain":1,"obj":"1.3","diff":"medium","q":"An organization posts an acceptable use policy that instructs employees on permitted activities. Which control function does the policy most directly serve?","options":["Corrective","Compensating","Detective","Directive"],"answer":3,"explain":"<strong>Correct.</strong> A policy that instructs and guides behavior is a directive control function.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Corrective</b>: Corrective controls restore systems after an incident, which a policy does not do.</span><span class='qd'><b>Detective</b>: Detective controls identify incidents; a policy does not detect activity.</span><span class='qd'><b>Compensating</b>: Compensating controls substitute for another control; the policy is a primary directive, not a substitute.</span>"},{"id":"D1-029","domain":1,"obj":"1.3","diff":"hard","q":"A firewall that blocks unauthorized inbound connections demonstrates which combination of control category and function?","options":["Technical and preventive","Administrative and detective","Physical and corrective","Administrative and deterrent"],"answer":0,"explain":"<strong>Correct.</strong> A firewall is implemented through technology (technical category) and stops unwanted connections before they occur (preventive function).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Administrative and detective</b>: A firewall is technical, not administrative, and it blocks rather than merely detects.</span><span class='qd'><b>Physical and corrective</b>: A firewall is not a physical barrier and it prevents rather than corrects.</span><span class='qd'><b>Administrative and deterrent</b>: A firewall is technical and actively blocks; it does not rely on discouragement.</span>"},{"id":"D1-030","domain":1,"obj":"1.3","diff":"medium","q":"Which of the following is the best example of a detective control?","options":["A door lock","An intrusion detection system that alerts on suspicious traffic","A backup generator","A security policy"],"answer":1,"explain":"<strong>Correct.</strong> An intrusion detection system identifies and alerts on suspicious activity, fulfilling a detective function.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A door lock</b>: A lock prevents entry; it is preventive, not detective.</span><span class='qd'><b>A backup generator</b>: A generator restores power, serving a corrective or recovery function.</span><span class='qd'><b>A security policy</b>: A policy directs behavior and is a directive control, not detective.</span>"},{"id":"D1-031","domain":1,"obj":"1.4","diff":"easy","q":"How many canons are contained in the ISC2 Code of Ethics?","options":["Two","Three","Four","Five"],"answer":2,"explain":"<strong>Correct.</strong> The ISC2 Code of Ethics contains exactly four canons in addition to its preamble.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Two</b>: There are more than two canons; this undercounts.</span><span class='qd'><b>Three</b>: The code defines four canons, not three.</span><span class='qd'><b>Five</b>: There are four canons, not five.</span>"},{"id":"D1-032","domain":1,"obj":"1.4","diff":"medium","q":"Which is the FIRST canon of the ISC2 Code of Ethics?","options":["Act honorably, honestly, justly, responsibly, and legally","Advance and protect the profession","Provide diligent and competent service to principals","Protect society, the common good, necessary public trust and confidence, and the infrastructure"],"answer":3,"explain":"<strong>Correct.</strong> The first canon is to protect society, the common good, necessary public trust and confidence, and the infrastructure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Act honorably, honestly, justly, responsibly, and legally</b>: This is the second canon, not the first.</span><span class='qd'><b>Provide diligent and competent service to principals</b>: This is the third canon.</span><span class='qd'><b>Advance and protect the profession</b>: This is the fourth canon.</span>"},{"id":"D1-033","domain":1,"obj":"1.4","diff":"hard","q":"An ISC2 member faces a conflict where protecting their client's confidential interests appears to clash with protecting the public infrastructure. According to the ordering of the canons as a tie-breaker, which obligation takes precedence?","options":["The duty to protect society and the infrastructure","The duty to the client, as the paying principal","The duty to advance the profession","The duties are equal and the member chooses freely"],"answer":0,"explain":"<strong>Correct.</strong> The canons are applied in order, so the first canon, protecting society and the infrastructure, outranks the later duty to principals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The duty to the client, as the paying principal</b>: Service to principals is the third canon and yields to the first canon.</span><span class='qd'><b>The duty to advance the profession</b>: This is the fourth and lowest-priority canon.</span><span class='qd'><b>The duties are equal and the member chooses freely</b>: The canons are explicitly ordered, so they are not equal.</span>"},{"id":"D1-034","domain":1,"obj":"1.4","diff":"medium","q":"Which canon of the ISC2 Code of Ethics addresses providing diligent and competent service to those who employ or rely on the professional?","options":["The first canon","The third canon","The second canon","The fourth canon"],"answer":1,"explain":"<strong>Correct.</strong> The third canon requires members to provide diligent and competent service to principals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The first canon</b>: The first canon concerns protecting society and the infrastructure.</span><span class='qd'><b>The second canon</b>: The second canon concerns acting honorably, honestly, justly, responsibly, and legally.</span><span class='qd'><b>The fourth canon</b>: The fourth canon concerns advancing and protecting the profession.</span>"},{"id":"D1-035","domain":1,"obj":"1.4","diff":"easy","q":"Which statement best reflects the purpose of the preamble to the ISC2 Code of Ethics?","options":["It lists the specific penalties for each violation","It states that adherence is voluntary and optional","It establishes that the safety and welfare of society require high standards of ethical conduct","It defines the technical requirements for certification exams"],"answer":2,"explain":"<strong>Correct.</strong> The preamble emphasizes that the safety and welfare of society and the common good require members to adhere to high ethical standards.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It lists the specific penalties for each violation</b>: The preamble sets purpose and principles, not a penalty schedule.</span><span class='qd'><b>It states that adherence is voluntary and optional</b>: Adherence is a condition of certification, not optional.</span><span class='qd'><b>It defines the technical requirements for certification exams</b>: The preamble addresses ethics, not exam content.</span>"},{"id":"D1-036","domain":1,"obj":"1.4","diff":"medium","q":"An ISC2 certified professional discovers that knowingly publishing false information about a competitor would harm trust in the profession. Refraining from this act most directly upholds which canon?","options":["Protect society and the infrastructure","Act honorably, honestly, justly, responsibly, and legally","Provide diligent and competent service to principals","Advance and protect the profession"],"answer":3,"explain":"<strong>Correct.</strong> Avoiding conduct that damages the reputation and trust of the field upholds the fourth canon, to advance and protect the profession.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Protect society and the infrastructure</b>: This first canon concerns public safety, not professional reputation directly.</span><span class='qd'><b>Act honorably, honestly, justly, responsibly, and legally</b>: While related to honesty, the harm described is specifically to the profession.</span><span class='qd'><b>Provide diligent and competent service to principals</b>: This concerns service quality to clients, not protecting the profession's reputation.</span>"},{"id":"D1-037","domain":1,"obj":"1.4","diff":"easy","q":"To remain in good standing, an ISC2 member must agree to abide by what?","options":["The ISC2 Code of Ethics","A vendor partnership contract","A government security clearance","A non-disclosure agreement with ISC2"],"answer":0,"explain":"<strong>Correct.</strong> All ISC2 members must commit to fully support and abide by the ISC2 Code of Ethics.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A non-disclosure agreement with ISC2</b>: An NDA is not the binding ethical requirement for membership.</span><span class='qd'><b>A vendor partnership contract</b>: Vendor contracts are unrelated to maintaining ISC2 membership standing.</span><span class='qd'><b>A government security clearance</b>: A clearance is not required to hold ISC2 certification.</span>"},{"id":"D1-038","domain":1,"obj":"1.5","diff":"easy","q":"In the governance hierarchy, which document is a mandatory, high-level statement of management intent?","options":["Guideline","Policy","Procedure","Baseline reference only"],"answer":1,"explain":"<strong>Correct.</strong> A policy is a mandatory, high-level document that expresses management's intent and direction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guideline</b>: Guidelines are recommended, non-mandatory best practices, not high-level mandates.</span><span class='qd'><b>Procedure</b>: Procedures are detailed step-by-step instructions, not high-level statements.</span><span class='qd'><b>Baseline reference only</b>: A baseline is a minimum standard, not a high-level statement of intent.</span>"},{"id":"D1-039","domain":1,"obj":"1.5","diff":"easy","q":"Which governance document provides recommended, non-mandatory advice that helps people apply policies?","options":["Standard","Procedure","Guideline","Regulation"],"answer":2,"explain":"<strong>Correct.</strong> Guidelines offer recommended, optional guidance to help users apply policies and standards.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Standard</b>: Standards are mandatory specifications, not optional advice.</span><span class='qd'><b>Procedure</b>: Procedures are mandatory, detailed steps, not flexible recommendations.</span><span class='qd'><b>Regulation</b>: A regulation is an enforceable legal rule, not voluntary guidance.</span>"},{"id":"D1-040","domain":1,"obj":"1.5","diff":"medium","q":"A document specifies the exact step-by-step actions an administrator must take to configure a new server securely. Which type of governance document is this?","options":["Policy","Standard","Guideline","Procedure"],"answer":3,"explain":"<strong>Correct.</strong> A procedure provides detailed, mandatory, step-by-step instructions to accomplish a task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Policy</b>: A policy states high-level intent, not specific configuration steps.</span><span class='qd'><b>Standard</b>: A standard defines mandatory requirements but not the sequence of actions to perform them.</span><span class='qd'><b>Guideline</b>: A guideline offers optional recommendations, not mandatory steps.</span>"},{"id":"D1-041","domain":1,"obj":"1.5","diff":"medium","q":"A document mandates that all company laptops must use full-disk encryption with AES-256. Which type of governance document specifies this required technology choice?","options":["Standard","Guideline","Procedure","Policy"],"answer":0,"explain":"<strong>Correct.</strong> A standard defines mandatory, specific requirements such as a required encryption algorithm and key length.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guideline</b>: Guidelines are recommendations, not mandatory technical requirements.</span><span class='qd'><b>Procedure</b>: A procedure describes how to perform the encryption steps, not the required specification itself.</span><span class='qd'><b>Policy</b>: A policy would state the intent to protect data, while the standard specifies the exact requirement.</span>"},{"id":"D1-042","domain":1,"obj":"1.5","diff":"medium","q":"A European online retailer must protect the personal data of EU residents and report certain breaches within 72 hours. Which regulation imposes these obligations?","options":["HIPAA","GDPR","SOX","GLBA"],"answer":1,"explain":"<strong>Correct.</strong> The General Data Protection Regulation (GDPR) governs personal data of EU residents and includes a 72-hour breach notification requirement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HIPAA</b>: HIPAA governs protected health information in the United States, not EU personal data broadly.</span><span class='qd'><b>SOX</b>: The Sarbanes-Oxley Act addresses financial reporting and corporate governance, not EU privacy.</span><span class='qd'><b>GLBA</b>: The Gramm-Leach-Bliley Act covers financial institutions' handling of customer data in the US.</span>"},{"id":"D1-043","domain":1,"obj":"1.5","diff":"easy","q":"Which U.S. regulation primarily governs the privacy and security of protected health information?","options":["GDPR","PCI DSS","HIPAA","FERPA"],"answer":2,"explain":"<strong>Correct.</strong> The Health Insurance Portability and Accountability Act (HIPAA) protects the privacy and security of health information in the United States.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GDPR</b>: GDPR is the EU data protection regulation, not specific to U.S. health information.</span><span class='qd'><b>PCI DSS</b>: PCI DSS is a payment card industry standard, not a health information law.</span><span class='qd'><b>FERPA</b>: FERPA protects student education records, not health information broadly.</span>"},{"id":"D1-044","domain":1,"obj":"1.5","diff":"hard","q":"A company performs ongoing monitoring and periodic reviews to ensure its previously implemented security controls continue to operate effectively. Which concept does this ongoing activity best illustrate?","options":["Due care","Risk acceptance","Separation of duties","Due diligence"],"answer":3,"explain":"<strong>Correct.</strong> Due diligence is the ongoing practice of investigating, monitoring, and verifying that controls and obligations continue to be met.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Due care</b>: Due care is taking the reasonable actions a prudent person would take; ongoing verification is the diligence aspect.</span><span class='qd'><b>Risk acceptance</b>: Risk acceptance is choosing to absorb a risk, not monitoring controls.</span><span class='qd'><b>Separation of duties</b>: This divides tasks among individuals to prevent fraud, unrelated to ongoing control review.</span>"},{"id":"D1-045","domain":1,"obj":"1.5","diff":"medium","q":"Which statement best distinguishes due care from due diligence?","options":["Due care is doing what a reasonable person would do; due diligence is the ongoing investigation and monitoring to know what to do","Due care is the ongoing investigation; due diligence is taking action","They are identical legal concepts","Due care applies only to physical security and due diligence only to technical security"],"answer":0,"explain":"<strong>Correct.</strong> Due care is acting reasonably as a prudent person would, while due diligence is the ongoing investigation and monitoring that informs those actions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Due care is the ongoing investigation; due diligence is taking action</b>: This reverses the definitions of the two terms.</span><span class='qd'><b>They are identical legal concepts</b>: They are related but distinct; one is action, the other is investigation.</span><span class='qd'><b>Due care applies only to physical security and due diligence only to technical security</b>: Neither concept is limited to a single security domain.</span>"},{"id":"D1-046","domain":1,"obj":"1.5","diff":"hard","q":"In the governance hierarchy, which sequence correctly orders documents from the most mandatory and high-level to the most optional?","options":["Procedure, policy, standard, guideline","Policy, standard, procedure, guideline","Guideline, standard, policy, procedure","Standard, guideline, policy, procedure"],"answer":1,"explain":"<strong>Correct.</strong> The typical hierarchy flows from policy (high-level intent) to standard (mandatory specifics) to procedure (mandatory steps) to guideline (optional advice).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Procedure, policy, standard, guideline</b>: A procedure derives from policy and standards, so it should not come first.</span><span class='qd'><b>Guideline, standard, policy, procedure</b>: A guideline is optional and lowest, so it cannot lead the hierarchy.</span><span class='qd'><b>Standard, guideline, policy, procedure</b>: This misorders the items; policy is the highest-level driver.</span>"},{"id":"D1-047","domain":1,"obj":"1.5","diff":"easy","q":"What is the primary purpose of organizational security governance?","options":["To replace all technical controls with policies","To eliminate all risk from the organization","To direct and oversee the organization's security activities in line with business objectives and legal requirements","To assign blame after a security incident"],"answer":2,"explain":"<strong>Correct.</strong> Governance provides the direction and oversight that align security activities with business goals and legal or regulatory obligations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To replace all technical controls with policies</b>: Governance guides controls; it does not replace them.</span><span class='qd'><b>To eliminate all risk from the organization</b>: Risk cannot be fully eliminated; governance manages it.</span><span class='qd'><b>To assign blame after a security incident</b>: Governance is about direction and oversight, not assigning blame.</span>"},{"id":"D1-048","domain":1,"obj":"1.1","diff":"hard","q":"A bank wants to ensure that account balances displayed to customers exactly match the authoritative ledger and cannot be silently corrupted. Which combination of mechanisms most directly supports this integrity goal?","options":["Load balancing and failover clustering","Tokenization for confidentiality only","Multi-factor authentication and SSO","Hashing and checksums to detect unauthorized changes"],"answer":3,"explain":"<strong>Correct.</strong> Hashing and checksums detect unauthorized or accidental modifications to data, directly supporting integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Load balancing and failover clustering</b>: These support availability, not detection of data alteration.</span><span class='qd'><b>Multi-factor authentication and SSO</b>: These verify identity but do not detect changes to the balances themselves.</span><span class='qd'><b>Tokenization for confidentiality only</b>: Tokenization protects confidentiality of sensitive values, not data integrity.</span>"},{"id":"D1-049","domain":1,"obj":"1.2","diff":"easy","q":"Which best defines 'risk' in information security?","options":["The potential for loss or damage when a threat exploits a vulnerability","Any entity that may cause harm","Any weakness in a system","A control implemented to reduce harm"],"answer":0,"explain":"<strong>Correct.</strong> Risk is the potential for loss or damage that arises when a threat exploits a vulnerability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Any weakness in a system</b>: That defines a vulnerability, one component of risk.</span><span class='qd'><b>Any entity that may cause harm</b>: That defines a threat or threat actor, not risk itself.</span><span class='qd'><b>A control implemented to reduce harm</b>: That defines a safeguard or control, which reduces risk rather than being risk.</span>"},{"id":"D1-050","domain":1,"obj":"1.3","diff":"medium","q":"An organization wants a control that primarily discourages potential attackers before they act, rather than blocking or detecting them. Which control function best fits this goal?","options":["Preventive","Deterrent","Detective","Corrective"],"answer":1,"explain":"<strong>Correct.</strong> A deterrent control aims to discourage a threat actor from attempting an attack in the first place.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive</b>: Preventive controls actively block an action rather than merely discouraging it.</span><span class='qd'><b>Detective</b>: Detective controls identify events after they begin, not discourage them beforehand.</span><span class='qd'><b>Corrective</b>: Corrective controls remediate after an incident has occurred.</span>"},{"id":"D1-051","domain":1,"obj":"1.1","diff":"easy","q":"Which element of the CIA triad is most directly violated when an attacker alters the dollar amounts in a stored payroll database?","options":["Confidentiality","Availability","Integrity","Non-repudiation"],"answer":2,"explain":"<strong>Correct.</strong> Integrity ensures that data is not modified in an unauthorized or undetected manner; altering stored values is a direct integrity violation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: This concerns unauthorized disclosure or reading of data, not its alteration.</span><span class='qd'><b>Availability</b>: This concerns whether data and systems are accessible when needed, which the alteration does not by itself prevent.</span><span class='qd'><b>Non-repudiation</b>: This concerns proving who performed an action, not protecting the data values themselves.</span>"},{"id":"D1-052","domain":1,"obj":"1.1","diff":"easy","q":"A user logs in with a password and then enters a one-time code from a hardware token. Which two authentication factor categories are being combined?","options":["Somewhere you are and something you know","Something you have and something you are","Something you know and something you are","Something you know and something you have"],"answer":3,"explain":"<strong>Correct.</strong> A password is something you know and a hardware token is something you have, so two distinct factor categories are combined for MFA.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you have and something you are</b>: There is no biometric (are) factor here; a password is knowledge.</span><span class='qd'><b>Something you know and something you are</b>: The token is a possession factor, not a biometric.</span><span class='qd'><b>Somewhere you are and something you know</b>: No location-based factor is used in this scenario.</span>"},{"id":"D1-053","domain":1,"obj":"1.1","diff":"easy","q":"An auditor wants to confirm that a specific employee, and no one else, approved a wire transfer so the employee cannot later deny it. Which security concept directly supports this goal?","options":["Non-repudiation","Availability","Least privilege","Confidentiality"],"answer":0,"explain":"<strong>Correct.</strong> Non-repudiation provides assurance that an individual cannot deny having performed an action, typically through digital signatures or strong logging tied to identity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Availability</b>: This ensures access to resources when needed, not proof of who acted.</span><span class='qd'><b>Least privilege</b>: This limits access rights but does not prove authorship of an action.</span><span class='qd'><b>Confidentiality</b>: This protects data from disclosure, not the attribution of an action.</span>"},{"id":"D1-054","domain":1,"obj":"1.1","diff":"medium","q":"A bank must be able to prove that a specific customer submitted a wire-transfer request and prevent that customer from later denying it. Which security concept does this requirement describe?","options":["Confidentiality","Non-repudiation","Availability","Single sign-on"],"answer":1,"explain":"<strong>Correct.</strong> Non-repudiation provides undeniable proof of origin and action, typically through digital signatures and logging, so the originator cannot credibly deny the transaction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: this protects data from unauthorized disclosure; it does nothing to prove who initiated an action.</span><span class='qd'><b>Availability</b>: this ensures systems are accessible when needed and is unrelated to proving the origin of a transaction.</span><span class='qd'><b>Single sign-on</b>: this is a convenience mechanism for authenticating once to many systems, not a means of preventing denial of an action.</span>"},{"id":"D1-055","domain":1,"obj":"1.1","diff":"medium","q":"A fingerprint scanner occasionally rejects a legitimate enrolled user. Which biometric error metric describes this outcome?","options":["False acceptance rate","Crossover error rate","False rejection rate","Failure to enroll rate"],"answer":2,"explain":"<strong>Correct.</strong> The false rejection rate (Type I error) measures how often a legitimate, enrolled user is incorrectly denied by the biometric system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False acceptance rate</b>: This measures how often an unauthorized user is wrongly accepted, the opposite error.</span><span class='qd'><b>Crossover error rate</b>: This is the point where false acceptance and false rejection rates are equal, not a single rejection event.</span><span class='qd'><b>Failure to enroll rate</b>: This measures inability to register a user during enrollment, not rejection of an enrolled user.</span>"},{"id":"D1-056","domain":1,"obj":"1.1","diff":"medium","q":"Which scenario best illustrates a violation of the DAD triad component that opposes availability?","options":["An attacker reads confidential salary data","A user is granted excessive permissions","An attacker modifies a configuration file","A ransomware attack encrypts files so staff cannot access them"],"answer":3,"explain":"<strong>Correct.</strong> In the DAD triad, disruption opposes availability; ransomware that blocks access to files is a disruption of availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An attacker reads confidential salary data</b>: This is disclosure, which opposes confidentiality.</span><span class='qd'><b>An attacker modifies a configuration file</b>: This is alteration, which opposes integrity.</span><span class='qd'><b>A user is granted excessive permissions</b>: This is a privilege management weakness, not directly a DAD triad disruption event.</span>"},{"id":"D1-057","domain":1,"obj":"1.1","diff":"hard","q":"An organization replaces a shared team login with individual accounts so that every action can be traced to a single person. Which combination of principles is BEST served by this change?","options":["Accountability and non-repudiation","Confidentiality and availability","Redundancy and resilience","Encryption and hashing"],"answer":0,"explain":"<strong>Correct.</strong> Unique individual accounts enable accountability by tying actions to identities and strengthen non-repudiation because users cannot credibly deny actions logged under their own account.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality and availability</b>: Individual accounts do not primarily protect secrecy or uptime; they enable attribution.</span><span class='qd'><b>Redundancy and resilience</b>: These relate to fault tolerance and recovery, not user attribution.</span><span class='qd'><b>Encryption and hashing</b>: These are cryptographic techniques and are not what individual accounts inherently provide.</span>"},{"id":"D1-058","domain":1,"obj":"1.1","diff":"easy","q":"Which of the following is considered personally identifiable information (PII) that most directly identifies an individual?","options":["A favorite color preference","A Social Security number","A company's quarterly revenue","A server's IP subnet mask"],"answer":1,"explain":"<strong>Correct.</strong> A Social Security number is a sensitive identifier that directly distinguishes one individual and is classic PII.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A favorite color preference</b>: This is not uniquely identifying and is not regulated PII on its own.</span><span class='qd'><b>A company's quarterly revenue</b>: This is corporate data, not personal information about an individual.</span><span class='qd'><b>A server's IP subnet mask</b>: This is network configuration data, not information about a person.</span>"},{"id":"D1-059","domain":1,"obj":"1.1","diff":"medium","q":"A bank requires customers to provide a PIN, a debit card, and a fingerprint at high-value kiosks. How many distinct authentication factors are in use?","options":["One","Two","Three","Four"],"answer":2,"explain":"<strong>Correct.</strong> A PIN (something you know), a card (something you have), and a fingerprint (something you are) are three distinct factor categories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One</b>: Multiple unrelated categories are present, so this undercounts.</span><span class='qd'><b>Two</b>: Three different categories are present, not two.</span><span class='qd'><b>Four</b>: Only three factor categories are used; there is no fourth such as location.</span>"},{"id":"D1-060","domain":1,"obj":"1.1","diff":"hard","q":"A privacy officer argues that even encrypted health records must be protected against unauthorized internal viewing. Which CIA principle most directly supports restricting who may view the data?","options":["Integrity","Availability","Non-repudiation","Confidentiality"],"answer":3,"explain":"<strong>Correct.</strong> Confidentiality is the principle of limiting data access and disclosure to authorized parties only, which is the basis for restricting internal viewing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Integrity</b>: This ensures data is not improperly altered, not who may view it.</span><span class='qd'><b>Availability</b>: This ensures authorized access when needed, not restriction of viewing.</span><span class='qd'><b>Non-repudiation</b>: This proves who took an action; it does not govern viewing rights.</span>"},{"id":"D1-061","domain":1,"obj":"1.2","diff":"easy","q":"Which definition correctly distinguishes a vulnerability from a threat?","options":["A vulnerability is a weakness; a threat is something that can exploit it","A vulnerability is an attacker; a threat is a flaw","A vulnerability is the loss amount; a threat is the probability","A vulnerability and a threat are identical terms"],"answer":0,"explain":"<strong>Correct.</strong> A vulnerability is a weakness or gap in a control or asset, while a threat is any event or actor with the potential to exploit that weakness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A vulnerability is an attacker; a threat is a flaw</b>: This reverses the definitions.</span><span class='qd'><b>A vulnerability is the loss amount; a threat is the probability</b>: These describe risk quantification components, not the terms themselves.</span><span class='qd'><b>A vulnerability and a threat are identical terms</b>: They are distinct concepts in risk management.</span>"},{"id":"D1-062","domain":1,"obj":"1.2","diff":"medium","q":"A single loss expectancy (SLE) is 20,000 dollars and the annualized rate of occurrence (ARO) is 0.5. What is the annualized loss expectancy (ALE)?","options":["40,000 dollars","10,000 dollars","20,000 dollars","5,000 dollars"],"answer":1,"explain":"<strong>Correct.</strong> ALE equals SLE multiplied by ARO, so 20,000 times 0.5 equals 10,000 dollars.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>40,000 dollars</b>: This would result from multiplying by 2, not 0.5.</span><span class='qd'><b>20,000 dollars</b>: This is the SLE alone, ignoring the ARO of 0.5.</span><span class='qd'><b>5,000 dollars</b>: This incorrectly uses an ARO of 0.25 rather than 0.5.</span>"},{"id":"D1-063","domain":1,"obj":"1.2","diff":"easy","q":"An organization buys cyber insurance to cover potential breach losses. Which risk treatment strategy is this?","options":["Risk avoidance","Risk mitigation","Risk transfer","Risk acceptance"],"answer":2,"explain":"<strong>Correct.</strong> Purchasing insurance shifts the financial impact of a risk to a third party, which is risk transfer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: This means eliminating the activity that causes the risk, not insuring against it.</span><span class='qd'><b>Risk mitigation</b>: This reduces likelihood or impact through controls, not by transferring financial loss.</span><span class='qd'><b>Risk acceptance</b>: This means choosing to bear the risk without action, which insurance does not do.</span>"},{"id":"D1-064","domain":1,"obj":"1.2","diff":"medium","q":"After applying all selected controls, the risk that still remains is best described as which type of risk?","options":["Inherent risk","Total risk","Transferred risk","Residual risk"],"answer":3,"explain":"<strong>Correct.</strong> Residual risk is the risk that remains after controls and other treatments have been applied.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Inherent risk</b>: This is the risk present before any controls are applied.</span><span class='qd'><b>Total risk</b>: This refers to the full risk before treatment, similar to inherent risk.</span><span class='qd'><b>Transferred risk</b>: This is the portion shifted to a third party, not what remains internally.</span>"},{"id":"D1-065","domain":1,"obj":"1.2","diff":"hard","q":"A company decides to stop offering a legacy online service entirely because its security risks cannot be reduced to an acceptable level. Which risk treatment is this and why?","options":["Risk avoidance, because they eliminate the risky activity","Risk transfer, because they shift it to customers","Risk acceptance, because they tolerate the risk","Risk mitigation, because they reduce the impact"],"answer":0,"explain":"<strong>Correct.</strong> Discontinuing the activity entirely removes exposure to the associated risk, which is the definition of risk avoidance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk acceptance, because they tolerate the risk</b>: They are not tolerating it; they are ending the activity.</span><span class='qd'><b>Risk transfer, because they shift it to customers</b>: No third party is assuming the risk; the activity ceases.</span><span class='qd'><b>Risk mitigation, because they reduce the impact</b>: They are not reducing impact; they are eliminating the source.</span>"},{"id":"D1-066","domain":1,"obj":"1.2","diff":"easy","q":"Which approach to risk analysis assigns descriptive ratings such as high, medium, and low rather than numeric dollar values?","options":["Quantitative analysis","Qualitative analysis","Actuarial analysis","Statistical sampling"],"answer":1,"explain":"<strong>Correct.</strong> Qualitative risk analysis uses subjective, descriptive categories like high, medium, and low instead of precise monetary figures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Quantitative analysis</b>: This assigns numeric and monetary values such as ALE.</span><span class='qd'><b>Actuarial analysis</b>: This is a statistical insurance technique, not the descriptive rating method described.</span><span class='qd'><b>Statistical sampling</b>: This is a data collection method, not a risk rating scheme.</span>"},{"id":"D1-067","domain":1,"obj":"1.2","diff":"medium","q":"Senior leadership states the organization is willing to take on significant risk to pursue rapid market expansion. This statement best describes the organization's:","options":["Risk tolerance","Residual risk","Risk appetite","Single loss expectancy"],"answer":2,"explain":"<strong>Correct.</strong> Risk appetite is the broad amount and type of risk an organization is willing to pursue to meet its strategic objectives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk tolerance</b>: This is the acceptable variation around specific objectives, a narrower operational measure.</span><span class='qd'><b>Residual risk</b>: This is leftover risk after controls, not a strategic willingness statement.</span><span class='qd'><b>Single loss expectancy</b>: This is a monetary loss value for one event, not a strategic stance.</span>"},{"id":"D1-068","domain":1,"obj":"1.2","diff":"hard","q":"A risk register shows an asset value of 100,000 dollars, an exposure factor of 30 percent, and an ARO of 2. What is the ALE?","options":["30,000 dollars","200,000 dollars","15,000 dollars","60,000 dollars"],"answer":3,"explain":"<strong>Correct.</strong> SLE equals asset value times exposure factor (100,000 times 0.30 equals 30,000), and ALE equals SLE times ARO (30,000 times 2 equals 60,000 dollars).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>30,000 dollars</b>: This is only the SLE; it ignores the ARO of 2.</span><span class='qd'><b>15,000 dollars</b>: This uses an exposure factor of 15 percent, not 30 percent.</span><span class='qd'><b>200,000 dollars</b>: This incorrectly multiplies asset value by ARO without applying the exposure factor.</span>"},{"id":"D1-069","domain":1,"obj":"1.2","diff":"easy","q":"Management reviews a low-impact, low-likelihood risk and formally decides to take no action and bear it. Which treatment is this?","options":["Risk acceptance","Risk avoidance","Risk mitigation","Risk transfer"],"answer":0,"explain":"<strong>Correct.</strong> Knowingly choosing to bear a risk without additional controls is risk acceptance, appropriate when the risk falls within tolerance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: This would mean eliminating the activity, which management is not doing.</span><span class='qd'><b>Risk mitigation</b>: This involves applying controls to reduce the risk, which is explicitly not happening.</span><span class='qd'><b>Risk transfer</b>: This shifts the risk to a third party such as an insurer, which is not occurring.</span>"},{"id":"D1-070","domain":1,"obj":"1.2","diff":"medium","q":"Which statement correctly characterizes the relationship among threat, vulnerability, and risk?","options":["Risk exists whenever a vulnerability is present, regardless of threats","Risk exists only when a threat can exploit a vulnerability to cause impact","A threat with no vulnerability still produces high risk","Vulnerabilities are caused by risks"],"answer":1,"explain":"<strong>Correct.</strong> Risk arises from the intersection of a threat and a corresponding vulnerability that can produce an adverse impact; without both, meaningful risk is low.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk exists whenever a vulnerability is present, regardless of threats</b>: A vulnerability with no threat to exploit it produces little to no realized risk.</span><span class='qd'><b>A threat with no vulnerability still produces high risk</b>: Without an exploitable weakness, the threat cannot cause impact.</span><span class='qd'><b>Vulnerabilities are caused by risks</b>: This reverses the relationship; vulnerabilities contribute to risk, not the other way around.</span>"},{"id":"D1-071","domain":1,"obj":"1.3","diff":"easy","q":"A locked door, a security guard, and a fence are examples of which category of security control?","options":["Technical controls","Administrative controls","Physical controls","Compensating controls"],"answer":2,"explain":"<strong>Correct.</strong> Physical controls are tangible measures such as locks, guards, and fences that protect facilities and assets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Technical controls</b>: These are implemented through technology such as firewalls and encryption.</span><span class='qd'><b>Administrative controls</b>: These are policies, procedures, and training, not physical barriers.</span><span class='qd'><b>Compensating controls</b>: This describes a control's purpose as an alternative, not the physical category itself.</span>"},{"id":"D1-072","domain":1,"obj":"1.3","diff":"medium","q":"A security team installs an intrusion detection system that alerts analysts after suspicious activity occurs but does not block it. By control function, this is primarily a:","options":["Preventive control","Corrective control","Deterrent control","Detective control"],"answer":3,"explain":"<strong>Correct.</strong> A detective control identifies and alerts on incidents that have occurred or are in progress, which is exactly what an alerting IDS does.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive control</b>: This would stop or block the activity, but the IDS only alerts.</span><span class='qd'><b>Corrective control</b>: This restores systems after an incident, which detection alone does not do.</span><span class='qd'><b>Deterrent control</b>: This discourages action through visible threat of consequence, not by detecting after the fact.</span>"},{"id":"D1-073","domain":1,"obj":"1.3","diff":"easy","q":"A prominent warning sign stating that premises are under 24-hour video surveillance is intended mainly to discourage intruders. This is an example of which control function?","options":["Deterrent","Corrective","Detective","Compensating"],"answer":0,"explain":"<strong>Correct.</strong> A deterrent control aims to discourage a potential attacker from acting by signaling consequences, which is the purpose of the warning sign.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detective</b>: The camera itself detects, but the sign's purpose is to discourage, not to record.</span><span class='qd'><b>Corrective</b>: This restores after an event and does not describe a warning sign.</span><span class='qd'><b>Compensating</b>: This substitutes for another control; the sign is a primary deterrent, not a substitute.</span>"},{"id":"D1-074","domain":1,"obj":"1.3","diff":"hard","q":"A required control cannot be implemented because the legacy application does not support it, so management approves additional network segmentation and monitoring to provide equivalent protection. The segmentation and monitoring are functioning as which type of control?","options":["Directive controls","Compensating controls","Deterrent controls","Preventive controls only"],"answer":1,"explain":"<strong>Correct.</strong> Compensating controls are alternative measures put in place when a primary required control cannot be used, providing comparable protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Directive controls</b>: These instruct or mandate behavior through policy, not substitute for an unavailable control.</span><span class='qd'><b>Deterrent controls</b>: These discourage attackers but are not defined by substituting for a missing control.</span><span class='qd'><b>Preventive controls only</b>: While they help prevent, the defining role here is substitution, making compensating the best answer.</span>"},{"id":"D1-075","domain":1,"obj":"1.3","diff":"easy","q":"Security awareness training and an acceptable use policy are examples of which control category?","options":["Physical controls","Technical controls","Administrative controls","Logical controls"],"answer":2,"explain":"<strong>Correct.</strong> Administrative (managerial) controls include policies, procedures, and training that govern how people behave and operate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical controls</b>: These are tangible barriers like locks and guards, not policies or training.</span><span class='qd'><b>Technical controls</b>: These are technology-based mechanisms such as access control lists.</span><span class='qd'><b>Logical controls</b>: This is another term for technical controls, not policies and training.</span>"},{"id":"D1-076","domain":1,"obj":"1.3","diff":"medium","q":"After a malware infection, an organization restores affected systems from clean backups to return to normal operation. The restoration represents which control function?","options":["Preventive","Detective","Directive","Corrective"],"answer":3,"explain":"<strong>Correct.</strong> Corrective controls act after an incident to remediate damage and restore systems to a secure operational state, as restoring from backup does.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive</b>: This would have stopped the infection before it occurred, not restored afterward.</span><span class='qd'><b>Detective</b>: This identifies the incident but does not restore operations.</span><span class='qd'><b>Directive</b>: This mandates required behavior and does not perform recovery.</span>"},{"id":"D1-077","domain":1,"obj":"1.3","diff":"hard","q":"A firewall rule that blocks all inbound traffic to a sensitive subnet except approved ports is BEST classified by category and function as which of the following?","options":["A technical, preventive control","A physical, deterrent control","An administrative, detective control","A compensating, corrective control"],"answer":0,"explain":"<strong>Correct.</strong> A firewall is implemented through technology (technical category) and stops unauthorized traffic before it reaches the subnet (preventive function).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A physical, deterrent control</b>: A firewall is not a tangible barrier, and its goal is to block, not merely discourage.</span><span class='qd'><b>An administrative, detective control</b>: It is not a policy, and it actively blocks rather than only detecting.</span><span class='qd'><b>A compensating, corrective control</b>: It is a primary preventive measure, not a substitute or a post-incident remediation.</span>"},{"id":"D1-078","domain":1,"obj":"1.3","diff":"medium","q":"A policy that explicitly requires all employees to lock their workstations when stepping away is an example of which control function?","options":["Detective control","Directive control","Compensating control","Corrective control"],"answer":1,"explain":"<strong>Correct.</strong> A directive control instructs or mandates specific behavior, such as a policy requiring users to lock their workstations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detective control</b>: This identifies events after they happen, not mandates behavior in advance.</span><span class='qd'><b>Compensating control</b>: This substitutes for an unavailable control, which the policy does not do.</span><span class='qd'><b>Corrective control</b>: This remediates after an incident rather than directing behavior.</span>"},{"id":"D1-079","domain":1,"obj":"1.3","diff":"medium","q":"Which pairing correctly matches a control to BOTH a valid category and a valid function?","options":["Encryption: physical, deterrent","Bollard at an entrance: technical, corrective","Background check: administrative, preventive","Audit log review: physical, directive"],"answer":2,"explain":"<strong>Correct.</strong> A background check is an administrative control and serves a preventive function by screening out unsuitable individuals before hiring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption: physical, deterrent</b>: Encryption is a technical control with a preventive (confidentiality) function, not physical or deterrent.</span><span class='qd'><b>Bollard at an entrance: technical, corrective</b>: A bollard is a physical control with a preventive or deterrent function, not technical or corrective.</span><span class='qd'><b>Audit log review: physical, directive</b>: Reviewing logs is a technical or administrative detective activity, not physical or directive.</span>"},{"id":"D1-080","domain":1,"obj":"1.3","diff":"hard","q":"An organization wants a single control that both discourages tailgating and records who enters a data center. Which solution best provides a deterrent and a detective function together?","options":["A posted no-entry sign only","A nightly backup job","An acceptable use policy","A mantrap with badge logging and CCTV"],"answer":3,"explain":"<strong>Correct.</strong> A mantrap with badge logging and CCTV deters tailgating by controlling single-person passage and detects entries by recording badge use and video.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A posted no-entry sign only</b>: This may deter but does not detect or record who enters.</span><span class='qd'><b>An acceptable use policy</b>: This is administrative guidance and provides neither physical deterrence nor entry detection.</span><span class='qd'><b>A nightly backup job</b>: This is a corrective control unrelated to deterring or detecting physical entry.</span>"},{"id":"D1-081","domain":1,"obj":"1.4","diff":"medium","q":"An ISC2 member discovers a serious, previously unknown vulnerability in a client public-facing system. Acting in accordance with the ISC2 Code of Ethics, what is the MOST appropriate action?","options":["Responsibly and privately disclose the issue to the client so it can be remediated","Publicly post full exploit details immediately to pressure the client","Quietly ignore it because it falls outside the original engagement scope","Offer to sell the details to a competing firm"],"answer":0,"explain":"<strong>Correct.</strong> Acting honorably and providing diligent, competent service to principals means reporting the flaw responsibly to the party that can fix it, protecting the public trust.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publicly post full exploit details immediately to pressure the client</b>: irresponsible disclosure endangers the public and violates the canon to protect society and act honorably.</span><span class='qd'><b>Quietly ignore it because it falls outside the original engagement scope</b>: knowingly leaving a serious risk unaddressed fails the duty to act honorably and protect the public.</span><span class='qd'><b>Offer to sell the details to a competing firm</b>: this is dishonest and illegal, breaching every canon of the Code.</span>"},{"id":"D1-082","domain":1,"obj":"1.4","diff":"easy","q":"Under the ISC2 ethics complaint process, who may generally file a complaint alleging that a member violated a canon of the Code of Ethics?","options":["Only another ISC2-certified member","Anyone affected by the conduct, subject to the published complaint procedures","Only the member direct employer","Only a government regulator"],"answer":1,"explain":"<strong>Correct.</strong> ISC2 accepts ethics complaints under its published procedures; standing to file depends on which canon is alleged to be violated, but complaints are not limited to fellow members.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only another ISC2-certified member</b>: membership is not a prerequisite to raise an ethics concern under the published procedures.</span><span class='qd'><b>Only the member direct employer</b>: employers are not the sole parties with standing; affected individuals may file.</span><span class='qd'><b>Only a government regulator</b>: the ethics process is administered by ISC2, not restricted to regulators.</span>"},{"id":"D1-083","domain":1,"obj":"1.4","diff":"medium","q":"Which choice lists the ISC2 Code of Ethics canons in their correct order?","options":["Provide diligent service; protect society; act honorably; advance the profession","Act honorably; protect society; advance the profession; provide diligent service","Protect society; act honorably; provide diligent service; advance the profession","Advance the profession; act honorably; protect society; provide diligent service"],"answer":2,"explain":"<strong>Correct.</strong> The canons in order are: protect society and the infrastructure; act honorably, honestly, justly, responsibly, and legally; provide diligent and competent service to principals; and advance and protect the profession.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Act honorably; protect society; advance the profession; provide diligent service</b>: This places acting honorably first and misorders the rest.</span><span class='qd'><b>Provide diligent service; protect society; act honorably; advance the profession</b>: This starts with the third canon out of order.</span><span class='qd'><b>Advance the profession; act honorably; protect society; provide diligent service</b>: This starts with the fourth canon out of order.</span>"},{"id":"D1-084","domain":1,"obj":"1.4","diff":"medium","q":"A certified professional discovers a serious flaw but is told to stay silent to protect a client's reputation, even though the flaw endangers the public. Which canon most directly guides the professional to prioritize public safety?","options":["The canon to advance and protect the profession","The canon to act honorably toward employers","The canon to provide diligent service to principals","The canon to protect society and the common good"],"answer":3,"explain":"<strong>Correct.</strong> The first canon, to protect society, the common good, and the infrastructure, prioritizes public welfare and supports disclosing dangers to the public.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The canon to advance and protect the profession</b>: This concerns the profession's reputation, not directly public safety in this dilemma.</span><span class='qd'><b>The canon to provide diligent service to principals</b>: This favors the client and is the source of the conflict, not the resolution.</span><span class='qd'><b>The canon to act honorably toward employers</b>: This is part of acting honorably but does not establish public safety as the priority the way the first canon does.</span>"},{"id":"D1-085","domain":1,"obj":"1.4","diff":"medium","q":"When two ISC2 canons appear to conflict, which guidance does the Code provide for applying them?","options":["The canons are listed in order of priority and applied as guidance, not as rigid rules","Members may ignore any canon they personally disagree with","The fourth canon always takes precedence","Conflicts are resolved by majority vote of peers"],"answer":0,"explain":"<strong>Correct.</strong> ISC2 presents the canons in order of priority and intends them as broad ethical guidance, with earlier canons generally taking precedence when conflicts arise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Members may ignore any canon they personally disagree with</b>: Members agree to uphold all canons; personal disagreement is not a valid exemption.</span><span class='qd'><b>The fourth canon always takes precedence</b>: The fourth canon is the lowest priority, not the highest.</span><span class='qd'><b>Conflicts are resolved by majority vote of peers</b>: The Code does not specify peer voting as the resolution mechanism.</span>"},{"id":"D1-086","domain":1,"obj":"1.4","diff":"easy","q":"'Act honorably, honestly, justly, responsibly, and legally' corresponds to which canon by position?","options":["The first canon","The second canon","The third canon","The fourth canon"],"answer":1,"explain":"<strong>Correct.</strong> Acting honorably, honestly, justly, responsibly, and legally is the second canon of the ISC2 Code of Ethics.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The first canon</b>: The first canon is to protect society and the infrastructure.</span><span class='qd'><b>The third canon</b>: The third canon is to provide diligent and competent service to principals.</span><span class='qd'><b>The fourth canon</b>: The fourth canon is to advance and protect the profession.</span>"},{"id":"D1-087","domain":1,"obj":"1.4","diff":"medium","q":"A consultant deliberately exaggerates credentials to win a contract. Which canon does this conduct most directly violate?","options":["Protect society and the infrastructure","Provide diligent and competent service to principals","Act honorably, honestly, justly, responsibly, and legally","Advance and protect the profession"],"answer":2,"explain":"<strong>Correct.</strong> Misrepresenting credentials is dishonest conduct, directly violating the second canon to act honorably, honestly, justly, responsibly, and legally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Protect society and the infrastructure</b>: This concerns public welfare, which is not the central breach in lying about credentials.</span><span class='qd'><b>Provide diligent and competent service to principals</b>: While related, the core violation is dishonesty, not service quality.</span><span class='qd'><b>Advance and protect the profession</b>: Although such conduct harms the profession, the direct violation is the dishonest act under the second canon.</span>"},{"id":"D1-088","domain":1,"obj":"1.4","diff":"hard","q":"A member knowingly performs work outside their area of competence and conceals errors from the client. Which canon is MOST directly breached?","options":["Comply with all local laws only","Protect society and the infrastructure","Advance and protect the profession","Provide diligent and competent service to principals"],"answer":3,"explain":"<strong>Correct.</strong> The third canon requires diligent and competent service to principals; working beyond one's competence and hiding errors directly violates it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Protect society and the infrastructure</b>: This addresses public welfare, which is not the most direct breach in a client-service failure.</span><span class='qd'><b>Advance and protect the profession</b>: The conduct harms the profession indirectly, but the direct breach is the failure of competent service.</span><span class='qd'><b>Comply with all local laws only</b>: This is not a canon of the ISC2 Code of Ethics.</span>"},{"id":"D1-089","domain":1,"obj":"1.4","diff":"medium","q":"Mentoring newcomers, supporting the certification's integrity, and not bringing disrepute to the field most directly reflect which canon?","options":["Advance and protect the profession","Act honorably, honestly, justly, responsibly, and legally","Provide diligent and competent service to principals","Protect society and the infrastructure"],"answer":0,"explain":"<strong>Correct.</strong> Advancing and protecting the profession (the fourth canon) encompasses mentoring, supporting certification integrity, and avoiding disrepute to the field.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Protect society and the infrastructure</b>: This focuses on public welfare, not professional advancement.</span><span class='qd'><b>Act honorably, honestly, justly, responsibly, and legally</b>: This addresses personal conduct rather than advancing the profession.</span><span class='qd'><b>Provide diligent and competent service to principals</b>: This concerns service to clients, not the profession as a whole.</span>"},{"id":"D1-090","domain":1,"obj":"1.4","diff":"easy","q":"Agreeing to and upholding the ISC2 Code of Ethics is a condition of:","options":["Renting office space","Holding ISC2 certification","Purchasing security software","Filing a privacy complaint"],"answer":1,"explain":"<strong>Correct.</strong> All ISC2 members and certification holders must agree to and abide by the Code of Ethics as a condition of certification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Renting office space</b>: This has no connection to the ISC2 Code of Ethics.</span><span class='qd'><b>Purchasing security software</b>: Buying products does not require adhering to the Code.</span><span class='qd'><b>Filing a privacy complaint</b>: This is unrelated to the certification ethics requirement.</span>"},{"id":"D1-091","domain":1,"obj":"1.5","diff":"easy","q":"Which governance document is a mandatory, high-level statement of management intent and direction?","options":["A guideline","A procedure","A policy","A baseline diagram"],"answer":2,"explain":"<strong>Correct.</strong> A policy is a mandatory, high-level document that states management's intent and overall direction for a topic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A guideline</b>: This is a recommended, non-mandatory suggestion, not a high-level mandate.</span><span class='qd'><b>A procedure</b>: This provides detailed step-by-step instructions, not high-level intent.</span><span class='qd'><b>A baseline diagram</b>: This is not a governance document type defining management intent.</span>"},{"id":"D1-092","domain":1,"obj":"1.5","diff":"easy","q":"Which governance document provides detailed, mandatory, step-by-step instructions for completing a specific task?","options":["Policy","Standard","Guideline","Procedure"],"answer":3,"explain":"<strong>Correct.</strong> A procedure is a mandatory, detailed set of step-by-step instructions describing exactly how to perform a task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Policy</b>: This is high-level intent and does not provide step-by-step instructions.</span><span class='qd'><b>Standard</b>: This specifies mandatory requirements or configurations but not the detailed steps to perform a task.</span><span class='qd'><b>Guideline</b>: This offers optional recommendations, not mandatory detailed steps.</span>"},{"id":"D1-093","domain":1,"obj":"1.5","diff":"medium","q":"Which document type is recommended but optional, offering helpful advice rather than mandatory requirements?","options":["Guideline","Procedure","Standard","Policy"],"answer":0,"explain":"<strong>Correct.</strong> A guideline provides recommended, discretionary advice and is not mandatory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Standard</b>: This sets mandatory requirements, not optional advice.</span><span class='qd'><b>Procedure</b>: This is a mandatory step-by-step instruction set.</span><span class='qd'><b>Policy</b>: This is a mandatory high-level directive.</span>"},{"id":"D1-094","domain":1,"obj":"1.5","diff":"medium","q":"A regulation that governs the protection and privacy of personal data for individuals in the European Union is:","options":["HIPAA","GDPR","PCI DSS","SOX"],"answer":1,"explain":"<strong>Correct.</strong> The General Data Protection Regulation (GDPR) governs the protection and privacy of personal data for individuals in the European Union.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HIPAA</b>: This is a U.S. law protecting health information, not an EU-wide data privacy regulation.</span><span class='qd'><b>PCI DSS</b>: This is a payment card industry security standard, not a government privacy regulation.</span><span class='qd'><b>SOX</b>: This is U.S. legislation focused on financial reporting and corporate accountability.</span>"},{"id":"D1-095","domain":1,"obj":"1.5","diff":"medium","q":"Which U.S. law primarily governs the privacy and security of protected health information?","options":["GDPR","GLBA","HIPAA","FERPA"],"answer":2,"explain":"<strong>Correct.</strong> The Health Insurance Portability and Accountability Act (HIPAA) governs the privacy and security of protected health information in the United States.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GDPR</b>: This is the European Union's data protection regulation, not a U.S. health law.</span><span class='qd'><b>GLBA</b>: This governs financial institutions' handling of consumer financial information.</span><span class='qd'><b>FERPA</b>: This protects the privacy of student education records, not health information.</span>"},{"id":"D1-096","domain":1,"obj":"1.5","diff":"medium","q":"Within the governance document hierarchy, which document type is MANDATORY and specifies an exact, measurable requirement such as a minimum password length of 14 characters?","options":["Procedure","Guideline","Mission statement","Standard"],"answer":3,"explain":"<strong>Correct.</strong> A standard is a mandatory rule that translates a high-level policy into specific, measurable requirements such as a minimum password length.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guideline</b>: a guideline is a recommended, non-mandatory best practice, so it cannot impose an exact required value.</span><span class='qd'><b>Mission statement</b>: this expresses organizational purpose and contains no enforceable technical requirements.</span><span class='qd'><b>Procedure</b>: a procedure is a step-by-step set of instructions for performing a task, not a statement of a required parameter.</span>"},{"id":"D1-097","domain":1,"obj":"1.5","diff":"hard","q":"An organization wants to mandate that all servers use a minimum TLS version. Which governance document is the MOST appropriate place to specify this required configuration?","options":["A standard","A guideline","A high-level policy statement","A general procedure"],"answer":0,"explain":"<strong>Correct.</strong> A standard defines mandatory, specific requirements such as a minimum TLS version that must be uniformly applied across systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A guideline</b>: This is optional advice and cannot impose a mandatory minimum version.</span><span class='qd'><b>A high-level policy statement</b>: A policy states intent broadly and would not specify a precise technical setting.</span><span class='qd'><b>A general procedure</b>: A procedure describes how to perform steps, not the mandated configuration requirement itself.</span>"},{"id":"D1-098","domain":1,"obj":"1.5","diff":"medium","q":"Which sequence correctly orders governance documents from highest-level intent to most detailed task instructions?","options":["Procedure, standard, policy","Policy, standard, procedure","Standard, policy, guideline","Guideline, procedure, policy"],"answer":1,"explain":"<strong>Correct.</strong> Governance flows from policy (high-level intent) to standard (mandatory requirements) to procedure (detailed step-by-step instructions).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Procedure, standard, policy</b>: This reverses the hierarchy, putting detailed steps first.</span><span class='qd'><b>Standard, policy, guideline</b>: A policy is higher-level than a standard, so this misorders them.</span><span class='qd'><b>Guideline, procedure, policy</b>: A guideline is optional and not the highest-level document, so this is incorrect.</span>"},{"id":"D1-099","domain":1,"obj":"1.5","diff":"medium","q":"A company operating only in the United States begins offering services to customers located in the European Union. Which obligation most directly arises from this expansion?","options":["It must replace HIPAA with PCI DSS","It is exempt from all privacy laws because it is U.S.-based","It must comply with GDPR for the personal data of EU individuals","GDPR no longer applies once data leaves the EU"],"answer":2,"explain":"<strong>Correct.</strong> GDPR applies extraterritorially when an organization offers goods or services to individuals in the EU, so the company must comply with GDPR for those individuals' personal data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is exempt from all privacy laws because it is U.S.-based</b>: Being U.S.-based does not exempt a company from GDPR when serving EU residents.</span><span class='qd'><b>It must replace HIPAA with PCI DSS</b>: These are unrelated frameworks and neither replaces the other based on EU expansion.</span><span class='qd'><b>GDPR no longer applies once data leaves the EU</b>: GDPR obligations follow the personal data of EU individuals regardless of where it is transferred.</span>"},{"id":"D1-100","domain":1,"obj":"1.5","diff":"medium","q":"Failing to take reasonable, expected protective measures that a prudent organization would take is best described as a failure of:","options":["Separation of duties","Risk appetite","Non-repudiation","Due care"],"answer":3,"explain":"<strong>Correct.</strong> Due care is the obligation to take reasonable, prudent steps to protect assets; failing to do so is a failure of due care, which can constitute negligence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk appetite</b>: This describes how much risk an organization is willing to accept, not a failure to act prudently.</span><span class='qd'><b>Non-repudiation</b>: This concerns proving who performed an action, unrelated to protective diligence.</span><span class='qd'><b>Separation of duties</b>: This divides tasks to prevent fraud and is not the general standard of reasonable protective action.</span>"},{"id":"D2-001","domain":2,"obj":"2.1","diff":"easy","q":"What is the primary purpose of a Business Continuity Plan (BCP)?","options":["To keep critical business functions operating during and after a disruption","To document software licensing agreements","To train new employees on company policy","To recover deleted files from backup media"],"answer":0,"explain":"<strong>Correct.</strong> A BCP focuses on keeping the organization's critical functions running (or quickly resumed) during and after a disruptive event.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To recover deleted files from backup media</b>: That is a narrow backup/restore task, not the scope of business continuity.</span><span class='qd'><b>To document software licensing agreements</b>: Licensing is an asset-management concern unrelated to continuity.</span><span class='qd'><b>To train new employees on company policy</b>: Onboarding is an HR function, not the purpose of a BCP.</span>"},{"id":"D2-002","domain":2,"obj":"2.1","diff":"easy","q":"A Business Impact Analysis (BIA) is performed mainly to identify which of the following?","options":["The market value of the company's stock","The organization's critical functions and the impact of their disruption","The personal preferences of department managers","The brand colors used in marketing materials"],"answer":1,"explain":"<strong>Correct.</strong> A BIA identifies critical business functions and quantifies the operational and financial impact if they are disrupted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The market value of the company's stock</b>: Stock valuation is a financial-market concern, not a BIA output.</span><span class='qd'><b>The personal preferences of department managers</b>: Preferences are subjective and not part of impact analysis.</span><span class='qd'><b>The brand colors used in marketing materials</b>: Branding is unrelated to continuity impact.</span>"},{"id":"D2-003","domain":2,"obj":"2.1","diff":"easy","q":"What does MTD stand for in business continuity planning?","options":["Minimum Transfer Delay","Mean Time to Detect","Maximum Tolerable Downtime","Managed Threat Database"],"answer":2,"explain":"<strong>Correct.</strong> MTD is the Maximum Tolerable Downtime, the longest a function can be unavailable before causing unacceptable harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean Time to Detect</b>: That is a security metric (MTTD), not a BC term.</span><span class='qd'><b>Minimum Transfer Delay</b>: This is not a recognized continuity term.</span><span class='qd'><b>Managed Threat Database</b>: This is a fabricated term unrelated to MTD.</span>"},{"id":"D2-004","domain":2,"obj":"2.1","diff":"easy","q":"Which of the following best describes fault tolerance?","options":["The practice of deleting old log files automatically","The process of disabling unused user accounts","The encryption of data while it is stored at rest","The ability of a system to keep operating despite the failure of a component"],"answer":3,"explain":"<strong>Correct.</strong> Fault tolerance lets a system continue functioning even when one of its components fails, typically through redundancy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The practice of deleting old log files automatically</b>: That is log rotation, unrelated to fault tolerance.</span><span class='qd'><b>The encryption of data while it is stored at rest</b>: Encryption protects confidentiality, not availability through failure.</span><span class='qd'><b>The process of disabling unused user accounts</b>: That is account hygiene, not fault tolerance.</span>"},{"id":"D2-005","domain":2,"obj":"2.1","diff":"easy","q":"In a RAID 1 configuration, data is protected by which technique?","options":["Mirroring identical data across two or more disks","Encrypting each block with a unique key","Spreading parity across a single dedicated disk","Compressing data to save disk space"],"answer":0,"explain":"<strong>Correct.</strong> RAID 1 mirrors the same data onto two (or more) disks so a single disk failure does not lose data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compressing data to save disk space</b>: Compression is unrelated to RAID redundancy.</span><span class='qd'><b>Encrypting each block with a unique key</b>: Encryption is a confidentiality control, not a RAID level feature.</span><span class='qd'><b>Spreading parity across a single dedicated disk</b>: That describes RAID 4, not RAID 1.</span>"},{"id":"D2-006","domain":2,"obj":"2.1","diff":"easy","q":"What is the main goal of load balancing?","options":["Backing up data to an offsite tape library","Distributing work across multiple systems to improve availability and performance","Scanning network traffic for malware signatures","Encrypting traffic between two endpoints"],"answer":1,"explain":"<strong>Correct.</strong> Load balancing spreads requests across multiple servers, improving availability and performance and avoiding any single overloaded node.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Backing up data to an offsite tape library</b>: That is a backup task, not load distribution.</span><span class='qd'><b>Scanning network traffic for malware signatures</b>: That is an IDS/antimalware function.</span><span class='qd'><b>Encrypting traffic between two endpoints</b>: That is a VPN/TLS function, not load balancing.</span>"},{"id":"D2-007","domain":2,"obj":"2.1","diff":"easy","q":"High availability is most directly associated with which security objective?","options":["Non-repudiation","Confidentiality","Availability","Authentication"],"answer":2,"explain":"<strong>Correct.</strong> High availability supports the availability leg of the CIA triad by minimizing downtime.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: Confidentiality concerns keeping data secret, not uptime.</span><span class='qd'><b>Non-repudiation</b>: Non-repudiation prevents denial of an action, unrelated to uptime.</span><span class='qd'><b>Authentication</b>: Authentication verifies identity, not system availability.</span>"},{"id":"D2-008","domain":2,"obj":"2.1","diff":"easy","q":"Which document typically lists the personnel, contact information, and step-by-step actions to keep operations running during a disruption?","options":["The acceptable use policy","The software bill of materials","The data classification matrix","The business continuity plan"],"answer":3,"explain":"<strong>Correct.</strong> The business continuity plan documents roles, contacts, and procedures to sustain operations during a disruption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The acceptable use policy</b>: That governs how users may use IT resources.</span><span class='qd'><b>The software bill of materials</b>: That inventories software components, not continuity steps.</span><span class='qd'><b>The data classification matrix</b>: That defines sensitivity levels, not continuity actions.</span>"},{"id":"D2-009","domain":2,"obj":"2.1","diff":"easy","q":"Clustering servers primarily provides which benefit?","options":["Continued service if one node fails by sharing the workload across multiple nodes","Stronger password complexity requirements","Faster physical shredding of decommissioned drives","Automatic patching of operating systems"],"answer":0,"explain":"<strong>Correct.</strong> A cluster groups servers so that if one node fails, others continue providing the service, supporting high availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stronger password complexity requirements</b>: That is an authentication policy, unrelated to clustering.</span><span class='qd'><b>Faster physical shredding of decommissioned drives</b>: That is media disposal, not clustering.</span><span class='qd'><b>Automatic patching of operating systems</b>: Patching is configuration management, not a clustering goal.</span>"},{"id":"D2-010","domain":2,"obj":"2.1","diff":"easy","q":"Redundancy in a system design refers to what?","options":["Removing all unnecessary code from an application","Having duplicate components so a backup can take over if the primary fails","Limiting users to a single login session","Reducing the number of firewall rules"],"answer":1,"explain":"<strong>Correct.</strong> Redundancy means providing duplicate components so a spare can take over if the primary fails, improving availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Removing all unnecessary code from an application</b>: That is code minimization, not redundancy.</span><span class='qd'><b>Limiting users to a single login session</b>: That is a session-control policy.</span><span class='qd'><b>Reducing the number of firewall rules</b>: That is rule cleanup, unrelated to redundancy.</span>"},{"id":"D2-011","domain":2,"obj":"2.1","diff":"medium","q":"A hospital identifies that its patient-admissions system can be down no longer than 30 minutes before patient safety is endangered. This 30-minute figure is best described as the system's:","options":["Mean Time Between Failures","Recovery Point Objective","Maximum Tolerable Downtime","Service Level Agreement"],"answer":2,"explain":"<strong>Correct.</strong> The longest acceptable outage before unacceptable harm occurs is the Maximum Tolerable Downtime (MTD).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery Point Objective</b>: RPO measures acceptable data loss in time, not allowable downtime.</span><span class='qd'><b>Mean Time Between Failures</b>: MTBF is a reliability statistic, not a tolerance threshold.</span><span class='qd'><b>Service Level Agreement</b>: An SLA is a contract; it may reference downtime but is not this 30-minute limit itself.</span>"},{"id":"D2-012","domain":2,"obj":"2.1","diff":"medium","q":"During a BIA, an analyst ranks business functions to decide which to restore first after an outage. What is this prioritization most directly used to determine?","options":["The annual marketing budget","The vendor for new laptop purchases","The office floor plan layout","The recovery sequence and resource allocation for critical functions"],"answer":3,"explain":"<strong>Correct.</strong> Prioritizing functions in the BIA drives the recovery order and how limited resources are allocated to the most critical functions first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The annual marketing budget</b>: Budgeting is a finance activity, not a BIA output.</span><span class='qd'><b>The vendor for new laptop purchases</b>: Procurement decisions are unrelated to recovery prioritization.</span><span class='qd'><b>The office floor plan layout</b>: Facility design is not driven by BIA function ranking.</span>"},{"id":"D2-013","domain":2,"obj":"2.1","diff":"medium","q":"An e-commerce site uses two internet circuits from different providers so that if one fails, traffic flows over the other. This is an example of:","options":["Redundancy to improve availability","Least privilege","Data classification","Separation of duties"],"answer":0,"explain":"<strong>Correct.</strong> Using two diverse circuits provides redundancy, eliminating a single point of failure and improving availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification</b>: That labels data by sensitivity, unrelated to circuit design.</span><span class='qd'><b>Least privilege</b>: That restricts access rights, not network redundancy.</span><span class='qd'><b>Separation of duties</b>: That splits tasks among people to prevent fraud, not a network control.</span>"},{"id":"D2-014","domain":2,"obj":"2.1","diff":"medium","q":"Which RAID level uses block-level striping with distributed parity, allowing the array to survive a single disk failure while using disk space efficiently?","options":["RAID 0","RAID 5","RAID 1","JBOD"],"answer":1,"explain":"<strong>Correct.</strong> RAID 5 stripes data with parity distributed across all disks, tolerating one disk failure while using space more efficiently than mirroring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID 0</b>: RAID 0 stripes data with no parity and offers no fault tolerance.</span><span class='qd'><b>RAID 1</b>: RAID 1 mirrors data but does not use distributed parity and is less space-efficient.</span><span class='qd'><b>JBOD</b>: JBOD is just a bunch of disks with no redundancy.</span>"},{"id":"D2-015","domain":2,"obj":"2.1","diff":"medium","q":"A manufacturing firm wants to ensure that a sudden power loss does not immediately shut down its servers, giving time for an orderly shutdown or generator startup. Which control most directly addresses this need?","options":["A web application firewall","A data loss prevention system","An uninterruptible power supply (UPS)","A password manager"],"answer":2,"explain":"<strong>Correct.</strong> A UPS provides short-term battery power that keeps systems running through brief outages and bridges to generator power, supporting availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A web application firewall</b>: A WAF filters web attacks, not power events.</span><span class='qd'><b>A data loss prevention system</b>: DLP prevents data exfiltration, not power loss.</span><span class='qd'><b>A password manager</b>: A password manager stores credentials, unrelated to power.</span>"},{"id":"D2-016","domain":2,"obj":"2.1","diff":"medium","q":"Why is executive (senior management) support considered essential to a successful business continuity program?","options":["It replaces the need for technical recovery controls","It eliminates the need to perform a BIA","It guarantees that no incidents will ever occur","It provides the authority, funding, and organization-wide commitment the program needs"],"answer":3,"explain":"<strong>Correct.</strong> Senior management sponsorship supplies the authority, budget, and cultural buy-in required for an effective BC program.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It eliminates the need to perform a BIA</b>: A BIA is still required regardless of executive support.</span><span class='qd'><b>It guarantees that no incidents will ever occur</b>: No control can guarantee zero incidents.</span><span class='qd'><b>It replaces the need for technical recovery controls</b>: Support funds controls; it does not replace them.</span>"},{"id":"D2-017","domain":2,"obj":"2.1","diff":"medium","q":"A company configures two firewalls in an active-passive pair so the standby unit takes over automatically if the primary fails. This arrangement is best described as:","options":["A high-availability failover configuration","A load-balanced cluster","A cold standby with manual restore","A RAID 0 stripe"],"answer":0,"explain":"<strong>Correct.</strong> Active-passive firewalls provide high availability through automatic failover from the primary to the standby unit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A load-balanced cluster</b>: Load balancing shares live traffic across nodes; active-passive keeps the standby idle until failover.</span><span class='qd'><b>A cold standby with manual restore</b>: Cold standby requires manual intervention, not automatic failover.</span><span class='qd'><b>A RAID 0 stripe</b>: RAID 0 is a disk technique with no fault tolerance, unrelated to firewalls.</span>"},{"id":"D2-018","domain":2,"obj":"2.1","diff":"medium","q":"Which statement best distinguishes a critical business function from a non-critical one?","options":["A critical function is simply any function performed by managers","A critical function would cause severe or unacceptable impact if disrupted for an extended time","A critical function is one that runs on the newest hardware","A critical function is any task documented in a policy"],"answer":1,"explain":"<strong>Correct.</strong> Criticality is defined by impact: a critical function causes severe or unacceptable harm if it is disrupted long enough.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A critical function is simply any function performed by managers</b>: Criticality is based on impact, not who performs it.</span><span class='qd'><b>A critical function is one that runs on the newest hardware</b>: Hardware age does not define criticality.</span><span class='qd'><b>A critical function is any task documented in a policy</b>: Documentation alone does not make a function critical.</span>"},{"id":"D2-019","domain":2,"obj":"2.1","diff":"hard","q":"An organization has an MTD of 4 hours for its order-processing system but has only budgeted recovery capabilities that restore service in 8 hours. What is the most accurate conclusion?","options":["The system is fully protected because a recovery capability exists","The MTD should be ignored once a recovery plan is written","There is an unacceptable gap; recovery capability must be improved or the MTD revisited","RPO automatically guarantees the MTD is met"],"answer":2,"explain":"<strong>Correct.</strong> If recovery takes longer than the MTD, the organization cannot meet its tolerance, so it must shorten recovery time or re-examine the MTD assumptions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The system is fully protected because a recovery capability exists</b>: A capability that misses the MTD is inadequate, not full protection.</span><span class='qd'><b>The MTD should be ignored once a recovery plan is written</b>: The MTD is the requirement the plan must satisfy; it cannot be ignored.</span><span class='qd'><b>RPO automatically guarantees the MTD is met</b>: RPO addresses data loss, not recovery duration, so it cannot guarantee the MTD.</span>"},{"id":"D2-020","domain":2,"obj":"2.1","diff":"hard","q":"A storage administrator chooses RAID 6 over RAID 5 for an archive array. What is the primary continuity advantage of this choice?","options":["RAID 6 encrypts data at rest automatically","RAID 6 eliminates the need for backups","RAID 6 is faster on writes than RAID 0","RAID 6 can tolerate the simultaneous failure of two disks"],"answer":3,"explain":"<strong>Correct.</strong> RAID 6 uses dual distributed parity, so the array survives two concurrent disk failures, valuable for large archive arrays with longer rebuild times.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID 6 encrypts data at rest automatically</b>: RAID provides redundancy, not encryption.</span><span class='qd'><b>RAID 6 eliminates the need for backups</b>: RAID protects against disk failure, not deletion, corruption, or disaster, so backups are still required.</span><span class='qd'><b>RAID 6 is faster on writes than RAID 0</b>: RAID 6 is slower on writes due to dual parity overhead.</span>"},{"id":"D2-021","domain":2,"obj":"2.2","diff":"easy","q":"What does RTO stand for in disaster recovery?","options":["Recovery Time Objective","Reliable Transmission Option","Recovery Transfer Order","Redundant Tape Operation"],"answer":0,"explain":"<strong>Correct.</strong> RTO is the Recovery Time Objective, the target time to restore a function after a disruption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery Transfer Order</b>: This is not a recognized DR term.</span><span class='qd'><b>Reliable Transmission Option</b>: This is a fabricated networking-sounding term.</span><span class='qd'><b>Redundant Tape Operation</b>: This is not what RTO stands for.</span>"},{"id":"D2-022","domain":2,"obj":"2.2","diff":"easy","q":"The Recovery Point Objective (RPO) defines which of the following?","options":["The maximum time allowed to restore a service","The maximum acceptable amount of data loss measured in time","The physical distance to the backup site","The number of staff on the recovery team"],"answer":1,"explain":"<strong>Correct.</strong> RPO expresses how much data, measured as a time interval, the organization can afford to lose before the last good backup.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The maximum time allowed to restore a service</b>: That defines RTO, not RPO.</span><span class='qd'><b>The number of staff on the recovery team</b>: Team size is unrelated to RPO.</span><span class='qd'><b>The physical distance to the backup site</b>: Distance is a site-design consideration, not RPO.</span>"},{"id":"D2-023","domain":2,"obj":"2.2","diff":"easy","q":"Which type of recovery site is fully equipped and operational, allowing near-immediate takeover of operations?","options":["Cold site","Warm site","Hot site","Mobile shredding unit"],"answer":2,"explain":"<strong>Correct.</strong> A hot site is fully equipped with hardware, software, and current data, enabling near-immediate failover.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cold site</b>: A cold site provides only space and utilities and requires significant setup time.</span><span class='qd'><b>Warm site</b>: A warm site has some equipment but still needs configuration and data before use.</span><span class='qd'><b>Mobile shredding unit</b>: That is a media-destruction service, not a recovery site.</span>"},{"id":"D2-024","domain":2,"obj":"2.2","diff":"easy","q":"A full backup copies what data?","options":["Only the system registry","Only the data changed since the last full backup","Only the data changed since any previous backup","All selected data, regardless of whether it has changed"],"answer":3,"explain":"<strong>Correct.</strong> A full backup copies all selected data every time, whether or not it has changed since the last backup.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the data changed since the last full backup</b>: That describes a differential backup.</span><span class='qd'><b>Only the data changed since any previous backup</b>: That describes an incremental backup.</span><span class='qd'><b>Only the system registry</b>: A full backup is not limited to the registry.</span>"},{"id":"D2-025","domain":2,"obj":"2.2","diff":"easy","q":"In the 3-2-1 backup rule, what does the '1' represent?","options":["One copy kept offsite","One full backup per year","One administrator with access","One backup software vendor"],"answer":0,"explain":"<strong>Correct.</strong> The 3-2-1 rule recommends 3 copies of data, on 2 different media types, with 1 copy stored offsite.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One full backup per year</b>: The rule does not specify yearly frequency.</span><span class='qd'><b>One administrator with access</b>: Access count is not part of the rule.</span><span class='qd'><b>One backup software vendor</b>: Vendor count is not part of the rule.</span>"},{"id":"D2-026","domain":2,"obj":"2.2","diff":"easy","q":"What is the defining characteristic of an immutable backup?","options":["It is automatically encrypted with the user's password","It cannot be altered or deleted for a defined retention period","It overwrites itself every 24 hours","It is stored only in volatile memory"],"answer":1,"explain":"<strong>Correct.</strong> An immutable backup cannot be changed or deleted during its retention period, protecting it from ransomware and tampering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is automatically encrypted with the user's password</b>: Immutability concerns write-protection, not encryption.</span><span class='qd'><b>It is stored only in volatile memory</b>: Volatile memory is lost on power off and would not retain backups.</span><span class='qd'><b>It overwrites itself every 24 hours</b>: Self-overwriting is the opposite of immutability.</span>"},{"id":"D2-027","domain":2,"obj":"2.2","diff":"easy","q":"Which disaster recovery test involves team members talking through the recovery plan around a table without performing any actual recovery actions?","options":["Full-interruption test","Parallel test","Tabletop exercise","Hot-site cutover"],"answer":2,"explain":"<strong>Correct.</strong> A tabletop exercise has participants discuss and walk through the plan in a meeting setting without taking real recovery actions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full-interruption test</b>: That actually shuts down production to test failover, far beyond discussion.</span><span class='qd'><b>Parallel test</b>: That brings the recovery site online alongside production, which is hands-on.</span><span class='qd'><b>Hot-site cutover</b>: That is an actual switch to the hot site, not a discussion.</span>"},{"id":"D2-028","domain":2,"obj":"2.2","diff":"easy","q":"A cold site typically provides which of the following?","options":["A fully mirrored, ready-to-run duplicate of production","An always-on real-time data replica","A complete pre-staged staff roster on standby","Basic facilities such as space, power, and cooling but little or no equipment"],"answer":3,"explain":"<strong>Correct.</strong> A cold site offers only the physical environment, space, power, and cooling, requiring equipment and data to be brought in after a disaster.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A fully mirrored, ready-to-run duplicate of production</b>: That describes a hot site.</span><span class='qd'><b>An always-on real-time data replica</b>: Real-time replication is characteristic of a hot site, not cold.</span><span class='qd'><b>A complete pre-staged staff roster on standby</b>: Cold sites do not inherently include standby staff.</span>"},{"id":"D2-029","domain":2,"obj":"2.2","diff":"easy","q":"Which backup type copies only the data that has changed since the last backup of any type, making each backup small but requiring all of them plus the last full backup to restore?","options":["Incremental backup","Differential backup","Full backup","Mirror backup"],"answer":0,"explain":"<strong>Correct.</strong> An incremental backup captures only changes since the last backup of any type; restoration needs the last full backup plus every incremental in sequence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Differential backup</b>: A differential copies all changes since the last full backup, growing larger each day.</span><span class='qd'><b>Full backup</b>: A full backup copies everything, not just changes.</span><span class='qd'><b>Mirror backup</b>: A mirror is an exact ongoing copy, not an incremental change set.</span>"},{"id":"D2-030","domain":2,"obj":"2.2","diff":"easy","q":"What is the purpose of a disaster recovery plan (DRP)?","options":["To define acceptable employee internet usage","To restore IT systems and data after a disruptive event","To onboard new vendors securely","To classify data by sensitivity level"],"answer":1,"explain":"<strong>Correct.</strong> A DRP focuses on restoring IT systems, infrastructure, and data following a disruptive event.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To define acceptable employee internet usage</b>: That is an acceptable use policy.</span><span class='qd'><b>To classify data by sensitivity level</b>: That is data classification, not disaster recovery.</span><span class='qd'><b>To onboard new vendors securely</b>: That is vendor management, unrelated to DR.</span>"},{"id":"D2-031","domain":2,"obj":"2.2","diff":"medium","q":"An organization sets an RPO of 1 hour for its database. Which backup approach best meets this objective?","options":["Performing one full backup every weekend","Keeping a single yearly archival snapshot","Replicating or backing up transaction data at least every hour","Relying solely on RAID 5 on the database server"],"answer":2,"explain":"<strong>Correct.</strong> A one-hour RPO requires capturing data at least hourly, so frequent backups or near-continuous replication keep potential data loss within one hour.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performing one full backup every weekend</b>: Weekly backups could lose up to a week of data, far exceeding the RPO.</span><span class='qd'><b>Keeping a single yearly archival snapshot</b>: Yearly snapshots allow massive data loss, violating the RPO.</span><span class='qd'><b>Relying solely on RAID 5 on the database server</b>: RAID protects against disk failure, not corruption or deletion, and is not a backup.</span>"},{"id":"D2-032","domain":2,"obj":"2.2","diff":"medium","q":"A company performs a full backup every Sunday and differential backups Monday through Saturday. To fully restore data lost on Thursday, which backups are needed?","options":["Every backup from Sunday through Thursday","Only Thursday's differential backup","Sunday's full backup plus all daily incrementals","Sunday's full backup plus Thursday's differential backup"],"answer":3,"explain":"<strong>Correct.</strong> A differential captures all changes since the last full, so restoring Thursday needs only Sunday's full plus Thursday's differential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Every backup from Sunday through Thursday</b>: Differentials are cumulative, so intermediate days are unnecessary.</span><span class='qd'><b>Only Thursday's differential backup</b>: A differential alone cannot restore without the base full backup.</span><span class='qd'><b>Sunday's full backup plus all daily incrementals</b>: This scenario uses differentials, not incrementals.</span>"},{"id":"D2-033","domain":2,"obj":"2.2","diff":"medium","q":"A retailer chooses a warm site for disaster recovery. Compared with a hot site, what trade-off is it accepting?","options":["Lower cost in exchange for longer time to become fully operational","Higher cost in exchange for instant failover","No recovery capability at all","Elimination of the need for backups"],"answer":0,"explain":"<strong>Correct.</strong> A warm site costs less than a hot site but requires additional time to load current data and finish configuration before it is operational.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Higher cost in exchange for instant failover</b>: Instant failover and higher cost describe a hot site, not a warm site.</span><span class='qd'><b>No recovery capability at all</b>: A warm site does provide partial recovery capability.</span><span class='qd'><b>Elimination of the need for backups</b>: Backups are still required to populate the warm site.</span>"},{"id":"D2-034","domain":2,"obj":"2.2","diff":"medium","q":"Why are immutable backups particularly valuable as a defense against ransomware?","options":["They run faster than ordinary backups","Attackers cannot encrypt or delete the protected copies during the retention period","They automatically remove malware from infected files","They reduce the storage space backups require"],"answer":1,"explain":"<strong>Correct.</strong> Because immutable backups cannot be altered or deleted during retention, ransomware that compromises live systems still cannot destroy the recovery copies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They run faster than ordinary backups</b>: Immutability affects write-protection, not speed.</span><span class='qd'><b>They reduce the storage space backups require</b>: Immutability does not shrink storage needs.</span><span class='qd'><b>They automatically remove malware from infected files</b>: Backups preserve data; they do not clean malware.</span>"},{"id":"D2-035","domain":2,"obj":"2.2","diff":"medium","q":"During a parallel DR test, what happens?","options":["Team members only read through the plan individually","Production systems are shut down entirely to force a true failover","Recovery systems are brought online and run alongside production without taking over real operations","The plan is discussed verbally with no systems involved"],"answer":2,"explain":"<strong>Correct.</strong> In a parallel test the recovery environment is activated and processes real data in parallel with production, validating capability without disrupting live operations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Production systems are shut down entirely to force a true failover</b>: That describes a full-interruption test.</span><span class='qd'><b>Team members only read through the plan individually</b>: That describes a read-through (checklist) review.</span><span class='qd'><b>The plan is discussed verbally with no systems involved</b>: That describes a tabletop exercise.</span>"},{"id":"D2-036","domain":2,"obj":"2.2","diff":"medium","q":"Which DR test type carries the highest risk because it actually shuts down production operations to validate failover?","options":["Read-through test","Structured walkthrough","Tabletop exercise","Full-interruption test"],"answer":3,"explain":"<strong>Correct.</strong> A full-interruption test halts production to prove the recovery site can truly take over, making it the most realistic but riskiest test.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Read-through test</b>: A read-through simply reviews the plan on paper, with no production impact.</span><span class='qd'><b>Tabletop exercise</b>: A tabletop is a discussion-based exercise with no real shutdown.</span><span class='qd'><b>Structured walkthrough</b>: A walkthrough reviews the plan step by step without interrupting production.</span>"},{"id":"D2-037","domain":2,"obj":"2.2","diff":"medium","q":"An administrator stores three copies of backups: one on local disk, one on a NAS, and one in cloud storage in another region. Which best practice does this satisfy?","options":["The 3-2-1 backup rule","The principle of least privilege","Separation of duties","Defense in depth for network segmentation"],"answer":0,"explain":"<strong>Correct.</strong> Three copies, on more than one media type, with one stored offsite (the cloud, in another region) satisfies the 3-2-1 backup rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The principle of least privilege</b>: That governs access rights, not backup copies.</span><span class='qd'><b>Separation of duties</b>: That divides tasks among people, unrelated to backup placement.</span><span class='qd'><b>Defense in depth for network segmentation</b>: Segmentation isolates network zones, not backup copies.</span>"},{"id":"D2-038","domain":2,"obj":"2.2","diff":"hard","q":"A firm has RTO = 2 hours and RPO = 15 minutes for its core system. Which combined strategy best satisfies both objectives?","options":["Nightly full backups to tape stored offsite only","A hot or warm standby for fast restoration plus near-continuous data replication every few minutes","A cold site with monthly backups","RAID 1 on the primary server as the sole measure"],"answer":1,"explain":"<strong>Correct.</strong> A short RTO requires a quickly available standby, while a 15-minute RPO requires frequent (near-continuous) replication, so combining both meets the goals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Nightly full backups to tape stored offsite only</b>: Nightly tape could lose up to a day of data and take long to restore, missing both objectives.</span><span class='qd'><b>A cold site with monthly backups</b>: A cold site is far too slow for a 2-hour RTO and monthly backups violate the 15-minute RPO.</span><span class='qd'><b>RAID 1 on the primary server as the sole measure</b>: RAID is not a backup and does not address site loss or recovery time.</span>"},{"id":"D2-039","domain":2,"obj":"2.2","diff":"hard","q":"An organization conducts only tabletop exercises and never tests actual restoration of its backups. What is the most significant risk of this approach?","options":["Tabletop exercises are illegal in most jurisdictions","The RTO will automatically be cut in half","Backups may be corrupt or incomplete and fail when an actual recovery is attempted","Restoration testing would violate the principle of least privilege"],"answer":2,"explain":"<strong>Correct.</strong> Without testing actual restores, the organization may not discover corrupt, incomplete, or unreadable backups until a real disaster, when recovery fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tabletop exercises are illegal in most jurisdictions</b>: Tabletop exercises are a standard, legal practice.</span><span class='qd'><b>The RTO will automatically be cut in half</b>: Test type does not change the RTO value.</span><span class='qd'><b>Restoration testing would violate the principle of least privilege</b>: Properly scoped restore testing does not violate least privilege.</span>"},{"id":"D2-040","domain":2,"obj":"2.2","diff":"hard","q":"Two data centers continuously replicate data so that either can take over instantly if the other fails, and both serve users during normal operation. This design is best described as:","options":["A cold-site arrangement","A differential backup rotation","An air-gapped offline archive","Active-active high availability with real-time replication"],"answer":3,"explain":"<strong>Correct.</strong> Two sites both serving traffic with continuous replication and instant takeover is an active-active high-availability design.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A cold-site arrangement</b>: A cold site is unequipped and cannot take over instantly.</span><span class='qd'><b>A differential backup rotation</b>: A backup rotation is a periodic copy scheme, not real-time dual-site operation.</span><span class='qd'><b>An air-gapped offline archive</b>: An air-gapped archive is intentionally disconnected, the opposite of continuous replication.</span>"},{"id":"D2-041","domain":2,"obj":"2.3","diff":"easy","q":"In incident response terminology, what is an event?","options":["Any observable occurrence in a system or network","A confirmed unauthorized disclosure of protected data","A planned company social gathering","A signed service-level agreement"],"answer":0,"explain":"<strong>Correct.</strong> An event is simply any observable occurrence in a system or network; most events are benign.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A confirmed unauthorized disclosure of protected data</b>: That describes a breach, a specific outcome, not an event in general.</span><span class='qd'><b>A planned company social gathering</b>: That is unrelated to IR terminology.</span><span class='qd'><b>A signed service-level agreement</b>: An SLA is a contract, not a system occurrence.</span>"},{"id":"D2-042","domain":2,"obj":"2.3","diff":"easy","q":"What distinguishes a security incident from an ordinary event?","options":["An incident always involves physical theft of hardware","An incident is an event that actually or potentially harms confidentiality, integrity, or availability","An incident is any event logged by a server","An incident is only declared after a year-end audit"],"answer":1,"explain":"<strong>Correct.</strong> An incident is an event (or series of events) that negatively affects, or threatens to affect, the confidentiality, integrity, or availability of assets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An incident always involves physical theft of hardware</b>: Most incidents are not physical theft.</span><span class='qd'><b>An incident is any event logged by a server</b>: Routine logged events are not necessarily incidents.</span><span class='qd'><b>An incident is only declared after a year-end audit</b>: Incidents are declared when detected, not on an audit schedule.</span>"},{"id":"D2-043","domain":2,"obj":"2.3","diff":"easy","q":"What is the commonly cited correct order of the incident response lifecycle phases?","options":["Containment; preparation; detection; recovery","Recovery; preparation; analysis; containment","Preparation; detection and analysis; containment, eradication and recovery; post-incident activity","Post-incident activity; detection; preparation; eradication"],"answer":2,"explain":"<strong>Correct.</strong> The widely used four-phase lifecycle is preparation; detection and analysis; containment, eradication and recovery; then post-incident activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Containment; preparation; detection; recovery</b>: Preparation must come first, before detection and containment.</span><span class='qd'><b>Recovery; preparation; analysis; containment</b>: Recovery cannot precede detection and preparation.</span><span class='qd'><b>Post-incident activity; detection; preparation; eradication</b>: Post-incident activity is the final phase, not the first.</span>"},{"id":"D2-044","domain":2,"obj":"2.3","diff":"easy","q":"What does CSIRT stand for?","options":["Centralized Server Integrity Review Tool","Cloud Storage Information Retention Today","Critical System Internal Recovery Test","Computer Security Incident Response Team"],"answer":3,"explain":"<strong>Correct.</strong> CSIRT stands for Computer Security Incident Response Team, the group responsible for responding to incidents.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Centralized Server Integrity Review Tool</b>: This is a fabricated expansion.</span><span class='qd'><b>Cloud Storage Information Retention Today</b>: This is not what CSIRT means.</span><span class='qd'><b>Critical System Internal Recovery Test</b>: This is unrelated to the CSIRT acronym.</span>"},{"id":"D2-045","domain":2,"obj":"2.3","diff":"easy","q":"What is the purpose of maintaining a chain of custody for evidence during incident response?","options":["To document who handled evidence and when, preserving its integrity for potential legal use","To assign blame to a specific employee","To reduce the cost of backup storage","To speed up the eradication of malware"],"answer":0,"explain":"<strong>Correct.</strong> Chain of custody records every person who handled evidence and when, preserving its integrity and admissibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To speed up the eradication of malware</b>: Chain of custody documents evidence handling, not eradication speed.</span><span class='qd'><b>To assign blame to a specific employee</b>: Its purpose is integrity of evidence, not blame.</span><span class='qd'><b>To reduce the cost of backup storage</b>: It has nothing to do with storage cost.</span>"},{"id":"D2-046","domain":2,"obj":"2.3","diff":"easy","q":"During which phase of the IR lifecycle does the team conduct a lessons-learned review to improve future response?","options":["Preparation","Post-incident activity","Detection and analysis","Containment"],"answer":1,"explain":"<strong>Correct.</strong> The lessons-learned review occurs in the post-incident activity phase, capturing improvements after the incident is resolved.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preparation</b>: Preparation sets up tools and procedures before incidents, not after.</span><span class='qd'><b>Detection and analysis</b>: That phase identifies and scopes the incident, not reviews it afterward.</span><span class='qd'><b>Containment</b>: Containment limits damage during the incident, not retrospective review.</span>"},{"id":"D2-047","domain":2,"obj":"2.3","diff":"medium","q":"A SOC analyst confirms that an attacker copied a database of customer Social Security numbers out of the network. In IR terms, this confirmed unauthorized disclosure is best classified as a:","options":["False positive","Benign event","Breach","Routine alert"],"answer":2,"explain":"<strong>Correct.</strong> A breach is a confirmed unauthorized disclosure (or loss) of protected data, exactly what occurred here.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Benign event</b>: A confirmed data theft is harmful, not benign.</span><span class='qd'><b>False positive</b>: The disclosure was confirmed, so it is not a false positive.</span><span class='qd'><b>Routine alert</b>: A confirmed exfiltration of sensitive data is far more than a routine alert.</span>"},{"id":"D2-048","domain":2,"obj":"2.3","diff":"medium","q":"An incident responder isolates an infected workstation from the network to stop malware from spreading while keeping it powered on for analysis. Which IR phase does this action belong to?","options":["Preparation","Post-incident activity","Detection and analysis","Containment"],"answer":3,"explain":"<strong>Correct.</strong> Isolating an affected system to stop the spread is a containment action within the containment, eradication, and recovery phase.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preparation</b>: Preparation happens before an incident, not while responding to one.</span><span class='qd'><b>Post-incident activity</b>: That phase occurs after recovery, reviewing lessons learned.</span><span class='qd'><b>Detection and analysis</b>: Detection identifies the incident; isolating the host is a containment step that follows.</span>"},{"id":"D2-049","domain":2,"obj":"2.3","diff":"medium","q":"Why should an incident response communications plan specify in advance who may speak to the media and regulators?","options":["To ensure consistent, accurate messaging and avoid unauthorized or conflicting disclosures","To guarantee the incident is never reported to anyone","To eliminate the need for technical containment","To shorten the RPO automatically"],"answer":0,"explain":"<strong>Correct.</strong> Predefining authorized spokespeople ensures consistent, accurate communication and prevents harmful unauthorized or conflicting statements during a stressful event.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To guarantee the incident is never reported to anyone</b>: A communications plan manages disclosure; many incidents must be reported.</span><span class='qd'><b>To eliminate the need for technical containment</b>: Communication and containment are separate, both necessary, activities.</span><span class='qd'><b>To shorten the RPO automatically</b>: Communication planning does not change the RPO.</span>"},{"id":"D2-050","domain":2,"obj":"2.3","diff":"hard","q":"After containing and eradicating a phishing-driven malware outbreak, the IR team rebuilds affected systems from known-good images, restores data from clean backups, and monitors closely before returning systems to production. These steps occur in which phase?","options":["Preparation","Recovery (within containment, eradication, and recovery)","Detection and analysis","Lessons learned"],"answer":1,"explain":"<strong>Correct.</strong> Rebuilding systems, restoring clean data, and validating before return to service are recovery activities within the containment, eradication, and recovery phase.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preparation</b>: Preparation precedes the incident and sets up capabilities, not post-eradication restoration.</span><span class='qd'><b>Detection and analysis</b>: That phase identifies and scopes the incident before containment, not restores systems.</span><span class='qd'><b>Lessons learned</b>: Lessons learned is part of post-incident activity that follows full recovery.</span>"},{"id":"D2-051","domain":2,"obj":"2.1","diff":"easy","q":"What is the primary goal of a Business Continuity Plan (BCP)?","options":["To restore IT systems after a disaster","To assign legal liability after an outage","To keep critical business functions operating during a disruption","To document software licensing requirements"],"answer":2,"explain":"<strong>Correct.</strong> A BCP focuses on keeping the organization's critical business functions running while a disruption is occurring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To restore IT systems after a disaster</b>: That describes the disaster recovery plan, which is a subset focused on technology restoration.</span><span class='qd'><b>To assign legal liability after an outage</b>: BCP is operational, not a liability or legal-blame exercise.</span><span class='qd'><b>To document software licensing requirements</b>: Licensing is an asset-management task unrelated to continuity.</span>"},{"id":"D2-052","domain":2,"obj":"2.1","diff":"easy","q":"Which document identifies an organization's critical processes and estimates the impact of their loss over time?","options":["Memorandum of Understanding","Acceptable Use Policy","Service Level Agreement","Business Impact Analysis (BIA)"],"answer":3,"explain":"<strong>Correct.</strong> The BIA identifies critical processes and quantifies the impact of their disruption, driving recovery priorities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Acceptable Use Policy</b>: It governs how users may use systems, not impact of outages.</span><span class='qd'><b>Service Level Agreement</b>: An SLA sets performance commitments between parties but does not analyze impact of loss.</span><span class='qd'><b>Memorandum of Understanding</b>: An MOU records a general agreement between parties, not impact analysis.</span>"},{"id":"D2-053","domain":2,"obj":"2.1","diff":"medium","q":"A retailer determines that its order-processing system can be down no longer than four hours before the damage to the business becomes unacceptable. What metric does four hours represent?","options":["Maximum Tolerable Downtime","Recovery Point Objective","Mean Time Between Failures","Recovery Time Actual"],"answer":0,"explain":"<strong>Correct.</strong> Maximum Tolerable Downtime (MTD) is the longest a function can be unavailable before unacceptable harm occurs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery Point Objective</b>: RPO measures acceptable data loss, not allowable downtime.</span><span class='qd'><b>Mean Time Between Failures</b>: MTBF is a reliability average between component failures, not a tolerance limit.</span><span class='qd'><b>Recovery Time Actual</b>: That is the measured time a recovery actually took, not the tolerance threshold.</span>"},{"id":"D2-054","domain":2,"obj":"2.1","diff":"medium","q":"Which RAID level mirrors data across two disks, providing fault tolerance but no striping for performance gains from parity?","options":["RAID 0","RAID 1","RAID 5","RAID 6"],"answer":1,"explain":"<strong>Correct.</strong> RAID 1 mirrors identical data on two drives, so if one fails the other still holds a complete copy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID 0</b>: RAID 0 stripes data for speed but has no redundancy, so any disk failure loses data.</span><span class='qd'><b>RAID 5</b>: RAID 5 uses striping with distributed parity, not simple mirroring.</span><span class='qd'><b>RAID 6</b>: RAID 6 uses double distributed parity, tolerating two failures, not mirroring.</span>"},{"id":"D2-055","domain":2,"obj":"2.1","diff":"easy","q":"What is the purpose of load balancing in a high-availability environment?","options":["To encrypt traffic between servers","To back up data to an offsite location","To distribute requests across multiple servers so no single one is overwhelmed","To detect malware in network traffic"],"answer":2,"explain":"<strong>Correct.</strong> Load balancing spreads incoming requests across multiple servers, improving availability and preventing any one server from being overloaded.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt traffic between servers</b>: Encryption is a confidentiality control, not the function of a load balancer.</span><span class='qd'><b>To back up data to an offsite location</b>: That is a backup or replication task, unrelated to distributing live requests.</span><span class='qd'><b>To detect malware in network traffic</b>: Malware detection is the role of IDS/IPS or antivirus tools.</span>"},{"id":"D2-056","domain":2,"obj":"2.1","diff":"medium","q":"An administrator configures two database servers so that if the active node fails, the standby node automatically takes over the workload. What high-availability technique is this?","options":["Striping","Round-robin DNS","Cold standby archiving","Clustering with failover"],"answer":3,"explain":"<strong>Correct.</strong> Failover clustering groups servers so a standby node automatically assumes the workload when the active node fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Striping</b>: Striping is a RAID disk technique, not a server failover method.</span><span class='qd'><b>Cold standby archiving</b>: A cold standby is powered off and not configured for automatic, immediate takeover.</span><span class='qd'><b>Round-robin DNS</b>: Round-robin DNS distributes name lookups but does not detect failure or fail over automatically.</span>"},{"id":"D2-057","domain":2,"obj":"2.1","diff":"hard","q":"During a BIA, a team assigns a high recovery priority to payroll processing even though it runs only twice a month. What factor most justifies this prioritization?","options":["Loss of payroll on pay dates causes severe financial and legal impact","The system uses the most disk space","Payroll servers are the newest hardware","The application has the most users logged in daily"],"answer":0,"explain":"<strong>Correct.</strong> Recovery priority is driven by the impact of disruption; failing to pay employees on schedule carries severe financial, legal, and morale consequences.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The system uses the most disk space</b>: Storage consumption is not a measure of business criticality.</span><span class='qd'><b>Payroll servers are the newest hardware</b>: Hardware age does not determine business impact.</span><span class='qd'><b>The application has the most users logged in daily</b>: User count alone does not establish the criticality; impact severity does.</span>"},{"id":"D2-058","domain":2,"obj":"2.1","diff":"easy","q":"Which term describes a system's ability to continue operating despite the failure of one or more components?","options":["Data classification","Fault tolerance","Penetration testing","Patch management"],"answer":1,"explain":"<strong>Correct.</strong> Fault tolerance is the capability of a system to keep functioning even when components fail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification</b>: Classification labels data by sensitivity, not resilience to failure.</span><span class='qd'><b>Penetration testing</b>: Pen testing evaluates security weaknesses, not component-failure tolerance.</span><span class='qd'><b>Patch management</b>: Patching updates software but does not itself provide continued operation during a failure.</span>"},{"id":"D2-059","domain":2,"obj":"2.1","diff":"medium","q":"Which of the following best illustrates redundancy designed to eliminate a single point of failure?","options":["Storing one copy of backups in a fireproof safe","Requiring complex passwords for all users","Installing dual power supplies and dual network uplinks on a server","Encrypting the hard drive of a laptop"],"answer":2,"explain":"<strong>Correct.</strong> Dual power supplies and dual uplinks provide redundant paths so the loss of one does not take the server offline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Storing one copy of backups in a fireproof safe</b>: A single copy is not redundancy and could still be lost or destroyed.</span><span class='qd'><b>Requiring complex passwords for all users</b>: Strong passwords address authentication, not single points of failure.</span><span class='qd'><b>Encrypting the hard drive of a laptop</b>: Encryption protects confidentiality, not availability or redundancy.</span>"},{"id":"D2-060","domain":2,"obj":"2.1","diff":"medium","q":"A hospital wants its patient-monitoring application to remain available 99.999% of the time. This requirement is best described as a target for what?","options":["Recovery Point Objective","Chain of custody","Data retention","High availability"],"answer":3,"explain":"<strong>Correct.</strong> A 99.999% uptime goal is a high-availability target, expressing how continuously the service must remain operational.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery Point Objective</b>: RPO addresses acceptable data loss, not uptime percentage.</span><span class='qd'><b>Data retention</b>: Retention defines how long data is kept, not service availability.</span><span class='qd'><b>Chain of custody</b>: Chain of custody is an evidence-handling concept in incident response.</span>"},{"id":"D2-061","domain":2,"obj":"2.1","diff":"hard","q":"An organization has an MTD of two hours for its e-commerce site but its current recovery solution restores service in six hours. What should the BCP team conclude?","options":["A gap exists; recovery capability must be improved to meet the MTD","The recovery solution exceeds requirements and can be downgraded","The MTD should be ignored because hardware is reliable","RPO and MTD are the same value, so no action is needed"],"answer":0,"explain":"<strong>Correct.</strong> A six-hour recovery against a two-hour MTD is a deficiency; the team must invest in faster recovery to close the gap.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The recovery solution exceeds requirements and can be downgraded</b>: It falls short of the requirement, so downgrading would worsen the gap.</span><span class='qd'><b>The MTD should be ignored because hardware is reliable</b>: Ignoring the MTD defeats the purpose of continuity planning.</span><span class='qd'><b>RPO and MTD are the same value, so no action is needed</b>: RPO and MTD measure different things and are not interchangeable.</span>"},{"id":"D2-062","domain":2,"obj":"2.1","diff":"easy","q":"Which of the following is the FIRST step typically performed when developing a business continuity program?","options":["Purchasing backup generators","Conducting a Business Impact Analysis","Negotiating a hot-site contract","Running a full-interruption test"],"answer":1,"explain":"<strong>Correct.</strong> Conducting a BIA comes first because it identifies critical functions and recovery requirements that shape all later decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purchasing backup generators</b>: Buying equipment before analysis risks spending on the wrong priorities.</span><span class='qd'><b>Negotiating a hot-site contract</b>: Site selection should follow the requirements the BIA defines.</span><span class='qd'><b>Running a full-interruption test</b>: Testing validates a plan that does not yet exist this early.</span>"},{"id":"D2-063","domain":2,"obj":"2.1","diff":"medium","q":"Which scenario best demonstrates the difference between high availability and fault tolerance?","options":["Both terms mean exactly the same thing","High availability requires no redundant components","Fault tolerance lets a single system survive a component failure without interruption, while high availability minimizes overall downtime, possibly with brief failover","Fault tolerance applies only to network cabling"],"answer":2,"explain":"<strong>Correct.</strong> Fault tolerance keeps a single system running uninterrupted through a component failure, whereas high availability aims for minimal downtime, which may include short failover gaps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both terms mean exactly the same thing</b>: They are related but distinct concepts with different tolerances for interruption.</span><span class='qd'><b>High availability requires no redundant components</b>: HA typically relies on redundancy to reduce downtime.</span><span class='qd'><b>Fault tolerance applies only to network cabling</b>: Fault tolerance applies broadly to power, storage, processing, and more.</span>"},{"id":"D2-064","domain":2,"obj":"2.1","diff":"medium","q":"A company places duplicate web servers behind a single virtual IP address managed by a balancer. One server can be taken offline for maintenance without users noticing. This benefit of load balancing is best described as supporting what objective?","options":["Confidentiality","Data classification","Non-repudiation","Availability"],"answer":3,"explain":"<strong>Correct.</strong> Keeping service running while a server is removed for maintenance directly supports availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: Confidentiality concerns preventing unauthorized disclosure, not uptime.</span><span class='qd'><b>Non-repudiation</b>: Non-repudiation ensures actions cannot be denied, unrelated to balancing load.</span><span class='qd'><b>Data classification</b>: Classification labels sensitivity and is unrelated to maintenance availability.</span>"},{"id":"D2-065","domain":2,"obj":"2.1","diff":"hard","q":"A BIA shows that a manufacturing line generates losses of $50,000 per hour when stopped, and management accepts no more than $100,000 in losses from a single outage. What MTD does this imply?","options":["2 hours","30 minutes","6 hours","24 hours"],"answer":0,"explain":"<strong>Correct.</strong> At $50,000 per hour, the $100,000 acceptable-loss ceiling is reached after two hours, so the MTD is two hours.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>30 minutes</b>: A half hour would total only $25,000, well below the accepted ceiling.</span><span class='qd'><b>6 hours</b>: Six hours would cost $300,000, far exceeding the accepted loss.</span><span class='qd'><b>24 hours</b>: A full day would cost $1,200,000, vastly over the threshold.</span>"},{"id":"D2-066","domain":2,"obj":"2.2","diff":"easy","q":"What does the Recovery Time Objective (RTO) specify?","options":["The maximum acceptable amount of data loss measured in time","The targeted duration within which a system must be restored after a disruption","The average time between hardware failures","The number of backup copies required"],"answer":1,"explain":"<strong>Correct.</strong> RTO is the target time within which a system or process must be restored to operation after an outage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The maximum acceptable amount of data loss measured in time</b>: That defines the RPO, not the RTO.</span><span class='qd'><b>The average time between hardware failures</b>: That is MTBF, a reliability metric.</span><span class='qd'><b>The number of backup copies required</b>: Backup count is a separate strategy decision, not the RTO.</span>"},{"id":"D2-067","domain":2,"obj":"2.2","diff":"medium","q":"A company performs backups every six hours. After a crash, the most recent backup is restored. Which metric describes the up-to-six-hours of data that could be lost?","options":["Recovery Time Objective","Maximum Tolerable Downtime","Recovery Point Objective","Mean Time To Repair"],"answer":2,"explain":"<strong>Correct.</strong> RPO is the maximum acceptable data loss measured in time; a six-hour backup interval means up to six hours of data may be lost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery Time Objective</b>: RTO measures how quickly service is restored, not how much data is lost.</span><span class='qd'><b>Maximum Tolerable Downtime</b>: MTD is the outer limit of allowable downtime, not data loss.</span><span class='qd'><b>Mean Time To Repair</b>: MTTR is the average time to fix a failed component, not a data-loss measure.</span>"},{"id":"D2-068","domain":2,"obj":"2.2","diff":"easy","q":"Which backup type copies only the data that has changed since the last backup of any kind and then clears the archive marker?","options":["Full backup","Snapshot backup","Differential backup","Incremental backup"],"answer":3,"explain":"<strong>Correct.</strong> An incremental backup captures only data changed since the last backup of any type and resets the archive bit, keeping each job small.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full backup</b>: A full backup copies all selected data every time, regardless of changes.</span><span class='qd'><b>Differential backup</b>: A differential copies everything changed since the last full backup and does not clear the archive marker.</span><span class='qd'><b>Snapshot backup</b>: A snapshot captures a point-in-time image and is not defined by clearing archive bits incrementally.</span>"},{"id":"D2-069","domain":2,"obj":"2.2","diff":"medium","q":"To restore from a differential backup strategy, what must an administrator restore?","options":["The last full backup plus only the most recent differential","The last full backup plus every incremental since","Only the latest differential backup","Every differential backup made since the last full backup"],"answer":0,"explain":"<strong>Correct.</strong> A differential restore needs the last full backup plus only the most recent differential, since each differential contains all changes since the full.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the latest differential backup</b>: The differential alone is incomplete without the underlying full backup.</span><span class='qd'><b>The last full backup plus every incremental since</b>: Chaining every incremental describes an incremental strategy, not a differential one.</span><span class='qd'><b>Every differential backup made since the last full backup</b>: Only the most recent differential is needed because each one already includes prior changes.</span>"},{"id":"D2-070","domain":2,"obj":"2.2","diff":"hard","q":"An organization performs a full backup Sunday and incremental backups Monday through Saturday. A failure occurs Thursday afternoon. Which backups are required to fully restore?","options":["Only Thursday's incremental","Sunday's full plus Monday, Tuesday, Wednesday, and Thursday incrementals","Sunday's full and Thursday's incremental","Sunday's full and Wednesday's incremental"],"answer":1,"explain":"<strong>Correct.</strong> Incremental restores require the last full backup plus every incremental in order, so Sunday's full and the Monday-through-Thursday incrementals are all needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only Thursday's incremental</b>: A single incremental holds just one day's changes and cannot stand alone.</span><span class='qd'><b>Sunday's full and Thursday's incremental</b>: Skipping the intervening incrementals would omit Monday-through-Wednesday changes.</span><span class='qd'><b>Sunday's full and Wednesday's incremental</b>: This omits Monday, Tuesday, and Thursday changes, leaving the restore incomplete.</span>"},{"id":"D2-071","domain":2,"obj":"2.2","diff":"easy","q":"The 3-2-1 backup rule recommends keeping three copies of data, on two different media types, with how many copies stored offsite?","options":["Zero","Two","One","Three"],"answer":2,"explain":"<strong>Correct.</strong> The 3-2-1 rule calls for three copies, on two media types, with at least one copy stored offsite for protection against local disasters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Zero</b>: Keeping no copies offsite defeats the rule's protection against site-wide events.</span><span class='qd'><b>Two</b>: The rule specifies one offsite copy, not two, though more is not harmful it is not what 3-2-1 states.</span><span class='qd'><b>Three</b>: Three offsite copies is not the standard; the rule mandates one offsite minimum.</span>"},{"id":"D2-072","domain":2,"obj":"2.2","diff":"medium","q":"An organization sets a Recovery Point Objective (RPO) of 15 minutes for a critical database. Which backup approach BEST satisfies this requirement?","options":["Annual archival to cold storage","A single full backup taken once per week","Quarterly full backups stored off-site","Continuous or near-continuous replication with frequent snapshots"],"answer":3,"explain":"<strong>Correct.</strong> An RPO of 15 minutes means no more than 15 minutes of data may be lost, which requires continuous or near-continuous replication or very frequent snapshots.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single full backup taken once per week</b>: this risks up to a week of data loss, far exceeding the 15-minute RPO.</span><span class='qd'><b>Quarterly full backups stored off-site</b>: a quarterly cadence could lose months of data, grossly violating the RPO.</span><span class='qd'><b>Annual archival to cold storage</b>: yearly archival is for long-term retention, not for meeting a tight RPO.</span>"},{"id":"D2-073","domain":2,"obj":"2.2","diff":"medium","q":"Which recovery site can take over operations almost immediately because it has fully configured systems and near-real-time data replication?","options":["Hot site","Warm site","Cold site","Mobile site"],"answer":0,"explain":"<strong>Correct.</strong> A hot site is fully equipped with running systems and current data, enabling near-immediate takeover.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cold site</b>: A cold site provides only space and basic infrastructure, requiring lengthy setup.</span><span class='qd'><b>Warm site</b>: A warm site has hardware but needs current data loaded and configuration, so recovery takes longer.</span><span class='qd'><b>Mobile site</b>: A mobile site is a portable facility whose readiness varies and is not inherently immediate.</span>"},{"id":"D2-074","domain":2,"obj":"2.2","diff":"easy","q":"A business requires an alternate site that can resume operations within minutes of a disaster, with fully redundant hardware and near-real-time data replication. Which site type is MOST appropriate?","options":["Cold site","Hot site","Warm site","Reciprocal agreement"],"answer":1,"explain":"<strong>Correct.</strong> A hot site is fully equipped and continuously updated, enabling near-immediate failover at the highest cost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cold site</b>: a cold site provides only space and utilities, requiring days to stand up hardware and data.</span><span class='qd'><b>Warm site</b>: a warm site has some equipment but still needs hours and data restoration before it is operational.</span><span class='qd'><b>Reciprocal agreement</b>: this is a mutual-aid arrangement with another organization and offers no guaranteed, immediately ready capacity.</span>"},{"id":"D2-075","domain":2,"obj":"2.2","diff":"hard","q":"A firm needs an RTO of 15 minutes but wants to control costs by avoiding a fully staffed duplicate facility. Which recovery approach best balances these goals?","options":["A cold site activated only when needed","A warm site with periodic data updates","Cloud-based failover with automated, near-instant spin-up of replicated systems","Shipping tapes to an offsite vault for monthly retrieval"],"answer":2,"explain":"<strong>Correct.</strong> Cloud failover with replicated systems can spin up automatically in minutes, meeting a tight RTO without maintaining a permanently staffed physical duplicate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A cold site activated only when needed</b>: A cold site takes hours or days to provision, far exceeding a 15-minute RTO.</span><span class='qd'><b>A warm site with periodic data updates</b>: Warm sites still require data loading and startup that can miss a 15-minute target.</span><span class='qd'><b>Shipping tapes to an offsite vault for monthly retrieval</b>: Tape retrieval is slow and offers very poor RTO and RPO.</span>"},{"id":"D2-076","domain":2,"obj":"2.2","diff":"medium","q":"Which disaster recovery test involves team members verbally walking through the plan step by step in a conference room without affecting production systems?","options":["Full-interruption test","Parallel test","Simulation with live failover","Tabletop (walk-through) exercise"],"answer":3,"explain":"<strong>Correct.</strong> A tabletop exercise has participants talk through the plan in a discussion format, validating roles and steps without touching production.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full-interruption test</b>: That actually shuts down production to test recovery, the most disruptive method.</span><span class='qd'><b>Parallel test</b>: A parallel test brings up recovery systems alongside production but is not just a discussion.</span><span class='qd'><b>Simulation with live failover</b>: Live failover affects systems, unlike a purely verbal walk-through.</span>"},{"id":"D2-077","domain":2,"obj":"2.2","diff":"hard","q":"Which DR test type carries the greatest risk of causing an actual outage if the recovery environment fails to perform?","options":["Full-interruption test","Tabletop exercise","Parallel test","Read-through (checklist) test"],"answer":0,"explain":"<strong>Correct.</strong> A full-interruption test shuts down production and fails over to the recovery site, so a flawed recovery environment can cause a real outage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Read-through (checklist) test</b>: A checklist review is purely documentary and cannot cause an outage.</span><span class='qd'><b>Tabletop exercise</b>: A tabletop is a discussion and does not touch live systems.</span><span class='qd'><b>Parallel test</b>: A parallel test runs recovery alongside production without taking production offline.</span>"},{"id":"D2-078","domain":2,"obj":"2.2","diff":"medium","q":"A company sets an RPO of zero for its financial transaction database. Which solution best satisfies this requirement?","options":["Nightly full tape backups","Synchronous real-time data replication to a second site","Weekly differential backups","Quarterly archiving to cold storage"],"answer":1,"explain":"<strong>Correct.</strong> An RPO of zero means no acceptable data loss, which synchronous real-time replication provides by committing each transaction to a second site as it occurs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Nightly full tape backups</b>: Nightly backups could lose up to a day of transactions, violating a zero RPO.</span><span class='qd'><b>Weekly differential backups</b>: Weekly intervals risk losing days of data, far from zero.</span><span class='qd'><b>Quarterly archiving to cold storage</b>: Quarterly archives would lose months of data, completely failing the requirement.</span>"},{"id":"D2-079","domain":2,"obj":"2.2","diff":"easy","q":"What is the main reason organizations store at least one backup copy offsite?","options":["To reduce the cost of local storage","To make backups run faster","To protect data against a disaster that destroys the primary location","To avoid encrypting the data"],"answer":2,"explain":"<strong>Correct.</strong> An offsite copy survives a localized disaster, such as fire or flood, that could destroy both the primary systems and any onsite backups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To reduce the cost of local storage</b>: Offsite storage is about resilience, not necessarily cost savings.</span><span class='qd'><b>To make backups run faster</b>: Offsite location does not inherently speed up the backup process.</span><span class='qd'><b>To avoid encrypting the data</b>: Offsite copies should still be encrypted; location does not replace encryption.</span>"},{"id":"D2-080","domain":2,"obj":"2.2","diff":"medium","q":"Compared with incremental backups, a key trade-off of differential backups is that they typically:","options":["Take less storage and restore more slowly","Always run faster to create than incrementals","Cannot be combined with full backups","Take more storage over time but restore more quickly"],"answer":3,"explain":"<strong>Correct.</strong> Differentials grow larger each day because they capture all changes since the last full, using more storage, but restores are faster since only the full plus one differential are needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Take less storage and restore more slowly</b>: This reverses the trade-off; differentials use more storage and restore faster.</span><span class='qd'><b>Cannot be combined with full backups</b>: Differentials depend on a preceding full backup by definition.</span><span class='qd'><b>Always run faster to create than incrementals</b>: Incrementals are generally faster to create because they copy less data each run.</span>"},{"id":"D2-081","domain":2,"obj":"2.2","diff":"medium","q":"Which statement correctly distinguishes a Disaster Recovery Plan (DRP) from a Business Continuity Plan (BCP)?","options":["The DRP focuses on restoring IT systems and operations, while the BCP keeps the whole business functioning","The DRP is broader and the BCP only covers IT","They are identical documents with different names","The BCP applies only after the DRP fails"],"answer":0,"explain":"<strong>Correct.</strong> The DRP concentrates on restoring IT systems and technical operations, whereas the BCP is broader, sustaining overall business functions during and after a disruption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The DRP is broader and the BCP only covers IT</b>: This is reversed; the BCP is the broader plan.</span><span class='qd'><b>They are identical documents with different names</b>: They serve different scopes and are not interchangeable.</span><span class='qd'><b>The BCP applies only after the DRP fails</b>: The BCP operates throughout a disruption, not only after DRP failure.</span>"},{"id":"D2-082","domain":2,"obj":"2.2","diff":"hard","q":"An administrator notices that nightly backups complete successfully but a recent restore attempt failed because the files were corrupt. What practice would have caught this earlier?","options":["Increasing backup frequency","Regularly testing restores from backups","Adding more offsite copies","Switching from incremental to full backups"],"answer":1,"explain":"<strong>Correct.</strong> Periodically testing actual restores verifies that backups are usable and would have revealed the corruption before a real emergency.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing backup frequency</b>: More frequent backups of corrupt data would still produce unusable copies.</span><span class='qd'><b>Adding more offsite copies</b>: Extra copies of corrupt data do not solve the integrity problem.</span><span class='qd'><b>Switching from incremental to full backups</b>: Changing backup type does not by itself confirm restorability.</span>"},{"id":"D2-083","domain":2,"obj":"2.3","diff":"medium","q":"According to the four-phase incident response lifecycle, which phase immediately FOLLOWS detection and analysis?","options":["Post-incident activity","Preparation","Containment, eradication, and recovery","Risk assessment"],"answer":2,"explain":"<strong>Correct.</strong> After an incident is detected and analyzed, responders move to contain it, eradicate the cause, and recover operations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preparation</b>: preparation precedes detection; it is the first phase, not a follow-on to analysis.</span><span class='qd'><b>Post-incident activity</b>: lessons-learned is the final phase, occurring after recovery, not immediately after analysis.</span><span class='qd'><b>Risk assessment</b>: risk assessment is a governance activity and is not one of the four incident-response phases.</span>"},{"id":"D2-084","domain":2,"obj":"2.3","diff":"medium","q":"How does a security 'incident' differ from a security 'event'?","options":["An incident is always less severe than an event","Events require reporting but incidents do not","An incident only involves physical security","An incident is an event that actually or potentially harms confidentiality, integrity, or availability"],"answer":3,"explain":"<strong>Correct.</strong> An incident is an event (or series of events) that negatively affects, or threatens to affect, the confidentiality, integrity, or availability of information or systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An incident is always less severe than an event</b>: Incidents are more significant than ordinary events, not less.</span><span class='qd'><b>An incident only involves physical security</b>: Incidents can be logical, physical, or both.</span><span class='qd'><b>Events require reporting but incidents do not</b>: Incidents in particular require formal response and reporting.</span>"},{"id":"D2-085","domain":2,"obj":"2.3","diff":"medium","q":"An attacker exfiltrates a database of customer Social Security numbers. Beyond being an incident, this is specifically classified as what?","options":["A breach","An event","A false positive","A vulnerability"],"answer":0,"explain":"<strong>Correct.</strong> A breach is the confirmed unauthorized disclosure or loss of protected data, which exfiltrating customer records represents.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An event</b>: An event is a neutral observable occurrence; this is far more serious.</span><span class='qd'><b>A false positive</b>: A false positive is a benign activity wrongly flagged, not a real data loss.</span><span class='qd'><b>A vulnerability</b>: A vulnerability is a weakness that could be exploited, not the act of data being taken.</span>"},{"id":"D2-086","domain":2,"obj":"2.3","diff":"easy","q":"What is the primary role of a Computer Security Incident Response Team (CSIRT)?","options":["To write all company software","To detect, respond to, and recover from security incidents","To manage employee payroll","To negotiate vendor contracts"],"answer":1,"explain":"<strong>Correct.</strong> A CSIRT is responsible for detecting, responding to, and recovering from security incidents in a coordinated way.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To write all company software</b>: Software development is a separate function from incident response.</span><span class='qd'><b>To manage employee payroll</b>: Payroll is an HR and finance responsibility, unrelated to the CSIRT.</span><span class='qd'><b>To negotiate vendor contracts</b>: Procurement and contracts are handled by other teams.</span>"},{"id":"D2-087","domain":2,"obj":"2.3","diff":"medium","q":"Which phase of the four-phase incident response lifecycle (preparation; detection and analysis; containment, eradication, and recovery; post-incident activity) includes developing policies and training the team before any incident occurs?","options":["Detection and analysis","Containment, eradication, and recovery","Preparation","Post-incident activity"],"answer":2,"explain":"<strong>Correct.</strong> Preparation covers building policies, tools, and team training in advance so the organization is ready to respond.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection and analysis</b>: This phase identifies and assesses incidents as they happen, not beforehand.</span><span class='qd'><b>Containment, eradication, and recovery</b>: This phase acts during and after an active incident, not in advance.</span><span class='qd'><b>Post-incident activity</b>: This phase reviews lessons after the incident is resolved.</span>"},{"id":"D2-088","domain":2,"obj":"2.3","diff":"medium","q":"During a malware outbreak, the response team isolates infected machines from the network to stop the spread. Which activity in the incident lifecycle is this?","options":["Detection","Preparation","Lessons learned","Containment"],"answer":3,"explain":"<strong>Correct.</strong> Isolating affected systems to limit damage and prevent spread is the containment activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection</b>: Detection is recognizing that an incident is occurring, which precedes isolation.</span><span class='qd'><b>Lessons learned</b>: Lessons learned is a post-incident review, not active isolation.</span><span class='qd'><b>Preparation</b>: Preparation happens before any incident, not during the active outbreak.</span>"},{"id":"D2-089","domain":2,"obj":"2.3","diff":"hard","q":"After containing an incident, the team removes the malware, patches the exploited vulnerability, and rebuilds affected systems from clean images. Which combined activities are being performed?","options":["Eradication and recovery","Detection and analysis","Preparation and detection","Lessons learned only"],"answer":0,"explain":"<strong>Correct.</strong> Removing the malware and closing the vulnerability is eradication, while rebuilding systems to resume operations is recovery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection and analysis</b>: That phase identifies the incident and occurs before containment, not after.</span><span class='qd'><b>Preparation and detection</b>: Preparation precedes incidents and detection identifies them; neither is removal and rebuild.</span><span class='qd'><b>Lessons learned only</b>: Lessons learned is a later review, separate from technically eradicating and restoring.</span>"},{"id":"D2-090","domain":2,"obj":"2.3","diff":"easy","q":"What is the purpose of a communications plan within incident response?","options":["To configure network routers","To define how and to whom information about an incident is shared","To schedule routine maintenance","To assign software licenses"],"answer":1,"explain":"<strong>Correct.</strong> A communications plan establishes who is notified, how, and when during an incident, including internal staff, management, customers, and possibly regulators.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To configure network routers</b>: Router configuration is a networking task, not communications planning.</span><span class='qd'><b>To schedule routine maintenance</b>: Maintenance scheduling is operational, unrelated to incident messaging.</span><span class='qd'><b>To assign software licenses</b>: License assignment is asset management, not incident communication.</span>"},{"id":"D2-091","domain":2,"obj":"2.3","diff":"medium","q":"Why is maintaining a documented chain of custody important when handling evidence after a security incident?","options":["It speeds up system restoration","It encrypts the evidence automatically","It proves who handled the evidence and that it was not altered, preserving its admissibility","It replaces the need for backups"],"answer":2,"explain":"<strong>Correct.</strong> Chain of custody documents every person who handled evidence and how it was protected, demonstrating integrity so it can be admissible in legal proceedings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It speeds up system restoration</b>: Chain of custody concerns evidence integrity, not recovery speed.</span><span class='qd'><b>It encrypts the evidence automatically</b>: Documentation does not perform encryption on its own.</span><span class='qd'><b>It replaces the need for backups</b>: Evidence handling and data backups are separate concerns.</span>"},{"id":"D2-092","domain":2,"obj":"2.3","diff":"medium","q":"A 'lessons learned' meeting is held after an incident is fully resolved. What is its primary objective?","options":["To assign blame to individuals","To purchase new firewalls","To immediately contain the threat","To identify what worked, what failed, and how to improve future response"],"answer":3,"explain":"<strong>Correct.</strong> The lessons-learned review analyzes the response objectively to identify improvements for processes, tools, and training going forward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To assign blame to individuals</b>: The goal is improvement, not blame, which discourages honest reporting.</span><span class='qd'><b>To immediately contain the threat</b>: Containment already happened earlier; the incident is resolved by this point.</span><span class='qd'><b>To purchase new firewalls</b>: Buying equipment may result from findings but is not the meeting's purpose.</span>"},{"id":"D2-093","domain":2,"obj":"2.3","diff":"hard","q":"An analyst discovers a server is sending unusual outbound traffic to an unknown IP. Before declaring an incident, what should the analyst do first?","options":["Analyze the activity to confirm whether it represents a genuine incident","Immediately wipe the server","Notify the media","Disconnect every server in the data center"],"answer":0,"explain":"<strong>Correct.</strong> Detection and analysis requires validating the suspicious activity to confirm a real incident before escalating or taking disruptive action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately wipe the server</b>: Wiping destroys potential evidence and may be premature if it is benign.</span><span class='qd'><b>Notify the media</b>: External notification is governed by the communications plan and is not the analyst's first step.</span><span class='qd'><b>Disconnect every server in the data center</b>: A blanket shutdown is excessive before confirming the scope and nature of the activity.</span>"},{"id":"D2-094","domain":2,"obj":"2.3","diff":"easy","q":"Which of the following best describes a 'false positive' in incident detection?","options":["A real attack that the system missed","A legitimate activity that an alert incorrectly flags as malicious","An attacker using stolen credentials","A successful data breach"],"answer":1,"explain":"<strong>Correct.</strong> A false positive is benign or legitimate activity that a detection system mistakenly reports as a threat.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A real attack that the system missed</b>: A missed attack is a false negative, the opposite error.</span><span class='qd'><b>An attacker using stolen credentials</b>: That is a genuine attack technique, not a detection error.</span><span class='qd'><b>A successful data breach</b>: A breach is a real event, whereas a false positive is a mistaken alert.</span>"},{"id":"D2-095","domain":2,"obj":"2.3","diff":"medium","q":"Who should typically be included on a CSIRT to ensure a well-rounded response capability?","options":["Only the IT help desk","Only external consultants","Representatives from IT, security, legal, communications, and management","Only the marketing department"],"answer":2,"explain":"<strong>Correct.</strong> An effective CSIRT draws from multiple disciplines such as IT, security, legal, communications, and management so technical, legal, and business needs are all addressed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the IT help desk</b>: The help desk alone lacks legal, communications, and management expertise.</span><span class='qd'><b>Only external consultants</b>: Outside experts may assist, but internal stakeholders are essential.</span><span class='qd'><b>Only the marketing department</b>: Marketing alone cannot perform technical containment or analysis.</span>"},{"id":"D2-096","domain":2,"obj":"2.3","diff":"medium","q":"During evidence collection, an investigator labels a seized drive, records the date, time, and her name, and stores it in a sealed, tracked container. These steps primarily support what?","options":["Data classification","Fault tolerance","Load balancing","Chain of custody"],"answer":3,"explain":"<strong>Correct.</strong> Labeling, logging handlers and times, and sealing evidence are core chain-of-custody practices that preserve evidentiary integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification</b>: Classification labels data by sensitivity, not evidence handling.</span><span class='qd'><b>Load balancing</b>: Load balancing distributes workloads and is unrelated to evidence.</span><span class='qd'><b>Fault tolerance</b>: Fault tolerance keeps systems running through failures, not an evidence concept.</span>"},{"id":"D2-097","domain":2,"obj":"2.3","diff":"hard","q":"An organization resolves a phishing incident but never updates its training or email filtering afterward. A similar attack succeeds two months later. Which incident response phase did the organization most likely neglect?","options":["Post-incident activity (lessons learned)","Containment","Detection","Preparation"],"answer":0,"explain":"<strong>Correct.</strong> Failing to apply improvements from the first incident reflects a neglected post-incident, lessons-learned phase, which exists to strengthen defenses against recurrence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Containment</b>: Containment addresses stopping the active incident, which they apparently did the first time.</span><span class='qd'><b>Detection</b>: Detection concerns recognizing incidents, but the failure here was not learning from the resolved one.</span><span class='qd'><b>Preparation</b>: Preparation sets up initial capability; the specific gap was failing to update after the incident.</span>"},{"id":"D2-098","domain":2,"obj":"2.3","diff":"easy","q":"Which sequence correctly orders the four phases of the incident response lifecycle?","options":["Detection, preparation, recovery, lessons learned","Preparation; detection and analysis; containment, eradication, and recovery; post-incident activity","Containment, preparation, detection, recovery","Lessons learned, detection, preparation, containment"],"answer":1,"explain":"<strong>Correct.</strong> The accepted order is preparation; detection and analysis; containment, eradication, and recovery; and post-incident activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection, preparation, recovery, lessons learned</b>: Preparation must precede detection, so this order is wrong.</span><span class='qd'><b>Containment, preparation, detection, recovery</b>: Containment cannot occur before preparation and detection.</span><span class='qd'><b>Lessons learned, detection, preparation, containment</b>: Lessons learned is the final phase, not the first.</span>"},{"id":"D2-099","domain":2,"obj":"2.3","diff":"medium","q":"Why should incident responders avoid powering off a compromised system if volatile evidence may be needed?","options":["Powering off voids the warranty","It always alerts the attacker","Volatile data in memory, such as running processes and network connections, would be lost","It permanently encrypts the disk"],"answer":2,"explain":"<strong>Correct.</strong> Shutting down a system erases volatile memory contents like active processes and connections, which can be critical evidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Powering off voids the warranty</b>: Warranty status is irrelevant to evidence preservation.</span><span class='qd'><b>It always alerts the attacker</b>: A shutdown does not inherently notify an attacker; the real concern is lost volatile data.</span><span class='qd'><b>It permanently encrypts the disk</b>: Powering off does not encrypt the disk by itself.</span>"},{"id":"D2-100","domain":2,"obj":"2.3","diff":"medium","q":"An incident response plan specifies that regulators must be notified within 72 hours of confirming a data breach. This requirement is part of which component of the plan?","options":["The load-balancing policy","The backup schedule","The RAID configuration","The communications plan"],"answer":3,"explain":"<strong>Correct.</strong> Notification timelines and recipients, including regulators, are defined in the incident communications plan.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The backup schedule</b>: Backup timing relates to data protection, not breach notification.</span><span class='qd'><b>The RAID configuration</b>: RAID is a disk redundancy setup, unrelated to notifying regulators.</span><span class='qd'><b>The load-balancing policy</b>: Load balancing distributes traffic and has nothing to do with breach reporting.</span>"},{"id":"D3-001","domain":3,"obj":"3.1","diff":"easy","q":"What is the primary purpose of an access control vestibule (mantrap)?","options":["To prevent tailgating by allowing only one person through at a time","To monitor network traffic entering a facility","To encrypt data stored on local servers","To provide backup power during outages"],"answer":0,"explain":"<strong>Correct.</strong> An access control vestibule uses two interlocking doors so only one authenticated person passes at a time, defeating tailgating and piggybacking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To monitor network traffic entering a facility</b>: That is a function of an IDS or firewall, not a physical entry control.</span><span class='qd'><b>To encrypt data stored on local servers</b>: Encryption is a logical control unrelated to a physical vestibule.</span><span class='qd'><b>To provide backup power during outages</b>: That is the role of a UPS or generator, not an access vestibule.</span>"},{"id":"D3-002","domain":3,"obj":"3.1","diff":"easy","q":"In biometric systems, what does the False Rejection Rate (FRR) measure?","options":["The rate at which unauthorized users are accepted","The rate at which legitimate users are incorrectly denied","The point where false accepts equal false rejects","The speed of the biometric scan"],"answer":1,"explain":"<strong>Correct.</strong> FRR (a Type I error) is how often a valid, enrolled user is wrongly rejected by the system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The rate at which unauthorized users are accepted</b>: That describes the False Acceptance Rate (FAR), a Type II error.</span><span class='qd'><b>The point where false accepts equal false rejects</b>: That defines the Crossover Error Rate (CER).</span><span class='qd'><b>The speed of the biometric scan</b>: Scan speed is throughput, not an error rate.</span>"},{"id":"D3-003","domain":3,"obj":"3.1","diff":"easy","q":"Which biometric metric is used to compare the overall accuracy of two different biometric systems?","options":["False Acceptance Rate (FAR)","False Rejection Rate (FRR)","Crossover Error Rate (CER)","Enrollment time"],"answer":2,"explain":"<strong>Correct.</strong> The CER is the point where FAR equals FRR; a lower CER indicates a more accurate system, making it the standard comparison metric.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False Acceptance Rate (FAR)</b>: FAR alone reflects only one error type and can be tuned, so it is not a balanced comparison.</span><span class='qd'><b>False Rejection Rate (FRR)</b>: FRR alone likewise reflects only one error type.</span><span class='qd'><b>Enrollment time</b>: Enrollment time is a usability factor, not an accuracy measure.</span>"},{"id":"D3-004","domain":3,"obj":"3.1","diff":"easy","q":"What concept describes using multiple layers of physical security controls so that defeating one does not compromise the whole facility?","options":["Fail open","Single sign-on","Least privilege","Defense in depth"],"answer":3,"explain":"<strong>Correct.</strong> Defense in depth layers controls (fences, lighting, guards, locks) so an attacker must defeat several, not just one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single sign-on</b>: SSO is a logical authentication convenience, not a layered physical strategy.</span><span class='qd'><b>Least privilege</b>: Least privilege restricts permissions, not physical layers.</span><span class='qd'><b>Fail open</b>: Fail open is a failure-mode behavior, not a layering strategy.</span>"},{"id":"D3-005","domain":3,"obj":"3.1","diff":"easy","q":"What is the main purpose of bollards placed outside a building entrance?","options":["To prevent vehicles from ramming into the structure","To authenticate visitors before entry","To detect motion in the parking lot","To provide emergency lighting"],"answer":0,"explain":"<strong>Correct.</strong> Bollards are sturdy posts that block vehicles from driving into a building or crowd while still allowing pedestrians to pass.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To authenticate visitors before entry</b>: Authentication is done by badges or guards, not bollards.</span><span class='qd'><b>To detect motion in the parking lot</b>: Motion detection is the job of sensors or CCTV.</span><span class='qd'><b>To provide emergency lighting</b>: Lighting is a separate control from physical vehicle barriers.</span>"},{"id":"D3-006","domain":3,"obj":"3.1","diff":"easy","q":"What does CPTED stand for in physical security design?","options":["Central Protection Through Electronic Devices","Crime Prevention Through Environmental Design","Controlled Perimeter Threat Evaluation Doctrine","Critical Physical Threat Emergency Detection"],"answer":1,"explain":"<strong>Correct.</strong> CPTED, Crime Prevention Through Environmental Design, uses landscaping, lighting, and layout to deter crime naturally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Central Protection Through Electronic Devices</b>: This is a fabricated expansion not used in the field.</span><span class='qd'><b>Controlled Perimeter Threat Evaluation Doctrine</b>: This phrase is invented and not a recognized term.</span><span class='qd'><b>Critical Physical Threat Emergency Detection</b>: This is not what the acronym CPTED represents.</span>"},{"id":"D3-007","domain":3,"obj":"3.1","diff":"easy","q":"Which control requires two authorized people to be present simultaneously to access a highly sensitive area or asset?","options":["Need-to-know","Single sign-on","Two-person integrity","Mandatory vacation"],"answer":2,"explain":"<strong>Correct.</strong> Two-person integrity (the two-person rule) mandates that no single individual can access the asset alone, reducing insider risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Need-to-know</b>: Need-to-know limits information access but does not require two people present.</span><span class='qd'><b>Single sign-on</b>: SSO is an authentication convenience, not a dual-control requirement.</span><span class='qd'><b>Mandatory vacation</b>: Mandatory vacation is a detective personnel control, not simultaneous access.</span>"},{"id":"D3-008","domain":3,"obj":"3.1","diff":"easy","q":"What is the primary security purpose of a visitor log at a facility entrance?","options":["To encrypt visitor credentials","To assign network permissions to visitors","To replace the need for security guards","To create an audit record of who entered and when"],"answer":3,"explain":"<strong>Correct.</strong> A visitor log records identity, time in, time out, and host, providing accountability and an audit trail of facility access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt visitor credentials</b>: A log records data; it does not encrypt anything.</span><span class='qd'><b>To replace the need for security guards</b>: Logs complement guards rather than replacing them.</span><span class='qd'><b>To assign network permissions to visitors</b>: Network access is a logical control, not a function of a sign-in log.</span>"},{"id":"D3-009","domain":3,"obj":"3.1","diff":"easy","q":"Which physical control is a deterrent that also delays an intruder by forming a perimeter barrier?","options":["Fencing","Audit log","Encryption key","Service account"],"answer":0,"explain":"<strong>Correct.</strong> Fencing deters casual intruders and delays determined ones, giving guards or sensors time to respond.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Audit log</b>: An audit log is a detective logical control, not a perimeter barrier.</span><span class='qd'><b>Encryption key</b>: A key protects data confidentiality, not physical perimeters.</span><span class='qd'><b>Service account</b>: A service account is a logical account type, not a physical barrier.</span>"},{"id":"D3-010","domain":3,"obj":"3.1","diff":"easy","q":"What is a key benefit of using a security guard compared to a purely automated physical control?","options":["Guards never make mistakes","Guards can apply judgment and respond to unexpected situations","Guards eliminate the need for any logging","Guards encrypt facility data"],"answer":1,"explain":"<strong>Correct.</strong> A human guard can reason about novel situations, deter through presence, and adapt where fixed automation cannot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guards never make mistakes</b>: Humans are fallible; this is false.</span><span class='qd'><b>Guards eliminate the need for any logging</b>: Logging is still needed for accountability even with guards.</span><span class='qd'><b>Guards encrypt facility data</b>: Encryption is a technical control unrelated to a guard's duties.</span>"},{"id":"D3-011","domain":3,"obj":"3.1","diff":"medium","q":"A high-security data center sets its biometric scanners to a very strict threshold. Which outcome is the most likely direct result?","options":["The False Acceptance Rate increases","The Crossover Error Rate is eliminated","The False Rejection Rate increases","Enrollment becomes unnecessary"],"answer":2,"explain":"<strong>Correct.</strong> Tightening the threshold makes the system more demanding, so more legitimate users get rejected, raising the FRR.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The False Acceptance Rate increases</b>: A stricter setting lowers FAR, not raises it.</span><span class='qd'><b>The Crossover Error Rate is eliminated</b>: The CER is an inherent property of the system and cannot be eliminated by tuning.</span><span class='qd'><b>Enrollment becomes unnecessary</b>: Users must always be enrolled before biometric matching can occur.</span>"},{"id":"D3-012","domain":3,"obj":"3.1","diff":"medium","q":"An organization wants natural surveillance and clear sightlines as part of its physical design philosophy. Which approach best fits this goal?","options":["Installing tall opaque walls around all walkways","Removing the visitor management process","Disabling all exterior lighting","Applying CPTED principles"],"answer":3,"explain":"<strong>Correct.</strong> CPTED promotes natural surveillance, clear sightlines, lighting, and territorial reinforcement to discourage crime.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Installing tall opaque walls around all walkways</b>: Opaque walls block the natural surveillance CPTED encourages.</span><span class='qd'><b>Disabling all exterior lighting</b>: Removing lighting reduces visibility and increases risk, opposite of CPTED.</span><span class='qd'><b>Removing the visitor management process</b>: Eliminating visitor controls weakens security and is unrelated to design sightlines.</span>"},{"id":"D3-013","domain":3,"obj":"3.1","diff":"medium","q":"A badge reader controlling a server room door is configured to fail-secure. What happens to the door if the system loses power?","options":["The door remains locked","The door unlocks to allow free exit and entry","The door alarm is disabled","The badge reader grants access to everyone"],"answer":0,"explain":"<strong>Correct.</strong> Fail-secure means the lock defaults to the locked state on power loss, prioritizing asset protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The door unlocks to allow free exit and entry</b>: That describes fail-safe (fail-open), used where life safety dominates.</span><span class='qd'><b>The door alarm is disabled</b>: Fail-secure concerns the lock state, not necessarily the alarm.</span><span class='qd'><b>The badge reader grants access to everyone</b>: Fail-secure denies access by default, not grants it.</span>"},{"id":"D3-014","domain":3,"obj":"3.1","diff":"medium","q":"Why might a life-safety code require certain locked doors to be fail-safe (fail-open) rather than fail-secure?","options":["To prevent any unauthorized access at all costs","To allow occupants to evacuate during a power loss or fire","To reduce the cost of the locking hardware","To eliminate the need for fire alarms"],"answer":1,"explain":"<strong>Correct.</strong> Fail-safe doors unlock on failure so people can escape; human life takes precedence over asset protection on egress routes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To prevent any unauthorized access at all costs</b>: That is the goal of fail-secure, which conflicts with safe egress.</span><span class='qd'><b>To reduce the cost of the locking hardware</b>: Fail-safe is chosen for safety, not cost savings.</span><span class='qd'><b>To eliminate the need for fire alarms</b>: Door behavior does not replace required fire detection systems.</span>"},{"id":"D3-015","domain":3,"obj":"3.1","diff":"medium","q":"A visitor is issued a temporary badge and assigned an employee who accompanies them throughout the building. What control does the accompanying employee represent?","options":["Privilege creep","Separation of duties","An escort","Non-repudiation"],"answer":2,"explain":"<strong>Correct.</strong> An escort is a person who supervises a visitor at all times, ensuring they only access approved areas.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Privilege creep</b>: Privilege creep is the gradual accumulation of access rights, not visitor supervision.</span><span class='qd'><b>Separation of duties</b>: Separation of duties splits a task among people; it is not escorting.</span><span class='qd'><b>Non-repudiation</b>: Non-repudiation proves an action occurred and cannot be denied, unrelated to escorting.</span>"},{"id":"D3-016","domain":3,"obj":"3.1","diff":"medium","q":"Closed-circuit television (CCTV) recording an entrance and storing footage primarily functions as which type of control?","options":["A preventive control that physically blocks entry","A directive control that orders staff behavior","A corrective control that repairs damaged doors","A detective control that records events for later review"],"answer":3,"explain":"<strong>Correct.</strong> CCTV recording captures evidence of who did what and when, making it primarily a detective control (with a deterrent effect).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A preventive control that physically blocks entry</b>: Cameras observe; they do not physically stop someone from entering.</span><span class='qd'><b>A corrective control that repairs damaged doors</b>: CCTV does not fix or restore anything.</span><span class='qd'><b>A directive control that orders staff behavior</b>: Directive controls are policies or signs, not cameras.</span>"},{"id":"D3-017","domain":3,"obj":"3.1","diff":"medium","q":"Which combination best illustrates layered physical defense in depth at a corporate campus?","options":["Perimeter fence, exterior lighting, guarded lobby, badge access, and locked server room","A single locked front door","Only a CCTV camera at the entrance","A firewall and antivirus software"],"answer":0,"explain":"<strong>Correct.</strong> Multiple complementary physical layers, fence to lighting to guard to badge to locked room, force an intruder to defeat each in turn.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single locked front door</b>: One control is not layered defense in depth.</span><span class='qd'><b>Only a CCTV camera at the entrance</b>: A single detective control is not multiple layers.</span><span class='qd'><b>A firewall and antivirus software</b>: These are logical controls, not layered physical defenses.</span>"},{"id":"D3-018","domain":3,"obj":"3.1","diff":"medium","q":"An organization replaces traditional keyed locks with electronic badge readers. What is a significant security advantage of this change?","options":["Badges can never be lost or stolen","Access can be instantly revoked and individual entries are logged","Badges remove the need for any access policy","Badge systems do not require power"],"answer":1,"explain":"<strong>Correct.</strong> Electronic badge systems allow instant revocation of a lost credential and produce per-user audit logs that mechanical keys cannot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Badges can never be lost or stolen</b>: Badges absolutely can be lost or cloned; that is why revocation matters.</span><span class='qd'><b>Badges remove the need for any access policy</b>: A policy is still required to define who gets which access.</span><span class='qd'><b>Badge systems do not require power</b>: Electronic readers depend on power and need fail planning.</span>"},{"id":"D3-019","domain":3,"obj":"3.1","diff":"medium","q":"Adequate exterior lighting around a facility primarily supports security in which way?","options":["By encrypting traffic between cameras","By authenticating badge holders","By improving visibility for surveillance and deterring intruders","By enforcing least privilege on accounts"],"answer":2,"explain":"<strong>Correct.</strong> Lighting deters intruders who prefer darkness and improves the effectiveness of guards and CCTV by increasing visibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By encrypting traffic between cameras</b>: Lighting has nothing to do with encryption.</span><span class='qd'><b>By authenticating badge holders</b>: Authentication is performed by readers or guards, not lights.</span><span class='qd'><b>By enforcing least privilege on accounts</b>: Least privilege is a logical access concept unrelated to lighting.</span>"},{"id":"D3-020","domain":3,"obj":"3.1","diff":"hard","q":"A facility experiences tailgating despite badge readers on every door. Which solution most directly addresses the root cause?","options":["Increasing the password complexity policy","Shortening the visitor log retention period","Adding more antivirus scanning servers","Installing access control vestibules or turnstiles at entry points"],"answer":3,"explain":"<strong>Correct.</strong> Tailgating is people following an authorized person through a door; vestibules or turnstiles physically enforce one-person-per-authentication entry.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the password complexity policy</b>: Passwords are a logical control and do not stop physical tailgating.</span><span class='qd'><b>Adding more antivirus scanning servers</b>: Antivirus addresses malware, not physical entry behavior.</span><span class='qd'><b>Shortening the visitor log retention period</b>: Reducing log retention weakens accountability and does nothing to prevent tailgating.</span>"},{"id":"D3-021","domain":3,"obj":"3.1","diff":"hard","q":"During a power outage, a high-value vault must remain inaccessible, while an occupied office must allow safe exit. Which design correctly satisfies both?","options":["Vault fail-secure, office egress door fail-safe","Both doors fail-secure","Both doors fail-safe","Vault fail-safe, office egress door fail-secure"],"answer":0,"explain":"<strong>Correct.</strong> Asset protection drives the vault to fail-secure (stays locked), while life safety drives the occupied egress door to fail-safe (unlocks for escape).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both doors fail-safe</b>: A fail-safe vault would unlock during the outage, exposing high-value assets.</span><span class='qd'><b>Both doors fail-secure</b>: A fail-secure egress door could trap occupants, violating life safety.</span><span class='qd'><b>Vault fail-safe, office egress door fail-secure</b>: This reverses both requirements, endangering people and exposing assets.</span>"},{"id":"D3-022","domain":3,"obj":"3.1","diff":"hard","q":"An auditor notes that visitor badges are collected at exit but no one verifies the visitor actually left the building. Which control gap does this represent?","options":["Lack of separation of duties","Incomplete visitor escort and egress accountability","Excessive privilege creep","Weak encryption of badge data"],"answer":1,"explain":"<strong>Correct.</strong> Without confirming and logging departure or maintaining escort, the organization cannot account for a visitor's whereabouts, a gap in visitor management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lack of separation of duties</b>: Separation of duties concerns dividing tasks, not tracking visitor exit.</span><span class='qd'><b>Excessive privilege creep</b>: Privilege creep involves accumulated logical permissions, not visitor egress.</span><span class='qd'><b>Weak encryption of badge data</b>: The issue is verifying departure, not cryptographic strength.</span>"},{"id":"D3-023","domain":3,"obj":"3.1","diff":"hard","q":"A security architect wants a control that both deters intrusion and provides recorded evidence usable for investigations, while not physically blocking anyone. Which single control best meets this?","options":["A bollard","A fail-secure lock","Monitored and recorded CCTV","An access control vestibule"],"answer":2,"explain":"<strong>Correct.</strong> CCTV that is monitored and recorded deters would-be intruders and produces evidentiary footage, yet does not itself block passage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A bollard</b>: A bollard physically blocks vehicles and records nothing.</span><span class='qd'><b>A fail-secure lock</b>: A lock physically blocks entry and does not record events.</span><span class='qd'><b>An access control vestibule</b>: A vestibule physically restricts passage rather than only deterring and recording.</span>"},{"id":"D3-024","domain":3,"obj":"3.1","diff":"hard","q":"An attacker presents a cloned badge that the reader accepts as a legitimate employee. In access control terms, which failure has occurred at the physical layer?","options":["A false rejection","A deprovisioning failure","A crossover error","A false acceptance"],"answer":3,"explain":"<strong>Correct.</strong> The system accepted an unauthorized credential as valid, which is a false acceptance, the most dangerous error type because it admits an intruder.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A false rejection</b>: A false rejection wrongly denies a legitimate user, the opposite of what happened.</span><span class='qd'><b>A crossover error</b>: The crossover (CER) is a measured equilibrium point, not a single event.</span><span class='qd'><b>A deprovisioning failure</b>: Deprovisioning concerns removing access for departing users, not accepting a cloned badge.</span>"},{"id":"D3-025","domain":3,"obj":"3.2","diff":"easy","q":"What does the principle of least privilege require?","options":["Granting users only the access necessary to perform their job","Giving all users administrator rights for flexibility","Allowing access to any data a user requests","Removing all logging to improve performance"],"answer":0,"explain":"<strong>Correct.</strong> Least privilege limits each subject to the minimum permissions needed for their role, shrinking the attack surface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Giving all users administrator rights for flexibility</b>: Universal admin rights are the opposite of least privilege.</span><span class='qd'><b>Allowing access to any data a user requests</b>: Open access ignores the minimum-necessary rule.</span><span class='qd'><b>Removing all logging to improve performance</b>: Removing logging harms accountability and is unrelated to least privilege.</span>"},{"id":"D3-026","domain":3,"obj":"3.2","diff":"easy","q":"What does need-to-know restrict access based on?","options":["The user's seniority alone","Whether the information is required to perform a specific task","The size of the data file","The time of day"],"answer":1,"explain":"<strong>Correct.</strong> Need-to-know grants access to specific information only when it is required for the user's assigned task, even if they hold sufficient clearance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The user's seniority alone</b>: Rank alone does not justify access without an actual need.</span><span class='qd'><b>The size of the data file</b>: File size is irrelevant to need-to-know decisions.</span><span class='qd'><b>The time of day</b>: Time-based rules are a separate concept from need-to-know.</span>"},{"id":"D3-027","domain":3,"obj":"3.2","diff":"easy","q":"In Role-Based Access Control (RBAC), permissions are assigned based on what?","options":["The owner's personal discretion for each file","Security labels and clearances","A user's role or job function within the organization","The random assignment by the system"],"answer":2,"explain":"<strong>Correct.</strong> RBAC ties permissions to roles; users inherit access by being assigned to a role that matches their job function.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The owner's personal discretion for each file</b>: Owner discretion describes DAC, not RBAC.</span><span class='qd'><b>Security labels and clearances</b>: Labels and clearances describe MAC.</span><span class='qd'><b>The random assignment by the system</b>: Access is deliberately mapped to roles, never random.</span>"},{"id":"D3-028","domain":3,"obj":"3.2","diff":"easy","q":"In Mandatory Access Control (MAC), who ultimately determines access to a resource?","options":["The data owner at their discretion","The end user requesting access","Any user who creates the file","The system based on security labels and clearances set by policy"],"answer":3,"explain":"<strong>Correct.</strong> MAC enforces access through system-assigned security labels and clearances defined by central policy, not individual discretion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data owner at their discretion</b>: Owner discretion is the defining trait of DAC, not MAC.</span><span class='qd'><b>Any user who creates the file</b>: Creators cannot override MAC labels.</span><span class='qd'><b>The end user requesting access</b>: Users cannot grant themselves access under MAC.</span>"},{"id":"D3-029","domain":3,"obj":"3.2","diff":"easy","q":"In Discretionary Access Control (DAC), who decides who can access a resource?","options":["The owner of the resource","A central administrator using mandatory labels","The operating system kernel only","An external auditor"],"answer":0,"explain":"<strong>Correct.</strong> Under DAC, the resource owner has discretion to grant or revoke access to that resource.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A central administrator using mandatory labels</b>: Central label-based control is MAC, not DAC.</span><span class='qd'><b>The operating system kernel only</b>: The kernel enforces decisions but does not make discretionary grants.</span><span class='qd'><b>An external auditor</b>: Auditors review access; they do not assign it.</span>"},{"id":"D3-030","domain":3,"obj":"3.2","diff":"easy","q":"What is separation of duties designed to prevent?","options":["Users from logging into the system","A single individual having enough control to commit and conceal fraud","Data from being encrypted","Backups from running on schedule"],"answer":1,"explain":"<strong>Correct.</strong> Separation of duties divides critical tasks among multiple people so no one person can both perform and hide a fraudulent act.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Users from logging into the system</b>: It does not block legitimate logins.</span><span class='qd'><b>Data from being encrypted</b>: Encryption is unrelated to splitting duties.</span><span class='qd'><b>Backups from running on schedule</b>: Scheduling backups is an operational task, not the goal of separation of duties.</span>"},{"id":"D3-031","domain":3,"obj":"3.2","diff":"easy","q":"What is privilege creep?","options":["The encryption of user credentials","A type of malware that spreads laterally","The gradual accumulation of access rights beyond what a user currently needs","The process of onboarding a new employee"],"answer":2,"explain":"<strong>Correct.</strong> Privilege creep occurs when a user retains rights from past roles and gains new ones over time, ending up with more access than their job requires.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A type of malware that spreads laterally</b>: That describes a worm, not privilege creep.</span><span class='qd'><b>The encryption of user credentials</b>: Encryption is unrelated to accumulated permissions.</span><span class='qd'><b>The process of onboarding a new employee</b>: Onboarding is provisioning, not the gradual buildup of excess rights.</span>"},{"id":"D3-032","domain":3,"obj":"3.2","diff":"easy","q":"What is the purpose of an audit trail in logical access control?","options":["To grant new permissions automatically","To increase network bandwidth","To encrypt all stored data","To provide a record of system activity supporting accountability"],"answer":3,"explain":"<strong>Correct.</strong> An audit trail logs actions and the subjects that performed them, enabling accountability and after-the-fact investigation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To grant new permissions automatically</b>: Audit trails record activity; they do not assign rights.</span><span class='qd'><b>To encrypt all stored data</b>: Logging is not encryption.</span><span class='qd'><b>To increase network bandwidth</b>: Audit trails have no effect on bandwidth.</span>"},{"id":"D3-033","domain":3,"obj":"3.2","diff":"easy","q":"Which account type is typically used by an application or background process rather than a human being?","options":["Service account","Guest account","User account","Visitor account"],"answer":0,"explain":"<strong>Correct.</strong> A service account is a non-human account used by applications, services, or processes to run and access resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guest account</b>: A guest account is for temporary human users with limited rights.</span><span class='qd'><b>User account</b>: A user account belongs to an individual person.</span><span class='qd'><b>Visitor account</b>: Visitor access is a physical concept, not a standard logical account type for processes.</span>"},{"id":"D3-034","domain":3,"obj":"3.2","diff":"easy","q":"What does non-repudiation provide in an access control context?","options":["Faster login times","Assurance that a user cannot deny having performed an action","Automatic password resets","Encryption of network traffic"],"answer":1,"explain":"<strong>Correct.</strong> Non-repudiation links an action to an identity with sufficient assurance that the actor cannot credibly deny it later.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster login times</b>: Speed is unrelated to non-repudiation.</span><span class='qd'><b>Automatic password resets</b>: Password resets are an account management feature, not non-repudiation.</span><span class='qd'><b>Encryption of network traffic</b>: Encryption protects confidentiality; it is distinct from proving who acted.</span>"},{"id":"D3-035","domain":3,"obj":"3.2","diff":"medium","q":"An administrator removes all of a departing employee's accounts and access on their last day. What is this process called?","options":["Provisioning","Privilege escalation","Deprovisioning","Authentication"],"answer":2,"explain":"<strong>Correct.</strong> Deprovisioning is the timely removal of access and accounts when a user leaves or changes roles, closing a key insider-risk gap.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Provisioning</b>: Provisioning is creating and granting access, the opposite action.</span><span class='qd'><b>Privilege escalation</b>: Privilege escalation is gaining higher rights, not removing access.</span><span class='qd'><b>Authentication</b>: Authentication verifies identity at login, not the removal of accounts.</span>"},{"id":"D3-036","domain":3,"obj":"3.2","diff":"medium","q":"A company grants access dynamically based on attributes such as department, location, device, and time of day. Which access control model is in use?","options":["Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)","Mandatory Access Control (MAC)","Attribute-Based Access Control (ABAC)"],"answer":3,"explain":"<strong>Correct.</strong> ABAC evaluates multiple attributes of the subject, resource, action, and environment to make fine-grained, dynamic access decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary Access Control (DAC)</b>: DAC relies on owner discretion, not multi-attribute policies.</span><span class='qd'><b>Mandatory Access Control (MAC)</b>: MAC uses fixed security labels and clearances, not flexible attributes.</span><span class='qd'><b>Role-Based Access Control (RBAC)</b>: RBAC assigns by role only, lacking the multi-attribute granularity of ABAC.</span>"},{"id":"D3-037","domain":3,"obj":"3.2","diff":"medium","q":"A firewall rule set processes entries top to bottom and grants or denies traffic based on the order of statements. This is an example of which control approach?","options":["Rule-based access control","Discretionary access control","Mandatory access control","Need-to-know"],"answer":0,"explain":"<strong>Correct.</strong> Rule-based access control applies a set of administrator-defined rules (such as ordered ACL entries) uniformly to all subjects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary access control</b>: DAC is owner-driven per resource, not a global ordered rule set.</span><span class='qd'><b>Mandatory access control</b>: MAC uses labels and clearances, not ordered firewall rules.</span><span class='qd'><b>Need-to-know</b>: Need-to-know is an information-access principle, not a firewall rule mechanism.</span>"},{"id":"D3-038","domain":3,"obj":"3.2","diff":"medium","q":"Why are shared accounts discouraged in a well-controlled environment?","options":["They are faster to log in with","They undermine accountability because actions cannot be tied to one individual","They automatically enforce least privilege","They cannot be assigned any permissions"],"answer":1,"explain":"<strong>Correct.</strong> When several people use one credential, audit logs cannot attribute an action to a specific person, defeating accountability and non-repudiation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are faster to log in with</b>: Any speed benefit does not justify losing accountability.</span><span class='qd'><b>They automatically enforce least privilege</b>: Shared accounts often have broad, not minimal, access.</span><span class='qd'><b>They cannot be assigned any permissions</b>: Shared accounts can hold permissions; that is part of the problem.</span>"},{"id":"D3-039","domain":3,"obj":"3.2","diff":"medium","q":"An access control list (ACL) on a file specifies which subjects may read or write it. The ACL is best described as what?","options":["A physical barrier at the data center","A biometric enrollment template","A list of permissions attached to an object","A backup rotation schedule"],"answer":2,"explain":"<strong>Correct.</strong> An ACL is a list bound to an object that enumerates which subjects have which permissions on that object.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A biometric enrollment template</b>: A biometric template stores physiological data, not object permissions.</span><span class='qd'><b>A physical barrier at the data center</b>: An ACL is a logical construct, not a physical barrier.</span><span class='qd'><b>A backup rotation schedule</b>: A backup schedule has nothing to do with object permissions.</span>"},{"id":"D3-040","domain":3,"obj":"3.2","diff":"medium","q":"A privileged (administrator) account should follow which practice to limit risk?","options":["Be used for everyday email and web browsing","Never be logged or monitored","Be shared among the whole IT team","Be used only when elevated tasks are required, with normal work done on a standard account"],"answer":3,"explain":"<strong>Correct.</strong> Privileged accounts should be reserved for administrative tasks and used separately from a standard account, reducing exposure of high-value credentials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Be used for everyday email and web browsing</b>: Routine use exposes admin credentials to phishing and malware.</span><span class='qd'><b>Be shared among the whole IT team</b>: Sharing destroys accountability for privileged actions.</span><span class='qd'><b>Never be logged or monitored</b>: Privileged accounts demand the most logging, not the least.</span>"},{"id":"D3-041","domain":3,"obj":"3.2","diff":"medium","q":"Authorization, as distinct from authentication, determines what?","options":["What an authenticated subject is permitted to do","Whether the claimed identity is genuine","How fast a user can log in","Which encryption algorithm is used"],"answer":0,"explain":"<strong>Correct.</strong> Authorization defines the permissions an already-authenticated subject has, deciding what resources and actions are allowed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether the claimed identity is genuine</b>: That is authentication, which precedes authorization.</span><span class='qd'><b>How fast a user can log in</b>: Login speed is a performance matter, not authorization.</span><span class='qd'><b>Which encryption algorithm is used</b>: Algorithm selection is a cryptographic decision, not authorization.</span>"},{"id":"D3-042","domain":3,"obj":"3.2","diff":"medium","q":"Accountability in access control depends most directly on which combination?","options":["Shared accounts plus minimal logging","Unique identities plus logging of their actions","Anonymous access plus encryption","Guest accounts plus open ACLs"],"answer":1,"explain":"<strong>Correct.</strong> Accountability requires that each subject have a unique identity and that the system log their actions so behavior can be traced to that individual.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Shared accounts plus minimal logging</b>: Shared accounts and sparse logs make tracing actions impossible.</span><span class='qd'><b>Anonymous access plus encryption</b>: Anonymity removes the identity needed for accountability.</span><span class='qd'><b>Guest accounts plus open ACLs</b>: Generic guest access and open permissions undermine traceability.</span>"},{"id":"D3-043","domain":3,"obj":"3.2","diff":"hard","q":"An employee transfers from finance to HR but keeps all former finance permissions while gaining new HR permissions. Which problem and remedy pair is correct?","options":["Non-repudiation, remedied by disabling logging","Separation of duties, remedied by adding more roles","Privilege creep, remedied by an access review and right-sizing of permissions","Least privilege, remedied by granting administrator rights"],"answer":2,"explain":"<strong>Correct.</strong> Retaining old rights while adding new ones is privilege creep; periodic access reviews and recertification remove no-longer-needed permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Separation of duties, remedied by adding more roles</b>: Adding roles would worsen the accumulation, not fix it.</span><span class='qd'><b>Non-repudiation, remedied by disabling logging</b>: Disabling logging destroys accountability and is unrelated.</span><span class='qd'><b>Least privilege, remedied by granting administrator rights</b>: Granting more rights directly violates least privilege.</span>"},{"id":"D3-044","domain":3,"obj":"3.2","diff":"hard","q":"A defense agency requires that documents labeled 'Secret' be readable only by users with Secret clearance or higher, enforced centrally and not changeable by document owners. Which model is required?","options":["Discretionary Access Control (DAC)","Rule-based access control","Role-Based Access Control (RBAC)","Mandatory Access Control (MAC)"],"answer":3,"explain":"<strong>Correct.</strong> Centrally enforced clearance-and-label matching that owners cannot override is the defining behavior of MAC.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary Access Control (DAC)</b>: DAC lets owners change access, which the scenario forbids.</span><span class='qd'><b>Role-Based Access Control (RBAC)</b>: RBAC assigns by job role, not by clearance labels.</span><span class='qd'><b>Rule-based access control</b>: Rule-based controls apply generic rules but not the mandatory clearance-label model described.</span>"},{"id":"D3-045","domain":3,"obj":"3.2","diff":"hard","q":"In an organization with thousands of employees and frequent role changes, which model most efficiently keeps permissions aligned to job functions while easing administration?","options":["Role-Based Access Control","Discretionary Access Control with per-user grants","Assigning unique custom permissions to each individual","Shared accounts per department"],"answer":0,"explain":"<strong>Correct.</strong> RBAC maps permissions to roles, so moving a user between roles updates their access at scale without per-user permission editing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary Access Control with per-user grants</b>: Per-user owner grants do not scale and drift out of alignment.</span><span class='qd'><b>Assigning unique custom permissions to each individual</b>: Bespoke per-person permissions are unmanageable at thousands of users.</span><span class='qd'><b>Shared accounts per department</b>: Shared accounts break accountability and least privilege.</span>"},{"id":"D3-046","domain":3,"obj":"3.2","diff":"hard","q":"To enforce separation of duties for payments, which assignment is appropriate?","options":["One person both creates and approves every payment","One person submits payment requests while a different person approves them","A single shared account performs all payment steps","The same administrator provisions accounts and approves their own access"],"answer":1,"explain":"<strong>Correct.</strong> Splitting submission and approval between two people prevents any one individual from authorizing fraudulent payments alone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One person both creates and approves every payment</b>: Concentrating both steps in one person is exactly the risk separation of duties prevents.</span><span class='qd'><b>A single shared account performs all payment steps</b>: A shared account hides who acted and concentrates control.</span><span class='qd'><b>The same administrator provisions accounts and approves their own access</b>: Self-approval is a separation-of-duties violation.</span>"},{"id":"D3-047","domain":3,"obj":"3.2","diff":"hard","q":"An investigator must prove that a specific user, and no one else, deleted a critical record. Which combination of controls best supports this conclusion?","options":["Guest access with anonymous sessions","Shared service accounts and disabled logging","Unique authentication, comprehensive audit trails, and no shared accounts","Open ACLs with owner discretion only"],"answer":2,"explain":"<strong>Correct.</strong> Unique credentials plus detailed, protected audit logs and the absence of shared accounts tie the deletion to one identity, supporting non-repudiation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Shared service accounts and disabled logging</b>: Shared use and no logs make attribution impossible.</span><span class='qd'><b>Guest access with anonymous sessions</b>: Anonymity removes the identity needed to prove who acted.</span><span class='qd'><b>Open ACLs with owner discretion only</b>: Open permissions without logging do not establish who performed the deletion.</span>"},{"id":"D3-048","domain":3,"obj":"3.2","diff":"hard","q":"A guest account on a kiosk is found with permissions to modify system configuration files. Which two principles are most directly violated?","options":["Two-person integrity and CPTED","Non-repudiation and encryption strength","Defense in depth and lighting standards","Least privilege and need-to-know"],"answer":3,"explain":"<strong>Correct.</strong> A guest having configuration-modification rights exceeds the minimum required (least privilege) and provides access not needed for its purpose (need-to-know).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Non-repudiation and encryption strength</b>: These concern proving actions and cipher strength, not excessive guest permissions.</span><span class='qd'><b>Defense in depth and lighting standards</b>: These are physical-layer concepts unrelated to a guest account's rights.</span><span class='qd'><b>Two-person integrity and CPTED</b>: Both are physical controls, not logical permission principles.</span>"},{"id":"D3-049","domain":3,"obj":"3.2","diff":"hard","q":"During an access recertification review, a manager confirms each team member still needs every right they hold and removes those that are no longer justified. This activity most directly enforces which principle and counters which problem?","options":["Least privilege; privilege creep","Defense in depth; tailgating","Non-repudiation; false acceptance","Separation of duties; piggybacking"],"answer":0,"explain":"<strong>Correct.</strong> Periodic recertification trims access back to what is needed, enforcing least privilege and directly countering privilege creep.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defense in depth; tailgating</b>: These are physical-layer concerns, not logical access reviews.</span><span class='qd'><b>Non-repudiation; false acceptance</b>: These relate to proving actions and biometric errors, not right-sizing permissions.</span><span class='qd'><b>Separation of duties; piggybacking</b>: Separation of duties splits tasks and piggybacking is physical; neither matches a recertification review.</span>"},{"id":"D3-050","domain":3,"obj":"3.2","diff":"hard","q":"A cloud platform evaluates each request against policy expressions that combine the subject's clearance, the resource's classification, the request's action, and the current risk score. Which model and characteristic are described?","options":["DAC, because owners set the rules","ABAC, because decisions are made dynamically from multiple attributes","MAC, because only static labels are used","RBAC, because access depends solely on a single role"],"answer":1,"explain":"<strong>Correct.</strong> Combining subject, resource, action, and environmental (risk) attributes into dynamic policy decisions is the hallmark of ABAC.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DAC, because owners set the rules</b>: DAC is owner discretion, not policy-driven attribute evaluation.</span><span class='qd'><b>MAC, because only static labels are used</b>: The scenario uses dynamic risk and multiple attributes, exceeding MAC's static labels.</span><span class='qd'><b>RBAC, because access depends solely on a single role</b>: RBAC keys on role alone, lacking the multi-attribute, risk-aware logic described.</span>"},{"id":"D3-051","domain":3,"obj":"3.1","diff":"medium","q":"When comparing biometric systems, which metric identifies the point where the false acceptance rate equals the false rejection rate and is used to gauge overall accuracy?","options":["False Rejection Rate (FRR)","False Acceptance Rate (FAR)","Crossover Error Rate (CER)","Failure to Enroll Rate (FER)"],"answer":2,"explain":"<strong>Correct.</strong> The Crossover Error Rate (CER), or equal error rate, is where FAR and FRR meet; a lower CER indicates a more accurate biometric system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False Acceptance Rate (FAR)</b>: FAR measures how often an unauthorized person is wrongly accepted, only one of the two curves that meet at the CER.</span><span class='qd'><b>False Rejection Rate (FRR)</b>: FRR measures how often a legitimate user is wrongly rejected, again only one side of the comparison.</span><span class='qd'><b>Failure to Enroll Rate (FER)</b>: FER describes how often users cannot be enrolled at all and is not the FAR/FRR crossover.</span>"},{"id":"D3-052","domain":3,"obj":"3.1","diff":"easy","q":"Which physical security strategy uses layered controls such as fences, guards, and locked doors so that defeating one layer does not grant full access?","options":["Mandatory access control","Single sign-on","Need-to-know","Defense in depth"],"answer":3,"explain":"<strong>Correct.</strong> Defense in depth layers multiple physical controls so an attacker must defeat several barriers, not just one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single sign-on</b>: SSO is a logical authentication convenience, not a physical layering concept.</span><span class='qd'><b>Need-to-know</b>: Need-to-know restricts information access, not physical layering.</span><span class='qd'><b>Mandatory access control</b>: MAC is a logical access model based on labels, not physical layers.</span>"},{"id":"D3-053","domain":3,"obj":"3.1","diff":"medium","q":"A biometric system is tuned so that it rarely lets unauthorized people in, but legitimate users are frequently rejected. Which metric is high in this configuration?","options":["False Rejection Rate (FRR)","False Acceptance Rate (FAR)","Crossover Error Rate (CER)","Mean Time To Repair (MTTR)"],"answer":0,"explain":"<strong>Correct.</strong> When legitimate users are wrongly turned away, the False Rejection Rate (Type I error) is high.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False Acceptance Rate (FAR)</b>: FAR rises when unauthorized people are let in, the opposite of this scenario.</span><span class='qd'><b>Crossover Error Rate (CER)</b>: CER is the single point where FAR equals FRR, not a description of this imbalance.</span><span class='qd'><b>Mean Time To Repair (MTTR)</b>: MTTR is a maintenance metric unrelated to biometric accuracy.</span>"},{"id":"D3-054","domain":3,"obj":"3.1","diff":"medium","q":"When comparing two biometric devices, which metric best represents overall accuracy because it is the point where false acceptance and false rejection are equal?","options":["False Acceptance Rate (FAR)","Crossover Error Rate (CER)","False Rejection Rate (FRR)","Throughput rate"],"answer":1,"explain":"<strong>Correct.</strong> The Crossover Error Rate is where FAR equals FRR; a lower CER indicates a more accurate biometric device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False Acceptance Rate (FAR)</b>: FAR alone reflects only one error type and can be tuned, so it is not the overall accuracy measure.</span><span class='qd'><b>False Rejection Rate (FRR)</b>: FRR alone also reflects only one error type and varies with sensitivity.</span><span class='qd'><b>Throughput rate</b>: Throughput measures speed of processing users, not accuracy.</span>"},{"id":"D3-055","domain":3,"obj":"3.1","diff":"easy","q":"What does CPTED stand for in physical security?","options":["Centralized Physical Entry Tracking Database","Critical Power Emergency Transfer Device","Crime Prevention Through Environmental Design","Controlled Perimeter Entry and Threat Detection"],"answer":2,"explain":"<strong>Correct.</strong> CPTED stands for Crime Prevention Through Environmental Design, which uses the built environment to reduce crime.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Critical Power Emergency Transfer Device</b>: This is a fabricated term, not the CPTED acronym.</span><span class='qd'><b>Centralized Physical Entry Tracking Database</b>: This is invented and not what CPTED means.</span><span class='qd'><b>Controlled Perimeter Entry and Threat Detection</b>: This is a distractor and not the correct expansion.</span>"},{"id":"D3-056","domain":3,"obj":"3.1","diff":"medium","q":"A facility uses natural surveillance, territorial reinforcement, and natural access control as part of its design philosophy. Which concept is being applied?","options":["Rule-based access control","Two-person integrity","Separation of duties","CPTED"],"answer":3,"explain":"<strong>Correct.</strong> Natural surveillance, territorial reinforcement, and natural access control are the core principles of CPTED.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Two-person integrity</b>: This requires two people for sensitive tasks and is not an environmental design philosophy.</span><span class='qd'><b>Separation of duties</b>: This is an administrative control that splits tasks among people, not a design strategy.</span><span class='qd'><b>Rule-based access control</b>: This is a logical access model using rules, not physical environmental design.</span>"},{"id":"D3-057","domain":3,"obj":"3.1","diff":"easy","q":"Which physical barrier is specifically designed to stop a vehicle from ramming into a building entrance?","options":["Bollards","Turnstile","Badge reader","CCTV camera"],"answer":0,"explain":"<strong>Correct.</strong> Bollards are sturdy posts placed to block vehicles from driving into pedestrian areas or buildings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Turnstile</b>: A turnstile controls pedestrian flow, not vehicles.</span><span class='qd'><b>Badge reader</b>: A badge reader authenticates people, it cannot physically stop a vehicle.</span><span class='qd'><b>CCTV camera</b>: A camera records activity but provides no physical barrier.</span>"},{"id":"D3-058","domain":3,"obj":"3.1","diff":"medium","q":"A security policy requires that two authorized individuals must be present whenever the vault containing master encryption keys is opened. Which control is this?","options":["Least privilege","Two-person integrity","Privilege creep","Discretionary access control"],"answer":1,"explain":"<strong>Correct.</strong> Two-person integrity (two-person control) requires two authorized people to be present for highly sensitive operations, preventing a single insider from acting alone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Least privilege</b>: Least privilege limits each person's rights but does not require two people to be present.</span><span class='qd'><b>Privilege creep</b>: Privilege creep is the unwanted accumulation of rights over time, not a control.</span><span class='qd'><b>Discretionary access control</b>: DAC lets owners grant access at their discretion and is unrelated to dual presence.</span>"},{"id":"D3-059","domain":3,"obj":"3.1","diff":"medium","q":"A visitor arrives at a secured office. Following good visitor management, what should happen after they sign in?","options":["They are allowed to roam freely once identity is verified","They are given a permanent employee badge for the day","They are issued a temporary badge and escorted by an employee","They are added to the building's privileged access group"],"answer":2,"explain":"<strong>Correct.</strong> Proper visitor management issues a temporary, visibly distinct badge and requires an employee escort within secure areas.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are given a permanent employee badge for the day</b>: Visitors should never receive employee-equivalent credentials.</span><span class='qd'><b>They are allowed to roam freely once identity is verified</b>: Verified identity does not authorize unescorted movement.</span><span class='qd'><b>They are added to the building's privileged access group</b>: Granting privileged access to a visitor violates least privilege.</span>"},{"id":"D3-060","domain":3,"obj":"3.1","diff":"hard","q":"A data center wants a physical control that not only deters intruders but can also actively respond to unexpected situations, make judgment calls, and detain a trespasser. Which control best fits?","options":["Warning signage","Fencing","Lighting","Security guards"],"answer":3,"explain":"<strong>Correct.</strong> Security guards provide a discretionary, intelligent control able to assess situations, respond dynamically, and detain intruders, something automated controls cannot do.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fencing</b>: Fencing is a static deterrent and delay control with no judgment capability.</span><span class='qd'><b>Lighting</b>: Lighting deters and aids visibility but cannot respond or detain.</span><span class='qd'><b>Warning signage</b>: Signage only deters and informs; it takes no action.</span>"},{"id":"D3-061","domain":3,"obj":"3.1","diff":"easy","q":"Which device captures and records video footage for later review and acts as a detective control?","options":["CCTV","Bollard","Mantrap","Cipher lock"],"answer":0,"explain":"<strong>Correct.</strong> Closed-circuit television (CCTV) records activity, serving primarily as a detective control and deterrent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bollard</b>: A bollard physically blocks vehicles and records nothing.</span><span class='qd'><b>Mantrap</b>: A mantrap (vestibule) controls entry flow but does not record video by itself.</span><span class='qd'><b>Cipher lock</b>: A cipher lock controls door access via a code; it does not capture footage.</span>"},{"id":"D3-062","domain":3,"obj":"3.1","diff":"medium","q":"An organization wants to control which doors an employee can open and to revoke that access instantly if the employee is terminated. Which technology best supports this?","options":["Traditional brass key locks","Electronic badge access system","Combination padlocks","A logbook signed by a guard"],"answer":1,"explain":"<strong>Correct.</strong> An electronic badge system lets administrators assign door permissions and instantly deactivate a badge upon termination.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Traditional brass key locks</b>: Physical keys cannot be revoked instantly and may require rekeying if lost.</span><span class='qd'><b>Combination padlocks</b>: A shared combination cannot be revoked for one person without changing it for everyone.</span><span class='qd'><b>A logbook signed by a guard</b>: A logbook records entries but does not control or revoke access.</span>"},{"id":"D3-063","domain":3,"obj":"3.1","diff":"hard","q":"A high-security site installs fences of increasing height in concentric rings, with the tallest topped by barbed wire around the most sensitive building. Which two functions does this fencing primarily provide?","options":["Authorization and accounting","Encryption and authentication","Deterrence and delay","Detection and correction"],"answer":2,"explain":"<strong>Correct.</strong> Fencing primarily deters casual intruders and delays determined ones long enough for other controls to respond.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption and authentication</b>: These are logical security functions unrelated to a physical fence.</span><span class='qd'><b>Authorization and accounting</b>: These are access management functions, not properties of a fence.</span><span class='qd'><b>Detection and correction</b>: A fence does not detect or correct; sensors and responders do that.</span>"},{"id":"D3-064","domain":3,"obj":"3.1","diff":"medium","q":"Which authentication factor category does a fingerprint scanner rely on?","options":["Somewhere you are","Something you know","Something you have","Something you are"],"answer":3,"explain":"<strong>Correct.</strong> A fingerprint is a biometric trait, which is the 'something you are' factor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you know</b>: This refers to knowledge like a password or PIN, not a physical trait.</span><span class='qd'><b>Something you have</b>: This refers to a token or badge you possess, not a biometric.</span><span class='qd'><b>Somewhere you are</b>: This refers to location-based factors such as geolocation, not fingerprints.</span>"},{"id":"D3-065","domain":3,"obj":"3.1","diff":"easy","q":"What is 'tailgating' (piggybacking) in physical security?","options":["An unauthorized person following an authorized person through a secure door","Encrypting data before it leaves the building","Assigning excessive permissions to a user account","Reviewing audit logs after an incident"],"answer":0,"explain":"<strong>Correct.</strong> Tailgating occurs when an unauthorized person slips through a controlled door behind someone who legitimately badged in.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting data before it leaves the building</b>: That is a data protection measure, not a physical entry attack.</span><span class='qd'><b>Assigning excessive permissions to a user account</b>: That describes privilege issues, not physical tailgating.</span><span class='qd'><b>Reviewing audit logs after an incident</b>: That is a detective activity, unrelated to tailgating.</span>"},{"id":"D3-066","domain":3,"obj":"3.1","diff":"medium","q":"A facility manager wants lighting that turns on automatically and stays bright through the night to discourage intruders and support camera coverage. Which control category does lighting primarily fall under?","options":["Compensating control for encryption","Deterrent control","Authentication control","Non-repudiation control"],"answer":1,"explain":"<strong>Correct.</strong> Lighting deters intruders by removing concealment and improving visibility for guards and cameras, making it a deterrent control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compensating control for encryption</b>: Lighting has nothing to do with compensating for missing encryption.</span><span class='qd'><b>Authentication control</b>: Lighting does not verify identity.</span><span class='qd'><b>Non-repudiation control</b>: Lighting does not provide proof of who performed an action.</span>"},{"id":"D3-067","domain":3,"obj":"3.1","diff":"hard","q":"A door lock uses a keypad where users enter a numeric code, and the same code is shared among a small team. From a security standpoint, what is the biggest weakness of this cipher lock approach?","options":["It cannot be installed on exterior doors","It requires biometric enrollment for every user","A shared code provides no individual accountability and is hard to revoke per person","It encrypts the code too strongly to audit"],"answer":2,"explain":"<strong>Correct.</strong> A shared keypad code cannot identify which individual entered, undermining accountability, and cannot be revoked for one person without changing it for all.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It requires biometric enrollment for every user</b>: Cipher locks use codes, not biometrics, so this is false.</span><span class='qd'><b>It cannot be installed on exterior doors</b>: Cipher locks can be installed on exterior doors.</span><span class='qd'><b>It encrypts the code too strongly to audit</b>: The weakness is lack of individual tracking, not over-encryption.</span>"},{"id":"D3-068","domain":3,"obj":"3.1","diff":"medium","q":"Why might an organization place a turnstile at a building lobby in addition to a staffed reception desk?","options":["To serve as the organization's audit trail of logical access","To encrypt the badge data in transit","To provide separation of duties for finance staff","To physically enforce one-person-at-a-time entry and reduce reliance on the guard's attention"],"answer":3,"explain":"<strong>Correct.</strong> A turnstile physically restricts entry to one person per authentication, reinforcing the human guard and reducing tailgating.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt the badge data in transit</b>: A turnstile is a physical barrier and does not encrypt data.</span><span class='qd'><b>To provide separation of duties for finance staff</b>: Separation of duties is an administrative control, not a turnstile function.</span><span class='qd'><b>To serve as the organization's audit trail of logical access</b>: Logical audit trails are maintained in systems, not by a turnstile.</span>"},{"id":"D3-069","domain":3,"obj":"3.1","diff":"easy","q":"Which control combines something a user has (a badge) and something a user knows (a PIN) to enter a secure room?","options":["Multi-factor physical access control","Single-factor biometric control","Discretionary access control","Rule-based access control"],"answer":0,"explain":"<strong>Correct.</strong> Requiring a badge plus a PIN uses two different factor types, making it multi-factor physical access control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single-factor biometric control</b>: This uses only one biometric factor, not a badge and PIN combination.</span><span class='qd'><b>Discretionary access control</b>: DAC is a logical model where owners grant access, not a description of factors.</span><span class='qd'><b>Rule-based access control</b>: Rule-based control applies rules like time windows, not badge-plus-PIN factor counting.</span>"},{"id":"D3-070","domain":3,"obj":"3.1","diff":"hard","q":"During a physical security review, an auditor notes that a sensitive server room has a strong door lock but the drop ceiling tiles can be lifted to climb over the wall into the room. What principle has been violated?","options":["Least privilege was not applied to the door lock","The room's barrier does not extend from true floor to true ceiling, breaking defense in depth","Non-repudiation was not enforced on entry logs","The biometric CER was set too high"],"answer":1,"explain":"<strong>Correct.</strong> A secure room must have walls extending slab-to-slab; a gap above a drop ceiling defeats the physical barrier and breaks the layered defense.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Least privilege was not applied to the door lock</b>: Least privilege concerns granted permissions, not a structural ceiling gap.</span><span class='qd'><b>Non-repudiation was not enforced on entry logs</b>: Non-repudiation concerns proving who acted, not a physical gap.</span><span class='qd'><b>The biometric CER was set too high</b>: No biometric tuning issue is described; the flaw is structural.</span>"},{"id":"D3-071","domain":3,"obj":"3.2","diff":"easy","q":"Which principle states that users should be granted only the minimum permissions needed to perform their job?","options":["Separation of duties","Need-to-know","Least privilege","Two-person integrity"],"answer":2,"explain":"<strong>Correct.</strong> Least privilege grants each user only the access required to do their job and nothing more.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Need-to-know</b>: Need-to-know restricts access to specific information based on necessity, a related but distinct concept.</span><span class='qd'><b>Separation of duties</b>: Separation of duties splits a task among multiple people, not about minimum permissions.</span><span class='qd'><b>Two-person integrity</b>: This requires two people for sensitive actions, not minimal permissions.</span>"},{"id":"D3-072","domain":3,"obj":"3.2","diff":"easy","q":"What does the principle of 'need-to-know' restrict?","options":["The encryption strength used on backups","The number of doors a badge can open","The physical height of perimeter fences","Access to specific information based on whether the user must have it for their role"],"answer":3,"explain":"<strong>Correct.</strong> Need-to-know limits access to particular pieces of information to those who require it for their duties, even if they hold a sufficient clearance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The number of doors a badge can open</b>: That is a physical access concern, not information need-to-know.</span><span class='qd'><b>The physical height of perimeter fences</b>: Fence height is a physical control unrelated to need-to-know.</span><span class='qd'><b>The encryption strength used on backups</b>: Encryption strength is a data protection setting, not need-to-know.</span>"},{"id":"D3-073","domain":3,"obj":"3.2","diff":"medium","q":"A company splits the ability to create a vendor and the ability to approve payments to that vendor between two different employees. Which principle does this enforce?","options":["Separation of duties","Privilege creep","Least privilege","Mandatory access control"],"answer":0,"explain":"<strong>Correct.</strong> Separation of duties divides a critical process among multiple people so no single person can commit and conceal fraud.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Privilege creep</b>: Privilege creep is the accumulation of unneeded rights, the problem this control helps avoid, not the control itself.</span><span class='qd'><b>Least privilege</b>: Least privilege limits each user's rights but does not specifically split a single transaction between people.</span><span class='qd'><b>Mandatory access control</b>: MAC uses labels and clearances, not the division of a business process.</span>"},{"id":"D3-074","domain":3,"obj":"3.2","diff":"medium","q":"An employee has moved through several departments over five years and still holds all the permissions from each former role. What is this condition called?","options":["Separation of duties","Privilege creep","Non-repudiation","Two-person integrity"],"answer":1,"explain":"<strong>Correct.</strong> Privilege creep (privilege accumulation) occurs when a user retains old permissions after changing roles, violating least privilege.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Separation of duties</b>: That is a control that divides tasks, not the accumulation of stale rights.</span><span class='qd'><b>Non-repudiation</b>: Non-repudiation ensures actions cannot be denied; it is unrelated to accumulated permissions.</span><span class='qd'><b>Two-person integrity</b>: That requires two people for sensitive tasks, not the result of role changes.</span>"},{"id":"D3-075","domain":3,"obj":"3.2","diff":"hard","q":"In a Mandatory Access Control (MAC) model, who ultimately determines whether a subject can access an object?","options":["Any user with the file can share it freely","The individual file owner grants access at their discretion","The system enforces access based on labels and clearances set by policy, not the data owner","The most recently logged-in administrator"],"answer":2,"explain":"<strong>Correct.</strong> In MAC, the operating system enforces access by comparing security labels and clearances according to central policy; users cannot override it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The individual file owner grants access at their discretion</b>: That describes DAC, where owners decide, not MAC.</span><span class='qd'><b>Any user with the file can share it freely</b>: Free sharing contradicts MAC's mandatory enforcement.</span><span class='qd'><b>The most recently logged-in administrator</b>: Access in MAC follows labels and policy, not whoever logged in last.</span>"},{"id":"D3-076","domain":3,"obj":"3.2","diff":"medium","q":"In Discretionary Access Control (DAC), who decides who may access a resource?","options":["The hardware firewall","A central security policy enforced by the OS","The user's manager only","The owner of the resource"],"answer":3,"explain":"<strong>Correct.</strong> Under DAC, the resource owner has discretion to grant or deny access to others.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A central security policy enforced by the OS</b>: That describes MAC, not DAC.</span><span class='qd'><b>The user's manager only</b>: DAC vests discretion in the owner, who may or may not be the manager.</span><span class='qd'><b>The hardware firewall</b>: A firewall filters network traffic and does not assign DAC permissions.</span>"},{"id":"D3-077","domain":3,"obj":"3.2","diff":"medium","q":"A hospital assigns permissions to the roles 'Nurse', 'Physician', and 'Billing Clerk', and users inherit access by being placed in a role. Which access control model is in use?","options":["Role-Based Access Control (RBAC)","Discretionary Access Control (DAC)","Mandatory Access Control (MAC)","Attribute-Based Access Control (ABAC)"],"answer":0,"explain":"<strong>Correct.</strong> RBAC grants permissions to roles, and users gain access by being assigned to the appropriate role.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary Access Control (DAC)</b>: DAC relies on resource owners granting access individually, not predefined roles.</span><span class='qd'><b>Mandatory Access Control (MAC)</b>: MAC uses labels and clearances, not job roles.</span><span class='qd'><b>Attribute-Based Access Control (ABAC)</b>: ABAC evaluates many attributes dynamically, not a simple role assignment.</span>"},{"id":"D3-078","domain":3,"obj":"3.2","diff":"hard","q":"A cloud system grants access only when conditions like user department equals 'Finance', device is managed, time is within business hours, and location is the corporate network are all met. Which model is this?","options":["Role-Based Access Control (RBAC)","Attribute-Based Access Control (ABAC)","Discretionary Access Control (DAC)","Mandatory Access Control (MAC)"],"answer":1,"explain":"<strong>Correct.</strong> ABAC makes decisions by evaluating multiple attributes of the user, resource, action, and environment together.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Role-Based Access Control (RBAC)</b>: RBAC decides on role membership alone, not a combination of dynamic attributes.</span><span class='qd'><b>Discretionary Access Control (DAC)</b>: DAC leaves decisions to the resource owner, not attribute policies.</span><span class='qd'><b>Mandatory Access Control (MAC)</b>: MAC uses fixed labels and clearances, not flexible attribute conditions.</span>"},{"id":"D3-079","domain":3,"obj":"3.2","diff":"medium","q":"A firewall permits or denies traffic based on configured statements such as 'allow port 443 from any to the web server'. Which access control approach does this represent?","options":["Discretionary access control","Role-based access control","Rule-based access control","Mandatory access control"],"answer":2,"explain":"<strong>Correct.</strong> Rule-based access control applies predefined rules (such as firewall ACL entries) uniformly to all traffic or subjects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Role-based access control</b>: RBAC assigns access by user role, not by traffic rules.</span><span class='qd'><b>Discretionary access control</b>: DAC depends on owner discretion, not global firewall rules.</span><span class='qd'><b>Mandatory access control</b>: MAC uses security labels and clearances, not firewall rule statements.</span>"},{"id":"D3-080","domain":3,"obj":"3.2","diff":"easy","q":"What is an Access Control List (ACL) on a file?","options":["A schedule for backing up the file","A log of every login attempt on the network","An encryption key used to protect the file","A list specifying which subjects may access the object and what actions they may perform"],"answer":3,"explain":"<strong>Correct.</strong> An ACL is attached to an object and lists the subjects (users or groups) and the permissions each is granted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A log of every login attempt on the network</b>: That describes an audit log, not an ACL.</span><span class='qd'><b>An encryption key used to protect the file</b>: An ACL defines permissions, not cryptographic keys.</span><span class='qd'><b>A schedule for backing up the file</b>: A backup schedule is unrelated to access permissions.</span>"},{"id":"D3-081","domain":3,"obj":"3.2","diff":"medium","q":"Which security property ensures that a user cannot credibly deny having performed a specific action, such as signing a transaction?","options":["Non-repudiation","Availability","Redundancy","Least privilege"],"answer":0,"explain":"<strong>Correct.</strong> Non-repudiation provides proof of origin and action so the actor cannot later deny it, often via digital signatures and audit trails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Availability</b>: Availability ensures systems are accessible, not proof of who acted.</span><span class='qd'><b>Redundancy</b>: Redundancy provides backups for resilience, unrelated to denial of actions.</span><span class='qd'><b>Least privilege</b>: Least privilege limits permissions but does not prove who did something.</span>"},{"id":"D3-082","domain":3,"obj":"3.2","diff":"medium","q":"Why are audit trails important to access control?","options":["They automatically grant new permissions to active users","They record who did what and when, supporting accountability and investigations","They encrypt all stored data at rest","They replace the need for authentication"],"answer":1,"explain":"<strong>Correct.</strong> Audit trails capture user actions with timestamps, enabling accountability, detection, and forensic investigation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They automatically grant new permissions to active users</b>: Audit trails record activity; they do not grant permissions.</span><span class='qd'><b>They encrypt all stored data at rest</b>: Encryption is a separate control from logging.</span><span class='qd'><b>They replace the need for authentication</b>: Logging supplements authentication; it does not replace it.</span>"},{"id":"D3-083","domain":3,"obj":"3.2","diff":"hard","q":"A new hire in the marketing team is automatically placed in the 'Marketing' role, which grants the standard set of marketing application permissions. This automated assignment during onboarding is best described as what?","options":["Privilege creep","Deprovisioning","Provisioning","Non-repudiation"],"answer":2,"explain":"<strong>Correct.</strong> Provisioning is the process of creating an account and granting the appropriate access when a user joins or changes roles.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deprovisioning</b>: Deprovisioning removes access when a user leaves, the opposite of onboarding.</span><span class='qd'><b>Privilege creep</b>: Privilege creep is accumulating excess rights over time, not the initial grant.</span><span class='qd'><b>Non-repudiation</b>: Non-repudiation concerns proving actions, not assigning access.</span>"},{"id":"D3-084","domain":3,"obj":"3.2","diff":"medium","q":"An employee resigns. Which action most directly reduces the risk that their account is misused after departure?","options":["Lowering the biometric CER","Increasing the office lighting at night","Adding a new bollard at the entrance","Promptly deprovisioning (disabling or removing) the account"],"answer":3,"explain":"<strong>Correct.</strong> Timely deprovisioning disables or removes the departing user's access, closing off the account before it can be misused.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the office lighting at night</b>: Lighting is a physical deterrent and does not affect a digital account.</span><span class='qd'><b>Adding a new bollard at the entrance</b>: A bollard blocks vehicles and has no bearing on account access.</span><span class='qd'><b>Lowering the biometric CER</b>: Biometric tuning does not disable an existing logical account.</span>"},{"id":"D3-085","domain":3,"obj":"3.2","diff":"easy","q":"Which type of account typically has elevated permissions and should be tightly controlled and monitored?","options":["Privileged (administrator) account","Standard user account","Guest account","Anonymous account"],"answer":0,"explain":"<strong>Correct.</strong> Privileged or administrator accounts carry elevated rights and require strict control, monitoring, and minimal use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Standard user account</b>: A standard account has ordinary, limited permissions.</span><span class='qd'><b>Guest account</b>: A guest account has minimal, temporary access, not elevated rights.</span><span class='qd'><b>Anonymous account</b>: An anonymous account is unauthenticated and typically very limited.</span>"},{"id":"D3-086","domain":3,"obj":"3.2","diff":"hard","q":"A security team wants to detect privilege creep across the organization. Which activity most directly accomplishes this?","options":["Installing additional CCTV cameras in the data center","Conducting periodic access reviews comparing each user's permissions to their current role","Increasing the height of the perimeter fence","Encrypting all email in transit"],"answer":1,"explain":"<strong>Correct.</strong> Periodic access reviews (recertification) compare granted permissions against current job needs, surfacing accumulated, unneeded rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Installing additional CCTV cameras in the data center</b>: Cameras monitor physical space, not logical permission accumulation.</span><span class='qd'><b>Increasing the height of the perimeter fence</b>: Fences are physical controls unrelated to user permissions.</span><span class='qd'><b>Encrypting all email in transit</b>: Email encryption protects confidentiality, not access reviews.</span>"},{"id":"D3-087","domain":3,"obj":"3.2","diff":"medium","q":"Authorization, in the context of access control, answers which question?","options":["Is this user's identity proven?","Who is this person claiming to be?","What is this authenticated subject permitted to do?","What time did the event occur?"],"answer":2,"explain":"<strong>Correct.</strong> Authorization determines what an already-authenticated subject is allowed to access or perform.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Who is this person claiming to be?</b>: That is identification, which precedes authorization.</span><span class='qd'><b>Is this user's identity proven?</b>: That is authentication, which verifies identity before authorization.</span><span class='qd'><b>What time did the event occur?</b>: That is accounting or logging, not authorization.</span>"},{"id":"D3-088","domain":3,"obj":"3.2","diff":"hard","q":"In a MAC environment, a user with a 'Secret' clearance tries to read a document labeled 'Top Secret'. What happens and why?","options":["Access is denied only if an ACL explicitly lists the user","Access is granted because the user owns the document","Access is granted because the user is an administrator","Access is denied because the subject's clearance is below the object's classification"],"answer":3,"explain":"<strong>Correct.</strong> MAC enforces that a subject cannot read an object classified above their clearance level, so a Secret user is denied Top Secret data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Access is granted because the user owns the document</b>: Ownership does not override MAC labels.</span><span class='qd'><b>Access is granted because the user is an administrator</b>: Administrative status does not bypass mandatory clearance rules.</span><span class='qd'><b>Access is denied only if an ACL explicitly lists the user</b>: MAC decisions follow labels and clearances, not per-user ACL entries.</span>"},{"id":"D3-089","domain":3,"obj":"3.2","diff":"medium","q":"A bank requires that no single employee can both initiate a wire transfer and approve it. If one person could do both, which risk increases most?","options":["Fraud by a single insider acting alone","Loss of network availability","Weak password complexity","Physical tailgating at the entrance"],"answer":0,"explain":"<strong>Correct.</strong> Allowing one person to initiate and approve enables undetected fraud; separation of duties mitigates this insider risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Loss of network availability</b>: Availability is an uptime concern unrelated to who approves transfers.</span><span class='qd'><b>Weak password complexity</b>: Password strength is a separate authentication issue.</span><span class='qd'><b>Physical tailgating at the entrance</b>: Tailgating is a physical access risk, not a transaction approval risk.</span>"},{"id":"D3-090","domain":3,"obj":"3.2","diff":"easy","q":"Provisioning and deprovisioning are part of which broader process?","options":["Fire suppression planning","Identity and account lifecycle management","Perimeter fence maintenance","Camera footage retention"],"answer":1,"explain":"<strong>Correct.</strong> Provisioning and deprovisioning are key stages of the identity and account lifecycle, from creation through removal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fire suppression planning</b>: Fire suppression is a physical/environmental control, not account management.</span><span class='qd'><b>Perimeter fence maintenance</b>: Fence upkeep is physical security, unrelated to accounts.</span><span class='qd'><b>Camera footage retention</b>: Footage retention is a surveillance policy, not identity lifecycle.</span>"},{"id":"D3-091","domain":3,"obj":"3.2","diff":"medium","q":"A service account is used by an automated backup application to access file shares. What is the best practice for such accounts?","options":["Share its password among all IT staff","Give it full domain administrator rights for convenience","Grant only the specific permissions the service needs and monitor its use","Use the same account for interactive human logins too"],"answer":2,"explain":"<strong>Correct.</strong> Service accounts should follow least privilege, holding only the access the application requires, with monitoring of their activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Give it full domain administrator rights for convenience</b>: Excessive rights violate least privilege and increase blast radius if compromised.</span><span class='qd'><b>Share its password among all IT staff</b>: Sharing credentials destroys accountability and increases exposure.</span><span class='qd'><b>Use the same account for interactive human logins too</b>: Mixing service and human use breaks accountability and least privilege.</span>"},{"id":"D3-092","domain":3,"obj":"3.2","diff":"hard","q":"An auditor finds that access decisions in an application cannot be tied back to individual users because everyone logs in with a shared 'admin' account. Which security goal is most directly undermined?","options":["Fault tolerance","Confidentiality of data at rest","Physical deterrence","Accountability"],"answer":3,"explain":"<strong>Correct.</strong> Shared accounts make it impossible to attribute actions to a specific person, directly undermining accountability and non-repudiation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality of data at rest</b>: Shared logins affect attribution, not how stored data is encrypted.</span><span class='qd'><b>Physical deterrence</b>: Physical deterrence concerns the building perimeter, not login attribution.</span><span class='qd'><b>Fault tolerance</b>: Fault tolerance is about resilience to failures, unrelated to shared accounts.</span>"},{"id":"D3-093","domain":3,"obj":"3.2","diff":"medium","q":"Which scenario best illustrates least privilege being correctly applied?","options":["A help desk agent can reset passwords but cannot access payroll records","A new intern is given the same rights as the CIO","Every employee is placed in the domain administrators group","A contractor keeps all access after the project ends"],"answer":0,"explain":"<strong>Correct.</strong> Granting the help desk agent only password-reset rights, and nothing more, exemplifies least privilege.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A new intern is given the same rights as the CIO</b>: That grants excessive access, violating least privilege.</span><span class='qd'><b>Every employee is placed in the domain administrators group</b>: Universal admin rights are the opposite of least privilege.</span><span class='qd'><b>A contractor keeps all access after the project ends</b>: Retaining access reflects failed deprovisioning, not least privilege.</span>"},{"id":"D3-094","domain":3,"obj":"3.2","diff":"hard","q":"A company wants centralized, consistent permissions that are easy to manage as employees are hired, transferred, and terminated across hundreds of similar job functions. Which access control model is generally most efficient for this?","options":["Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)","Rule-based filtering on each device","Per-user ACLs maintained individually"],"answer":1,"explain":"<strong>Correct.</strong> RBAC ties permissions to roles, so managing many similar users becomes a matter of role assignment, scaling well across a large workforce.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary Access Control (DAC)</b>: DAC's owner-by-owner grants become inconsistent and hard to manage at scale.</span><span class='qd'><b>Rule-based filtering on each device</b>: Device-level rules do not centrally manage user job permissions.</span><span class='qd'><b>Per-user ACLs maintained individually</b>: Individually editing ACLs for hundreds of users is error-prone and inefficient.</span>"},{"id":"D3-095","domain":3,"obj":"3.2","diff":"medium","q":"What distinguishes need-to-know from least privilege, even though they are closely related?","options":["Need-to-know applies only to physical doors","They are identical terms with no difference","Need-to-know focuses on access to specific information, while least privilege concerns the minimum rights and capabilities overall","Least privilege applies only to encryption keys"],"answer":2,"explain":"<strong>Correct.</strong> Need-to-know narrows access to particular information a person must have, while least privilege limits the overall permissions and capabilities a user holds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are identical terms with no difference</b>: They are related but distinct, so this is incorrect.</span><span class='qd'><b>Need-to-know applies only to physical doors</b>: Need-to-know is about information access, not solely physical doors.</span><span class='qd'><b>Least privilege applies only to encryption keys</b>: Least privilege applies broadly to all permissions, not just keys.</span>"},{"id":"D3-096","domain":3,"obj":"3.2","diff":"medium","q":"An administrator reviews a system's logs and confirms that user 'jsmith' deleted a record at 02:14, with the action signed by jsmith's credentials. This supports which property?","options":["Redundancy","Confidentiality","Availability","Non-repudiation"],"answer":3,"explain":"<strong>Correct.</strong> A signed, logged action attributable to a specific user provides non-repudiation, preventing the user from denying it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: Confidentiality concerns preventing unauthorized disclosure, not proving who acted.</span><span class='qd'><b>Availability</b>: Availability is about systems being accessible, not attribution of actions.</span><span class='qd'><b>Redundancy</b>: Redundancy provides backup capacity, unrelated to proving an action occurred.</span>"},{"id":"D3-097","domain":3,"obj":"3.2","diff":"easy","q":"Which access control model lets the data owner decide, at their own discretion, who can read or modify a file they created?","options":["Discretionary Access Control (DAC)","Mandatory Access Control (MAC)","Role-Based Access Control (RBAC)","Attribute-Based Access Control (ABAC)"],"answer":0,"explain":"<strong>Correct.</strong> DAC gives the owner discretion to set permissions on resources they control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mandatory Access Control (MAC)</b>: MAC enforces access by labels and policy, removing owner discretion.</span><span class='qd'><b>Role-Based Access Control (RBAC)</b>: RBAC assigns access by role, not owner choice.</span><span class='qd'><b>Attribute-Based Access Control (ABAC)</b>: ABAC uses attribute policies, not owner discretion.</span>"},{"id":"D3-098","domain":3,"obj":"3.2","diff":"hard","q":"During offboarding, IT disables an employee's account but forgets a separate VPN credential the user set up. Two weeks later, the former employee logs in via VPN. Which control failure best explains this?","options":["Excessive use of separation of duties","Incomplete deprovisioning across all access paths","Overly strict least privilege","A high biometric false rejection rate"],"answer":1,"explain":"<strong>Correct.</strong> Deprovisioning must remove every access path; missing the VPN credential left an unrevoked entry point, an incomplete deprovisioning failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Excessive use of separation of duties</b>: Separation of duties is unrelated to forgetting a credential at offboarding.</span><span class='qd'><b>Overly strict least privilege</b>: Least privilege being too strict would not leave an extra credential active.</span><span class='qd'><b>A high biometric false rejection rate</b>: Biometric tuning has nothing to do with an unrevoked VPN account.</span>"},{"id":"D3-099","domain":3,"obj":"3.2","diff":"medium","q":"A company uses groups in its directory and assigns file permissions to those groups rather than to individuals. New staff are added to the relevant group on hire. This approach most closely reflects which model?","options":["Attribute-Based Access Control (ABAC)","Mandatory Access Control (MAC)","Role-Based Access Control (RBAC)","Rule-based access control"],"answer":2,"explain":"<strong>Correct.</strong> Assigning permissions to groups that represent job functions and adding users to those groups is the essence of RBAC.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mandatory Access Control (MAC)</b>: MAC relies on classification labels and clearances, not directory groups.</span><span class='qd'><b>Attribute-Based Access Control (ABAC)</b>: ABAC evaluates multiple dynamic attributes, not simple group membership.</span><span class='qd'><b>Rule-based access control</b>: Rule-based control applies conditions like time or address, not role groups.</span>"},{"id":"D3-100","domain":3,"obj":"3.2","diff":"medium","q":"Which statement best describes the relationship between authentication and authorization?","options":["Authorization replaces the need for any audit trail","Authorization always occurs before authentication","They are the same step performed once at login","Authentication verifies identity first; authorization then determines what that identity may do"],"answer":3,"explain":"<strong>Correct.</strong> A subject is first authenticated (identity proven), and then authorization decides what actions or resources that identity is permitted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Authorization always occurs before authentication</b>: The order is reversed; you must verify identity before granting rights.</span><span class='qd'><b>They are the same step performed once at login</b>: They are distinct steps with different purposes.</span><span class='qd'><b>Authorization replaces the need for any audit trail</b>: Authorization controls access but does not eliminate the need for logging.</span>"},{"id":"D4-001","domain":4,"obj":"4.1","diff":"easy","q":"Which layer of the OSI model is responsible for end-to-end delivery, segmentation, and reliable transmission using protocols such as TCP?","options":["Transport layer","Network layer","Data Link layer","Session layer"],"answer":0,"explain":"<strong>Correct.</strong> The Transport layer (Layer 4) handles end-to-end delivery, segmentation, flow control, and houses TCP and UDP.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network layer</b>: Layer 3 handles logical addressing (IP) and routing between networks, not end-to-end reliability.</span><span class='qd'><b>Data Link layer</b>: Layer 2 frames data and handles MAC addressing on the local link, not end-to-end transport.</span><span class='qd'><b>Session layer</b>: Layer 5 establishes and manages sessions/dialogs but does not perform segmentation or reliable delivery.</span>"},{"id":"D4-002","domain":4,"obj":"4.1","diff":"easy","q":"Which protocol is connectionless and does not guarantee delivery, making it suitable for streaming and DNS queries?","options":["TCP","UDP","ICMP","ARP"],"answer":1,"explain":"<strong>Correct.</strong> UDP is connectionless and best-effort, with no handshake or retransmission, which gives it low overhead for streaming and DNS lookups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TCP</b>: It is connection-oriented and guarantees delivery via a handshake, sequencing, and retransmission.</span><span class='qd'><b>ICMP</b>: It is used for diagnostics and error messaging (like ping), not as a general transport protocol.</span><span class='qd'><b>ARP</b>: It resolves IP addresses to MAC addresses on a local network, not a transport protocol.</span>"},{"id":"D4-003","domain":4,"obj":"4.1","diff":"easy","q":"What is the default well-known port for HTTPS?","options":["80","8080","443","22"],"answer":2,"explain":"<strong>Correct.</strong> HTTPS (HTTP over TLS) uses port 443 by default.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>80</b>: Port 80 is the default for unencrypted HTTP.</span><span class='qd'><b>8080</b>: Port 8080 is a common alternate HTTP/proxy port, not the HTTPS standard.</span><span class='qd'><b>22</b>: Port 22 is used by SSH for secure remote administration.</span>"},{"id":"D4-004","domain":4,"obj":"4.1","diff":"easy","q":"Which protocol automatically assigns IP addresses, subnet masks, and gateway information to hosts on a network?","options":["DNS","ARP","NAT","DHCP"],"answer":3,"explain":"<strong>Correct.</strong> DHCP (Dynamic Host Configuration Protocol) leases IP addresses and related configuration to clients automatically.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS</b>: It resolves hostnames to IP addresses, not assign addresses to clients.</span><span class='qd'><b>NAT</b>: It translates private addresses to public addresses, not assign client configuration.</span><span class='qd'><b>ARP</b>: It maps IP addresses to MAC addresses on the local segment.</span>"},{"id":"D4-005","domain":4,"obj":"4.1","diff":"easy","q":"Which of the following is a private (RFC 1918) IPv4 address range?","options":["172.16.0.0/12","8.8.8.0/24","100.64.0.0/10","169.254.0.0/16"],"answer":0,"explain":"<strong>Correct.</strong> 172.16.0.0/12 is one of the three RFC 1918 private ranges, alongside 10.0.0.0/8 and 192.168.0.0/16.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>8.8.8.0/24</b>: This is public address space (used by Google's public DNS).</span><span class='qd'><b>100.64.0.0/10</b>: This is shared/CGN space defined by RFC 6598, not RFC 1918 private space.</span><span class='qd'><b>169.254.0.0/16</b>: This is APIPA/link-local space, used when DHCP fails, not RFC 1918.</span>"},{"id":"D4-006","domain":4,"obj":"4.1","diff":"easy","q":"What does NAT (Network Address Translation) primarily accomplish?","options":["Encrypts traffic between two endpoints","Maps private internal IP addresses to one or more public addresses","Resolves domain names to IP addresses","Assigns MAC addresses to network interfaces"],"answer":1,"explain":"<strong>Correct.</strong> NAT translates private internal IP addresses to public address(es), conserving public IPs and hiding internal structure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypts traffic between two endpoints</b>: Encryption is provided by protocols like IPsec or TLS, not NAT.</span><span class='qd'><b>Resolves domain names to IP addresses</b>: That is the function of DNS.</span><span class='qd'><b>Assigns MAC addresses to network interfaces</b>: MAC addresses are burned into hardware, not assigned by NAT.</span>"},{"id":"D4-007","domain":4,"obj":"4.1","diff":"easy","q":"Which port is used by SSH for secure remote command-line access?","options":["23","21","22","25"],"answer":2,"explain":"<strong>Correct.</strong> SSH (Secure Shell) uses TCP port 22 for encrypted remote administration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>23</b>: Port 23 is Telnet, which transmits in cleartext and is insecure.</span><span class='qd'><b>21</b>: Port 21 is the FTP control channel.</span><span class='qd'><b>25</b>: Port 25 is SMTP for sending email.</span>"},{"id":"D4-008","domain":4,"obj":"4.1","diff":"easy","q":"How many bits are in an IPv6 address?","options":["32","64","256","128"],"answer":3,"explain":"<strong>Correct.</strong> IPv6 addresses are 128 bits long, written as eight groups of four hexadecimal digits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>32</b>: 32 bits is the length of an IPv4 address, not IPv6.</span><span class='qd'><b>64</b>: 64 bits is typically the prefix or interface-identifier portion, not the full address.</span><span class='qd'><b>256</b>: No standard IP version uses 256-bit addresses.</span>"},{"id":"D4-009","domain":4,"obj":"4.1","diff":"medium","q":"A technician needs to resolve a hostname to its IP address. Which protocol and default port are involved?","options":["DNS over port 53","DHCP over port 67","HTTP over port 80","LDAP over port 389"],"answer":0,"explain":"<strong>Correct.</strong> DNS performs name resolution and uses port 53 (UDP for queries, TCP for zone transfers).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP over port 67</b>: DHCP assigns addresses; it does not resolve hostnames to IPs.</span><span class='qd'><b>HTTP over port 80</b>: HTTP transfers web content and does not perform name resolution.</span><span class='qd'><b>LDAP over port 389</b>: LDAP queries directory services, not DNS name resolution.</span>"},{"id":"D4-010","domain":4,"obj":"4.1","diff":"medium","q":"Which wireless security standard is the strongest and introduces Simultaneous Authentication of Equals (SAE)?","options":["WEP","WPA3","WPA2","WPA"],"answer":1,"explain":"<strong>Correct.</strong> WPA3 is the most current and secure standard, replacing the PSK handshake with SAE to resist offline dictionary attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WEP</b>: WEP is badly broken and trivially cracked due to weak RC4/IV use.</span><span class='qd'><b>WPA</b>: WPA was an interim fix using TKIP and is now deprecated.</span><span class='qd'><b>WPA2</b>: WPA2 uses AES-CCMP and is strong but predates SAE and is vulnerable to KRACK.</span>"},{"id":"D4-011","domain":4,"obj":"4.1","diff":"medium","q":"An attacker sets up a rogue access point that mimics a legitimate corporate SSID to capture credentials. What is this attack called?","options":["ARP poisoning","Smurf attack","Evil twin","DNS tunneling"],"answer":2,"explain":"<strong>Correct.</strong> An evil twin is a rogue AP impersonating a legitimate SSID to lure clients and intercept their traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Smurf attack</b>: That is an ICMP amplification denial-of-service attack, unrelated to rogue APs.</span><span class='qd'><b>ARP poisoning</b>: That corrupts the ARP cache on a wired/local segment, not a wireless impersonation.</span><span class='qd'><b>DNS tunneling</b>: That smuggles data inside DNS queries to exfiltrate data, not a rogue AP.</span>"},{"id":"D4-012","domain":4,"obj":"4.1","diff":"medium","q":"What is the primary security benefit of placing devices in separate VLANs?","options":["It encrypts all traffic between the VLANs","It guarantees higher internet bandwidth","It provides automatic IP address assignment","It logically segments traffic and limits broadcast domains"],"answer":3,"explain":"<strong>Correct.</strong> VLANs logically segment a network at Layer 2, isolating broadcast domains and limiting which hosts can communicate directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It encrypts all traffic between the VLANs</b>: VLAN tagging does not encrypt traffic; encryption requires separate mechanisms.</span><span class='qd'><b>It provides automatic IP address assignment</b>: That is the role of DHCP, not VLANs.</span><span class='qd'><b>It guarantees higher internet bandwidth</b>: VLANs do not increase available internet bandwidth.</span>"},{"id":"D4-013","domain":4,"obj":"4.1","diff":"medium","q":"Which statement best describes the difference between the OSI model and the TCP/IP model?","options":["The OSI model has 7 layers while the TCP/IP model is commonly described with 4","The TCP/IP model has more layers than the OSI model","Both models have exactly 5 layers","The OSI model lacks a transport function"],"answer":0,"explain":"<strong>Correct.</strong> The OSI reference model defines 7 layers, while the TCP/IP model is commonly collapsed into 4 layers (Link, Internet, Transport, Application).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The TCP/IP model has more layers than the OSI model</b>: It has fewer layers, not more.</span><span class='qd'><b>Both models have exactly 5 layers</b>: Neither model is canonically 5 layers; OSI is 7 and TCP/IP is 4.</span><span class='qd'><b>The OSI model lacks a transport function</b>: OSI explicitly includes a Transport layer (Layer 4).</span>"},{"id":"D4-014","domain":4,"obj":"4.1","diff":"medium","q":"A MAC address is associated with which layer and what is its length?","options":["Layer 3, 32 bits","Layer 2, 48 bits","Layer 4, 16 bits","Layer 2, 32 bits"],"answer":1,"explain":"<strong>Correct.</strong> A MAC address operates at the Data Link layer (Layer 2) and is 48 bits long, typically shown as six hex octets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 3, 32 bits</b>: 32 bits at Layer 3 describes an IPv4 address, not a MAC.</span><span class='qd'><b>Layer 4, 16 bits</b>: 16 bits at Layer 4 describes a port number, not a MAC.</span><span class='qd'><b>Layer 2, 32 bits</b>: The layer is right but a MAC is 48 bits, not 32.</span>"},{"id":"D4-015","domain":4,"obj":"4.1","diff":"medium","q":"Which protocol resolves a known IP address to the corresponding MAC address on a local Ethernet segment?","options":["DNS","RARP","ARP","DHCP"],"answer":2,"explain":"<strong>Correct.</strong> ARP (Address Resolution Protocol) maps a known IPv4 address to its MAC address on the local link.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS</b>: DNS maps hostnames to IP addresses, not IPs to MACs.</span><span class='qd'><b>RARP</b>: RARP did the reverse (MAC to IP) and is obsolete, replaced by DHCP/BOOTP.</span><span class='qd'><b>DHCP</b>: DHCP leases IP configuration; it does not resolve IP to MAC.</span>"},{"id":"D4-016","domain":4,"obj":"4.1","diff":"hard","q":"802.1X port-based network access control relies on which three roles to authenticate a device before granting network access?","options":["Client, gateway, and proxy","Host, switch, and DNS server","Sender, receiver, and relay","Supplicant, authenticator, and authentication server"],"answer":3,"explain":"<strong>Correct.</strong> 802.1X uses a supplicant (client), an authenticator (such as a switch or AP), and an authentication server (typically RADIUS) to control port access via EAP.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Client, gateway, and proxy</b>: These are generic networking terms, not the defined 802.1X roles.</span><span class='qd'><b>Sender, receiver, and relay</b>: These describe message flow, not the 802.1X authentication architecture.</span><span class='qd'><b>Host, switch, and DNS server</b>: DNS plays no role in 802.1X authentication.</span>"},{"id":"D4-017","domain":4,"obj":"4.1","diff":"hard","q":"A host with no DHCP server available self-assigns an address in the 169.254.0.0/16 range. What mechanism produced this address?","options":["APIPA (link-local autoconfiguration)","RFC 1918 private addressing","Static NAT mapping","Multicast group assignment"],"answer":0,"explain":"<strong>Correct.</strong> APIPA (Automatic Private IP Addressing) self-assigns a 169.254.x.x link-local address when no DHCP server responds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RFC 1918 private addressing</b>: RFC 1918 covers 10/8, 172.16/12, and 192.168/16, not the 169.254 link-local range.</span><span class='qd'><b>Static NAT mapping</b>: NAT translates addresses; it does not auto-assign link-local addresses to a host.</span><span class='qd'><b>Multicast group assignment</b>: Multicast uses 224.0.0.0/4, not 169.254.0.0/16.</span>"},{"id":"D4-018","domain":4,"obj":"4.1","diff":"hard","q":"During a TCP three-way handshake, which sequence of flags correctly establishes a connection?","options":["ACK, SYN, FIN","SYN, SYN-ACK, ACK","SYN, ACK, RST","FIN, FIN-ACK, ACK"],"answer":1,"explain":"<strong>Correct.</strong> A TCP connection is established with SYN from the client, SYN-ACK from the server, and a final ACK from the client.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ACK, SYN, FIN</b>: This mixes connection setup and teardown flags out of order.</span><span class='qd'><b>SYN, ACK, RST</b>: RST resets/aborts a connection rather than completing the handshake.</span><span class='qd'><b>FIN, FIN-ACK, ACK</b>: FIN flags are used to gracefully close a connection, not open one.</span>"},{"id":"D4-019","domain":4,"obj":"4.1","diff":"medium","q":"Which port and protocol combination is used by RDP for remote graphical desktop sessions?","options":["UDP 53","TCP 443","TCP 3389","TCP 23"],"answer":2,"explain":"<strong>Correct.</strong> Remote Desktop Protocol (RDP) uses TCP port 3389 for remote graphical sessions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TCP 443</b>: Port 443 is HTTPS, not RDP.</span><span class='qd'><b>UDP 53</b>: Port 53 is DNS.</span><span class='qd'><b>TCP 23</b>: Port 23 is Telnet, a cleartext remote terminal protocol.</span>"},{"id":"D4-020","domain":4,"obj":"4.1","diff":"easy","q":"Which port does SMTP use to send email between mail servers?","options":["110","143","993","25"],"answer":3,"explain":"<strong>Correct.</strong> SMTP (Simple Mail Transfer Protocol) uses port 25 for server-to-server mail delivery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>110</b>: Port 110 is POP3 for retrieving mail.</span><span class='qd'><b>143</b>: Port 143 is IMAP for retrieving mail.</span><span class='qd'><b>993</b>: Port 993 is IMAP over TLS/SSL.</span>"},{"id":"D4-021","domain":4,"obj":"4.2","diff":"easy","q":"Which type of malware can replicate itself and spread across a network without any user interaction?","options":["Worm","Virus","Trojan","Spyware"],"answer":0,"explain":"<strong>Correct.</strong> A worm self-replicates and propagates across networks on its own, without needing a host file or user action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Virus</b>: A virus requires a host file and typically user action to execute and spread.</span><span class='qd'><b>Trojan</b>: A trojan masquerades as legitimate software and relies on the user to run it.</span><span class='qd'><b>Spyware</b>: Spyware covertly gathers information; it does not self-replicate across networks.</span>"},{"id":"D4-022","domain":4,"obj":"4.2","diff":"easy","q":"Which malware type encrypts a victim's files and demands payment for the decryption key?","options":["Rootkit","Ransomware","Adware","Logic bomb"],"answer":1,"explain":"<strong>Correct.</strong> Ransomware encrypts a victim's data and demands a ransom in exchange for the decryption key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rootkit</b>: A rootkit hides its presence and maintains privileged access rather than encrypting files for ransom.</span><span class='qd'><b>Adware</b>: Adware displays unwanted advertising and does not encrypt files.</span><span class='qd'><b>Logic bomb</b>: A logic bomb triggers a malicious action on a condition but is not defined by ransom encryption.</span>"},{"id":"D4-023","domain":4,"obj":"4.2","diff":"easy","q":"What is malware that disguises itself as legitimate software to trick a user into installing it?","options":["Worm","Botnet","Trojan","Rootkit"],"answer":2,"explain":"<strong>Correct.</strong> A trojan (Trojan horse) appears to be legitimate software but carries a hidden malicious payload that runs when installed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: A worm self-propagates over networks and does not rely on disguise to be installed.</span><span class='qd'><b>Botnet</b>: A botnet is a network of compromised hosts, not a disguised installer.</span><span class='qd'><b>Rootkit</b>: A rootkit conceals activity at a low level rather than masquerading as an app the user installs.</span>"},{"id":"D4-024","domain":4,"obj":"4.2","diff":"easy","q":"A group of compromised computers remotely controlled by an attacker to launch coordinated attacks is known as a:","options":["Honeypot","Demilitarized zone","Sandbox","Botnet"],"answer":3,"explain":"<strong>Correct.</strong> A botnet is a collection of compromised hosts (bots) controlled by an attacker, often used for DDoS or spam.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Honeypot</b>: A honeypot is a decoy system used to attract and study attackers, not attacker-controlled hosts.</span><span class='qd'><b>Sandbox</b>: A sandbox is an isolated environment for safely running untrusted code.</span><span class='qd'><b>Demilitarized zone</b>: A DMZ is a network segment exposing services, not a group of compromised hosts.</span>"},{"id":"D4-025","domain":4,"obj":"4.2","diff":"medium","q":"An attacker positions themselves between two communicating parties to intercept and possibly alter traffic. What category of attack is this?","options":["On-path (man-in-the-middle)","Buffer overflow","Privilege escalation","SQL injection"],"answer":0,"explain":"<strong>Correct.</strong> An on-path (man-in-the-middle) attack inserts the attacker between two parties to intercept or modify traffic in transit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buffer overflow</b>: That exploits memory handling in a program, not interception between two parties.</span><span class='qd'><b>Privilege escalation</b>: That gains higher access rights on a system rather than intercepting communications.</span><span class='qd'><b>SQL injection</b>: That injects malicious queries into a database, not a network interception.</span>"},{"id":"D4-026","domain":4,"obj":"4.2","diff":"medium","q":"Which malware type provides an attacker with covert, persistent, often privileged remote control over an infected host?","options":["Adware","RAT (Remote Access Trojan)","Keylogger only","Macro virus"],"answer":1,"explain":"<strong>Correct.</strong> A Remote Access Trojan (RAT) gives the attacker covert remote control of the infected machine, often with full privileges.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adware</b>: Adware serves ads and does not provide remote control of the host.</span><span class='qd'><b>Keylogger only</b>: A keylogger records keystrokes but does not by itself grant remote interactive control.</span><span class='qd'><b>Macro virus</b>: A macro virus spreads through document macros and is not defined by remote control capability.</span>"},{"id":"D4-027","domain":4,"obj":"4.2","diff":"medium","q":"A denial-of-service attack launched simultaneously from thousands of distributed compromised hosts is specifically called a:","options":["DoS","Replay attack","DDoS","Phishing campaign"],"answer":2,"explain":"<strong>Correct.</strong> A Distributed Denial-of-Service (DDoS) attack overwhelms a target using many distributed sources, typically a botnet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DoS</b>: A plain DoS comes from a single source, not thousands of distributed hosts.</span><span class='qd'><b>Replay attack</b>: A replay reuses captured legitimate traffic, not a flood from many hosts.</span><span class='qd'><b>Phishing campaign</b>: Phishing tricks users into revealing information; it is not a flooding attack.</span>"},{"id":"D4-028","domain":4,"obj":"4.2","diff":"medium","q":"Capturing and analyzing network packets as they traverse a network, often to steal cleartext credentials, is known as:","options":["Fuzzing","Pharming","Spoofing","Sniffing"],"answer":3,"explain":"<strong>Correct.</strong> Sniffing is the passive capture and inspection of network traffic, which can expose cleartext credentials and data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pharming</b>: Pharming redirects users to fraudulent sites by poisoning DNS or hosts files.</span><span class='qd'><b>Spoofing</b>: Spoofing forges a source identity such as an IP or MAC address.</span><span class='qd'><b>Fuzzing</b>: Fuzzing sends malformed input to find software vulnerabilities, not capture traffic.</span>"},{"id":"D4-029","domain":4,"obj":"4.2","diff":"medium","q":"Which malware is specifically designed to conceal its presence and that of other malware, often by subverting the operating system at a low level?","options":["Rootkit","Worm","Trojan","Ransomware"],"answer":0,"explain":"<strong>Correct.</strong> A rootkit hides itself and other malicious components, frequently by hooking or modifying low-level OS functions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: A worm focuses on self-propagation, not stealth concealment of other malware.</span><span class='qd'><b>Trojan</b>: A trojan relies on disguise to be installed but is not defined by deep OS-level hiding.</span><span class='qd'><b>Ransomware</b>: Ransomware encrypts data for extortion and is intentionally visible to the victim.</span>"},{"id":"D4-030","domain":4,"obj":"4.2","diff":"hard","q":"An attacker recovers a cryptographic key by measuring the device's power consumption and electromagnetic emissions during operations. What class of attack is this?","options":["On-path attack","Side-channel attack","Dictionary attack","Smurf attack"],"answer":1,"explain":"<strong>Correct.</strong> A side-channel attack derives secrets from physical leakage such as power draw, timing, or electromagnetic emissions rather than breaking the algorithm directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>On-path attack</b>: That intercepts network communications, not physical emanations.</span><span class='qd'><b>Dictionary attack</b>: That guesses passwords from a wordlist, not via physical measurements.</span><span class='qd'><b>Smurf attack</b>: That is an ICMP amplification flood, unrelated to leakage analysis.</span>"},{"id":"D4-031","domain":4,"obj":"4.2","diff":"hard","q":"Malware lies dormant on a system and executes its destructive payload only when a specific condition, such as a particular date, is met. What is it?","options":["Worm","Botnet","Logic bomb","Spyware"],"answer":2,"explain":"<strong>Correct.</strong> A logic bomb stays inactive until a defined trigger condition (a date, event, or action) is met, then executes its payload.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Botnet</b>: A botnet is a network of remotely controlled hosts, not condition-triggered dormant code.</span><span class='qd'><b>Worm</b>: A worm actively self-propagates rather than waiting for a trigger.</span><span class='qd'><b>Spyware</b>: Spyware continuously gathers information; it is not defined by a delayed trigger.</span>"},{"id":"D4-032","domain":4,"obj":"4.2","diff":"hard","q":"During an on-path attack on a switched LAN, an attacker sends forged ARP replies to associate their MAC with the default gateway's IP. What is this technique called?","options":["Session hijacking via cookies","DNS spoofing","Port scanning","ARP poisoning"],"answer":3,"explain":"<strong>Correct.</strong> ARP poisoning (ARP spoofing) sends forged ARP replies so victims send traffic to the attacker's MAC, enabling interception on a switched LAN.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS spoofing</b>: That falsifies name-resolution responses rather than manipulating ARP caches.</span><span class='qd'><b>Port scanning</b>: That enumerates open ports and does not redirect traffic via forged ARP.</span><span class='qd'><b>Session hijacking via cookies</b>: That steals or forges session tokens at the application layer, not Layer 2 ARP.</span>"},{"id":"D4-033","domain":4,"obj":"4.2","diff":"easy","q":"Which malware covertly monitors user activity, such as keystrokes and browsing habits, and reports it to a third party?","options":["Spyware","Worm","Trojan","Rootkit"],"answer":0,"explain":"<strong>Correct.</strong> Spyware secretly observes user activity and exfiltrates the collected data to a third party.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: A worm self-replicates across networks rather than covertly monitoring a user.</span><span class='qd'><b>Trojan</b>: A trojan is a delivery disguise; monitoring is a payload, not the defining trait.</span><span class='qd'><b>Rootkit</b>: A rootkit hides presence and maintains access rather than reporting user activity.</span>"},{"id":"D4-034","domain":4,"obj":"4.2","diff":"medium","q":"Spoofing the source IP address of a packet is most directly used by an attacker to:","options":["Encrypt the payload","Hide the true origin or impersonate a trusted host","Compress the traffic","Increase throughput"],"answer":1,"explain":"<strong>Correct.</strong> IP spoofing forges the source address to conceal the real origin or impersonate a trusted host, aiding attacks like reflection/amplification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt the payload</b>: Spoofing changes addressing, not the confidentiality of the payload.</span><span class='qd'><b>Compress the traffic</b>: Spoofing has nothing to do with reducing data size.</span><span class='qd'><b>Increase throughput</b>: Forging a source address does not improve performance.</span>"},{"id":"D4-035","domain":4,"obj":"4.3","diff":"easy","q":"Which device monitors network traffic and actively blocks detected malicious activity in real time?","options":["IDS","Hub","IPS","Modem"],"answer":2,"explain":"<strong>Correct.</strong> An Intrusion Prevention System (IPS) sits inline and can actively block or drop traffic it identifies as malicious.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IDS</b>: An IDS only detects and alerts; it does not block traffic by itself.</span><span class='qd'><b>Hub</b>: A hub simply repeats electrical signals to all ports with no security function.</span><span class='qd'><b>Modem</b>: A modem modulates/demodulates signals for connectivity and does not inspect for threats.</span>"},{"id":"D4-036","domain":4,"obj":"4.3","diff":"easy","q":"What is the main difference between an IDS and an IPS?","options":["An IDS assigns IP addresses while an IPS resolves names","An IDS encrypts traffic while an IPS does not","An IPS only works on wireless networks","An IDS detects and alerts, while an IPS can also actively block traffic"],"answer":3,"explain":"<strong>Correct.</strong> An IDS is passive and generates alerts, whereas an IPS is inline and can actively block or drop malicious traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An IDS encrypts traffic while an IPS does not</b>: Neither device is defined by encrypting traffic.</span><span class='qd'><b>An IPS only works on wireless networks</b>: An IPS works on wired and wireless networks alike.</span><span class='qd'><b>An IDS assigns IP addresses while an IPS resolves names</b>: Those are DHCP and DNS functions, not IDS/IPS.</span>"},{"id":"D4-037","domain":4,"obj":"4.3","diff":"easy","q":"A VPN provides which primary security benefit when users connect over the public internet?","options":["An encrypted tunnel protecting data in transit","Faster physical cabling","Automatic malware removal","Increased screen resolution"],"answer":0,"explain":"<strong>Correct.</strong> A VPN creates an encrypted tunnel that protects the confidentiality and integrity of data traversing untrusted networks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster physical cabling</b>: A VPN is software-based encryption and does not change physical media.</span><span class='qd'><b>Automatic malware removal</b>: Malware removal is the job of antivirus/EDR, not a VPN.</span><span class='qd'><b>Increased screen resolution</b>: This is unrelated to networking security entirely.</span>"},{"id":"D4-038","domain":4,"obj":"4.3","diff":"easy","q":"In the cloud shared responsibility model, the cloud provider is always responsible for:","options":["Configuring customer firewall rules","Security of the underlying physical infrastructure","Managing customer user passwords","Classifying the customer's data"],"answer":1,"explain":"<strong>Correct.</strong> Under the shared responsibility model, the provider secures the underlying physical infrastructure (facilities, hardware, and the hypervisor layer).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Configuring customer firewall rules</b>: Customer-defined security configurations remain the customer's responsibility.</span><span class='qd'><b>Managing customer user passwords</b>: Identity and credential management is typically the customer's duty.</span><span class='qd'><b>Classifying the customer's data</b>: Data classification and ownership stay with the customer.</span>"},{"id":"D4-039","domain":4,"obj":"4.3","diff":"medium","q":"Which firewall type tracks the state of active connections and makes filtering decisions based on the context of traffic flows?","options":["Packet-filtering firewall","Repeater","Stateful inspection firewall","Layer 2 hub"],"answer":2,"explain":"<strong>Correct.</strong> A stateful inspection firewall maintains a state table of active connections and allows return traffic that matches established sessions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Packet-filtering firewall</b>: A basic packet filter evaluates each packet independently without tracking connection state.</span><span class='qd'><b>Repeater</b>: A repeater regenerates signals and performs no filtering.</span><span class='qd'><b>Layer 2 hub</b>: A hub forwards all traffic to all ports with no inspection.</span>"},{"id":"D4-040","domain":4,"obj":"4.3","diff":"medium","q":"A WAF (Web Application Firewall) is specifically designed to protect against attacks targeting:","options":["Layer 2 switching loops","Power supply failures","Physical theft of servers","Web application vulnerabilities such as SQL injection and XSS"],"answer":3,"explain":"<strong>Correct.</strong> A WAF inspects HTTP/HTTPS traffic to block web application attacks such as SQL injection and cross-site scripting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 2 switching loops</b>: Those are handled by spanning tree protocols, not a WAF.</span><span class='qd'><b>Physical theft of servers</b>: That is addressed by physical security controls, not a WAF.</span><span class='qd'><b>Power supply failures</b>: Those are mitigated by UPS and redundant power, not a WAF.</span>"},{"id":"D4-041","domain":4,"obj":"4.3","diff":"medium","q":"A screened subnet (DMZ) is used to:","options":["Host internet-facing services in a segment isolated from the internal LAN","Encrypt all internal email","Replace the need for DNS","Provide wireless authentication"],"answer":0,"explain":"<strong>Correct.</strong> A screened subnet (DMZ) places internet-facing services in a buffer segment isolated from the trusted internal network, limiting exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt all internal email</b>: Email encryption is a separate control unrelated to DMZ placement.</span><span class='qd'><b>Replace the need for DNS</b>: A DMZ does not provide name resolution.</span><span class='qd'><b>Provide wireless authentication</b>: Wireless authentication is handled by 802.1X/WPA, not a DMZ.</span>"},{"id":"D4-042","domain":4,"obj":"4.3","diff":"medium","q":"Network Access Control (NAC) primarily enforces security by:","options":["Encrypting all stored data","Checking a device's compliance posture before allowing it onto the network","Assigning domain names","Generating digital certificates for websites"],"answer":1,"explain":"<strong>Correct.</strong> NAC evaluates a device's identity and health/compliance posture and grants, limits, or denies network access accordingly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting all stored data</b>: Data-at-rest encryption is a separate control, not NAC's function.</span><span class='qd'><b>Assigning domain names</b>: That is DNS, not NAC.</span><span class='qd'><b>Generating digital certificates for websites</b>: That is the role of a certificate authority/PKI.</span>"},{"id":"D4-043","domain":4,"obj":"4.3","diff":"medium","q":"Which cloud service model gives the customer the most control, providing virtualized compute, storage, and networking that the customer manages?","options":["SaaS","PaaS","IaaS","FaaS"],"answer":2,"explain":"<strong>Correct.</strong> Infrastructure as a Service (IaaS) supplies fundamental compute, storage, and networking, leaving OS, runtime, and applications under customer control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SaaS</b>: SaaS delivers a finished application and gives the customer the least infrastructure control.</span><span class='qd'><b>PaaS</b>: PaaS provides a managed platform for app development, abstracting away the underlying infrastructure.</span><span class='qd'><b>FaaS</b>: FaaS runs event-driven functions and hides almost all infrastructure from the customer.</span>"},{"id":"D4-044","domain":4,"obj":"4.3","diff":"medium","q":"Endpoint Detection and Response (EDR) improves upon traditional antivirus primarily by:","options":["Only using signature matching","Encrypting the boot sector","Eliminating the need for any firewall","Providing continuous monitoring, behavioral detection, and response capabilities on endpoints"],"answer":3,"explain":"<strong>Correct.</strong> EDR continuously monitors endpoint behavior, detects suspicious activity beyond signatures, and supports investigation and automated response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only using signature matching</b>: Signature-only matching is the limitation of traditional antivirus that EDR moves beyond.</span><span class='qd'><b>Eliminating the need for any firewall</b>: EDR complements firewalls but does not replace network controls.</span><span class='qd'><b>Encrypting the boot sector</b>: That is a function of full-disk encryption, not EDR.</span>"},{"id":"D4-045","domain":4,"obj":"4.3","diff":"hard","q":"An IDS that detects threats by comparing observed traffic to a database of known attack patterns is using which detection method?","options":["Signature-based detection","Anomaly-based detection","Heuristic sandboxing only","Geofencing"],"answer":0,"explain":"<strong>Correct.</strong> Signature-based detection matches traffic against a database of known attack patterns, which is effective for known threats but misses novel ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Anomaly-based detection</b>: Anomaly detection flags deviations from a learned baseline rather than matching known signatures.</span><span class='qd'><b>Heuristic sandboxing only</b>: Sandboxing executes suspect code in isolation; it is not pattern matching against signatures.</span><span class='qd'><b>Geofencing</b>: Geofencing restricts access by geographic location, unrelated to traffic pattern matching.</span>"},{"id":"D4-046","domain":4,"obj":"4.3","diff":"hard","q":"Which VPN technology operates at the network layer and is commonly used for site-to-site tunnels with encryption and authentication?","options":["TLS","IPsec","SSH","Telnet"],"answer":1,"explain":"<strong>Correct.</strong> IPsec operates at the network layer and provides encryption and authentication, making it well suited for site-to-site VPN tunnels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TLS</b>: TLS operates above the transport layer and is typically used for clientless/SSL VPNs and HTTPS, not classic site-to-site network-layer tunnels.</span><span class='qd'><b>SSH</b>: SSH provides secure shell/tunneling at the application layer, not a network-layer site-to-site VPN standard.</span><span class='qd'><b>Telnet</b>: Telnet is an unencrypted remote terminal protocol and provides no VPN capability.</span>"},{"id":"D4-047","domain":4,"obj":"4.3","diff":"hard","q":"Why are IoT devices frequently considered high-risk on enterprise networks?","options":["They always use strong encryption by default","They cannot connect to networks","They often ship with weak defaults, limited patching, and broad network access","They are immune to malware"],"answer":2,"explain":"<strong>Correct.</strong> IoT devices commonly have default credentials, infrequent or no patches, and unsegmented network access, making them attractive, hard-to-secure targets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They always use strong encryption by default</b>: Many IoT devices use weak or no encryption out of the box.</span><span class='qd'><b>They cannot connect to networks</b>: Connectivity is the defining feature of IoT devices.</span><span class='qd'><b>They are immune to malware</b>: IoT devices are frequent malware and botnet targets, such as Mirai.</span>"},{"id":"D4-048","domain":4,"obj":"4.3","diff":"medium","q":"Network segmentation improves security primarily by:","options":["Increasing the broadcast domain size","Disabling all logging","Removing the need for authentication","Limiting the lateral movement of an attacker between systems"],"answer":3,"explain":"<strong>Correct.</strong> Segmentation divides a network into zones so that a compromise in one area cannot easily spread laterally to others.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the broadcast domain size</b>: Segmentation reduces broadcast domains; it does not enlarge them.</span><span class='qd'><b>Removing the need for authentication</b>: Segmentation complements, but never replaces, authentication.</span><span class='qd'><b>Disabling all logging</b>: Segmentation has nothing to do with turning off logging, which remains essential.</span>"},{"id":"D4-049","domain":4,"obj":"4.3","diff":"medium","q":"Which cloud deployment model is dedicated to a single organization and offers the greatest control over security and resources?","options":["Private cloud","Public cloud","Community cloud","Hybrid cloud"],"answer":0,"explain":"<strong>Correct.</strong> A private cloud is provisioned for exclusive use by a single organization, offering the greatest control over security and resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public cloud</b>: A public cloud shares multi-tenant infrastructure across many customers, with less direct control.</span><span class='qd'><b>Community cloud</b>: A community cloud is shared among organizations with common concerns, not a single org.</span><span class='qd'><b>Hybrid cloud</b>: A hybrid cloud combines public and private models rather than being dedicated to one organization.</span>"},{"id":"D4-050","domain":4,"obj":"4.3","diff":"hard","q":"A Next-Generation Firewall (NGFW) extends traditional firewall capabilities by adding which feature set?","options":["Only basic port and protocol filtering","Application awareness, deep packet inspection, and integrated intrusion prevention","Exclusively wireless signal boosting","DHCP address leasing only"],"answer":1,"explain":"<strong>Correct.</strong> An NGFW adds application-layer awareness, deep packet inspection, and integrated IPS and threat intelligence beyond simple port/protocol filtering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only basic port and protocol filtering</b>: That describes a traditional firewall, exactly what an NGFW improves upon.</span><span class='qd'><b>Exclusively wireless signal boosting</b>: Signal boosting is a wireless function, not a firewall capability.</span><span class='qd'><b>DHCP address leasing only</b>: Address leasing is a DHCP function, not the defining feature of an NGFW.</span>"},{"id":"D4-051","domain":4,"obj":"4.1","diff":"easy","q":"Which layer of the OSI model is responsible for logical addressing and routing of packets between networks?","options":["Layer 2 (Data Link)","Layer 4 (Transport)","Layer 3 (Network)","Layer 7 (Application)"],"answer":2,"explain":"<strong>Correct.</strong> Layer 3 (Network) handles logical addressing such as IP and routes packets between separate networks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 2 (Data Link)</b>: It uses physical MAC addresses and moves frames within a single local segment, not between networks.</span><span class='qd'><b>Layer 4 (Transport)</b>: It manages end-to-end delivery, segmentation, and ports, not network routing.</span><span class='qd'><b>Layer 7 (Application)</b>: It provides services directly to applications and has no addressing or routing role.</span>"},{"id":"D4-052","domain":4,"obj":"4.1","diff":"easy","q":"A protocol needs guaranteed, ordered delivery with retransmission of lost data. Which transport protocol fits this requirement?","options":["UDP","ICMP","ARP","TCP"],"answer":3,"explain":"<strong>Correct.</strong> TCP is connection-oriented and provides acknowledgments, sequencing, and retransmission for reliable, ordered delivery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>UDP</b>: It is connectionless and best-effort, offering no guaranteed delivery or ordering.</span><span class='qd'><b>ICMP</b>: It is used for diagnostics and error messaging, not data stream delivery.</span><span class='qd'><b>ARP</b>: It resolves IP addresses to MAC addresses and does not transport application data.</span>"},{"id":"D4-053","domain":4,"obj":"4.1","diff":"easy","q":"Which port is the default for HTTPS traffic?","options":["443","80","21","3389"],"answer":0,"explain":"<strong>Correct.</strong> HTTPS, which is HTTP secured with TLS, uses TCP port 443 by default.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>80</b>: This is the default for unencrypted HTTP, not HTTPS.</span><span class='qd'><b>21</b>: This is the FTP control port for file transfer.</span><span class='qd'><b>3389</b>: This is used by Remote Desktop Protocol (RDP).</span>"},{"id":"D4-054","domain":4,"obj":"4.1","diff":"medium","q":"An administrator wants to allow many internal hosts using private addresses to share a single public IP for Internet access. Which technology accomplishes this?","options":["DHCP","NAT","DNS","ARP"],"answer":1,"explain":"<strong>Correct.</strong> Network Address Translation (NAT) maps multiple private addresses to one public address for outbound Internet access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP</b>: It automatically assigns IP configuration to hosts but does not translate addresses.</span><span class='qd'><b>DNS</b>: It resolves hostnames to IP addresses and performs no address translation.</span><span class='qd'><b>ARP</b>: It maps IP addresses to MAC addresses on a local segment.</span>"},{"id":"D4-055","domain":4,"obj":"4.1","diff":"medium","q":"A workstation boots and automatically receives its IP address, subnet mask, gateway, and DNS server. Which protocol provided this?","options":["DNS","ARP","DHCP","NAT"],"answer":2,"explain":"<strong>Correct.</strong> DHCP (Dynamic Host Configuration Protocol) automatically leases IP configuration including address, mask, gateway, and DNS to clients.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS</b>: It resolves names to addresses but does not assign host configuration.</span><span class='qd'><b>ARP</b>: It resolves IP to MAC addresses locally and does not assign IP settings.</span><span class='qd'><b>NAT</b>: It translates addresses at the gateway and does not configure clients.</span>"},{"id":"D4-056","domain":4,"obj":"4.1","diff":"easy","q":"Which protocol resolves a known IPv4 address to its corresponding hardware MAC address on a local network?","options":["DNS","ICMP","DHCP","ARP"],"answer":3,"explain":"<strong>Correct.</strong> ARP (Address Resolution Protocol) maps a known IPv4 address to the MAC address needed for local frame delivery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS</b>: It maps hostnames to IP addresses, not IP to MAC.</span><span class='qd'><b>DHCP</b>: It assigns IP configuration and does not resolve MAC addresses.</span><span class='qd'><b>ICMP</b>: It carries diagnostic and error messages such as ping replies.</span>"},{"id":"D4-057","domain":4,"obj":"4.1","diff":"medium","q":"Which of the following is a valid private IPv4 address range defined in RFC 1918?","options":["192.168.0.0/16","172.32.0.0/12","11.0.0.0/8","169.254.0.0/16"],"answer":0,"explain":"<strong>Correct.</strong> 192.168.0.0/16 is one of the three RFC 1918 private ranges reserved for internal use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>172.32.0.0/12</b>: The private range is 172.16.0.0/12; 172.32 falls outside it and is public.</span><span class='qd'><b>11.0.0.0/8</b>: The private range is 10.0.0.0/8; 11.x.x.x is a routable public block.</span><span class='qd'><b>169.254.0.0/16</b>: This is the APIPA link-local range, not an RFC 1918 private range.</span>"},{"id":"D4-058","domain":4,"obj":"4.1","diff":"medium","q":"An attacker sets up a rogue wireless access point that broadcasts the same SSID as a legitimate corporate network to lure users into connecting. What is this attack called?","options":["War driving","Evil twin","Bluejacking","Smurf attack"],"answer":1,"explain":"<strong>Correct.</strong> An evil twin is a malicious access point impersonating a legitimate SSID to intercept users' traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>War driving</b>: This is the act of searching for wireless networks while moving, not impersonating one.</span><span class='qd'><b>Bluejacking</b>: This sends unsolicited messages over Bluetooth, unrelated to rogue Wi-Fi access points.</span><span class='qd'><b>Smurf attack</b>: This is an ICMP amplification denial-of-service attack, not a wireless impersonation.</span>"},{"id":"D4-059","domain":4,"obj":"4.1","diff":"hard","q":"A security team is upgrading wireless encryption and wants the strongest standard that uses Simultaneous Authentication of Equals (SAE) to resist offline dictionary attacks. Which should they choose?","options":["WEP","WPA","WPA3","WPA2-PSK"],"answer":2,"explain":"<strong>Correct.</strong> WPA3 introduces SAE (Dragonfly handshake), which resists offline dictionary attacks even with weak passphrases.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WEP</b>: It uses broken RC4 with weak IVs and is trivially cracked, offering no SAE.</span><span class='qd'><b>WPA</b>: It improved on WEP with TKIP but remains deprecated and lacks SAE.</span><span class='qd'><b>WPA2-PSK</b>: It uses a four-way handshake vulnerable to offline cracking and does not implement SAE.</span>"},{"id":"D4-060","domain":4,"obj":"4.1","diff":"medium","q":"Which port and protocol combination is used by SSH for secure remote command-line access?","options":["TCP 25","TCP 23","UDP 53","TCP 22"],"answer":3,"explain":"<strong>Correct.</strong> SSH provides encrypted remote shell access over TCP port 22.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TCP 23</b>: This is Telnet, which transmits credentials in cleartext and is insecure.</span><span class='qd'><b>UDP 53</b>: This is DNS query traffic, not remote shell access.</span><span class='qd'><b>TCP 25</b>: This is SMTP for sending email, not remote administration.</span>"},{"id":"D4-061","domain":4,"obj":"4.1","diff":"hard","q":"An organization deploys 802.1X on its wired switches. What primary security benefit does this provide?","options":["It authenticates devices before granting network port access","It encrypts all data at rest on the switch","It assigns dynamic IP addresses to clients","It translates private addresses to public ones"],"answer":0,"explain":"<strong>Correct.</strong> 802.1X is a port-based network access control standard that authenticates a device or user before the switch port is opened for traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It encrypts all data at rest on the switch</b>: 802.1X governs access authentication, not storage encryption.</span><span class='qd'><b>It assigns dynamic IP addresses to clients</b>: That is the function of DHCP, not 802.1X.</span><span class='qd'><b>It translates private addresses to public ones</b>: That is NAT, unrelated to port authentication.</span>"},{"id":"D4-062","domain":4,"obj":"4.1","diff":"easy","q":"How many bits are in an IPv4 address?","options":["64","32","128","48"],"answer":1,"explain":"<strong>Correct.</strong> An IPv4 address is 32 bits long, written as four 8-bit octets in dotted-decimal notation (for example, 192.168.1.1).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>64</b>: 64 bits matches neither IPv4 nor a standard IPv6 address; it is not an IP address length.</span><span class='qd'><b>128</b>: 128 bits is the length of an IPv6 address, not IPv4.</span><span class='qd'><b>48</b>: 48 bits is the length of a MAC (hardware) address, not an IPv4 address.</span>"},{"id":"D4-063","domain":4,"obj":"4.1","diff":"medium","q":"A network engineer wants to logically separate the finance and engineering departments on the same physical switch so their traffic is isolated. Which technology is most appropriate?","options":["VPN","NAT","VLAN","DMZ"],"answer":2,"explain":"<strong>Correct.</strong> A VLAN logically segments a single physical switch into separate broadcast domains, isolating department traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NAT</b>: It translates addresses for Internet access and does not segment internal traffic.</span><span class='qd'><b>VPN</b>: It creates encrypted tunnels across untrusted networks, not local switch segmentation.</span><span class='qd'><b>DMZ</b>: It is a perimeter zone for public-facing servers, not internal department isolation.</span>"},{"id":"D4-064","domain":4,"obj":"4.1","diff":"medium","q":"Which statement best describes the difference between the OSI and TCP/IP models?","options":["OSI has 4 layers and TCP/IP has 7","TCP/IP lacks an application layer entirely","They are identical in layer count and naming","OSI has 7 layers while TCP/IP condenses functions into 4 layers"],"answer":3,"explain":"<strong>Correct.</strong> The OSI model defines 7 layers, while the TCP/IP model groups similar functions into 4 layers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>OSI has 4 layers and TCP/IP has 7</b>: The counts are reversed; OSI has 7 and TCP/IP has 4.</span><span class='qd'><b>They are identical in layer count and naming</b>: They differ in both number and grouping of layers.</span><span class='qd'><b>TCP/IP lacks an application layer entirely</b>: TCP/IP does include an application layer that combines OSI layers 5 through 7.</span>"},{"id":"D4-065","domain":4,"obj":"4.1","diff":"hard","q":"A host is configured with the address 169.254.12.7 and cannot reach other subnets. What is the most likely cause?","options":["The DHCP server was unreachable and APIPA self-assigned an address","The host received a static public IP","NAT is misconfigured on the router","The host is using IPv6 only"],"answer":0,"explain":"<strong>Correct.</strong> The 169.254.0.0/16 range is APIPA, automatically self-assigned when a host fails to reach a DHCP server, leaving it unable to route off-subnet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The host received a static public IP</b>: 169.254 is a link-local range, not a routable public address.</span><span class='qd'><b>NAT is misconfigured on the router</b>: An APIPA address indicates no DHCP lease, a more direct cause than NAT.</span><span class='qd'><b>The host is using IPv6 only</b>: 169.254.12.7 is an IPv4 address, so the host is not IPv6 only.</span>"},{"id":"D4-066","domain":4,"obj":"4.1","diff":"easy","q":"Which port does DNS primarily use for standard name resolution queries?","options":["Port 80","Port 53","Port 443","Port 25"],"answer":1,"explain":"<strong>Correct.</strong> DNS uses port 53, primarily over UDP for queries and TCP for larger transfers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Port 80</b>: This is used by HTTP web traffic.</span><span class='qd'><b>Port 443</b>: This is used by HTTPS encrypted web traffic.</span><span class='qd'><b>Port 25</b>: This is used by SMTP for email transmission.</span>"},{"id":"D4-067","domain":4,"obj":"4.1","diff":"medium","q":"An application requires the lowest latency and can tolerate occasional packet loss, such as live video streaming. Which transport protocol is generally preferred?","options":["TCP","FTP","UDP","SMTP"],"answer":2,"explain":"<strong>Correct.</strong> UDP's connectionless, low-overhead design favors speed over reliability, making it ideal for latency-sensitive streaming.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TCP</b>: Its acknowledgments and retransmissions add latency that harms real-time streaming.</span><span class='qd'><b>FTP</b>: This is an application protocol for file transfer, not a transport protocol.</span><span class='qd'><b>SMTP</b>: This is an application protocol for email, not a transport choice for streaming.</span>"},{"id":"D4-068","domain":4,"obj":"4.1","diff":"medium","q":"A technician needs to determine the network and host portions of an IPv4 address. Which value defines this boundary?","options":["The default gateway","The DNS suffix","The MAC address","The subnet mask"],"answer":3,"explain":"<strong>Correct.</strong> The subnet mask marks which bits identify the network versus the host portion of an IPv4 address.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The default gateway</b>: This is the router used to leave the subnet, not the boundary definition.</span><span class='qd'><b>The MAC address</b>: This is a layer 2 hardware identifier unrelated to IP subnetting.</span><span class='qd'><b>The DNS suffix</b>: This appends a domain name for resolution and has no bearing on subnet boundaries.</span>"},{"id":"D4-069","domain":4,"obj":"4.1","diff":"easy","q":"Which port is associated with the Remote Desktop Protocol (RDP)?","options":["3389","22","23","443"],"answer":0,"explain":"<strong>Correct.</strong> RDP uses TCP port 3389 for remote graphical desktop sessions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>22</b>: This is used by SSH for secure command-line access.</span><span class='qd'><b>23</b>: This is used by Telnet for unencrypted remote terminals.</span><span class='qd'><b>443</b>: This is used by HTTPS for secure web traffic.</span>"},{"id":"D4-070","domain":4,"obj":"4.1","diff":"hard","q":"During a security review, an analyst notes that Telnet is permitted to network devices. Why is this a concern, and what is the recommended replacement?","options":["Telnet is slow; replace with FTP","Telnet sends credentials in cleartext; replace with SSH","Telnet uses too much bandwidth; replace with SNMP","Telnet only supports IPv6; replace with HTTP"],"answer":1,"explain":"<strong>Correct.</strong> Telnet transmits usernames and passwords in cleartext, so SSH, which encrypts the session, is the recommended replacement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Telnet is slow; replace with FTP</b>: The issue is cleartext exposure, and FTP is a file transfer protocol, not a shell replacement.</span><span class='qd'><b>Telnet uses too much bandwidth; replace with SNMP</b>: Bandwidth is not the concern, and SNMP is for device monitoring, not interactive sessions.</span><span class='qd'><b>Telnet only supports IPv6; replace with HTTP</b>: Telnet works on IPv4 and IPv6, and HTTP is for web traffic, not remote administration.</span>"},{"id":"D4-071","domain":4,"obj":"4.2","diff":"easy","q":"Which type of malware encrypts a victim's files and demands payment for the decryption key?","options":["Worm","Rootkit","Ransomware","Spyware"],"answer":2,"explain":"<strong>Correct.</strong> Ransomware encrypts data and extorts the victim by demanding payment to restore access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: It self-replicates across networks but does not inherently encrypt files for ransom.</span><span class='qd'><b>Rootkit</b>: It hides its presence to maintain stealthy privileged access, not extortion.</span><span class='qd'><b>Spyware</b>: It covertly collects information rather than encrypting files for payment.</span>"},{"id":"D4-072","domain":4,"obj":"4.2","diff":"medium","q":"Which characteristic best distinguishes a worm from a traditional virus?","options":["A worm requires a host file and user action to spread","A worm cannot cause damage","A worm only affects mobile devices","A worm self-replicates and spreads across networks without user interaction"],"answer":3,"explain":"<strong>Correct.</strong> A worm spreads autonomously across networks without needing a host file or user action, unlike a virus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A worm requires a host file and user action to spread</b>: That describes a virus; worms are self-propagating.</span><span class='qd'><b>A worm only affects mobile devices</b>: Worms target many platforms, not just mobile.</span><span class='qd'><b>A worm cannot cause damage</b>: Worms can consume bandwidth, drop payloads, and cause significant harm.</span>"},{"id":"D4-073","domain":4,"obj":"4.2","diff":"medium","q":"A user downloads what appears to be a free game, but it secretly installs a backdoor allowing remote attacker access. What category of malware is the disguised program?","options":["Trojan","Logic bomb","Botnet","Macro virus"],"answer":0,"explain":"<strong>Correct.</strong> A Trojan masquerades as legitimate software while secretly delivering a malicious payload such as a backdoor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Logic bomb</b>: It triggers on a specific condition or time, not by disguising itself as a desirable program.</span><span class='qd'><b>Botnet</b>: This is a network of compromised hosts, not the disguised delivery mechanism itself.</span><span class='qd'><b>Macro virus</b>: It hides in document macros, not in a downloaded game executable.</span>"},{"id":"D4-074","domain":4,"obj":"4.2","diff":"hard","q":"An attacker positions themselves between a client and server, silently relaying and potentially altering the communication. Which attack does this describe?","options":["Denial-of-service","On-path (man-in-the-middle) attack","Logic bomb","SQL injection"],"answer":1,"explain":"<strong>Correct.</strong> An on-path attack, also called man-in-the-middle, intercepts and may modify traffic flowing between two parties.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Denial-of-service</b>: It aims to make a resource unavailable, not to silently relay communications.</span><span class='qd'><b>Logic bomb</b>: It is dormant code that executes on a trigger, not an interception of live traffic.</span><span class='qd'><b>SQL injection</b>: It injects malicious database queries through input, not positioning between client and server.</span>"},{"id":"D4-075","domain":4,"obj":"4.2","diff":"medium","q":"Which malware is specifically designed to give an attacker remote control over an infected machine, often used to build a botnet?","options":["Keylogger","Adware","RAT (Remote Access Trojan)","Boot sector virus"],"answer":2,"explain":"<strong>Correct.</strong> A Remote Access Trojan (RAT) provides covert remote control of an infected host and is commonly enrolled into botnets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adware</b>: It displays unwanted advertisements and does not grant remote control.</span><span class='qd'><b>Keylogger</b>: It records keystrokes but does not by itself provide full remote control.</span><span class='qd'><b>Boot sector virus</b>: It infects the boot record to load early, not to enable remote operation.</span>"},{"id":"D4-076","domain":4,"obj":"4.2","diff":"medium","q":"A piece of malicious code lies dormant in payroll software and deletes records if a specific employee's ID is removed from the database. What is this an example of?","options":["Worm","Spyware","Ransomware","Logic bomb"],"answer":3,"explain":"<strong>Correct.</strong> A logic bomb is dormant code that executes its payload when a predefined condition, such as a triggering event, is met.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: It self-replicates across systems rather than waiting for a specific condition.</span><span class='qd'><b>Ransomware</b>: It encrypts data for extortion, not conditional deletion triggered by an event.</span><span class='qd'><b>Spyware</b>: It quietly gathers information rather than triggering a destructive action.</span>"},{"id":"D4-077","domain":4,"obj":"4.2","diff":"hard","q":"Thousands of compromised IoT devices simultaneously flood a target web server with traffic, overwhelming it. Which attack is this?","options":["DDoS (distributed denial-of-service)","DoS from a single host","On-path attack","Side-channel attack"],"answer":0,"explain":"<strong>Correct.</strong> A DDoS attack uses many distributed, compromised devices to flood a target and exhaust its resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DoS from a single host</b>: This scenario uses thousands of devices, making it distributed rather than single-source.</span><span class='qd'><b>On-path attack</b>: That intercepts communications between parties rather than flooding a server.</span><span class='qd'><b>Side-channel attack</b>: That extracts data from physical leakage like timing or power, not traffic floods.</span>"},{"id":"D4-078","domain":4,"obj":"4.2","diff":"medium","q":"An attacker uses a tool to passively capture and read unencrypted packets traversing a shared network segment. What is this activity called?","options":["Phishing","Packet sniffing","Privilege escalation","Buffer overflow"],"answer":1,"explain":"<strong>Correct.</strong> Packet sniffing passively captures network traffic, exposing data sent in cleartext.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Phishing</b>: This tricks users into revealing information through deceptive messages, not capturing packets.</span><span class='qd'><b>Privilege escalation</b>: This gains higher access rights on a system, not intercepting traffic.</span><span class='qd'><b>Buffer overflow</b>: This overruns memory to execute code, unrelated to passive traffic capture.</span>"},{"id":"D4-079","domain":4,"obj":"4.2","diff":"hard","q":"A researcher recovers a secret encryption key by measuring the precise power consumption and timing of a device during cryptographic operations. Which attack class is this?","options":["Trojan delivery","Denial-of-service","Side-channel attack","ARP spoofing"],"answer":2,"explain":"<strong>Correct.</strong> A side-channel attack derives secrets from physical leakage such as power usage, timing, or electromagnetic emissions rather than breaking the algorithm directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Denial-of-service</b>: It disrupts availability and does not extract keys from physical signals.</span><span class='qd'><b>Trojan delivery</b>: It disguises malware to gain a foothold, not measuring physical emissions.</span><span class='qd'><b>ARP spoofing</b>: It poisons address mappings to intercept traffic, not analyzing power or timing.</span>"},{"id":"D4-080","domain":4,"obj":"4.2","diff":"easy","q":"Which type of malware is primarily designed to covertly monitor user activity and gather information without consent?","options":["Rootkit","Worm","Ransomware","Spyware"],"answer":3,"explain":"<strong>Correct.</strong> Spyware secretly observes user behavior and collects information without the user's knowledge or consent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: It focuses on self-replication and spreading, not covert monitoring.</span><span class='qd'><b>Ransomware</b>: It encrypts data and demands payment rather than quietly gathering information.</span><span class='qd'><b>Rootkit</b>: It conceals malicious activity at a privileged level rather than primarily collecting user data.</span>"},{"id":"D4-081","domain":4,"obj":"4.2","diff":"medium","q":"Why is a rootkit particularly difficult to detect and remove?","options":["It operates at a deep, privileged level and hides its own presence","It only runs in a sandbox","It announces itself to antivirus software","It cannot survive a reboot"],"answer":0,"explain":"<strong>Correct.</strong> A rootkit embeds itself at a deep, privileged level of the system and actively conceals its files, processes, and activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It only runs in a sandbox</b>: Rootkits run on the real system, not confined to a sandbox.</span><span class='qd'><b>It announces itself to antivirus software</b>: Rootkits hide from security tools rather than revealing themselves.</span><span class='qd'><b>It cannot survive a reboot</b>: Many rootkits achieve persistence and survive reboots.</span>"},{"id":"D4-082","domain":4,"obj":"4.2","diff":"medium","q":"A botnet is best described as which of the following?","options":["A single infected computer","A network of compromised devices controlled by an attacker","A type of firewall ruleset","An encrypted VPN tunnel"],"answer":1,"explain":"<strong>Correct.</strong> A botnet is a collection of compromised devices remotely commanded by an attacker, often for DDoS or spam.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single infected computer</b>: A botnet involves many coordinated hosts, not just one.</span><span class='qd'><b>A type of firewall ruleset</b>: A firewall ruleset is a defensive control, not a network of compromised machines.</span><span class='qd'><b>An encrypted VPN tunnel</b>: A VPN tunnel is a secure connection, unrelated to attacker-controlled devices.</span>"},{"id":"D4-083","domain":4,"obj":"4.3","diff":"easy","q":"What is the primary difference between an IDS and an IPS?","options":["An IDS blocks traffic while an IPS only logs it","They are identical in function","An IDS detects and alerts while an IPS can actively block malicious traffic","An IPS only works on wireless networks"],"answer":2,"explain":"<strong>Correct.</strong> An IDS detects and alerts on suspicious activity, while an IPS sits inline and can actively block it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An IDS blocks traffic while an IPS only logs it</b>: The roles are reversed; the IPS blocks and the IDS alerts.</span><span class='qd'><b>They are identical in function</b>: They differ in that only the IPS can take blocking action inline.</span><span class='qd'><b>An IPS only works on wireless networks</b>: An IPS operates on wired and wireless networks alike.</span>"},{"id":"D4-084","domain":4,"obj":"4.3","diff":"medium","q":"A traditional packet-filtering firewall makes decisions based primarily on which criteria?","options":["The content of the application payload","The reputation of the sending domain","User identity and group membership","Source and destination IP addresses and ports"],"answer":3,"explain":"<strong>Correct.</strong> A packet-filtering firewall inspects header fields such as source and destination IP addresses, ports, and protocol to allow or deny traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The content of the application payload</b>: Deep payload inspection is performed by NGFWs and WAFs, not basic packet filters.</span><span class='qd'><b>User identity and group membership</b>: Identity-based decisions belong to NGFWs or NAC, not simple packet filtering.</span><span class='qd'><b>The reputation of the sending domain</b>: Reputation services are a feature of advanced filtering, not basic header-based rules.</span>"},{"id":"D4-085","domain":4,"obj":"4.3","diff":"medium","q":"Which firewall type tracks the state of active connections and allows return traffic that belongs to an established session?","options":["Stateful firewall","Packet-filtering firewall","Hardware switch","Proxy ARP"],"answer":0,"explain":"<strong>Correct.</strong> A stateful firewall maintains a connection table and permits return traffic that matches an established session.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Packet-filtering firewall</b>: It evaluates each packet in isolation without tracking connection state.</span><span class='qd'><b>Hardware switch</b>: A switch forwards frames by MAC address and does not filter by connection state.</span><span class='qd'><b>Proxy ARP</b>: This answers ARP requests on behalf of another host and is not a firewall.</span>"},{"id":"D4-086","domain":4,"obj":"4.3","diff":"medium","q":"Which device is specifically designed to inspect HTTP/HTTPS traffic and block web application attacks such as SQL injection and cross-site scripting?","options":["Layer 2 switch","WAF (Web Application Firewall)","DHCP server","Load balancer"],"answer":1,"explain":"<strong>Correct.</strong> A Web Application Firewall (WAF) inspects web traffic and blocks application-layer attacks like SQL injection and XSS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 2 switch</b>: It forwards frames by MAC address and does not inspect web application content.</span><span class='qd'><b>DHCP server</b>: It assigns IP configuration and offers no web attack protection.</span><span class='qd'><b>Load balancer</b>: It distributes traffic across servers but does not inherently filter application attacks.</span>"},{"id":"D4-087","domain":4,"obj":"4.3","diff":"easy","q":"What is the primary purpose of a DMZ in network architecture?","options":["To store backup tapes securely","To encrypt all internal email","To host public-facing services in a segmented zone between the Internet and internal network","To assign IP addresses to clients"],"answer":2,"explain":"<strong>Correct.</strong> A DMZ is a segmented perimeter zone that hosts public-facing services, isolating them from the trusted internal network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To store backup tapes securely</b>: A DMZ is a network segment for services, not physical media storage.</span><span class='qd'><b>To encrypt all internal email</b>: Email encryption is unrelated to the segmentation purpose of a DMZ.</span><span class='qd'><b>To assign IP addresses to clients</b>: That is the role of DHCP, not a DMZ.</span>"},{"id":"D4-088","domain":4,"obj":"4.3","diff":"medium","q":"An organization wants to ensure that any device connecting to the network meets security policies such as updated antivirus and patches before being granted access. Which technology enforces this?","options":["WAF","NAT","DNS","NAC (Network Access Control)"],"answer":3,"explain":"<strong>Correct.</strong> Network Access Control (NAC) assesses a device's compliance posture and grants or restricts access based on policy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NAT</b>: It translates addresses for Internet access and does not evaluate device posture.</span><span class='qd'><b>DNS</b>: It resolves names to addresses and enforces no access policy.</span><span class='qd'><b>WAF</b>: It filters web application traffic and does not check endpoint compliance.</span>"},{"id":"D4-089","domain":4,"obj":"4.3","diff":"medium","q":"How does an EDR solution differ from traditional signature-based antivirus?","options":["EDR continuously monitors endpoint behavior and supports detection, investigation, and response","EDR only scans email attachments","EDR is a hardware firewall","EDR replaces the need for any network controls"],"answer":0,"explain":"<strong>Correct.</strong> EDR continuously monitors endpoint activity, detecting and responding to threats with behavioral analysis beyond static signatures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>EDR only scans email attachments</b>: EDR monitors broad endpoint behavior, not just attachments.</span><span class='qd'><b>EDR is a hardware firewall</b>: EDR is endpoint software, not a network firewall appliance.</span><span class='qd'><b>EDR replaces the need for any network controls</b>: EDR complements but does not replace network defenses.</span>"},{"id":"D4-090","domain":4,"obj":"4.3","diff":"hard","q":"A company needs a site-to-site VPN that operates at the network layer and encrypts entire IP packets between two office gateways. Which protocol suite is most appropriate?","options":["TLS","IPsec","HTTP","SNMP"],"answer":1,"explain":"<strong>Correct.</strong> IPsec operates at the network layer and encrypts and authenticates entire IP packets, making it well suited for site-to-site VPNs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TLS</b>: It secures application-layer sessions and is typically used for client SSL VPNs, not network-layer packet encryption.</span><span class='qd'><b>HTTP</b>: It is an unencrypted web protocol and provides no VPN tunneling.</span><span class='qd'><b>SNMP</b>: It is a network management protocol, not a VPN encryption suite.</span>"},{"id":"D4-091","domain":4,"obj":"4.3","diff":"hard","q":"In the cloud shared responsibility model for Infrastructure as a Service (IaaS), which responsibility typically belongs to the customer rather than the provider?","options":["Securing the physical data center facilities","Maintaining the underlying virtualization hypervisor","Patching and configuring the guest operating system and applications","Securing the provider's core network hardware"],"answer":2,"explain":"<strong>Correct.</strong> In IaaS, the customer is responsible for the guest operating system, applications, and their configuration and patching.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Securing the physical data center facilities</b>: Physical security is always the provider's responsibility.</span><span class='qd'><b>Maintaining the underlying virtualization hypervisor</b>: The hypervisor layer is managed by the provider in IaaS.</span><span class='qd'><b>Securing the provider's core network hardware</b>: The provider owns and secures the underlying infrastructure hardware.</span>"},{"id":"D4-092","domain":4,"obj":"4.3","diff":"medium","q":"A business uses Salesforce, a fully managed application accessed through a web browser, where the vendor maintains everything from the application down to the hardware. Which cloud service model is this?","options":["IaaS","PaaS","On-premises","SaaS"],"answer":3,"explain":"<strong>Correct.</strong> Software as a Service (SaaS) delivers a complete, vendor-managed application that customers consume over the Internet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IaaS</b>: This provides raw compute and storage where the customer manages the OS and applications.</span><span class='qd'><b>PaaS</b>: This offers a development platform where the customer still builds and manages the application code.</span><span class='qd'><b>On-premises</b>: That model means the organization owns and manages everything locally, not a hosted application.</span>"},{"id":"D4-093","domain":4,"obj":"4.3","diff":"medium","q":"Which cloud deployment model combines a private cloud with one or more public clouds, allowing data and applications to move between them?","options":["Hybrid cloud","Private cloud","Public cloud","Community cloud"],"answer":0,"explain":"<strong>Correct.</strong> A hybrid cloud integrates private and public cloud environments so workloads and data can move between them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public cloud</b>: This is shared infrastructure for the general public, not a combination of private and public.</span><span class='qd'><b>Private cloud</b>: This is dedicated to a single organization and does not by itself include public cloud.</span><span class='qd'><b>Community cloud</b>: This is shared among organizations with common concerns, not a private-plus-public blend.</span>"},{"id":"D4-094","domain":4,"obj":"4.3","diff":"easy","q":"What is the main security benefit of network segmentation?","options":["It increases the overall bandwidth of the network","It limits the lateral movement of an attacker by isolating segments","It eliminates the need for passwords","It speeds up DNS resolution"],"answer":1,"explain":"<strong>Correct.</strong> Segmentation isolates network zones, containing breaches and limiting an attacker's lateral movement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It increases the overall bandwidth of the network</b>: Segmentation is a security control, not a bandwidth booster.</span><span class='qd'><b>It eliminates the need for passwords</b>: Authentication is still required regardless of segmentation.</span><span class='qd'><b>It speeds up DNS resolution</b>: Segmentation does not improve name resolution performance.</span>"},{"id":"D4-095","domain":4,"obj":"4.3","diff":"hard","q":"A security architect is concerned about insecure IoT devices on the corporate network. Which control most directly reduces the risk these devices pose to critical systems?","options":["Assigning IoT devices public IP addresses","Disabling the corporate firewall","Placing IoT devices on a segmented VLAN isolated from critical systems","Installing IoT devices on the same subnet as servers"],"answer":2,"explain":"<strong>Correct.</strong> Isolating IoT devices on a segmented VLAN limits their exposure to and from critical systems if they are compromised.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling the corporate firewall</b>: Removing the firewall increases risk rather than reducing it.</span><span class='qd'><b>Assigning IoT devices public IP addresses</b>: Exposing devices directly to the Internet greatly increases their attack surface.</span><span class='qd'><b>Installing IoT devices on the same subnet as servers</b>: Placing them alongside critical servers worsens lateral movement risk.</span>"},{"id":"D4-096","domain":4,"obj":"4.3","diff":"medium","q":"What advantage does a Next-Generation Firewall (NGFW) provide over a traditional stateful firewall?","options":["It can only filter by IP address","It operates exclusively at layer 1","It removes the need for any logging","It adds deep packet inspection, application awareness, and integrated intrusion prevention"],"answer":3,"explain":"<strong>Correct.</strong> An NGFW adds application awareness, deep packet inspection, and integrated intrusion prevention beyond simple stateful filtering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It can only filter by IP address</b>: That describes a basic packet filter, the opposite of an NGFW's capabilities.</span><span class='qd'><b>It removes the need for any logging</b>: NGFWs still log; logging remains an essential security function.</span><span class='qd'><b>It operates exclusively at layer 1</b>: NGFWs inspect up through the application layer, not just the physical layer.</span>"},{"id":"D4-097","domain":4,"obj":"4.3","diff":"easy","q":"What is the primary function of antivirus software?","options":["To detect, quarantine, and remove known malicious software","To assign IP addresses to hosts","To route traffic between networks","To encrypt all network communications"],"answer":0,"explain":"<strong>Correct.</strong> Antivirus software detects, quarantines, and removes known malware from a system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To assign IP addresses to hosts</b>: That is the role of DHCP, not antivirus.</span><span class='qd'><b>To route traffic between networks</b>: Routing is performed by routers, not antivirus software.</span><span class='qd'><b>To encrypt all network communications</b>: Encryption is provided by protocols like TLS or IPsec, not antivirus.</span>"},{"id":"D4-098","domain":4,"obj":"4.3","diff":"medium","q":"A remote worker connects to the corporate network through an encrypted tunnel established in their web browser using TLS. Which type of VPN is this?","options":["IPsec site-to-site VPN","SSL/TLS (clientless) VPN","Split-horizon DNS","MPLS circuit"],"answer":1,"explain":"<strong>Correct.</strong> An SSL/TLS VPN establishes an encrypted tunnel, often through a browser, ideal for individual remote access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IPsec site-to-site VPN</b>: That connects entire networks gateway-to-gateway, not a single browser-based user session.</span><span class='qd'><b>Split-horizon DNS</b>: This serves different DNS answers based on source and is not a VPN.</span><span class='qd'><b>MPLS circuit</b>: This is a provider-managed transport technology, not a browser-based encrypted tunnel.</span>"},{"id":"D4-099","domain":4,"obj":"4.3","diff":"hard","q":"In a Platform as a Service (PaaS) offering, which task is the customer typically responsible for?","options":["Managing the underlying operating system and runtime","Maintaining the physical servers","Developing and maintaining their own application code and data","Patching the host hypervisor"],"answer":2,"explain":"<strong>Correct.</strong> In PaaS, the provider manages the platform, OS, and runtime, while the customer develops and maintains their own application code and data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Managing the underlying operating system and runtime</b>: The provider manages the OS and runtime in PaaS.</span><span class='qd'><b>Maintaining the physical servers</b>: Physical infrastructure is always the provider's responsibility.</span><span class='qd'><b>Patching the host hypervisor</b>: The hypervisor is managed by the provider, not the customer.</span>"},{"id":"D4-100","domain":4,"obj":"4.3","diff":"medium","q":"A data center operator wants to ensure continuous availability during a utility power failure for the time needed to start backup generators. Which control directly addresses this gap?","options":["A VLAN","A stateful firewall","A web application firewall","An uninterruptible power supply (UPS)"],"answer":3,"explain":"<strong>Correct.</strong> A UPS provides immediate battery power to bridge the brief gap until generators come online, maintaining availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A stateful firewall</b>: It filters network traffic and provides no power continuity.</span><span class='qd'><b>A web application firewall</b>: It protects web applications and does nothing for power loss.</span><span class='qd'><b>A VLAN</b>: It segments network traffic and is unrelated to power resilience.</span>"},{"id":"D5-001","domain":5,"obj":"5.1","diff":"easy","q":"Which type of encryption uses the same key to both encrypt and decrypt data?","options":["Symmetric encryption","Asymmetric encryption","Public-key encryption","Digital signatures"],"answer":0,"explain":"<strong>Correct.</strong> Symmetric encryption uses a single shared secret key for both encryption and decryption, which makes it fast and well suited to bulk data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asymmetric encryption</b>: uses a mathematically related key pair, a public key and a private key, not a single shared key.</span><span class='qd'><b>Public-key encryption</b>: is another name for asymmetric encryption and relies on two different keys.</span><span class='qd'><b>Digital signatures</b>: are a use of asymmetric keys and hashing to prove integrity and origin, not a way to keep data confidential with one key.</span>"},{"id":"D5-002","domain":5,"obj":"5.1","diff":"easy","q":"Which algorithm is the modern symmetric block cipher recommended for protecting data today?","options":["DES","AES","RSA","MD5"],"answer":1,"explain":"<strong>Correct.</strong> AES (Advanced Encryption Standard) is the current, widely trusted symmetric block cipher, available in 128-, 192-, and 256-bit key sizes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DES</b>: is an older symmetric cipher with a 56-bit key that is now considered insecure and deprecated.</span><span class='qd'><b>RSA</b>: is an asymmetric algorithm used for key exchange and signatures, not a symmetric block cipher.</span><span class='qd'><b>MD5</b>: is a hashing algorithm, not an encryption algorithm, and is itself broken for security use.</span>"},{"id":"D5-003","domain":5,"obj":"5.1","diff":"easy","q":"What is the main purpose of a cryptographic hash function such as SHA-256?","options":["To encrypt data so only the holder of a key can read it","To exchange secret keys over an untrusted network","To produce a fixed-length fingerprint that verifies integrity","To compress a file so it takes less storage space"],"answer":2,"explain":"<strong>Correct.</strong> A hash function produces a fixed-length, one-way digest used to verify that data has not changed; the same input always yields the same hash.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt data so only the holder of a key can read it</b>: describes encryption, which is reversible with a key, unlike a one-way hash.</span><span class='qd'><b>To exchange secret keys over an untrusted network</b>: is the job of a key-exchange method such as Diffie-Hellman.</span><span class='qd'><b>To compress a file so it takes less storage space</b>: is data compression, which is unrelated to hashing for integrity.</span>"},{"id":"D5-004","domain":5,"obj":"5.1","diff":"easy","q":"Data being transmitted across a network is best described as data in which state?","options":["Data at rest","Data archived","Data in use","Data in transit"],"answer":3,"explain":"<strong>Correct.</strong> Data in transit (or in motion) is data actively moving across a network, and it is commonly protected with TLS or other transport encryption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data at rest</b>: refers to data stored on disk or other media, not data moving across a network.</span><span class='qd'><b>Data in use</b>: refers to data being actively processed in memory by an application.</span><span class='qd'><b>Data archived</b>: is simply a form of stored data at rest, not a recognized state for data crossing a network.</span>"},{"id":"D5-005","domain":5,"obj":"5.1","diff":"easy","q":"Which protocol is most commonly used to encrypt web traffic between a browser and a server?","options":["TLS","SNMP","FTP","Telnet"],"answer":0,"explain":"<strong>Correct.</strong> TLS (Transport Layer Security) encrypts data in transit and is the protocol behind HTTPS, protecting web traffic from eavesdropping and tampering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FTP</b>: transfers files in cleartext by default and provides no encryption.</span><span class='qd'><b>SNMP</b>: is used to manage and monitor network devices, not to encrypt web sessions.</span><span class='qd'><b>Telnet</b>: provides remote terminal access in cleartext and is considered insecure.</span>"},{"id":"D5-006","domain":5,"obj":"5.1","diff":"medium","q":"An organization labels data as public, internal, confidential, and restricted. What practice is this an example of?","options":["Data sanitization","Data classification","Data degaussing","Data masking"],"answer":1,"explain":"<strong>Correct.</strong> Assigning sensitivity labels such as public, internal, confidential, and restricted is data classification, which drives how each category must be handled and protected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data sanitization</b>: is the process of removing data so it cannot be recovered, not labeling its sensitivity.</span><span class='qd'><b>Data degaussing</b>: uses a magnetic field to erase media and is one method of sanitization.</span><span class='qd'><b>Data masking</b>: obscures specific field values, such as hiding part of a credit card number, rather than categorizing whole data sets.</span>"},{"id":"D5-007","domain":5,"obj":"5.1","diff":"medium","q":"Who is the individual ultimately accountable for the classification and protection of a particular set of data?","options":["Data custodian","Data subject","Data owner","Data processor"],"answer":2,"explain":"<strong>Correct.</strong> The data owner is accountable for classifying the data and deciding how it must be protected, even though others perform the hands-on tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data custodian</b>: implements and maintains the controls the owner specifies but is not ultimately accountable for classification decisions.</span><span class='qd'><b>Data subject</b>: is the person whom personal data is about, not the party responsible for protecting it.</span><span class='qd'><b>Data processor</b>: handles data on behalf of a controller and follows instructions rather than setting classification.</span>"},{"id":"D5-008","domain":5,"obj":"5.1","diff":"medium","q":"Which technology encrypts the entire contents of a laptop hard drive so that data is unreadable if the device is lost or stolen?","options":["File compression","Network segmentation","Tokenization","Full-disk encryption"],"answer":3,"explain":"<strong>Correct.</strong> Full-disk encryption protects data at rest by encrypting the whole drive, so a lost or stolen laptop yields only ciphertext without the key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>File compression</b>: reduces file size and does not provide confidentiality.</span><span class='qd'><b>Network segmentation</b>: divides a network into zones and does not protect data stored on a disk.</span><span class='qd'><b>Tokenization</b>: replaces sensitive values with tokens for specific fields rather than encrypting an entire drive.</span>"},{"id":"D5-009","domain":5,"obj":"5.1","diff":"medium","q":"Diffie-Hellman is primarily used to accomplish which task?","options":["Securely agree on a shared secret key over an untrusted channel","Encrypt large files quickly with a single key","Produce a one-way hash of a message","Permanently erase data from a hard drive"],"answer":0,"explain":"<strong>Correct.</strong> Diffie-Hellman is a key-exchange method that lets two parties establish a shared secret over an insecure channel without transmitting the secret itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt large files quickly with a single key</b>: describes a symmetric cipher such as AES, not a key-exchange algorithm.</span><span class='qd'><b>Produce a one-way hash of a message</b>: is the role of a hashing algorithm like SHA-256.</span><span class='qd'><b>Permanently erase data from a hard drive</b>: is data sanitization, unrelated to key exchange.</span>"},{"id":"D5-010","domain":5,"obj":"5.1","diff":"medium","q":"Adding a unique random value to a password before hashing it is known as what, and what attack does it primarily defend against?","options":["Padding; buffer overflow attacks","Salting; precomputed rainbow table attacks","Keying; brute-force key search","Chaining; replay attacks"],"answer":1,"explain":"<strong>Correct.</strong> Salting adds a unique random value to each password before hashing so identical passwords produce different hashes, defeating precomputed rainbow tables.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Padding; buffer overflow attacks</b>: padding adjusts data to a block size and is unrelated to defeating rainbow tables.</span><span class='qd'><b>Keying; brute-force key search</b>: keying refers to using a key, not adding randomness to a password hash.</span><span class='qd'><b>Chaining; replay attacks</b>: chaining is a block cipher mode concept and does not describe per-password randomization.</span>"},{"id":"D5-011","domain":5,"obj":"5.1","diff":"hard","q":"A message is hashed and that hash is then encrypted with the sender's private key. What security service does the result provide to a recipient who verifies it with the sender's public key?","options":["Confidentiality of the message contents","Availability of the message during transmission","Integrity and authenticity of the message origin","Anonymity of the sender's identity"],"answer":2,"explain":"<strong>Correct.</strong> This describes a digital signature: hashing provides integrity, and encrypting the hash with the sender's private key lets anyone verify origin with the public key, providing authenticity and non-repudiation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality of the message contents</b>: is not provided because the message body itself is not encrypted by signing.</span><span class='qd'><b>Availability of the message during transmission</b>: is unrelated to signing and concerns access, not proof of origin.</span><span class='qd'><b>Anonymity of the sender's identity</b>: is the opposite of what a signature does, since it ties the message to the signer.</span>"},{"id":"D5-012","domain":5,"obj":"5.1","diff":"hard","q":"An auditor needs assurance that an old set of hard drives can be reused outside the secure facility with no chance the original highly sensitive data is recovered. Which approach best meets this goal?","options":["Delete the files and empty the recycle bin","Reformat the drives using a quick format","Move the files into an encrypted folder","Securely sanitize the drives, for example by degaussing or cryptographic erase"],"answer":3,"explain":"<strong>Correct.</strong> Sanitization methods such as degaussing or cryptographic erase render the original data unrecoverable, which is required before reusing media that held highly sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the files and empty the recycle bin</b>: only removes pointers, leaving the underlying data recoverable.</span><span class='qd'><b>Reformat the drives using a quick format</b>: rewrites file tables but generally leaves data blocks intact and recoverable.</span><span class='qd'><b>Move the files into an encrypted folder</b>: does not remove the original sensitive data that already exists elsewhere on the drive.</span>"},{"id":"D5-013","domain":5,"obj":"5.1","diff":"medium","q":"HMAC combines a hash function with which additional element to provide both integrity and authentication?","options":["A secret key shared by the communicating parties","A public certificate from a trusted CA","A random salt stored in cleartext","A compression dictionary"],"answer":0,"explain":"<strong>Correct.</strong> HMAC (Hash-based Message Authentication Code) mixes a secret key into the hashing process, so a valid code proves both that data is unchanged and that it came from a party holding the key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public certificate from a trusted CA</b>: is used in PKI and signatures, not in computing an HMAC.</span><span class='qd'><b>A random salt stored in cleartext</b>: is used for password hashing and does not provide message authentication by itself.</span><span class='qd'><b>A compression dictionary</b>: relates to data compression and has nothing to do with authentication.</span>"},{"id":"D5-014","domain":5,"obj":"5.1","diff":"medium","q":"Which pair correctly matches an algorithm to its category?","options":["RSA is symmetric; AES is asymmetric","RSA is asymmetric; AES is symmetric","RSA and AES are both symmetric","RSA and AES are both hashing algorithms"],"answer":1,"explain":"<strong>Correct.</strong> RSA is an asymmetric (public-key) algorithm, while AES is a symmetric block cipher; this is a fundamental distinction in cryptography.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RSA is symmetric; AES is asymmetric</b>: reverses the two categories incorrectly.</span><span class='qd'><b>RSA and AES are both symmetric</b>: is wrong because RSA uses a public and private key pair.</span><span class='qd'><b>RSA and AES are both hashing algorithms</b>: is wrong because both are encryption algorithms, not hash functions.</span>"},{"id":"D5-015","domain":5,"obj":"5.1","diff":"hard","q":"Why is elliptic curve cryptography (ECC) attractive for mobile and IoT devices compared with traditional RSA?","options":["It eliminates the need for any key management","It is a symmetric cipher that runs faster than AES","It provides comparable security with much smaller key sizes and lower computational cost","It removes the need to ever exchange keys"],"answer":2,"explain":"<strong>Correct.</strong> ECC achieves strength comparable to RSA using far smaller keys, which means less computation, memory, and power, making it well suited to constrained mobile and IoT devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It eliminates the need for any key management</b>: is false; ECC still uses key pairs that must be managed.</span><span class='qd'><b>It is a symmetric cipher that runs faster than AES</b>: is wrong because ECC is an asymmetric scheme, not a symmetric cipher.</span><span class='qd'><b>It removes the need to ever exchange keys</b>: is incorrect; ECC is commonly used precisely to support secure key exchange and signatures.</span>"},{"id":"D5-016","domain":5,"obj":"5.1","diff":"easy","q":"Which option lists the typical stages of the data life cycle in a reasonable order?","options":["Archive, destroy, store, create","Destroy, archive, create, store","Share, destroy, create, use","Create, store, use, share, archive, destroy"],"answer":3,"explain":"<strong>Correct.</strong> Data generally moves through create, store, use, share, archive, and finally destroy, and controls should be applied at each stage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Destroy, archive, create, store</b>: places destruction before data even exists, which is illogical.</span><span class='qd'><b>Share, destroy, create, use</b>: lists the stages out of any meaningful order.</span><span class='qd'><b>Archive, destroy, store, create</b>: again ends with creation, reversing the natural flow.</span>"},{"id":"D5-017","domain":5,"obj":"5.1","diff":"medium","q":"Why is MD5 no longer recommended for security-sensitive integrity or password use?","options":["It is vulnerable to collisions, where different inputs produce the same hash","It produces an output that is too long to store","It can only hash text and not binary data","It requires a secret key that is easily lost"],"answer":0,"explain":"<strong>Correct.</strong> MD5 is broken because practical collision attacks let attackers craft two different inputs with the same hash, undermining its integrity guarantees.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It produces an output that is too long to store</b>: is false; MD5 produces a short 128-bit digest.</span><span class='qd'><b>It can only hash text and not binary data</b>: is incorrect; hash functions operate on any byte data.</span><span class='qd'><b>It requires a secret key that is easily lost</b>: is wrong because MD5 is a keyless hash, not a keyed algorithm.</span>"},{"id":"D5-018","domain":5,"obj":"5.1","diff":"hard","q":"A database server decrypts records into memory so an application can run reports against them. While being processed in RAM, this information is in which state and what is a key protection concern?","options":["Data at rest; the disk encryption fully protects it","Data in use; it is exposed in cleartext in memory and needs access and memory protections","Data in transit; TLS alone is sufficient","Data archived; retention policy is the main concern"],"answer":1,"explain":"<strong>Correct.</strong> Data being processed in memory is data in use, and because it is temporarily in cleartext, controls such as strong access control and memory protection are needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data at rest; the disk encryption fully protects it</b>: is wrong because disk encryption does not protect cleartext already loaded into memory.</span><span class='qd'><b>Data in transit; TLS alone is sufficient</b>: misclassifies in-memory data and addresses only network movement.</span><span class='qd'><b>Data archived; retention policy is the main concern</b>: is incorrect since the data is actively being used, not archived.</span>"},{"id":"D5-019","domain":5,"obj":"5.1","diff":"medium","q":"3DES was created as an interim improvement over which weaker algorithm?","options":["AES","SHA-1","DES","RSA"],"answer":2,"explain":"<strong>Correct.</strong> 3DES (Triple DES) applies the DES cipher three times to strengthen the original DES, which had become vulnerable due to its short key length.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AES</b>: is the modern replacement that succeeded 3DES, not a weaker predecessor.</span><span class='qd'><b>SHA-1</b>: is a hashing algorithm, not an encryption cipher that 3DES would extend.</span><span class='qd'><b>RSA</b>: is an asymmetric algorithm unrelated to the DES family of symmetric ciphers.</span>"},{"id":"D5-020","domain":5,"obj":"5.1","diff":"easy","q":"What does encrypting data at rest primarily protect against?","options":["Users forgetting their passwords","Slow application performance","Network congestion during transfers","Unauthorized access to stored data if the media is lost or stolen"],"answer":3,"explain":"<strong>Correct.</strong> Encrypting data at rest ensures that if storage media or devices are lost or stolen, the data remains unreadable without the decryption key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slow application performance</b>: is not a protection goal; encryption can even add slight overhead.</span><span class='qd'><b>Network congestion during transfers</b>: relates to bandwidth, not to protecting stored data.</span><span class='qd'><b>Users forgetting their passwords</b>: is an account recovery issue, not something at-rest encryption addresses.</span>"},{"id":"D5-021","domain":5,"obj":"5.2","diff":"easy","q":"A documented, approved standard configuration that all systems of a given type must match is called a what?","options":["Security baseline","Firewall rule","Incident report","Risk register"],"answer":0,"explain":"<strong>Correct.</strong> A security baseline defines the minimum approved configuration for a class of systems, giving a consistent and measurable standard for hardening.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Firewall rule</b>: controls specific network traffic and is only one possible element of a configuration.</span><span class='qd'><b>Incident report</b>: documents a security event after the fact, not a configuration standard.</span><span class='qd'><b>Risk register</b>: tracks identified risks and treatments, not system configuration settings.</span>"},{"id":"D5-022","domain":5,"obj":"5.2","diff":"easy","q":"What is the primary purpose of patch management?","options":["To classify data by sensitivity level","To apply updates that fix known vulnerabilities and bugs in software","To train employees about phishing","To negotiate vendor contracts"],"answer":1,"explain":"<strong>Correct.</strong> Patch management is the disciplined process of acquiring, testing, and applying software updates to remediate known vulnerabilities and defects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To classify data by sensitivity level</b>: is data classification, a separate data security activity.</span><span class='qd'><b>To train employees about phishing</b>: is part of security awareness, not patching.</span><span class='qd'><b>To negotiate vendor contracts</b>: is a procurement task unrelated to applying software fixes.</span>"},{"id":"D5-023","domain":5,"obj":"5.2","diff":"easy","q":"A preconfigured, hardened system template that can be deployed repeatedly to ensure consistency is commonly called a what?","options":["Honeypot","Demilitarized zone","Golden image","Service ticket"],"answer":2,"explain":"<strong>Correct.</strong> A golden image is a master template of an approved, hardened configuration used to deploy new systems consistently and quickly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Honeypot</b>: is a decoy system used to attract and study attackers, not a deployment template.</span><span class='qd'><b>Demilitarized zone</b>: is a network segment that isolates public-facing services, not a system image.</span><span class='qd'><b>Service ticket</b>: is a record of a help-desk or change request, unrelated to system images.</span>"},{"id":"D5-024","domain":5,"obj":"5.2","diff":"medium","q":"Why should default administrator accounts and passwords be changed or disabled during system hardening?","options":["They use too much disk space","They cannot be used to log in at all","They slow down the boot process","They are widely known and a common target for attackers"],"answer":3,"explain":"<strong>Correct.</strong> Default accounts and credentials are publicly documented, so leaving them in place gives attackers an easy, well-known path into the system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They use too much disk space</b>: is incorrect; accounts consume negligible space and that is not the concern.</span><span class='qd'><b>They slow down the boot process</b>: is unrelated to the security risk of default credentials.</span><span class='qd'><b>They cannot be used to log in at all</b>: is false; default accounts are fully usable, which is exactly the danger.</span>"},{"id":"D5-025","domain":5,"obj":"5.2","diff":"medium","q":"Disabling unneeded services and closing unused ports on a server primarily accomplishes what?","options":["Reduces the system's attack surface","Removes the need for patching","Encrypts all stored data automatically","Increases the number of default accounts"],"answer":0,"explain":"<strong>Correct.</strong> Every running service or open port is a potential entry point, so turning off what is not needed shrinks the attack surface available to attackers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increases the number of default accounts</b>: is the opposite of hardening and is not an effect of disabling services.</span><span class='qd'><b>Removes the need for patching</b>: is false; remaining services still require updates.</span><span class='qd'><b>Encrypts all stored data automatically</b>: is unrelated; disabling services does not provide encryption.</span>"},{"id":"D5-026","domain":5,"obj":"5.2","diff":"medium","q":"Configuration management is best described as the practice of doing what?","options":["Responding to security incidents after they occur","Establishing and maintaining consistent, documented, approved system settings","Classifying data into sensitivity tiers","Encrypting traffic between two endpoints"],"answer":1,"explain":"<strong>Correct.</strong> Configuration management establishes baselines and tracks, controls, and documents changes so systems remain in a known, approved, and consistent state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Responding to security incidents after they occur</b>: is incident response, a different operational function.</span><span class='qd'><b>Classifying data into sensitivity tiers</b>: is data classification within data security.</span><span class='qd'><b>Encrypting traffic between two endpoints</b>: is a transport security control, not configuration management.</span>"},{"id":"D5-027","domain":5,"obj":"5.2","diff":"medium","q":"A scan reveals that several servers were deployed with weak settings such as verbose error messages and unnecessary sample applications enabled. This is an example of what kind of weakness?","options":["A zero-day exploit","A social engineering attack","A configuration vulnerability","A denial-of-service condition"],"answer":2,"explain":"<strong>Correct.</strong> Insecure settings like enabled sample apps and verbose errors are configuration vulnerabilities, addressed by applying a hardened baseline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A zero-day exploit</b>: targets a previously unknown software flaw, not a misconfiguration the admin controls.</span><span class='qd'><b>A social engineering attack</b>: manipulates people rather than exploiting system settings.</span><span class='qd'><b>A denial-of-service condition</b>: aims to disrupt availability, which is not what these settings describe.</span>"},{"id":"D5-028","domain":5,"obj":"5.2","diff":"hard","q":"An organization wants to ensure that any drift from approved system settings is detected and corrected over time. Which combination of practices best supports this goal?","options":["Relying solely on annual user awareness training","Using full-disk encryption on every endpoint","Implementing a strong password policy only","Defining baselines and using configuration management to monitor and enforce them"],"answer":3,"explain":"<strong>Correct.</strong> Baselines define the approved state and configuration management continuously monitors for and remediates drift, keeping systems aligned with the standard.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Relying solely on annual user awareness training</b>: educates people but does nothing to detect technical configuration drift.</span><span class='qd'><b>Using full-disk encryption on every endpoint</b>: protects data at rest but does not monitor configuration settings.</span><span class='qd'><b>Implementing a strong password policy only</b>: strengthens authentication but does not address configuration drift across systems.</span>"},{"id":"D5-029","domain":5,"obj":"5.2","diff":"medium","q":"Before broadly deploying a new patch, why is it best practice to test it in a non-production environment first?","options":["To confirm the patch does not break functionality or cause instability","To avoid having to document the change","To bypass the change management process","To make the patch download faster"],"answer":0,"explain":"<strong>Correct.</strong> Testing patches in a representative non-production environment helps catch compatibility problems or instability before they affect live systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the patch download faster</b>: testing has no effect on download speed.</span><span class='qd'><b>To avoid having to document the change</b>: is wrong; changes should still be documented through change management.</span><span class='qd'><b>To bypass the change management process</b>: is the opposite of good practice, since patches should follow change control.</span>"},{"id":"D5-030","domain":5,"obj":"5.2","diff":"hard","q":"What is the main advantage of building new servers from a single approved golden image rather than configuring each one manually?","options":["It guarantees that no patches will ever be required","It enforces consistent, repeatable hardened configurations and reduces human error","It removes the need for any access controls","It automatically classifies all data on the server"],"answer":1,"explain":"<strong>Correct.</strong> Deploying from a golden image ensures every system starts in the same hardened, approved state, reducing configuration drift and manual mistakes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees that no patches will ever be required</b>: is false; images still need ongoing patching as new vulnerabilities emerge.</span><span class='qd'><b>It removes the need for any access controls</b>: is incorrect; access controls remain essential regardless of how a system is built.</span><span class='qd'><b>It automatically classifies all data on the server</b>: confuses system imaging with the separate task of data classification.</span>"},{"id":"D5-031","domain":5,"obj":"5.3","diff":"easy","q":"Which policy defines what employees may and may not do with organizational systems, networks, and internet access?","options":["Business continuity plan","Data retention schedule","Acceptable use policy (AUP)","Incident response plan"],"answer":2,"explain":"<strong>Correct.</strong> An acceptable use policy (AUP) sets the rules for proper use of organizational systems, networks, and resources by employees.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Business continuity plan</b>: focuses on keeping operations running during disruptions, not everyday system use.</span><span class='qd'><b>Data retention schedule</b>: specifies how long records are kept, not how systems may be used.</span><span class='qd'><b>Incident response plan</b>: guides how to handle security incidents, not acceptable behavior.</span>"},{"id":"D5-032","domain":5,"obj":"5.3","diff":"easy","q":"A formal request to make a change to an IT system, reviewed before it is approved, is commonly known as a what?","options":["Service-level agreement (SLA)","Memorandum of understanding (MOU)","Statement of work (SOW)","Request for change (RFC)"],"answer":3,"explain":"<strong>Correct.</strong> A request for change (RFC) formally documents a proposed change so it can be assessed and approved through the change management process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Service-level agreement (SLA)</b>: defines expected service levels between provider and customer, not a change request.</span><span class='qd'><b>Memorandum of understanding (MOU)</b>: records a general agreement between parties, not an IT change.</span><span class='qd'><b>Statement of work (SOW)</b>: describes deliverables and tasks for a project or contract.</span>"},{"id":"D5-033","domain":5,"obj":"5.3","diff":"medium","q":"In change management, what is the role of the change advisory board (CAB)?","options":["To review, assess, and authorize proposed changes","To write all application source code","To physically install network cabling","To respond to phishing emails"],"answer":0,"explain":"<strong>Correct.</strong> The change advisory board (CAB) evaluates the risk and impact of proposed changes and approves or rejects them before implementation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To write all application source code</b>: is a development task, not a governance function of the CAB.</span><span class='qd'><b>To physically install network cabling</b>: is hands-on infrastructure work, not change authorization.</span><span class='qd'><b>To respond to phishing emails</b>: is an awareness or incident-handling activity unrelated to change approval.</span>"},{"id":"D5-034","domain":5,"obj":"5.3","diff":"medium","q":"Why does a well-designed change management policy require a documented rollback plan for significant changes?","options":["So the change never needs to be tested","So the system can be restored to its prior working state if the change fails","So no approval is required for the change","So the change can be hidden from auditors"],"answer":1,"explain":"<strong>Correct.</strong> A rollback (back-out) plan lets the team return the system to its previous working state if a change causes problems, limiting downtime and impact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>So the change never needs to be tested</b>: is wrong; testing is still expected and a rollback is a safety net.</span><span class='qd'><b>So no approval is required for the change</b>: is incorrect; changes still go through approval regardless of rollback planning.</span><span class='qd'><b>So the change can be hidden from auditors</b>: is contrary to the transparency change management is meant to provide.</span>"},{"id":"D5-035","domain":5,"obj":"5.3","diff":"medium","q":"An organization lets employees use personal smartphones for work and enrolls those devices in mobile device management (MDM). Which policy most directly governs this arrangement?","options":["Data classification policy","Vendor management policy","Bring your own device (BYOD) policy","Physical security policy"],"answer":2,"explain":"<strong>Correct.</strong> A BYOD policy governs the use of employee-owned devices for work and typically requires MDM to enforce security controls on those devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification policy</b>: defines sensitivity levels for data, not rules for personal device use.</span><span class='qd'><b>Vendor management policy</b>: covers third-party suppliers and contracts, not employee devices.</span><span class='qd'><b>Physical security policy</b>: addresses facility and asset protection rather than mobile device enrollment.</span>"},{"id":"D5-036","domain":5,"obj":"5.3","diff":"easy","q":"Which document explains how an organization collects, uses, stores, and shares personal information?","options":["Acceptable use policy","Change management policy","Password policy","Privacy policy"],"answer":3,"explain":"<strong>Correct.</strong> A privacy policy describes how personal information is collected, used, stored, shared, and protected, often to meet legal and regulatory requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Acceptable use policy</b>: governs how users may use systems and resources, not handling of personal data specifically.</span><span class='qd'><b>Password policy</b>: sets rules for password strength and management.</span><span class='qd'><b>Change management policy</b>: governs how changes to systems are proposed and approved.</span>"},{"id":"D5-037","domain":5,"obj":"5.3","diff":"medium","q":"Which set of rules is typically defined by an organization's password policy?","options":["Minimum length, complexity, expiration, and reuse requirements","Which ports the firewall should block","How long backup tapes are retained","How incidents are escalated to management"],"answer":0,"explain":"<strong>Correct.</strong> A password policy specifies requirements such as minimum length, complexity, expiration intervals, and restrictions on reusing old passwords.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>How long backup tapes are retained</b>: is governed by a retention policy or backup schedule.</span><span class='qd'><b>Which ports the firewall should block</b>: is a firewall or network configuration matter, not a password policy.</span><span class='qd'><b>How incidents are escalated to management</b>: belongs to an incident response procedure.</span>"},{"id":"D5-038","domain":5,"obj":"5.3","diff":"hard","q":"A team needs to apply an emergency security fix outside the normal change schedule. How should a mature change management policy typically handle this?","options":["Skip all approvals and documentation permanently","Allow an expedited emergency change process with appropriate approval and after-the-fact documentation","Forbid the change until the next annual review","Require every employee to vote on the change"],"answer":1,"explain":"<strong>Correct.</strong> Mature change management includes an emergency change path that still requires appropriate approval and documentation, just on an accelerated basis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Skip all approvals and documentation permanently</b>: undermines accountability and is never acceptable even for emergencies.</span><span class='qd'><b>Forbid the change until the next annual review</b>: would leave a critical vulnerability unpatched for an unacceptable period.</span><span class='qd'><b>Require every employee to vote on the change</b>: is impractical and not how change authorization works.</span>"},{"id":"D5-039","domain":5,"obj":"5.3","diff":"medium","q":"What is the primary purpose of a data handling policy?","options":["To list the names of all employees","To set the office dress code","To define how data must be stored, transmitted, shared, and disposed of based on its classification","To schedule software demonstrations"],"answer":2,"explain":"<strong>Correct.</strong> A data handling policy specifies the required controls for storing, transmitting, sharing, and disposing of data according to its classification level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To list the names of all employees</b>: is an HR directory function, not a data handling control.</span><span class='qd'><b>To set the office dress code</b>: is an administrative matter unrelated to data security.</span><span class='qd'><b>To schedule software demonstrations</b>: is a project or sales activity, not a security policy purpose.</span>"},{"id":"D5-040","domain":5,"obj":"5.3","diff":"hard","q":"An auditor finds that production changes are frequently made directly by administrators with no tickets, approvals, or records. Which control is most clearly missing?","options":["A data classification scheme","An encryption standard for data at rest","A security awareness training program","A change management process with documented approvals and records"],"answer":3,"explain":"<strong>Correct.</strong> The absence of tickets, approvals, and records points to a missing or unenforced change management process, which is needed to authorize and track changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A data classification scheme</b>: concerns labeling data sensitivity, not controlling production changes.</span><span class='qd'><b>An encryption standard for data at rest</b>: addresses how stored data is protected, not change authorization.</span><span class='qd'><b>A security awareness training program</b>: educates users but does not provide the approval and recordkeeping controls that are absent.</span>"},{"id":"D5-041","domain":5,"obj":"5.4","diff":"easy","q":"A fraudulent email that tries to trick recipients into revealing credentials or clicking a malicious link is an example of what?","options":["Phishing","Patch management","Data classification","Full-disk encryption"],"answer":0,"explain":"<strong>Correct.</strong> Phishing uses deceptive emails or messages to lure recipients into disclosing sensitive information or interacting with malicious content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Patch management</b>: is the process of applying software updates, not a social engineering attack.</span><span class='qd'><b>Data classification</b>: is labeling data by sensitivity, unrelated to fraudulent emails.</span><span class='qd'><b>Full-disk encryption</b>: protects data at rest and is not an attack technique.</span>"},{"id":"D5-042","domain":5,"obj":"5.4","diff":"easy","q":"A social engineering phone call that pretends to be from the IT help desk to extract a password is best described as what?","options":["Smishing","Vishing","Tailgating","Baiting"],"answer":1,"explain":"<strong>Correct.</strong> Vishing is voice phishing, where the attacker uses a phone call to manipulate the victim into revealing information or taking an action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Smishing</b>: uses SMS text messages rather than phone calls.</span><span class='qd'><b>Tailgating</b>: is following someone through a physical door to gain unauthorized entry.</span><span class='qd'><b>Baiting</b>: lures victims with something enticing, such as an infected USB drive, not a phone call.</span>"},{"id":"D5-043","domain":5,"obj":"5.4","diff":"medium","q":"A highly targeted phishing email aimed specifically at a company's chief financial officer is best described as what?","options":["Mass phishing","Smishing","Whaling","Tailgating"],"answer":2,"explain":"<strong>Correct.</strong> Whaling is a form of spear phishing that targets high-value executives such as a CFO or CEO, often to authorize fraudulent transfers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mass phishing</b>: sends generic messages to many recipients rather than targeting a specific executive.</span><span class='qd'><b>Smishing</b>: is phishing carried out over SMS text messages.</span><span class='qd'><b>Tailgating</b>: is a physical intrusion technique, not an email attack.</span>"},{"id":"D5-044","domain":5,"obj":"5.4","diff":"medium","q":"An attacker follows an employee through a secured door before it closes, without using their own badge. This physical social engineering technique is called what?","options":["Vishing","Baiting","Pretexting","Tailgating"],"answer":3,"explain":"<strong>Correct.</strong> Tailgating (or piggybacking) is when an unauthorized person slips through a controlled entry by closely following an authorized individual.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Vishing</b>: is a phone-based phishing attack, not a physical entry method.</span><span class='qd'><b>Pretexting</b>: involves inventing a believable scenario to obtain information, which may or may not involve physical entry.</span><span class='qd'><b>Baiting</b>: relies on tempting the victim with something attractive, such as a dropped USB drive.</span>"},{"id":"D5-045","domain":5,"obj":"5.4","diff":"medium","q":"What distinguishes spear phishing from ordinary phishing?","options":["It is customized for a specific individual or group using researched details","It is always sent by text message","It never contains any links","It only targets random members of the public"],"answer":0,"explain":"<strong>Correct.</strong> Spear phishing is tailored to a particular target using personal or organizational details, making it more convincing than generic phishing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is always sent by text message</b>: describes smishing, not spear phishing, which is commonly email-based.</span><span class='qd'><b>It never contains any links</b>: is false; spear phishing frequently includes malicious links or attachments.</span><span class='qd'><b>It only targets random members of the public</b>: is the opposite of spear phishing's targeted nature.</span>"},{"id":"D5-046","domain":5,"obj":"5.4","diff":"medium","q":"Leaving an infected USB drive labeled 'Payroll' in a parking lot hoping an employee plugs it in is an example of which technique?","options":["Whaling","Baiting","Smishing","Tailgating"],"answer":1,"explain":"<strong>Correct.</strong> Baiting tempts a victim with something appealing, such as a labeled USB drive, to trick them into an action that compromises security.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whaling</b>: targets senior executives via tailored phishing messages, not physical bait.</span><span class='qd'><b>Smishing</b>: uses SMS messages to deceive victims.</span><span class='qd'><b>Tailgating</b>: is following someone through a secure door, not leaving bait.</span>"},{"id":"D5-047","domain":5,"obj":"5.4","diff":"easy","q":"Periodically sending fake but realistic phishing emails to employees and measuring who clicks is known as what?","options":["A penetration test of the firewall","A data classification exercise","A phishing simulation","A change advisory board review"],"answer":2,"explain":"<strong>Correct.</strong> A phishing simulation sends controlled, fake phishing messages to test and reinforce employees' ability to recognize and report such attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A penetration test of the firewall</b>: targets technical defenses, not employee awareness through fake emails.</span><span class='qd'><b>A data classification exercise</b>: involves labeling data, not testing user behavior.</span><span class='qd'><b>A change advisory board review</b>: evaluates proposed changes, unrelated to phishing tests.</span>"},{"id":"D5-048","domain":5,"obj":"5.4","diff":"hard","q":"In a security education program, which choice best distinguishes awareness from training?","options":["Awareness teaches programming, while training only shows posters","Awareness and training are identical terms with no difference","Awareness is for executives only, while training is for everyone","Awareness reinforces general good behavior, while training teaches specific skills for a role"],"answer":3,"explain":"<strong>Correct.</strong> Awareness keeps security top of mind and reinforces general good behavior, while training imparts specific skills and knowledge needed to perform a role securely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Awareness teaches programming, while training only shows posters</b>: reverses and misstates both concepts.</span><span class='qd'><b>Awareness is for executives only, while training is for everyone</b>: incorrectly limits awareness by audience.</span><span class='qd'><b>Awareness and training are identical terms with no difference</b>: is wrong because they serve distinct purposes in a security program.</span>"},{"id":"D5-049","domain":5,"obj":"5.4","diff":"medium","q":"An attacker invents a convincing false scenario, such as claiming to be an auditor needing access, to manipulate a victim. This technique is called what?","options":["Pretexting","Baiting","Tailgating","Smishing"],"answer":0,"explain":"<strong>Correct.</strong> Pretexting is the use of a fabricated but believable story or identity to gain a victim's trust and extract information or access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Baiting</b>: relies on a tempting physical or digital lure rather than a crafted false scenario.</span><span class='qd'><b>Tailgating</b>: is a physical entry technique following an authorized person.</span><span class='qd'><b>Smishing</b>: is phishing delivered through SMS text messages.</span>"},{"id":"D5-050","domain":5,"obj":"5.4","diff":"hard","q":"Why is building a strong security culture considered more effective than relying only on occasional mandatory training?","options":["It eliminates the need for any technical controls","It makes secure behavior a shared, ongoing habit rather than a once-a-year checkbox","It guarantees that no employee will ever make a mistake","It allows the organization to skip all policies"],"answer":1,"explain":"<strong>Correct.</strong> A strong security culture embeds secure behavior into everyday work as a continuous shared value, which is more durable than infrequent compliance-driven training.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It eliminates the need for any technical controls</b>: is false; culture complements but does not replace technical safeguards.</span><span class='qd'><b>It guarantees that no employee will ever make a mistake</b>: overstates the benefit, since culture reduces but cannot eliminate human error.</span><span class='qd'><b>It allows the organization to skip all policies</b>: is incorrect; a healthy culture reinforces policies rather than removing them.</span>"},{"id":"D5-051","domain":5,"obj":"5.1","diff":"easy","q":"Which type of cryptography uses the same key to both encrypt and decrypt data?","options":["Asymmetric cryptography","Public key cryptography","Symmetric cryptography","Hashing"],"answer":2,"explain":"<strong>Correct.</strong> Symmetric cryptography uses a single shared secret key for both encryption and decryption, which makes it fast but requires secure key distribution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asymmetric cryptography</b>: uses a key pair (public and private), not one shared key.</span><span class='qd'><b>Public key cryptography</b>: is another name for asymmetric cryptography, which uses two different keys.</span><span class='qd'><b>Hashing</b>: is a one-way function and does not decrypt anything, so it uses no key for reversal.</span>"},{"id":"D5-052","domain":5,"obj":"5.1","diff":"easy","q":"Which algorithm is the modern symmetric block cipher recommended as the standard for protecting data?","options":["DES","RSA","MD5","AES"],"answer":3,"explain":"<strong>Correct.</strong> AES (Advanced Encryption Standard) is the current symmetric block cipher standard, supporting 128, 192, and 256-bit keys, and replaced the aging DES.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DES</b>: uses a 56-bit key that is now considered insecure and obsolete.</span><span class='qd'><b>RSA</b>: is an asymmetric algorithm used for key exchange and signatures, not a symmetric block cipher.</span><span class='qd'><b>MD5</b>: is a hashing algorithm, not an encryption cipher.</span>"},{"id":"D5-053","domain":5,"obj":"5.1","diff":"medium","q":"A developer needs two parties who have never met to securely agree on a shared secret over an untrusted network. Which algorithm is specifically designed for this key exchange?","options":["Diffie-Hellman","SHA-256","3DES","AES"],"answer":0,"explain":"<strong>Correct.</strong> Diffie-Hellman is a key exchange algorithm that lets two parties derive a shared secret over an insecure channel without ever transmitting the secret itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AES</b>: encrypts data with an already-shared key but does not establish the key.</span><span class='qd'><b>SHA-256</b>: is a hashing algorithm and cannot exchange keys.</span><span class='qd'><b>3DES</b>: is a symmetric cipher that also assumes the key is already shared.</span>"},{"id":"D5-054","domain":5,"obj":"5.1","diff":"medium","q":"An organization wants strong asymmetric security on mobile devices using much smaller key sizes to save processing power and battery. Which algorithm best fits this requirement?","options":["RSA","ECC","HMAC","DES"],"answer":1,"explain":"<strong>Correct.</strong> ECC (Elliptic Curve Cryptography) provides asymmetric security equivalent to RSA but with far smaller keys, making it efficient for mobile and low-power devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RSA</b>: is asymmetric but requires much larger keys for the same security level.</span><span class='qd'><b>DES</b>: is a weak symmetric cipher, not asymmetric.</span><span class='qd'><b>HMAC</b>: is a keyed hashing mechanism for integrity, not an asymmetric cipher.</span>"},{"id":"D5-055","domain":5,"obj":"5.1","diff":"easy","q":"What is the primary security purpose of a hashing algorithm such as SHA-256?","options":["To encrypt data so it can be decrypted later","To exchange secret keys","To verify the integrity of data","To compress files for storage"],"answer":2,"explain":"<strong>Correct.</strong> Hashing produces a fixed-length, one-way digest used to verify that data has not been altered, providing integrity assurance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt data so it can be decrypted later</b>: describes reversible encryption, but hashing is one-way and cannot be reversed.</span><span class='qd'><b>To exchange secret keys</b>: is the role of key exchange algorithms like Diffie-Hellman.</span><span class='qd'><b>To compress files for storage</b>: hashing does not reconstruct the original data, so it is not compression.</span>"},{"id":"D5-056","domain":5,"obj":"5.1","diff":"medium","q":"Why is a random salt added to a password before it is hashed and stored?","options":["To make the hash reversible if needed","To encrypt the password with a shared key","To compress the password for storage","To defend against precomputed rainbow table attacks"],"answer":3,"explain":"<strong>Correct.</strong> A unique random salt ensures identical passwords produce different hashes, defeating precomputed rainbow tables and forcing attackers to crack each hash individually.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the hash reversible if needed</b>: salting does not make a hash reversible; hashing remains one-way.</span><span class='qd'><b>To compress the password for storage</b>: salting adds data and is unrelated to compression.</span><span class='qd'><b>To encrypt the password with a shared key</b>: a salt is not a key and hashing is not encryption.</span>"},{"id":"D5-057","domain":5,"obj":"5.1","diff":"hard","q":"A recipient verifies a digital signature on a message using the sender's public key and it validates. Which security services does this primarily provide?","options":["Integrity and authentication of the sender","Confidentiality and availability","Encryption of the message body","Key exchange and compression"],"answer":0,"explain":"<strong>Correct.</strong> A digital signature is created with the sender's private key and verified with the public key, proving the message was not altered (integrity) and confirming who sent it (authentication and non-repudiation).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality and availability</b>: a signature does not hide the message contents or ensure uptime.</span><span class='qd'><b>Encryption of the message body</b>: signing hashes and signs the message but does not by itself encrypt the body.</span><span class='qd'><b>Key exchange and compression</b>: signatures neither exchange keys nor compress data.</span>"},{"id":"D5-058","domain":5,"obj":"5.1","diff":"medium","q":"Files stored on a server's disk drives that are not currently being accessed or transmitted are an example of which data state?","options":["Data in transit","Data at rest","Data in use","Data in motion"],"answer":1,"explain":"<strong>Correct.</strong> Data at rest is information stored on a medium such as a disk, database, or backup tape and is commonly protected by encryption like full-disk encryption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data in transit</b>: refers to data actively moving across a network.</span><span class='qd'><b>Data in use</b>: refers to data being actively processed in memory by an application.</span><span class='qd'><b>Data in motion</b>: is another term for data in transit, not data sitting on disk.</span>"},{"id":"D5-059","domain":5,"obj":"5.1","diff":"medium","q":"A user submits a credit card number through a website and you want to protect that number while it travels from the browser to the server. Which control most directly protects this data in transit?","options":["Full-disk encryption","Degaussing","TLS","Data classification"],"answer":2,"explain":"<strong>Correct.</strong> TLS (Transport Layer Security) encrypts data as it moves across the network between client and server, protecting it from interception in transit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full-disk encryption</b>: protects data at rest on a drive, not data crossing the network.</span><span class='qd'><b>Degaussing</b>: is a media sanitization technique, not a transmission protection.</span><span class='qd'><b>Data classification</b>: labels data sensitivity but does not encrypt the connection.</span>"},{"id":"D5-060","domain":5,"obj":"5.1","diff":"easy","q":"Full-disk encryption (FDE) on a laptop is primarily intended to protect data in which state?","options":["Data in transit","Data being printed","Data in use","Data at rest"],"answer":3,"explain":"<strong>Correct.</strong> FDE encrypts the entire drive so that if the laptop is lost or stolen, the data at rest remains unreadable without the decryption key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data in transit</b>: is protected by network encryption such as TLS, not by FDE.</span><span class='qd'><b>Data in use</b>: is data in memory while the disk is unlocked and is not protected by FDE.</span><span class='qd'><b>Data being printed</b>: is an output process unrelated to disk encryption.</span>"},{"id":"D5-061","domain":5,"obj":"5.1","diff":"medium","q":"In a data classification scheme, which label is typically applied to information that can be freely released to anyone without harm to the organization?","options":["Public","Confidential","Restricted","Internal"],"answer":0,"explain":"<strong>Correct.</strong> Public data is information approved for unrestricted release, such as marketing material, where disclosure causes no harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Restricted</b>: is the most sensitive category whose disclosure could cause severe damage.</span><span class='qd'><b>Confidential</b>: is sensitive data limited to authorized parties.</span><span class='qd'><b>Internal</b>: is intended for employees only, not the general public.</span>"},{"id":"D5-062","domain":5,"obj":"5.1","diff":"hard","q":"In data governance, who is the individual accountable for classifying a data set and deciding who may access it, as opposed to the party who maintains and protects it day to day?","options":["The data custodian","The data owner","The end user","The data processor"],"answer":1,"explain":"<strong>Correct.</strong> The data owner is accountable for the data, including assigning its classification and authorizing access, while delegating hands-on protection to others.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data custodian</b>: implements and maintains the controls the owner specifies but does not set classification.</span><span class='qd'><b>The end user</b>: consumes the data under defined rules and does not own it.</span><span class='qd'><b>The data processor</b>: handles data on behalf of the owner but does not decide its classification.</span>"},{"id":"D5-063","domain":5,"obj":"5.1","diff":"medium","q":"Who is generally responsible for implementing and maintaining the technical controls that protect data, such as backups and access permissions, based on the owner's requirements?","options":["The data owner","The auditor","The data custodian","The regulator"],"answer":2,"explain":"<strong>Correct.</strong> The data custodian carries out the day-to-day technical protection of data, including backups, encryption, and enforcing access permissions defined by the owner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data owner</b>: sets requirements and classification but delegates the technical implementation.</span><span class='qd'><b>The auditor</b>: independently reviews controls rather than maintaining them.</span><span class='qd'><b>The regulator</b>: imposes external legal requirements but does not run the controls.</span>"},{"id":"D5-064","domain":5,"obj":"5.1","diff":"hard","q":"An organization must securely dispose of magnetic hard drives so that no residual data can ever be recovered. Which method uses a strong magnetic field to destroy the data on these drives?","options":["Reformatting","Overwriting","Encryption","Degaussing"],"answer":3,"explain":"<strong>Correct.</strong> Degaussing applies a powerful magnetic field that scrambles the magnetic domains on a hard drive or tape, rendering the data unrecoverable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Overwriting</b>: replaces data with new patterns but may leave remnants and does not work on damaged drives.</span><span class='qd'><b>Encryption</b>: protects confidentiality but does not destroy the stored data.</span><span class='qd'><b>Reformatting</b>: rebuilds file structures while leaving the underlying data largely recoverable.</span>"},{"id":"D5-065","domain":5,"obj":"5.1","diff":"hard","q":"Which sequence correctly represents an early-to-late ordering of stages in the data life cycle?","options":["Create, store, use, destroy","Destroy, store, create, use","Use, create, archive, store","Store, destroy, create, use"],"answer":0,"explain":"<strong>Correct.</strong> The data life cycle moves from creation through storage and use, and ends with secure destruction, so create, store, use, destroy is a valid ordering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Destroy, store, create, use</b>: places destruction first, which is illogical since data must exist before it can be destroyed.</span><span class='qd'><b>Use, create, archive, store</b>: puts use before creation, which cannot happen.</span><span class='qd'><b>Store, destroy, create, use</b>: destroys data before it is created and used.</span>"},{"id":"D5-066","domain":5,"obj":"5.1","diff":"easy","q":"3DES was developed mainly to address which weakness of the original DES algorithm?","options":["DES was too slow for modern hardware","DES had too small a key, making it vulnerable to brute force","DES could not encrypt text data","DES used asymmetric keys"],"answer":1,"explain":"<strong>Correct.</strong> 3DES (Triple DES) applies the DES cipher three times to effectively increase the key length, mitigating the brute-force vulnerability of DES's short 56-bit key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DES was too slow for modern hardware</b>: 3DES is actually slower, not faster, so speed was not the driver.</span><span class='qd'><b>DES could not encrypt text data</b>: DES could encrypt any binary data including text.</span><span class='qd'><b>DES used asymmetric keys</b>: DES is symmetric, and 3DES remained symmetric as well.</span>"},{"id":"D5-067","domain":5,"obj":"5.1","diff":"medium","q":"A security analyst wants to confirm that a downloaded file's contents are identical to the original publisher's copy. Which technique is most appropriate?","options":["Use Diffie-Hellman to exchange the file","Encrypt the file with AES and compare ciphertext","Compare a SHA-256 hash of the file against the published hash","Apply full-disk encryption to the file"],"answer":2,"explain":"<strong>Correct.</strong> Computing a SHA-256 hash and comparing it to the publisher's posted value confirms the file was not altered, since any change produces a completely different hash.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt the file with AES and compare ciphertext</b>: encryption does not verify integrity against an original source.</span><span class='qd'><b>Use Diffie-Hellman to exchange the file</b>: Diffie-Hellman exchanges keys, not files, and proves nothing about integrity.</span><span class='qd'><b>Apply full-disk encryption to the file</b>: FDE protects storage confidentiality, not content verification.</span>"},{"id":"D5-068","domain":5,"obj":"5.1","diff":"easy","q":"What does HMAC add beyond a plain hash like SHA-256 when verifying a message?","options":["It compresses the message before sending","It exchanges public keys between parties","It encrypts the message body for confidentiality","It uses a secret key so only key holders can produce or verify the value"],"answer":3,"explain":"<strong>Correct.</strong> HMAC combines a hash function with a secret key, providing both integrity and authentication because only parties holding the key can generate a valid code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It compresses the message before sending</b>: HMAC does not compress data.</span><span class='qd'><b>It encrypts the message body for confidentiality</b>: HMAC protects integrity and authenticity, not confidentiality of the message.</span><span class='qd'><b>It exchanges public keys between parties</b>: HMAC uses a pre-shared secret, not public key exchange.</span>"},{"id":"D5-069","domain":5,"obj":"5.1","diff":"easy","q":"Why is MD5 no longer recommended for security purposes such as verifying integrity of sensitive data?","options":["It is vulnerable to collisions where different inputs produce the same hash","It is too slow to compute","It requires a public and private key pair","It can only hash numbers"],"answer":0,"explain":"<strong>Correct.</strong> MD5 is considered cryptographically broken because attackers can engineer collisions, allowing two different inputs to share the same hash and undermining integrity assurance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is too slow to compute</b>: MD5 is actually fast; speed is not the issue.</span><span class='qd'><b>It requires a public and private key pair</b>: MD5 is a keyless hash, not an asymmetric algorithm.</span><span class='qd'><b>It can only hash numbers</b>: MD5 hashes any binary input, not just numbers.</span>"},{"id":"D5-070","domain":5,"obj":"5.1","diff":"medium","q":"A bank labels customer account records so that disclosure would cause serious harm and restricts them to authorized employees only. Which classification level best fits this data?","options":["Public","Confidential","Internal","Unclassified"],"answer":1,"explain":"<strong>Correct.</strong> Confidential applies to sensitive information whose unauthorized disclosure could cause significant harm and which is limited to specifically authorized parties.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public</b>: is for data approved for unrestricted release.</span><span class='qd'><b>Internal</b>: is for routine employee-only data with lower sensitivity than account records.</span><span class='qd'><b>Unclassified</b>: indicates no sensitivity controls are required.</span>"},{"id":"D5-071","domain":5,"obj":"5.2","diff":"easy","q":"What is a security baseline in the context of system hardening?","options":["A backup taken before a change","The fastest possible boot configuration","A documented standard minimum security configuration for a system","A list of all installed applications"],"answer":2,"explain":"<strong>Correct.</strong> A baseline defines the minimum, approved security configuration that systems must meet, providing a consistent standard to harden against.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A backup taken before a change</b>: describes a rollback point, not a configuration standard.</span><span class='qd'><b>The fastest possible boot configuration</b>: relates to performance, not security configuration.</span><span class='qd'><b>A list of all installed applications</b>: is an inventory, not a security standard.</span>"},{"id":"D5-072","domain":5,"obj":"5.2","diff":"medium","q":"An administrator builds a single fully patched and hardened operating system image and deploys clones of it to all new workstations. What is this preconfigured template called?","options":["A rainbow table","A baseline backup","A change request","A golden image"],"answer":3,"explain":"<strong>Correct.</strong> A golden image is a master, hardened, preconfigured template that is cloned to deploy consistent, secure systems quickly across an organization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A rainbow table</b>: is a precomputed hash table used in password cracking, unrelated to deployment.</span><span class='qd'><b>A baseline backup</b>: is a saved copy for recovery, not a deployment template.</span><span class='qd'><b>A change request</b>: is a formal proposal to make a change, not an OS image.</span>"},{"id":"D5-073","domain":5,"obj":"5.2","diff":"medium","q":"During hardening, why should administrators disable default accounts and change default passwords on a new device?","options":["Because default credentials are widely known and commonly exploited by attackers","To improve network throughput","To reduce the size of the operating system","To enable remote desktop by default"],"answer":0,"explain":"<strong>Correct.</strong> Default accounts and passwords are publicly documented for many products, so leaving them in place gives attackers an easy, well-known entry point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve network throughput</b>: credential changes do not affect performance.</span><span class='qd'><b>To reduce the size of the operating system</b>: disabling accounts does not shrink the OS.</span><span class='qd'><b>To enable remote desktop by default</b>: hardening typically disables unneeded remote services, not enables them.</span>"},{"id":"D5-074","domain":5,"obj":"5.2","diff":"easy","q":"As part of hardening a web server, why should an administrator disable services and ports that the server does not need?","options":["To increase the number of available user accounts","To reduce the system's attack surface","To make patching unnecessary","To improve screen resolution"],"answer":1,"explain":"<strong>Correct.</strong> Removing unneeded services and closing unused ports reduces the attack surface, leaving fewer entry points an attacker could exploit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase the number of available user accounts</b>: disabling services does not add accounts.</span><span class='qd'><b>To make patching unnecessary</b>: remaining services still require patching.</span><span class='qd'><b>To improve screen resolution</b>: this is unrelated to display settings.</span>"},{"id":"D5-075","domain":5,"obj":"5.2","diff":"easy","q":"What is the primary security purpose of applying vendor patches to systems promptly?","options":["To add new user-facing features only","To increase disk space","To remediate known vulnerabilities before they can be exploited","To change the desktop theme"],"answer":2,"explain":"<strong>Correct.</strong> Patching closes known security vulnerabilities, reducing the window during which attackers can exploit them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To add new user-facing features only</b>: feature updates are secondary; security fixes are the core purpose.</span><span class='qd'><b>To increase disk space</b>: patches typically consume space rather than free it.</span><span class='qd'><b>To change the desktop theme</b>: patching is unrelated to cosmetic settings.</span>"},{"id":"D5-076","domain":5,"obj":"5.2","diff":"hard","q":"A company discovers that its servers have drifted from their approved secure settings over time. Which practice would best detect and correct this drift on an ongoing basis?","options":["Degaussing the drives","Sending more phishing simulations","Issuing a new acceptable use policy","Configuration management against an established baseline"],"answer":3,"explain":"<strong>Correct.</strong> Configuration management continuously tracks systems against an approved baseline, detecting configuration drift and bringing systems back into a known secure state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sending more phishing simulations</b>: tests user awareness but does not manage server configurations.</span><span class='qd'><b>Issuing a new acceptable use policy</b>: governs user behavior, not technical configuration drift.</span><span class='qd'><b>Degaussing the drives</b>: destroys data and is a disposal method, not a configuration control.</span>"},{"id":"D5-077","domain":5,"obj":"5.2","diff":"medium","q":"Which of the following is the best example of reducing attack surface through hardening?","options":["Uninstalling software and disabling services that are not required","Installing every optional feature in case it is needed later","Granting all users administrator rights for convenience","Leaving default sample accounts enabled"],"answer":0,"explain":"<strong>Correct.</strong> Removing unnecessary software and disabling unused services minimizes the number of potential entry points, directly shrinking the attack surface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Installing every optional feature in case it is needed later</b>: adds unused components that expand the attack surface.</span><span class='qd'><b>Granting all users administrator rights for convenience</b>: increases risk by violating least privilege.</span><span class='qd'><b>Leaving default sample accounts enabled</b>: keeps well-known credentials available to attackers.</span>"},{"id":"D5-078","domain":5,"obj":"5.2","diff":"medium","q":"An organization wants to ensure every newly deployed laptop starts from an identical, known-secure state. Which approach best achieves this consistency?","options":["Let each technician configure laptops manually","Deploy from a standardized hardened golden image","Disable all logging to save resources","Allow users to install their own operating systems"],"answer":1,"explain":"<strong>Correct.</strong> Deploying from a standardized hardened golden image guarantees every laptop begins in the same known-secure configuration, reducing errors and drift.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let each technician configure laptops manually</b>: invites inconsistency and configuration mistakes.</span><span class='qd'><b>Disable all logging to save resources</b>: weakens security monitoring and is not a deployment standard.</span><span class='qd'><b>Allow users to install their own operating systems</b>: removes control and consistency entirely.</span>"},{"id":"D5-079","domain":5,"obj":"5.2","diff":"hard","q":"Before deploying a critical security patch to all production servers, which step best reduces the risk that the patch causes an unexpected outage?","options":["Deploy directly to all servers at once for speed","Skip the patch if any server is busy","Test the patch in a representative non-production environment first","Disable the antivirus before patching"],"answer":2,"explain":"<strong>Correct.</strong> Testing a patch in a representative non-production environment first reveals compatibility or stability problems before they can impact production systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deploy directly to all servers at once for speed</b>: risks a simultaneous outage across the environment if the patch is faulty.</span><span class='qd'><b>Skip the patch if any server is busy</b>: leaves known vulnerabilities unpatched.</span><span class='qd'><b>Disable the antivirus before patching</b>: needlessly removes protection and does not test the patch.</span>"},{"id":"D5-080","domain":5,"obj":"5.2","diff":"easy","q":"Configuration management primarily helps an organization by doing what?","options":["Encrypting all network traffic automatically","Physically shredding old hard drives","Training employees to recognize phishing","Maintaining systems in a known, documented, and consistent state"],"answer":3,"explain":"<strong>Correct.</strong> Configuration management keeps systems in a known, documented, and consistent state, making changes controlled and deviations detectable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting all network traffic automatically</b>: is a transport security function, not configuration management.</span><span class='qd'><b>Training employees to recognize phishing</b>: is a security awareness activity.</span><span class='qd'><b>Physically shredding old hard drives</b>: is media sanitization, not configuration control.</span>"},{"id":"D5-081","domain":5,"obj":"5.3","diff":"easy","q":"Which policy defines what employees are permitted and prohibited to do when using company computers and networks?","options":["Acceptable Use Policy (AUP)","Disaster recovery plan","Change management policy","Data classification policy"],"answer":0,"explain":"<strong>Correct.</strong> An Acceptable Use Policy (AUP) sets the rules for proper use of organizational systems and networks, defining what is allowed and forbidden.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disaster recovery plan</b>: addresses restoring operations after a disruption, not daily usage rules.</span><span class='qd'><b>Change management policy</b>: governs how changes are reviewed and approved.</span><span class='qd'><b>Data classification policy</b>: defines sensitivity labels, not acceptable use.</span>"},{"id":"D5-082","domain":5,"obj":"5.3","diff":"easy","q":"An organization allows employees to use their personal smartphones to access corporate email. Which policy specifically governs the security requirements for this arrangement?","options":["Acceptable Use Policy only","BYOD policy","Disaster recovery policy","Public data policy"],"answer":1,"explain":"<strong>Correct.</strong> A BYOD (Bring Your Own Device) policy defines the security requirements and controls for personal devices accessing corporate resources, often enforced through MDM.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Acceptable Use Policy only</b>: covers general usage but does not specifically address personal device controls.</span><span class='qd'><b>Disaster recovery policy</b>: concerns recovery after incidents, not personal device access.</span><span class='qd'><b>Public data policy</b>: deals with handling of public information, not devices.</span>"},{"id":"D5-083","domain":5,"obj":"5.3","diff":"medium","q":"Which technology is most commonly used to enforce security settings, require encryption, and enable remote wipe on employee mobile devices?","options":["Degaussing","HMAC","MDM (Mobile Device Management)","Golden image"],"answer":2,"explain":"<strong>Correct.</strong> Mobile Device Management (MDM) lets administrators enforce policies, require encryption, and remotely wipe mobile devices, supporting secure BYOD and corporate mobility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HMAC</b>: is a message authentication mechanism, not device management.</span><span class='qd'><b>Degaussing</b>: erases magnetic media and cannot manage mobile policy.</span><span class='qd'><b>Golden image</b>: is a deployment template, not a device management platform.</span>"},{"id":"D5-084","domain":5,"obj":"5.3","diff":"easy","q":"A change management process requires that every proposed change first be submitted formally and reviewed by a board before implementation. What is the body that reviews and approves these changes commonly called?","options":["Help Desk","Incident Response Team","Data Owner Council","Change Advisory Board (CAB)"],"answer":3,"explain":"<strong>Correct.</strong> The Change Advisory Board (CAB) reviews, evaluates, and approves or rejects proposed changes, helping ensure changes are controlled and low-risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incident Response Team</b>: handles security incidents, not routine change approvals.</span><span class='qd'><b>Data Owner Council</b>: is not the standard body responsible for change approval.</span><span class='qd'><b>Help Desk</b>: provides user support and does not authorize changes.</span>"},{"id":"D5-085","domain":5,"obj":"5.3","diff":"medium","q":"In a formal change management process, what is the purpose of documenting a rollback plan before applying a change?","options":["To provide a way to restore the prior state if the change fails","To permanently remove the old configuration","To skip testing the change","To classify the data involved"],"answer":0,"explain":"<strong>Correct.</strong> A rollback plan documents how to revert to the previous working state if a change causes problems, limiting downtime and impact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To permanently remove the old configuration</b>: a rollback plan preserves, rather than deletes, the ability to return to the old state.</span><span class='qd'><b>To skip testing the change</b>: rollback planning complements testing, it does not replace it.</span><span class='qd'><b>To classify the data involved</b>: data classification is a separate activity.</span>"},{"id":"D5-086","domain":5,"obj":"5.3","diff":"easy","q":"What is the primary purpose of a password policy?","options":["To define the layout of the corporate network","To establish requirements for password strength, expiration, and reuse","To list approved software vendors","To schedule data backups"],"answer":1,"explain":"<strong>Correct.</strong> A password policy sets requirements such as minimum length, complexity, expiration, and reuse restrictions to strengthen authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To define the layout of the corporate network</b>: that is network design documentation, not password policy.</span><span class='qd'><b>To list approved software vendors</b>: belongs to procurement or vendor policy.</span><span class='qd'><b>To schedule data backups</b>: is governed by backup or continuity policy.</span>"},{"id":"D5-087","domain":5,"obj":"5.3","diff":"medium","q":"A formal request to add, modify, or remove something in the IT environment, submitted for review and approval, is known as what?","options":["A rollback","A baseline","A Request for Change (RFC)","A salt"],"answer":2,"explain":"<strong>Correct.</strong> A Request for Change (RFC) is the formal document submitted into the change management process to propose a change for review and approval.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A rollback</b>: is the action of reverting a change, not the request to make one.</span><span class='qd'><b>A baseline</b>: is a standard configuration, not a change request.</span><span class='qd'><b>A salt</b>: is random data added before hashing, unrelated to change management.</span>"},{"id":"D5-088","domain":5,"obj":"5.3","diff":"hard","q":"A privacy policy at an organization most directly addresses which of the following?","options":["The schedule for replacing keyboards","The maximum CPU temperature for servers","Which switches connect to which routers","How the organization collects, uses, and protects personal information"],"answer":3,"explain":"<strong>Correct.</strong> A privacy policy describes how the organization collects, uses, shares, and protects personal information, supporting compliance and individual rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The maximum CPU temperature for servers</b>: is an environmental or facilities concern.</span><span class='qd'><b>Which switches connect to which routers</b>: is network topology documentation.</span><span class='qd'><b>The schedule for replacing keyboards</b>: is an asset maintenance matter, not privacy.</span>"},{"id":"D5-089","domain":5,"obj":"5.3","diff":"medium","q":"A data handling policy would most likely specify which of the following?","options":["How data should be labeled, stored, transmitted, and destroyed according to its classification","The brand of firewall to purchase","The hours the cafeteria is open","The color scheme of the company website"],"answer":0,"explain":"<strong>Correct.</strong> A data handling policy defines how information at each classification level must be labeled, stored, transmitted, retained, and destroyed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The brand of firewall to purchase</b>: is a procurement decision, not data handling guidance.</span><span class='qd'><b>The hours the cafeteria is open</b>: is unrelated to information security.</span><span class='qd'><b>The color scheme of the company website</b>: is a branding concern.</span>"},{"id":"D5-090","domain":5,"obj":"5.3","diff":"hard","q":"An administrator wants to push an urgent firewall rule change directly to production without submitting it through the change process. From a governance standpoint, why is this a problem?","options":["It is always faster and therefore preferred","It bypasses review, testing, and rollback planning, increasing the risk of an unreviewed harmful change","Change management only applies to hardware, not firewall rules","Firewall rules cannot be rolled back so review is pointless"],"answer":1,"explain":"<strong>Correct.</strong> Skipping the change process removes the safeguards of peer review, testing, and rollback planning, raising the risk that an unvetted change causes an outage or security gap.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is always faster and therefore preferred</b>: speed does not justify abandoning controls that prevent harmful changes.</span><span class='qd'><b>Change management only applies to hardware, not firewall rules</b>: change management covers configuration changes including firewall rules.</span><span class='qd'><b>Firewall rules cannot be rolled back so review is pointless</b>: firewall changes can typically be reverted, and review still matters.</span>"},{"id":"D5-091","domain":5,"obj":"5.4","diff":"easy","q":"An attacker sends a mass email pretending to be a bank, urging recipients to click a link and enter their credentials. Which social engineering attack is this?","options":["Degaussing","Tailgating","Phishing","Patching"],"answer":2,"explain":"<strong>Correct.</strong> Phishing uses fraudulent mass emails impersonating trusted entities to trick recipients into revealing credentials or clicking malicious links.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tailgating</b>: is a physical attack of following someone through a secure door.</span><span class='qd'><b>Degaussing</b>: is a media sanitization method, not an attack.</span><span class='qd'><b>Patching</b>: is a defensive maintenance activity, not an attack.</span>"},{"id":"D5-092","domain":5,"obj":"5.4","diff":"easy","q":"An attacker researches a specific finance manager and sends a personalized, convincing email referencing real projects to trick that individual. Which attack does this describe?","options":["Generic phishing","Baiting","Smishing","Spear phishing"],"answer":3,"explain":"<strong>Correct.</strong> Spear phishing targets a specific individual with personalized details gathered through research, making the message far more convincing than generic phishing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generic phishing</b>: is sent broadly without personalization to a specific person.</span><span class='qd'><b>Smishing</b>: is phishing conducted over SMS text messages.</span><span class='qd'><b>Baiting</b>: lures victims with a tempting item such as an infected USB drive.</span>"},{"id":"D5-093","domain":5,"obj":"5.4","diff":"hard","q":"An attacker specifically targets a company's CEO with a tailored fraudulent message to authorize a large wire transfer. This high-value targeting of a senior executive is best known as what?","options":["Whaling","Tailgating","Smishing","Vishing"],"answer":0,"explain":"<strong>Correct.</strong> Whaling is a form of spear phishing aimed at high-profile, high-value targets such as executives, often to authorize fraudulent payments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Vishing</b>: is voice phishing conducted over the phone, not specific to executives.</span><span class='qd'><b>Tailgating</b>: is unauthorized physical entry by following an authorized person.</span><span class='qd'><b>Smishing</b>: is phishing delivered via SMS text messages.</span>"},{"id":"D5-094","domain":5,"obj":"5.4","diff":"medium","q":"An employee receives a phone call from someone claiming to be IT support, asking them to read out their password to fix an account. Which social engineering technique is being used?","options":["Baiting","Vishing","FDE","Tailgating"],"answer":1,"explain":"<strong>Correct.</strong> Vishing (voice phishing) uses phone calls in which the attacker impersonates a trusted party to extract sensitive information such as passwords.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Baiting</b>: relies on a tempting physical or digital lure rather than a phone call.</span><span class='qd'><b>FDE</b>: is full-disk encryption, a defensive control, not an attack.</span><span class='qd'><b>Tailgating</b>: is a physical entry attack, not a phone-based one.</span>"},{"id":"D5-095","domain":5,"obj":"5.4","diff":"medium","q":"A user gets a text message claiming a package delivery failed and asking them to tap a link to reschedule, which leads to a credential-harvesting site. What is this attack called?","options":["Whaling","Pretexting","Smishing","Degaussing"],"answer":2,"explain":"<strong>Correct.</strong> Smishing is phishing delivered through SMS text messages, luring victims to malicious links or to disclose information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whaling</b>: targets senior executives, typically by email, not via generic SMS lures.</span><span class='qd'><b>Pretexting</b>: builds a fabricated scenario to gain trust, often over a conversation rather than a single text link.</span><span class='qd'><b>Degaussing</b>: is a data destruction method, not an attack.</span>"},{"id":"D5-096","domain":5,"obj":"5.4","diff":"hard","q":"An attacker calls an employee posing as a new auditor and invents a detailed but false backstory to convince the employee to share confidential records. Which technique best describes inventing this fabricated scenario to build trust?","options":["Tailgating","Baiting","Phishing simulation","Pretexting"],"answer":3,"explain":"<strong>Correct.</strong> Pretexting involves creating a fabricated but believable scenario or identity to manipulate a target into divulging information or granting access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tailgating</b>: is physically following someone into a restricted area, not inventing a story.</span><span class='qd'><b>Baiting</b>: lures victims with a tempting item rather than a fabricated narrative.</span><span class='qd'><b>Phishing simulation</b>: is a defensive training exercise, not an attacker technique.</span>"},{"id":"D5-097","domain":5,"obj":"5.4","diff":"medium","q":"An attacker leaves USB flash drives labeled 'Payroll' in a company parking lot, hoping employees will plug them into work computers. Which social engineering technique is this?","options":["Baiting","Whaling","Salting","Vishing"],"answer":0,"explain":"<strong>Correct.</strong> Baiting tempts victims with an enticing item, such as a malware-laden USB drive, relying on curiosity to compromise systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Vishing</b>: uses phone calls, not physical bait.</span><span class='qd'><b>Whaling</b>: targets executives via tailored messages.</span><span class='qd'><b>Salting</b>: is a cryptographic technique added to passwords, not an attack.</span>"},{"id":"D5-098","domain":5,"obj":"5.4","diff":"medium","q":"An unauthorized person closely follows an employee through a badge-controlled door before it closes, without presenting their own credentials. This physical attack is known as what?","options":["Smishing","Tailgating","Pretexting","Phishing"],"answer":1,"explain":"<strong>Correct.</strong> Tailgating is gaining physical entry to a restricted area by closely following an authorized person through a controlled door.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Smishing</b>: is an SMS-based phishing attack, not physical entry.</span><span class='qd'><b>Pretexting</b>: relies on a fabricated story rather than physical following.</span><span class='qd'><b>Phishing</b>: is an email-based deception, not a physical access attack.</span>"},{"id":"D5-099","domain":5,"obj":"5.4","diff":"hard","q":"A security team periodically sends fake phishing emails to employees and tracks who clicks. What is the primary purpose of these phishing simulations?","options":["To punish employees who fail","To harvest employee passwords for IT","To measure and reinforce employee awareness of phishing in a safe way","To replace technical email filtering"],"answer":2,"explain":"<strong>Correct.</strong> Phishing simulations safely test and reinforce user awareness, identifying who needs more training and reducing the chance of a real compromise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To punish employees who fail</b>: the goal is education and improvement, not punishment.</span><span class='qd'><b>To harvest employee passwords for IT</b>: simulations are not meant to collect real credentials.</span><span class='qd'><b>To replace technical email filtering</b>: simulations complement, but do not replace, technical controls.</span>"},{"id":"D5-100","domain":5,"obj":"5.4","diff":"hard","q":"In a security learning program, which best distinguishes awareness from training?","options":["Awareness develops deep expertise, while training only raises general attention","Awareness is only for executives, while training is only for IT staff","Awareness and training are identical terms","Awareness raises general attention to security issues, while training builds specific job-related skills"],"answer":3,"explain":"<strong>Correct.</strong> Awareness keeps security top of mind for everyone at a general level, while training teaches specific skills needed to perform security-relevant tasks; education goes further toward deep expertise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Awareness develops deep expertise, while training only raises general attention</b>: this reverses the roles; deep expertise aligns with education, not awareness.</span><span class='qd'><b>Awareness and training are identical terms</b>: they are distinct levels with different goals.</span><span class='qd'><b>Awareness is only for executives, while training is only for IT staff</b>: awareness applies to all staff, not just executives.</span>"}];
ISC2CC.pbqs = [{"id":"P1-01","format":1,"domain":3,"title":"Assign the Correct Account Type","brief":"A small clinic is creating identities in its new directory. For each subject below, pick the account type that best fits its purpose under the principle of least privilege.","exhibit":"Subjects to provision:\n - Dr. Lopez (logs in daily to chart patient visits)\n - The nightly database backup process\n - A front-desk kiosk that visitors use to sign in\n - Tom, an IT admin who patches the servers","summary":"Account type should match the function: ordinary humans get standard user accounts, automated processes get service accounts, public/temporary access uses guest accounts, and elevated maintenance work uses privileged accounts that are kept separate from daily-use accounts.","fields":[{"label":"Dr. Lopez, who logs in daily to chart patient visits, should receive which account type?","options":["Privileged account","Standard user account","Service account","Guest account"],"answer":1,"explain":"A clinician doing normal daily work needs only a standard user account; granting more would violate least privilege."},{"label":"The nightly database backup process should run under which account type?","options":["Service account","Standard user account","Guest account","Shared account"],"answer":0,"explain":"Automated, non-interactive processes should use a service account scoped only to the resources they need, not a human login."},{"label":"The front-desk kiosk used by visitors to sign in should use which account type?","options":["Privileged account","Service account","Guest account","Standard user account"],"answer":2,"explain":"A guest account provides limited, temporary access appropriate for untrusted visitors and exposes no sensitive resources."},{"label":"Tom patches and maintains the servers. What is the best practice for his elevated access?","options":["Use his daily standard account with admin rights added permanently","Use a shared admin login that all of IT knows","Use a separate privileged account only when performing admin tasks","Use a guest account for the maintenance window"],"answer":2,"explain":"Privileged access should live in a separate account used only when needed, keeping the high-risk credential out of everyday email and browsing."}]},{"id":"P1-02","format":1,"domain":3,"title":"Least Privilege: Allow or Deny","brief":"You administer a file server with these shares. For each request, decide ALLOW or DENY based strictly on least privilege (grant only what the job role requires).","exhibit":"Shares and their purpose:\n - \\Payroll  (salary data, used by Finance only)\n - \\Marketing (campaign assets, used by Marketing)\n - \\Public (company handbook, all staff)\nRequesters:\n - Ana: Finance analyst\n - Ben: Marketing designer\n - Carol: new intern (no role assigned yet)","summary":"Least privilege means a subject is allowed access only when its assigned role genuinely requires that object. When no business need exists, the correct default is to deny.","fields":[{"label":"Ana (Finance) requests read/write to \\Payroll. Decision?","options":["Allow","Deny"],"answer":0,"explain":"Finance is the defined owner-group of payroll data, so the access maps to a legitimate job requirement."},{"label":"Ben (Marketing) requests access to \\Payroll to 'see how budgets work'. Decision?","options":["Allow","Deny"],"answer":1,"explain":"Curiosity is not a business need; Marketing has no role requirement for salary data, so least privilege requires denial."},{"label":"Ben (Marketing) requests read/write to \\Marketing. Decision?","options":["Allow","Deny"],"answer":0,"explain":"The request matches his assigned role and the shares intended audience, so access is justified."},{"label":"Carol (intern, no role yet) requests access to \\Public. Decision?","options":["Allow","Deny"],"answer":0,"explain":"The Public share is intended for all staff and contains only the handbook, so granting it does not exceed least privilege."},{"label":"Carol (intern, no role yet) requests read access to \\Marketing. Decision?","options":["Allow","Deny"],"answer":1,"explain":"With no assigned role establishing a need, access to a department-specific share should be denied until a requirement is defined."}]},{"id":"P1-03","format":1,"domain":3,"title":"Separation of Duties","brief":"A finance workflow must be designed so that no single person can both create and approve a payment. Apply separation of duties to each scenario.","exhibit":"Process steps:\n 1. Create a vendor payment request\n 2. Approve the payment\n 3. Reconcile the bank statement\nPeople: Maria (clerk), Raj (manager), Sofia (auditor)","summary":"Separation of duties splits a sensitive transaction across multiple people so that fraud or error requires collusion. The person who initiates an action should not also be the one who approves or independently reviews it.","fields":[{"label":"Why is separation of duties applied to the payment process?","options":["To speed up payment processing","So no single person can complete a sensitive transaction alone","To reduce the number of employees needed","To let everyone access all financial systems"],"answer":1,"explain":"Separation of duties divides critical steps so that completing a fraudulent transaction would require collusion among multiple people."},{"label":"Maria created a vendor payment request. Who should approve it?","options":["Maria, since she knows the details","Raj, a different person with approval authority","No approval is needed if Maria is trusted","A shared approver account"],"answer":1,"explain":"The creator must not approve her own request; a separate authorized person (Raj) provides the independent control."},{"label":"Which assignment BEST preserves separation of duties for reconciliation?","options":["Maria reconciles the payments she created","Raj reconciles the payments he approved","Sofia, who neither created nor approved payments, reconciles","The bank reconciles itself automatically with no review"],"answer":2,"explain":"An independent party who was not involved in creating or approving the payment provides an unbiased reconciliation check."},{"label":"A manager asks for one super-account that can create, approve, AND reconcile to 'save time'. What is the correct response?","options":["Approve it; managers are trusted","Deny it; it would defeat separation of duties","Approve it but log the actions","Grant it only on weekends"],"answer":1,"explain":"Concentrating all conflicting duties in one account removes the control entirely, so the request must be denied regardless of trust."}]},{"id":"P1-04","format":1,"domain":3,"title":"Choose the Access Control Model","brief":"Match each organization to the access control model (DAC, MAC, RBAC, or ABAC) that its described behavior represents.","exhibit":"Models in scope:\n DAC  - owner decides who gets access\n MAC  - system enforces classification labels, users cannot override\n RBAC - access tied to job role\n ABAC - access decided by attributes (e.g., department, time, location)","summary":"Identify the model by what drives the decision: the resource owner (DAC), mandatory classification labels (MAC), the subjects assigned role (RBAC), or a policy combining multiple attributes (ABAC).","fields":[{"label":"A military system labels files Secret and Top Secret; the OS blocks access regardless of what users want. Which model?","options":["DAC","MAC","RBAC","ABAC"],"answer":1,"explain":"Mandatory Access Control enforces classification labels centrally; users cannot grant access that the labels forbid."},{"label":"On a shared drive, each file owner personally decides who may read or edit their files. Which model?","options":["DAC","MAC","RBAC","ABAC"],"answer":0,"explain":"Discretionary Access Control lets the resource owner decide and delegate access at their discretion."},{"label":"An HR app grants permissions automatically based on whether you are a 'Recruiter' or 'Manager'. Which model?","options":["DAC","MAC","RBAC","ABAC"],"answer":2,"explain":"Role-Based Access Control assigns permissions to roles, and users inherit them by holding that role."},{"label":"A policy allows access only if department=Finance AND time is business hours AND device is corporate. Which model?","options":["DAC","MAC","RBAC","ABAC"],"answer":3,"explain":"Attribute-Based Access Control evaluates multiple attributes of subject, resource, and environment to make the decision."}]},{"id":"P1-05","format":1,"domain":3,"title":"RBAC Role Assignment Matrix","brief":"A hospital uses RBAC. Each user should be granted permissions only through the role that matches their job. Pick the correct decision for each row.","exhibit":"Defined roles and permissions:\n - Nurse:    read/update patient charts\n - Billing:  read patient charts, edit invoices\n - Pharmacist: read charts, dispense medication\nUsers: Grace (nurse), Henry (billing clerk), Iris (pharmacist)","summary":"In RBAC, permissions flow from the role, not the individual. Requests are granted when they fall within the role definition and denied when they reach beyond it, even for trusted staff.","fields":[{"label":"Grace (Nurse) needs to update a patient chart. Decision?","options":["Allow via Nurse role","Deny"],"answer":0,"explain":"Updating charts is explicitly part of the Nurse role, so the permission is granted through that role."},{"label":"Henry (Billing) wants to edit a patients medication order. Decision?","options":["Allow","Deny"],"answer":1,"explain":"Dispensing or editing medication is not in the Billing role; RBAC grants nothing beyond the assigned roles permissions."},{"label":"Iris (Pharmacist) needs to dispense medication. Decision?","options":["Allow via Pharmacist role","Deny"],"answer":0,"explain":"Dispensing medication is a defined Pharmacist permission, so it is granted through that role."},{"label":"Henry (Billing) covers the front desk and asks to edit invoices. Decision?","options":["Allow via Billing role","Deny"],"answer":0,"explain":"Editing invoices is part of the Billing role, so the request is within his assigned permissions and is allowed."},{"label":"Grace (Nurse) is asked to edit invoices while Henry is on leave. Best RBAC practice?","options":["Quietly add invoice rights to her personal account","Deny; assign her the Billing role temporarily if a need is approved","Share Henrys login with Grace","Allow permanently just in case"],"answer":1,"explain":"RBAC handles coverage by formally granting the appropriate role, not by editing individual accounts or sharing credentials."}]},{"id":"P1-06","format":1,"domain":3,"title":"Authorization Principles in Practice","brief":"Identify the access-control or authorization principle that each situation illustrates.","exhibit":"Principles in scope:\n - Least privilege\n - Need to know\n - Default deny / implicit deny\n - Separation of duties\n - Privileged account management","summary":"These foundational principles often work together: least privilege limits scope, need-to-know restricts data exposure, default-deny blocks anything not explicitly allowed, separation of duties splits risky tasks, and privileged accounts are tightly controlled.","fields":[{"label":"A firewall rule set ends with a rule that blocks all traffic not explicitly permitted above it. This illustrates:","options":["Least privilege","Default deny (implicit deny)","Separation of duties","Need to know"],"answer":1,"explain":"A final catch-all block enforces default deny: anything not expressly allowed is rejected."},{"label":"An analyst has clearance for Secret data but is only shown the specific case files relevant to her investigation. This illustrates:","options":["Need to know","Default deny","Privileged account management","Separation of duties"],"answer":0,"explain":"Need to know restricts access to only the information required for a specific task, even when the user holds adequate clearance."},{"label":"Admins must check out the domain-admin credential from a vault, use it for a logged session, then it auto-rotates. This illustrates:","options":["Least privilege","Need to know","Privileged account management","Default deny"],"answer":2,"explain":"Vaulting, session logging, and credential rotation are hallmarks of privileged account (access) management."},{"label":"A new employee is given the minimum permissions to do her job and nothing more. This illustrates:","options":["Separation of duties","Least privilege","Default deny","Need to know"],"answer":1,"explain":"Granting only the minimum permissions required for the role is the definition of least privilege."}]},{"id":"P2-01","format":2,"domain":2,"title":"Repeated Login Failures","brief":"A SIEM rule fired on the corporate VPN gateway. Triage the authentication log and respond.","exhibit":"Jan 14 02:11:03 vpn-gw sshd: failed password for admin from 203.0.113.45 port 51002\nJan 14 02:11:05 vpn-gw sshd: failed password for admin from 203.0.113.45 port 51010\nJan 14 02:11:07 vpn-gw sshd: failed password for admin from 203.0.113.45 port 51018\nJan 14 02:11:09 vpn-gw sshd: failed password for root from 203.0.113.45 port 51026\nJan 14 02:11:11 vpn-gw sshd: failed password for root from 203.0.113.45 port 51034\nJan 14 02:11:13 vpn-gw sshd: failed password for guest from 203.0.113.45 port 51042","exhibitTitle":"auth.log","summary":"A single external IP generates many rapid failed logins against several usernames, with no successful login recorded.","fields":[{"label":"What event type does this log show?","options":["Brute-force login attempt","Phishing click","Port scan","Malware infection"],"answer":0,"explain":"Many rapid failed passwords from one source against multiple accounts is a classic brute-force (password guessing) attempt."},{"label":"What severity should you assign?","options":["Low - informational only","Medium - active attack, no success yet","Critical - data already exfiltrated"],"answer":1,"explain":"The attack is active and ongoing but no login succeeded, so it is a real threat that has not yet caused compromise - medium."},{"label":"What is the best first containment action?","options":["Restore the gateway from backup","Block the source IP 203.0.113.45 at the firewall","Email all users to change passwords","Rebuild the VPN server"],"answer":1,"explain":"Blocking the offending source IP immediately stops the active guessing while you investigate, without disrupting legitimate users.","hint":"Stop the attacker's traffic first."},{"label":"Which IR lifecycle phase are you in when the SIEM rule fires and you confirm the attack?","options":["Preparation","Detection and analysis","Post-incident activity"],"answer":1,"explain":"Recognizing alerts and confirming an event is occurring is the detection and analysis phase."}]},{"id":"P2-02","format":2,"domain":2,"title":"Endpoint Malware Alert","brief":"The EDR console raised an alert on a finance workstation. Triage and contain.","exhibit":"10:42 AV-ENGINE detected Trojan.GenericKD in C:\\Users\\jdoe\\Downloads\\invoice.exe\nQuarantine action failed - file locked by process pid 4821\n10:42 process invoice.exe spawned powershell with encoded command\n10:43 outbound connection to 198.51.100.7 port 443 from pid 4821\n10:43 registry run key added for persistence","exhibitTitle":"edr-alert.log","summary":"An executable disguised as an invoice ran, spawned PowerShell, added a persistence key, and is beaconing to an external host. Quarantine failed.","fields":[{"label":"What event type is this?","options":["Account compromise","Malware infection","Port scan","Denial of service"],"answer":1,"explain":"A malicious executable running, persisting, and beaconing out is an active malware infection."},{"label":"What severity should you assign?","options":["Low - quarantine handled it","High - active malware with persistence and C2","Informational"],"answer":1,"explain":"Quarantine failed and the malware is persisting and communicating with a command-and-control host - this is high severity."},{"label":"What is the best first containment action?","options":["Block port 443 for the whole company","Isolate the workstation from the network","Delete the Downloads folder","Ask the user to reboot"],"answer":1,"explain":"Isolating the host stops both the C2 beacon and any lateral spread while preserving the system for analysis.","hint":"Quarantine already failed - contain the whole host."},{"label":"After isolating and removing the malware, which phase verifies the host is clean before reconnecting?","options":["Preparation","Containment, eradication and recovery","Detection and analysis"],"answer":1,"explain":"Cleaning the malware and validating the system before returning it to service is part of containment, eradication and recovery."}]},{"id":"P2-03","format":2,"domain":2,"title":"Suspicious Inbound Email","brief":"A help-desk ticket reports a strange email. Review the mail gateway log and decide.","exhibit":"From: it-support@secure-acme-login.com\nSubject: Urgent - verify your account in 24 hours\nGateway: SPF softfail, DMARC none\nBody link: hxxp://secure-acme-login.com/reset?id=jdoe\n14:08 user jdoe clicked the link and submitted credentials","exhibitTitle":"mailgw.log","summary":"A spoofed-looking email with a credential-harvesting link reached a user, who clicked it and entered their password.","fields":[{"label":"What event type is this?","options":["Port scan","Phishing click leading to credential disclosure","Brute-force attack","Ransomware"],"answer":1,"explain":"A deceptive email tricked a user into clicking a fake link and submitting credentials - a phishing click with credential disclosure."},{"label":"What severity should you assign?","options":["Low - just spam","High - valid credentials were submitted to an attacker","Informational"],"answer":1,"explain":"The user actually entered credentials on the attacker site, so account takeover is now likely - high severity."},{"label":"What is the best first containment action?","options":["Disable or reset the affected user account credentials","Reimage every workstation","Block all email","Restore the mail server from backup"],"answer":0,"explain":"Because the user's password was disclosed, disabling or resetting that account prevents the attacker from logging in.","hint":"The credentials are the asset at risk."},{"label":"Which IR phase includes training users to recognize phishing so this is less likely?","options":["Preparation","Containment","Post-incident activity"],"answer":0,"explain":"Awareness training and readiness measures put in place before incidents occur belong to the preparation phase."}]},{"id":"P2-04","format":2,"domain":2,"title":"Firewall Port Sweep","brief":"The perimeter firewall flagged unusual connection attempts. Triage the log.","exhibit":"03:20:01 DENY tcp 192.0.2.66 to 10.0.0.5 port 21\n03:20:01 DENY tcp 192.0.2.66 to 10.0.0.5 port 22\n03:20:01 DENY tcp 192.0.2.66 to 10.0.0.5 port 23\n03:20:02 DENY tcp 192.0.2.66 to 10.0.0.5 port 25\n03:20:02 DENY tcp 192.0.2.66 to 10.0.0.5 port 80\n03:20:02 DENY tcp 192.0.2.66 to 10.0.0.5 port 443","exhibitTitle":"firewall.log","summary":"One external IP probes many sequential ports on a single internal host in under two seconds; all attempts are denied.","fields":[{"label":"What event type does this log show?","options":["Port scan / reconnaissance","Successful data breach","Phishing","Malware execution"],"answer":0,"explain":"One source touching many ports in sequence on a host is reconnaissance - a port scan probing for open services."},{"label":"What severity should you assign?","options":["Low to medium - reconnaissance, all denied","Critical - host already compromised","High - data exfiltrated"],"answer":0,"explain":"The firewall denied every attempt and no compromise occurred; scanning is early-stage recon, so low-to-medium severity."},{"label":"What is the best first containment action?","options":["Block the scanning source IP at the firewall","Shut down the internal host","Restore from backup","Reset all user passwords"],"answer":0,"explain":"Blocking the scanning IP stops the reconnaissance without disrupting the legitimately functioning internal host.","hint":"The traffic was already denied - just stop the source."},{"label":"Which IR phase are you in while reviewing this firewall log to confirm it is a scan?","options":["Preparation","Detection and analysis","Recovery"],"answer":1,"explain":"Examining log evidence to determine what is happening is the detection and analysis phase."}]},{"id":"P2-05","format":2,"domain":2,"title":"Unusual Account Activity","brief":"An identity alert fired for a sales account. Review the sign-in log and respond.","exhibit":"09:15 login success user msmith from 203.0.113.9 Lagos NG\n09:16 mailbox rule created - forward all mail to external address\n09:17 password changed by user msmith\n09:18 MFA device registered new phone\nNote: msmith normally signs in from Denver US and last did so 08:02","exhibitTitle":"identity.log","summary":"An account logs in from an unexpected country, then immediately creates a mail-forwarding rule, changes the password, and registers a new MFA device.","fields":[{"label":"What event type is this?","options":["Port scan","Account compromise / takeover","Phishing email delivered","Routine maintenance"],"answer":1,"explain":"A successful login from an anomalous location followed by attacker-style changes (forwarding rule, password change, new MFA) indicates the account is compromised."},{"label":"What severity should you assign?","options":["Low - user is just traveling","Critical - attacker controls the account and is locking out the owner","Informational"],"answer":1,"explain":"The attacker changed the password and added their own MFA device to lock out the real owner and set up persistence - critical."},{"label":"What is the best first containment action?","options":["Disable the compromised account and revoke its active sessions","Block port 443","Email the user a warning","Rebuild the mail server"],"answer":0,"explain":"Disabling the account and killing active sessions immediately removes the attacker's access; password reset alone is not enough once sessions exist.","hint":"The attacker is already inside the session."},{"label":"After containment, which phase reviews how the account was compromised to improve defenses?","options":["Preparation","Detection and analysis","Post-incident activity"],"answer":2,"explain":"Lessons-learned review and improving controls after the incident is resolved is the post-incident activity phase."}]},{"id":"P2-06","format":2,"domain":2,"title":"File Server Encryption Spike","brief":"Monitoring alerted on mass file changes on a shared drive. Triage and respond.","exhibit":"22:03 host FS-01 high rate of file writes on \\\\share\\finance\n22:03 thousands of files renamed with extension .locked\n22:04 file created READ_ME_TO_DECRYPT.txt in every folder\n22:04 volume shadow copies deleted by vssadmin\n22:05 backup job to offsite repository still running normally","exhibitTitle":"fileserver.log","summary":"Files across a share are being renamed with a .locked extension, a ransom note appears in each folder, and shadow copies were deleted. Offsite backups are intact.","fields":[{"label":"What event type is this?","options":["Ransomware encryption in progress","Port scan","Brute-force login","Phishing click"],"answer":0,"explain":"Mass file renaming to .locked, a ransom note, and deletion of shadow copies are the signature of an active ransomware attack."},{"label":"What severity should you assign?","options":["Low - just disk activity","Critical - active ransomware encrypting production data","Informational"],"answer":1,"explain":"Production data is being encrypted in real time and local recovery copies were destroyed - critical severity."},{"label":"What is the best first containment action?","options":["Isolate the file server from the network to stop the spread","Pay the ransom immediately","Reboot the server","Reset all user passwords"],"answer":0,"explain":"Isolating the affected server halts ongoing encryption and prevents the ransomware from reaching other systems.","hint":"Stop the spread before anything else."},{"label":"Because shadow copies were deleted, which recovery source should you rely on, and in which IR phase?","options":["The intact offsite backup, during containment, eradication and recovery","The deleted shadow copies, during preparation","No recovery is possible"],"answer":0,"explain":"With local copies destroyed, restoring from the unaffected offsite backup during the recovery phase is the correct path."}]},{"id":"P3-01","format":3,"domain":5,"title":"Bank Account Alert","brief":"You receive the email below in your personal inbox. Analyze the technique, red flags, and the correct response.","exhibitTitle":"email","exhibit":"From: Security Team (alerts at secure-paypa1 dot com)\nTo: you\nSubject: URGENT: Your account has been LIMITED\n\nDear Valued Customer,\n\nWe detected unusual activity on your account. Your access has been LIMITED. You must verify your identity within 24 HOURS or your account will be permanently closed.\n\nClick here to restore access: paypa1-secure dot com/verify\n\nFailure to act immediately will result in loss of all funds.\n\nThank you,\nThe Security Team","summary":"A mass email impersonating a payment provider, using a look-alike domain and false urgency to drive the victim to a fake login page.","fields":[{"label":"What social-engineering technique is this?","options":["Phishing","Whaling","Tailgating"],"answer":0,"explain":"This is a generic, mass-distributed email (Dear Valued Customer) impersonating a brand to steal credentials. That is classic phishing. Whaling targets specific high-level executives; tailgating is a physical technique."},{"label":"Which detail is the clearest red flag?","options":["The email has a subject line","The sender domain is paypa1 (with a number 1), a look-alike of the real domain","It is addressed to a customer"],"answer":1,"explain":"The domain paypa1 substitutes the digit 1 for the letter l, a classic look-alike domain meant to fool a quick glance. Subject lines and customer greetings are normal."},{"label":"What is the correct action per security policy?","options":["Click the link to confirm your account is safe","Reply asking the sender to verify they are legitimate","Do not click; report it to security/IT and delete it"],"answer":2,"explain":"Never click links or attachments in a suspicious message, and do not reply (replying confirms a live target). Report the message to security or IT, then delete it.","hint":"Two of these options put you in contact with the attacker."}]},{"id":"P3-02","format":3,"domain":5,"title":"The Urgent CEO Request","brief":"You work in finance. This email arrives appearing to come from your company's CEO. Evaluate it.","exhibitTitle":"email","exhibit":"From: Maria Chen, CEO (m.chen.ceo at gmail dot com)\nTo: you (Accounts Payable)\nSubject: Quick task - need this now\n\nHi,\n\nAre you at your desk? I am in a board meeting and cannot talk. I need you to process an urgent wire transfer to a new vendor today. It is time sensitive and confidential - do not discuss with anyone yet.\n\nReply and I will send the account details.\n\nSent from my iPhone\nMaria","summary":"An attacker impersonates the CEO and targets a specific finance employee to trigger a fraudulent wire transfer, relying on authority, urgency, and secrecy.","fields":[{"label":"What technique best describes this attack?","options":["Smishing","Whaling (a form of spear phishing impersonating or targeting executives)","Baiting"],"answer":1,"explain":"This targets a specific employee using the authority of a senior executive (the CEO) to drive a financial action - a business email compromise / whaling scenario. Smishing uses SMS; baiting uses a tempting item like a free download or USB drive."},{"label":"Which is the strongest red flag here?","options":["The CEO says hello","The 'CEO' is emailing from a personal gmail address, not the corporate domain","The message mentions a board meeting"],"answer":1,"explain":"A real executive request for a wire transfer would not come from a random personal gmail account. The mismatched, external sender address is the key red flag, reinforced by urgency and a demand for secrecy."},{"label":"What should you do before taking any action?","options":["Reply to get the account details and process the wire","Verify the request out-of-band by calling the CEO on a known number","Forward it to a coworker so they can handle the wire"],"answer":1,"explain":"For any unexpected payment request, verify out-of-band using a trusted, independently-known contact method - never the contact details in the message itself. Do not process the wire or simply hand it off."},{"label":"Why does the email demand confidentiality?","options":["To follow standard accounting practice","To stop you from verifying the request with colleagues who would spot the fraud","Because wire transfers are always secret"],"answer":1,"explain":"Demanding secrecy is a manipulation tactic: it isolates the victim and prevents the out-of-band verification that would expose the scam."}]},{"id":"P3-03","format":3,"domain":5,"title":"Text Message From 'The Bank'","brief":"This text message arrives on your phone. Determine what it is and how to respond.","exhibitTitle":"SMS message","exhibit":"From: 1-555-0142\nReceived: 2:14 AM\n\nFIRST NATIONAL BANK ALERT: A charge of 749.00 USD was attempted on your debit card. If this was NOT you, verify your card immediately here: fnb-secure-alerts dot info/card\n\nReply STOP to opt out.","summary":"A text message impersonating a bank fraud alert, using a scary charge amount and a suspicious link to harvest card details.","fields":[{"label":"What is this type of attack called?","options":["Vishing","Smishing (phishing carried out over SMS/text)","Pretexting"],"answer":1,"explain":"Phishing delivered via SMS text message is called smishing. Vishing is voice/phone phishing; pretexting is building a false story to extract information, often over a call."},{"label":"Which clue most strongly suggests this is fraudulent?","options":["It mentions a dollar amount","The link uses an odd domain (fnb-secure-alerts dot info), not the bank's real website","It arrived on your phone"],"answer":1,"explain":"Legitimate banks use their own well-known domains. A generic look-alike like fnb-secure-alerts dot info, especially a .info domain, is a strong indicator of a phishing link. The 2 AM timing is also suspicious."},{"label":"What is the safest response?","options":["Tap the link to check whether the charge is real","Do not tap the link; contact the bank using the number on your card","Reply STOP, which proves you saw it"],"answer":1,"explain":"Never tap links in unsolicited security texts. Contact the bank using the official number printed on your card or its website. Replying (even STOP) only confirms your number is active to the attacker."}]},{"id":"P3-04","format":3,"domain":5,"title":"The Phone Call From 'IT Support'","brief":"Your desk phone rings during a busy afternoon. Read the caller's script and decide how to respond.","exhibitTitle":"phone call transcript","exhibit":"Caller: Hi, this is Dave from the IT Help Desk. We are pushing a critical security patch and your workstation is failing to update.\n\nCaller: I just need to confirm your network username and password so I can apply the fix remotely before the system locks you out at 5 PM. Can you read those to me?\n\nCaller: Also, if a prompt pops up, just click Allow so I can connect.","summary":"An attacker phones an employee pretending to be internal IT, inventing a deadline to pressure them into revealing credentials and granting remote access.","fields":[{"label":"What technique is the caller using?","options":["Vishing combined with pretexting","Baiting","Tailgating"],"answer":0,"explain":"This is vishing (voice phishing) built on a pretext - a fabricated story (the urgent patch) used to justify the request. Baiting lures with a tempting item; tailgating is following someone through a secure door."},{"label":"What is the biggest warning sign?","options":["IT introduced themselves by name","Legitimate IT will never ask you to read out your password","The patch has a deadline"],"answer":1,"explain":"No legitimate IT or help desk will ask you to disclose your password - they never need it. That request alone confirms the call is malicious, alongside the manufactured 5 PM deadline."},{"label":"How should you handle the call?","options":["Give the password since IT already has access anyway","Refuse to share credentials, hang up, and report the call to security","Click Allow but withhold the password"],"answer":1,"explain":"Do not provide credentials or grant remote access. End the call, then report it to security/IT through a known channel so they can warn others and investigate."},{"label":"If you want to confirm IT really needs something, what should you do?","options":["Trust the caller because they knew it was patch season","Call the official IT help desk number yourself to verify","Ask the caller to prove it by reading your password back"],"answer":1,"explain":"Verify out-of-band by contacting IT through their official, independently-known number - not any number or detail the caller supplies."}]},{"id":"P3-05","format":3,"domain":5,"title":"You've Won a Gift Card","brief":"This email lands in your work inbox. Assess the offer and the attachment.","exhibitTitle":"email","exhibit":"From: Rewards Center (no-reply at prizes-winnerz dot net)\nTo: undisclosed-recipients\nSubject: Congratulations!!! You have been SELECTED\n\nYou have been randomly selected to receive a 500 USD gift card!\n\nTo claim your reward, simply open the attached form and enter your details. Limited slots remaining - claim before midnight!\n\nAttachment: Claim_Form.html.exe\n\nDo not miss this opportunity!","summary":"A too-good-to-be-true prize email using a tempting reward to lure the victim into opening a malicious attachment disguised as a form.","fields":[{"label":"What social-engineering technique is at work?","options":["Baiting (luring the victim with an enticing reward)","Whaling","Tailgating"],"answer":0,"explain":"Dangling a free prize to tempt the victim into taking a risky action (opening the attachment) is baiting. Whaling targets executives; tailgating is physical."},{"label":"Which detail should alarm you the most?","options":["The cheerful tone","The attachment is named Claim_Form.html.exe - a double extension hiding an executable","The email says congratulations"],"answer":1,"explain":"A double extension like .html.exe disguises an executable program as a harmless file. Opening it would run malware. The unknown sender, mass recipients, and urgency reinforce that it is malicious."},{"label":"What should you do with this email?","options":["Open the attachment to see if the prize is real","Do not open the attachment; report the email to security/IT and delete it","Forward it to friends so they can claim a prize too"],"answer":1,"explain":"Never open unexpected attachments, especially executables. Report the email to security/IT and delete it. Forwarding would only spread the threat."}]},{"id":"P3-06","format":3,"domain":5,"title":"The Friendly Stranger at the Door","brief":"You are badging into your office building one morning. Read the scenario and choose the best responses.","exhibitTitle":"scenario","exhibit":"As you tap your access badge to open the secure side entrance, a person in a delivery uniform walks up quickly behind you, arms full of boxes.\n\nThey smile and say: 'Oh thank you, could you hold that? My badge is buried in here somewhere and these packages are heavy. I'm dropping these at the third floor mailroom.'\n\nThey gesture for you to let them through the door you just opened.","summary":"A physical social-engineering attempt where someone without valid access tries to follow an authorized employee through a secured door by exploiting politeness.","fields":[{"label":"What technique is the stranger attempting?","options":["Tailgating (following an authorized person through a secure door)","Smishing","Vishing"],"answer":0,"explain":"Following an authorized person through a controlled door without using valid credentials is tailgating (or piggybacking). Smishing and vishing are remote attacks via text and phone."},{"label":"Why is the delivery story effective?","options":["It is obviously a lie","It uses a believable pretext and social pressure (politeness, heavy boxes) so refusing feels rude","Delivery staff never need access","Smiling proves they belong"],"answer":1,"explain":"Attackers craft a sympathetic pretext - full arms, a buried badge, urgency - so that holding the door feels like simple courtesy. That pressure is exactly the manipulation."},{"label":"What is the correct action?","options":["Hold the door open since they are clearly just a delivery person","Let the door close, and direct them to reception/security to be signed in","Take the boxes and carry them in yourself"],"answer":1,"explain":"Do not let anyone tailgate, no matter how legitimate they seem. Politely have them go through the proper check-in at reception or security so their access can be verified."},{"label":"After this happens, what else should you do?","options":["Nothing, since you did not let them in","Report the attempted tailgating to security so they are aware","Post about it on social media"],"answer":1,"explain":"Reporting the attempt helps security watch for the individual and reinforces physical access controls. Doing nothing leaves the team unaware of an active attempt."}]},{"id":"P4-01","format":4,"domain":5,"title":"Encrypting Laptop Hard Drives","brief":"A company issues laptops to a remote sales team. Leadership wants all data stored on each laptop to stay confidential if a device is lost or stolen, even when the laptop is powered off.","summary":"This is a classic <strong>data-at-rest</strong> protection requirement. Full-disk encryption with a strong symmetric cipher (AES) keeps the stored data unreadable without the key, while hashing and transit-layer tools solve different problems.","fields":[{"label":"What category of protection does this requirement describe?","options":["Data in transit","Data at rest","Data in use"],"answer":1,"explain":"Information sitting on a powered-off laptop's drive is stored data, which is the definition of data at rest. Data in transit is information moving across a network; data in use is data actively loaded in memory.","hint":"The laptop is powered off and the data is just sitting on the disk."},{"label":"Which tool best meets this requirement?","options":["TLS","Full-disk encryption (BitLocker)","A digital signature"],"answer":1,"explain":"Full-disk encryption such as BitLocker encrypts the entire volume so the stored data is unreadable without the key. TLS protects data moving over a network, and a digital signature provides integrity and non-repudiation, not confidentiality of stored data.","hint":"You need to scramble everything written to the disk."},{"label":"Which encryption algorithm is the right fit for encrypting the bulk of the disk?","options":["RSA","AES","MD5"],"answer":1,"explain":"AES is a fast symmetric algorithm well suited to encrypting large amounts of bulk data like an entire drive. RSA is asymmetric and far too slow for bulk encryption, and MD5 is a hashing algorithm, not an encryption algorithm.","hint":"For bulk data you want a fast symmetric cipher."},{"label":"Why would storing files in plaintext be the wrong choice here?","options":["Plaintext data can be read by anyone who obtains the drive","Plaintext is too slow to access","Plaintext files cannot be backed up"],"answer":0,"explain":"Plaintext means the data is not encrypted at all, so anyone who removes or boots from the stolen drive can read it directly. That defeats the confidentiality requirement.","hint":"Plaintext means no protection at all."}]},{"id":"P4-02","format":4,"domain":5,"title":"Securing Website Logins","brief":"An online store wants to make sure customer usernames, passwords, and credit card numbers cannot be intercepted as they travel between the customer's browser and the web server.","summary":"Protecting information while it moves across a network is a <strong>data-in-transit</strong> problem. TLS (the protocol behind HTTPS) encrypts the channel, and it relies on asymmetric cryptography to safely exchange the symmetric session key.","fields":[{"label":"What category of protection does this requirement describe?","options":["Data at rest","Data in transit","Data in use"],"answer":1,"explain":"The data is actively moving between the browser and the server across the Internet, which is the definition of data in transit.","hint":"The information is moving across the network."},{"label":"Which technology best protects this traffic?","options":["TLS (HTTPS)","Full-disk encryption","SHA-256 hashing"],"answer":0,"explain":"TLS encrypts the connection between browser and server, which is exactly what HTTPS uses. Full-disk encryption protects stored data, and hashing provides integrity but does not encrypt the channel.","hint":"Think about what the padlock in the browser uses."},{"label":"During the TLS handshake, what is asymmetric encryption mainly used for?","options":["Encrypting every packet of the whole session","Securely exchanging the symmetric session key","Hashing the customer's password"],"answer":1,"explain":"Asymmetric (public/private key) cryptography is used to securely exchange or agree on a symmetric session key. After that, the faster symmetric cipher encrypts the actual session data.","hint":"Asymmetric is slow, so it is used only briefly to set up the session."},{"label":"Why is the older WEP protocol a poor choice for protecting sensitive traffic?","options":["WEP only works on fiber networks","WEP encryption is weak and easily broken","WEP requires a digital certificate"],"answer":1,"explain":"WEP uses weak, outdated encryption that can be cracked quickly with readily available tools, so it should not be relied on to protect sensitive data. Modern protocols like TLS or WPA2/WPA3 should be used instead.","hint":"WEP is a deprecated, easily defeated wireless protocol."}]},{"id":"P4-03","format":4,"domain":5,"title":"Verifying a Downloaded File","brief":"A software vendor publishes an installer for download and wants users to be able to confirm the file was not altered or corrupted before they run it.","summary":"Detecting whether data has changed is an <strong>integrity</strong> requirement, and the right tool is a cryptographic hash function such as SHA-256. Hashing is one-way: it proves the file is unchanged but does not encrypt it.","fields":[{"label":"Which security goal does this requirement focus on?","options":["Confidentiality","Integrity","Availability"],"answer":1,"explain":"The goal is to confirm the file has not been altered, which is the definition of integrity. Confidentiality is about secrecy, and availability is about access when needed.","hint":"They want to know if the file changed, not keep it secret."},{"label":"Which tool should the vendor publish alongside the installer?","options":["A SHA-256 hash value","An AES-encrypted copy of the file","A TLS certificate"],"answer":0,"explain":"Publishing a SHA-256 hash lets users compute the hash of their downloaded file and compare it to the published value. If they match, the file is intact. AES encrypts data, and a TLS certificate secures connections.","hint":"You need a fingerprint of the file to compare against."},{"label":"What does it mean that a hash function is one-way?","options":["You cannot reverse the hash back into the original data","The hash can only be sent in one direction","The file can only be downloaded once"],"answer":0,"explain":"A cryptographic hash is one-way: you can compute the hash from the data, but you cannot reverse the hash value to recover the original data. This is why hashing provides integrity, not confidentiality.","hint":"Hashing is a fingerprint, not reversible encryption."},{"label":"Why is MD5 a weak choice for this integrity check?","options":["MD5 is too slow for large files","MD5 has known collision weaknesses and is considered insecure","MD5 encrypts the file instead of hashing it"],"answer":1,"explain":"MD5 has well-known collision weaknesses, meaning different inputs can produce the same hash, so an attacker could craft a malicious file with a matching MD5. A stronger function like SHA-256 should be used instead.","hint":"MD5 is broken because two files can share the same hash."}]},{"id":"P4-04","format":4,"domain":5,"title":"Proving Who Approved a Document","brief":"A finance manager emails a payment approval and the company needs to prove later that the manager really sent it and that the content was not changed, so the manager cannot deny sending it.","summary":"Proving the origin of a message and preventing the sender from denying it is <strong>non-repudiation</strong>. A digital signature, created with the sender's private key, provides both integrity and non-repudiation.","fields":[{"label":"Which property does the requirement to prevent the manager from denying the message describe?","options":["Availability","Non-repudiation","Redundancy"],"answer":1,"explain":"Non-repudiation means a sender cannot credibly deny having sent a message. That is exactly what the company needs here.","hint":"They want the sender to be unable to say 'I never sent that.'"},{"label":"Which cryptographic tool provides this?","options":["A digital signature","Full-disk encryption","A symmetric session key"],"answer":0,"explain":"A digital signature, created with the sender's private key and verified with their public key, proves who sent the message and that it was not altered. Full-disk encryption and shared symmetric keys do not bind a message to one identifiable sender.","hint":"It is created with the sender's private key."},{"label":"Which key does the manager use to create the digital signature?","options":["The manager's private key","The manager's public key","A shared symmetric key"],"answer":0,"explain":"The signer uses their own private key to sign, and recipients verify with the matching public key. Because only the manager holds the private key, a valid signature ties the message to the manager.","hint":"Only the signer holds this key."},{"label":"Why would a shared symmetric key fail to provide non-repudiation?","options":["Symmetric keys are too long to manage","Everyone who shares the key could have created the message","Symmetric keys cannot encrypt email"],"answer":1,"explain":"With a shared symmetric key, anyone holding the key could have produced the message, so it cannot prove which specific person sent it. Non-repudiation needs a private key that only the sender possesses.","hint":"If more than one person has the key, you cannot pin it on one sender."}]},{"id":"P4-05","format":4,"domain":5,"title":"Sending a Large Encrypted Backup","brief":"A team needs to encrypt a 50 GB backup file before storing it, and they also need a safe way to share the encryption key with a partner office across the Internet.","summary":"This requirement combines both worlds: use fast <strong>symmetric</strong> encryption (AES) for the large file, and use <strong>asymmetric</strong> encryption to safely deliver the symmetric key. This hybrid approach is how most real systems work.","fields":[{"label":"Which type of encryption is best for the 50 GB backup file itself?","options":["Symmetric encryption","Asymmetric encryption","No encryption needed"],"answer":0,"explain":"Symmetric encryption is fast and efficient, making it the right choice for encrypting large amounts of bulk data such as a 50 GB backup.","hint":"For lots of data you want speed."},{"label":"Which specific algorithm fits encrypting that bulk data?","options":["AES","RSA","SHA-256"],"answer":0,"explain":"AES is the standard fast symmetric cipher for bulk data. RSA is asymmetric and too slow for large files, and SHA-256 is a hash, not an encryption algorithm.","hint":"The standard symmetric cipher for bulk data."},{"label":"How should the symmetric key be safely sent to the partner office?","options":["Encrypt it with the partner's public key (asymmetric)","Email it in plaintext","Post it on a shared drive"],"answer":0,"explain":"Encrypting the symmetric key with the partner's public key means only the partner's matching private key can unlock it, so the key travels safely. Sending it in plaintext or posting it openly would expose it.","hint":"Use the recipient's public key so only they can open it."},{"label":"Why not just use RSA to encrypt the entire 50 GB file?","options":["RSA cannot encrypt files at all","Asymmetric encryption is far too slow for large data","RSA does not support large keys"],"answer":1,"explain":"Asymmetric algorithms like RSA are computationally expensive and much slower than symmetric ciphers, so encrypting 50 GB with RSA would be impractically slow. That is why symmetric encryption handles the bulk data.","hint":"Asymmetric is slow, so it is used only on small things like keys."}]},{"id":"P4-06","format":4,"domain":5,"title":"Protecting Stored Passwords","brief":"A web application must store user passwords so logins can be verified later, but the security team wants to ensure that even an attacker who steals the database cannot recover the original passwords.","summary":"Passwords should never be stored in a recoverable form. The correct approach is to store a <strong>hash</strong> of each password (ideally salted), not encryption and definitely not plaintext, because the application only needs to verify a match, not recover the original.","fields":[{"label":"How should the application store user passwords?","options":["As reversible encrypted values","As hashed values","As plaintext"],"answer":1,"explain":"Passwords should be stored as hashes. To verify a login, the app hashes the entered password and compares it to the stored hash, so the original password never needs to be recovered.","hint":"You only need to check a match, not get the password back."},{"label":"Why is hashing preferred over encryption for passwords?","options":["Encryption is reversible, so a stolen key would expose every password","Hashing is faster to type","Encryption cannot be used on text"],"answer":0,"explain":"Encryption is reversible, so if an attacker steals both the database and the key, every password can be decrypted. A hash is one-way, so even with the database an attacker cannot directly reverse it back to the password.","hint":"Think about what happens if the decryption key is stolen too."},{"label":"What does adding a salt to each password before hashing accomplish?","options":["It makes identical passwords produce different hashes","It encrypts the hash a second time","It compresses the password"],"answer":0,"explain":"A unique salt per user means two users with the same password get different hashes, which defeats precomputed lookup attacks and makes cracking much harder.","hint":"It ensures two people with the same password do not share a hash."},{"label":"Why is storing passwords in plaintext the worst option?","options":["Plaintext passwords are immediately readable if the database is stolen","Plaintext takes too much storage space","Plaintext cannot be searched"],"answer":0,"explain":"If passwords are stored in plaintext, anyone who steals the database instantly has every user's real password. That is why plaintext storage is never acceptable for credentials.","hint":"No protection at all means instant exposure."}]},{"id":"P5-01","format":5,"domain":4,"title":"Place the Perimeter Firewall","brief":"A small office connects to the Internet and wants to protect its internal LAN.","exhibit":"Internet -- [pos A] -- DMZ web server -- [pos B] -- internal LAN","exhibitTitle":"office perimeter","summary":"Choose the correct control for each position so traffic from the Internet is filtered before it reaches internal systems.","fields":[{"label":"Position A (boundary between the Internet and everything else)","options":["Perimeter firewall configured deny-by-default","Unmanaged network switch","Wireless access point"],"answer":0,"explain":"The boundary between the untrusted Internet and your network is where a perimeter firewall belongs. Configuring it deny-by-default means only explicitly allowed traffic passes; everything else is blocked.","hint":"What sits at the edge and filters traffic?"},{"label":"Why deny-by-default rather than allow-by-default?","options":["It blocks all traffic except what is explicitly permitted, reducing attack surface","It speeds up the Internet connection","It removes the need for any other controls"],"answer":0,"explain":"Deny-by-default (implicit deny) means nothing is allowed unless a rule explicitly permits it. This minimizes the attack surface compared to allowing everything and trying to block bad traffic.","hint":"Think least privilege for network traffic."},{"label":"Position B (boundary between the DMZ and the internal LAN)","options":["An internal firewall enforcing tighter rules toward the LAN","A simple hub with no filtering","A public DNS server"],"answer":0,"explain":"A second (internal) firewall between the DMZ and the LAN protects internal systems even if a DMZ host is compromised. It enforces stricter rules so the DMZ cannot freely reach the LAN.","hint":"Defense in depth means more than one filtering point."}]},{"id":"P5-02","format":5,"domain":4,"title":"DMZ Placement for a Public Web Server","brief":"A company hosts a website that customers on the Internet must reach, but the server must not sit on the internal LAN.","exhibit":"Internet -- firewall -- [pos A: which network?] \n internal LAN (employee workstations)","exhibitTitle":"public server placement","summary":"Decide where to place an Internet-facing server and how to filter access to it.","fields":[{"label":"Where should the public web server be placed?","options":["In a DMZ (screened subnet) separated from the internal LAN","Directly on the internal LAN with the workstations","On the Internet side of the firewall with no protection"],"answer":0,"explain":"Internet-facing servers belong in a DMZ (screened subnet). This isolates them so that if the server is compromised, attackers do not gain direct access to the internal LAN.","hint":"You want public access without exposing internal systems."},{"label":"Which inbound port should the firewall allow to the web server for secure web traffic?","options":["443 (HTTPS)","23 (Telnet)","3389 (RDP)"],"answer":0,"explain":"HTTPS uses TCP port 443. Allowing 443 lets customers reach the site over an encrypted connection. Telnet (23) is insecure and RDP (3389) should never be exposed to the Internet.","hint":"Secure web browsing."},{"label":"Should the firewall allow connections initiated from the DMZ web server into the internal LAN?","options":["No, deny by default; only allow specific required flows","Yes, allow all traffic so the server works","Yes, but only on weekends"],"answer":0,"explain":"Traffic from the DMZ to the LAN should be denied by default. Only narrowly defined, required connections (for example to a specific database host and port) should be permitted, limiting damage if the DMZ host is breached.","hint":"A compromised DMZ host should not roam the LAN."}]},{"id":"P5-03","format":5,"domain":4,"title":"IDS vs IPS Placement","brief":"Security wants to both watch traffic and actively stop attacks at the network edge.","exhibit":"Internet -- firewall -- [pos A: monitoring sensor] -- core switch -- [pos B: passive sensor on SPAN port] -- servers","exhibitTitle":"detection vs prevention","summary":"Match each monitoring need to an IDS or an IPS and place it correctly.","fields":[{"label":"Position A: a device that sits inline and can drop malicious packets in real time","options":["IPS (Intrusion Prevention System)","IDS (Intrusion Detection System)","DHCP server"],"answer":0,"explain":"An IPS sits inline in the traffic path and can actively block or drop malicious packets. Because it is inline, it can prevent attacks rather than just report them.","hint":"Prevention means it must be able to stop traffic."},{"label":"Position B: a sensor on a SPAN/mirror port that only watches a copy of traffic and alerts","options":["IDS (Intrusion Detection System)","IPS (Intrusion Prevention System)","Load balancer"],"answer":0,"explain":"An IDS receives a copy of traffic (for example via a SPAN/mirror port), detects suspicious activity, and raises alerts. It does not sit inline and therefore cannot block traffic itself.","hint":"Detection only watches and alerts."},{"label":"What is the key functional difference between IDS and IPS?","options":["IDS detects and alerts; IPS detects and can also block","IDS is faster than IPS","IPS only works on wireless networks"],"answer":0,"explain":"Both detect malicious activity, but an IDS only alerts (passive/out-of-band) while an IPS is inline and can actively block or drop the offending traffic.","hint":"One letter changes detection into prevention."}]},{"id":"P5-04","format":5,"domain":4,"title":"Remote Access for Teleworkers","brief":"Employees working from home need secure access to internal resources over the Internet.","exhibit":"Remote worker laptop -- Internet -- [pos A: secure entry device] -- internal LAN \n internal LAN -- [pos B: endpoint health check]","exhibitTitle":"secure remote access","summary":"Select the controls that let remote users connect securely and verify their devices.","fields":[{"label":"Position A: the device that terminates encrypted remote-access tunnels at the network edge","options":["VPN concentrator","Print server","Unencrypted FTP server"],"answer":0,"explain":"A VPN concentrator terminates encrypted VPN tunnels, giving remote users a secure, authenticated path into the internal network over the untrusted Internet.","hint":"Encrypted tunnel for remote workers."},{"label":"What protection does the VPN provide for traffic crossing the Internet?","options":["Confidentiality and integrity through encryption of the tunnel","Faster download speeds","A public IP address for each user"],"answer":0,"explain":"A VPN encrypts traffic between the remote device and the concentrator, protecting confidentiality and integrity so data cannot be read or altered in transit.","hint":"Encryption protects data in motion."},{"label":"Position B: the control that checks a connecting device for required patches and antivirus before granting access","options":["NAC (Network Access Control) with posture assessment","A spam filter","A backup tape drive"],"answer":0,"explain":"NAC evaluates the posture of a connecting endpoint (patch level, antivirus, configuration) and can deny or quarantine devices that do not meet policy before they reach the LAN.","hint":"It checks the endpoint's health before letting it in."}]},{"id":"P5-05","format":5,"domain":4,"title":"Segmentation and VLAN Boundaries","brief":"A hospital wants to keep medical devices separated from the general staff network.","exhibit":"Staff workstations VLAN -- [pos A: boundary control] -- Medical devices VLAN \n both VLANs -- core switch","exhibitTitle":"network segmentation","summary":"Apply segmentation so sensitive systems are isolated and traffic between zones is controlled.","fields":[{"label":"How should the medical devices be separated from staff workstations?","options":["Place them on a separate VLAN (network segment)","Put them on the same VLAN as staff for simplicity","Connect them directly to the Internet"],"answer":0,"explain":"Putting medical devices on their own VLAN segments them from the general staff network, limiting which systems can reach them and containing the blast radius of any compromise.","hint":"Keep sensitive systems on their own segment."},{"label":"Position A: the control that enforces rules on traffic crossing between the two VLANs","options":["A firewall (or ACL on a layer 3 device) between segments","A power strip","A label printer"],"answer":0,"explain":"Traffic between VLANs is routed, so a firewall or access control list (ACL) at the boundary enforces which flows are permitted between the staff and medical segments.","hint":"Something must filter traffic where the segments meet."},{"label":"What is the main security benefit of this segmentation?","options":["It limits lateral movement and contains a compromise to one segment","It increases the number of usable IP addresses only","It removes the need to patch the devices"],"answer":0,"explain":"Segmentation restricts lateral movement: if one segment is compromised, the boundary control prevents the attacker from freely reaching systems in the other segment.","hint":"Think containment if one side is breached."}]},{"id":"P5-06","format":5,"domain":4,"title":"Protecting a Web Application and Writing Firewall Rules","brief":"A public web application is being targeted by SQL injection and cross-site scripting attempts.","exhibit":"Internet -- firewall -- [pos A: app-layer filter] -- web application server -- database (internal)","exhibitTitle":"web app protection","summary":"Add an application-layer control and choose correct firewall-rule decisions.","fields":[{"label":"Position A: the control that inspects HTTP requests and blocks attacks like SQL injection and XSS","options":["WAF (Web Application Firewall)","A network hub","A DHCP relay"],"answer":0,"explain":"A WAF operates at the application layer, inspecting HTTP/HTTPS requests and blocking common web attacks such as SQL injection and cross-site scripting before they reach the web app.","hint":"It understands web traffic, not just ports."},{"label":"Firewall rule: an inbound request from the Internet to the web server on port 443","options":["Allow (HTTPS is required for the public site)","Deny (no public access should be possible)","Allow only from a random single host"],"answer":0,"explain":"The web application must be reachable by the public over HTTPS, so inbound TCP 443 to the web server should be allowed. This is an explicit permit that fits the deny-by-default baseline.","hint":"Customers need secure web access."},{"label":"Firewall rule: an inbound request from the Internet directly to the internal database on port 3306","options":["Deny (the database must not be exposed to the Internet)","Allow (it is faster)","Allow from any source"],"answer":0,"explain":"The database holds sensitive data and should only be reachable from the web server, not the Internet. Direct inbound access to the database (for example MySQL on 3306) must be denied.","hint":"Back-end data stores stay internal."},{"label":"Where should the database sit relative to the web server?","options":["On an internal segment, reachable only from the web server on the required port","In the DMZ next to the web server","On the public Internet side of the firewall"],"answer":0,"explain":"The database belongs on a protected internal segment. Only the web application server should reach it, and only on the specific required port, keeping sensitive data away from direct exposure.","hint":"Sensitive data belongs behind, not beside, the public server."}]}];
(function () {
  "use strict";

  var S = window.ISC2CC;
  /* app.js loads AFTER this file, so window.APP isn't ready at load time.
     Resolve it lazily: every public entry point calls ready() first, which
     binds A and el before any rendering helper runs. */
  var A, el;
  function ready() { A = window.APP; el = A.el; }

  /* ----- sampling helpers (Fisher–Yates) ----- */
  function shuffle(arr) {
    var a = arr.slice();
    for (var i = a.length - 1; i > 0; i--) { var j = Math.floor(Math.random() * (i + 1)); var t = a[i]; a[i] = a[j]; a[j] = t; }
    return a;
  }
  function sample(arr, n) { return shuffle(arr).slice(0, n); }
  function byDomain(d) { return S.questions.filter(function (q) { return q.domain === d; }); }
  var LETTERS = ["A", "B", "C", "D", "E", "F"];

  /* per-question option order is randomized so the answer index isn't a tell. */
  function prepare(q) {
    var order = shuffle(q.options.map(function (o, i) { return i; }));
    return {
      ref: q,
      opts: order.map(function (i) { return q.options[i]; }),
      answer: order.indexOf(q.answer)
    };
  }

  /* domain stats accumulator used by results + analytics */
  function blankStats() { var o = {}; (S.domainMeta || []).forEach(function (d) { o[d.id] = { correct: 0, total: 0 }; }); return o; }

  /* ===========================================================================
     ADAPTIVE / MISSED-QUESTION TRACKING
     Persists two things across every quiz/mock session (localStorage via APP):
       ISC2CC.objstats.v1 = { "1.2": {c, n}, ... }   per-objective accuracy
       ISC2CC.missed.v1   = { "D4-071": 1, ... }      questions answered wrong
     The adaptive set weights selection toward weak/unseen objectives (and prior
     misses); the missed queue re-serves only wrong questions until you get them
     right. Helpers read window.APP directly so the dashboard can call them
     before any quiz entry point binds A.
     =========================================================================== */
  var QS = {
    getObj: function () { return window.APP.store.get("objstats.v1", {}) || {}; },
    getMissed: function () { return window.APP.store.get("missed.v1", {}) || {}; },
    /* fold a graded set into the persistent stores. items = prepared array
       (each has .ref and .answer); picks = chosen indices into shuffled opts. */
    record: function (items, picks) {
      var obj = this.getObj(), missed = this.getMissed();
      items.forEach(function (it, i) {
        var q = it.ref, ok = picks[i] === it.answer;
        var o = obj[q.obj] || { c: 0, n: 0 }; o.n++; if (ok) o.c++; obj[q.obj] = o;
        if (ok) delete missed[q.id]; else missed[q.id] = 1;
      });
      window.APP.store.set("objstats.v1", obj);
      window.APP.store.set("missed.v1", missed);
    },
    missedCount: function () { return Object.keys(this.getMissed()).length; },
    /* weakest domain by accumulated objective accuracy (>= 3 attempts) */
    weakestDomain: function () {
      var obj = this.getObj(), dom = {};
      for (var k in obj) { var d = k[0]; dom[d] = dom[d] || { c: 0, n: 0 }; dom[d].c += obj[k].c; dom[d].n += obj[k].n; }
      var worst = null, worstAcc = 2;
      for (var dd in dom) { if (dom[dd].n >= 3) { var a = dom[dd].c / dom[dd].n; if (a < worstAcc) { worstAcc = a; worst = dd; } } }
      return worst ? ("Domain " + worst) : null;
    }
  };

  /* per-question weight: weak/unseen objectives and prior misses score higher */
  function adaptiveWeight(q, obj, missed) {
    var o = obj[q.obj], w;
    if (!o || !o.n) w = 2.2;                 // unseen objective → encourage coverage
    else w = 1 + 2 * (1 - o.c / o.n);        // weak objective weighted up to 3x
    if (missed[q.id]) w += 1.5;              // a prior miss gets an extra boost
    return w;
  }
  /* weighted sampling without replacement */
  function weightedSample(pool, n, wf) {
    var items = pool.map(function (q) { return { q: q, w: Math.max(0.01, wf(q)) }; });
    var out = [];
    n = Math.min(n, items.length);
    for (var k = 0; k < n; k++) {
      var total = items.reduce(function (a, x) { return a + x.w; }, 0);
      var r = Math.random() * total, acc = 0, idx = 0;
      for (var i = 0; i < items.length; i++) { acc += items[i].w; if (r <= acc) { idx = i; break; } }
      out.push(items[idx].q); items.splice(idx, 1);
    }
    return out;
  }
  function adaptiveSet(n) {
    var obj = QS.getObj(), missed = QS.getMissed();
    return weightedSample(S.questions, n, function (q) { return adaptiveWeight(q, obj, missed); });
  }

  /* ===========================================================================
     LINEAR QUIZ  (domain quiz + quick quiz): immediate feedback per question
     =========================================================================== */
  function runLinearQuiz(opts) {
    ready();
    var items = opts.items.map(prepare);
    var idx = 0, picks = new Array(items.length).fill(null);

    A.open({
      tag: opts.tag,
      render: function (host) {
        var pane = el("div");
        host.appendChild(A.crumb(opts.title, { onBack: function () {
          A.confirm("Leave quiz?", "Your progress on this quiz will not be saved.", "Leave", function () { A.dashboard(); A.renderDashboard(); });
        } }));
        host.appendChild(el("div.phead", null, [el("h1", { text: opts.title }), el("span.sub", { text: opts.sub })]));
        host.appendChild(pane);
        draw(pane);
      }
    });

    function draw(pane) {
      pane.innerHTML = "";
      var wrap = el("div.quizwrap");
      var bar = el("div.qmeta", null, [
        el("div.progressbar", null, el("i", { style: "width:" + (idx / items.length * 100) + "%" })),
        el("div.qcount", { text: "Question " + (idx + 1) + " of " + items.length })
      ]);
      wrap.appendChild(bar);

      var it = items[idx], q = it.ref, answered = picks[idx] != null;
      var dc = "d" + q.domain;
      var qc = el("div.qcard-full");
      qc.appendChild(el("div.qhead", null, [
        el("span.qdombadge." + dc, { text: "DOMAIN " + q.domain }),
        el("span.qobj", { text: "Objective " + q.obj }),
        el("span.qobj", { text: "· " + (q.diff || "medium") })
      ]));
      qc.appendChild(el("div.qtext", { html: q.q }));

      it.opts.forEach(function (text, i) {
        var cls = "opt";
        if (answered) {
          if (i === it.answer) cls += " correct";
          else if (i === picks[idx]) cls += " wrong";
        }
        var b = el("button." + cls.replace(/ /g, "."), { type: "button", disabled: answered ? "disabled" : null });
        b.appendChild(el("span.key", { text: LETTERS[i] }));
        b.appendChild(el("span", { html: text }));
        if (answered && i === it.answer) b.appendChild(el("span.tick", { text: "✓" }));
        if (answered && i === picks[idx] && i !== it.answer) b.appendChild(el("span.tick", { text: "✗" }));
        if (!answered) b.addEventListener("click", function () { picks[idx] = i; draw(pane); });
        qc.appendChild(b);
      });

      if (answered) {
        var correct = picks[idx] === it.answer;
        qc.appendChild(el("div.rationale" + (correct ? "" : ".bad"), null, [
          el("span.lbl", { text: correct ? "Correct" : "Not quite" }),
          el("span", { html: q.explain })
        ]));
      }

      var nav = el("div.qnav", null, [
        el("button.btn.ghost", { text: "← Previous", disabled: idx === 0 ? "disabled" : null, onclick: function () { if (idx > 0) { idx--; draw(pane); } } }),
        answered
          ? el("button.btn.primary", { text: idx === items.length - 1 ? "See results →" : "Next question →", onclick: function () { if (idx === items.length - 1) finish(); else { idx++; draw(pane); } } })
          : el("span.note", { text: "Select an answer to continue." })
      ]);
      qc.appendChild(nav);
      wrap.appendChild(qc);
      pane.appendChild(wrap);
    }

    function finish() {
      var stats = blankStats(), correct = 0, wrongList = [];
      items.forEach(function (it, i) {
        var ok = picks[i] === it.answer;
        stats[it.ref.domain].total++; if (ok) { stats[it.ref.domain].correct++; correct++; }
        if (!ok) wrongList.push({ it: it, pick: picks[i] });
      });
      var pct = Math.round(correct / items.length * 100);
      QS.record(items, picks); // feed adaptive engine + missed-question queue
      A.store.record({ mode: opts.mode, modeLabel: opts.modeLabel, detail: opts.detail, pct: pct, correct: correct, total: items.length, domainStats: stats });
      showResults({
        tag: opts.tag, title: opts.title, mode: opts.mode,
        correct: correct, total: items.length, pct: pct, stats: stats, wrongList: wrongList,
        retry: function () { opts.retry(); }
      });
    }
  }

  /* ===========================================================================
     RESULTS DASHBOARD (shared by quizzes + mock)
     =========================================================================== */
  function showResults(r) {
    A.open({
      tag: "Results", render: function (host) {
        host.appendChild(A.crumb("Results", { onBack: function () { A.dashboard(); A.renderDashboard(); } }));
        host.appendChild(el("div.phead", null, [el("h1", { text: r.title + " — Results" })]));
        var box = el("div.results");

        var isMock = r.mode === "mock";
        var pass = isMock ? r.scaled >= ((S.exam && S.exam.passing) || 700) : r.pct >= 70;
        var ringcol = pass ? "var(--low)" : (r.pct >= 50 ? "var(--amber)" : "var(--crit)");
        var hero = el("div.scorehero");
        var ring = el("div.scorering", { style: "--pct:" + r.pct + ";--ringcol:" + ringcol });
        ring.appendChild(el("div.inner", null, [el("div.pct", { text: r.pct + "%" }), el("div.lab", { text: r.correct + "/" + r.total })]));
        hero.appendChild(ring);
        hero.appendChild(el("div.verdict." + (pass ? "pass" : "fail"), { text: pass ? (isMock ? "Likely Pass" : "Strong") : (isMock ? "Not Yet Passing" : "Keep Studying") }));
        if (isMock) hero.appendChild(el("div.scaled", { html: "Scaled score <b style='color:var(--ink)'>" + r.scaled + "</b> / " + ((S.exam&&S.exam.scaleHigh)||1000) + " &nbsp;·&nbsp; passing is <b style='color:var(--ink)'>" + ((S.exam && S.exam.passing) || 700) + "</b>" }));
        else hero.appendChild(el("div.scaled", { text: r.correct + " of " + r.total + " correct" }));
        box.appendChild(hero);

        /* per-domain bars */
        box.appendChild(el("div.secthead", { text: "By domain" }));
        var bars = el("div.dombars");
        (S.domainMeta || []).forEach(function (d) {
          var st = r.stats[d.id]; if (!st || !st.total) return;
          var p = Math.round(st.correct / st.total * 100);
          bars.appendChild(el("div.dombar", null, [
            el("div.name", { text: "D" + d.id + " · " + d.title }),
            el("div.track", null, el("i", { style: "width:" + p + "%;background:var(--d" + d.id + ")" })),
            el("div.pct", { text: st.correct + "/" + st.total })
          ]));
        });
        box.appendChild(bars);

        /* review of missed items, mapped to objectives */
        box.appendChild(el("div.secthead", { text: r.wrongList.length ? "Review missed questions (" + r.wrongList.length + ")" : "Review" }));
        if (!r.wrongList.length) box.appendChild(el("div.empty", { text: "Perfect run — nothing to review. 🎯" }));
        var rl = el("div.reviewlist");
        r.wrongList.forEach(function (w) {
          var q = w.it.ref;
          var yourText = w.pick == null ? "(left blank)" : w.it.opts[w.pick];
          var corrText = w.it.opts[w.it.answer];
          rl.appendChild(el("div.ritem", null, [
            el("p.rq", { html: q.q }),
            el("div.ra", null, [el("span.you.bad", { html: "Your answer: " + A.esc(yourText) })]),
            el("div.ra", null, [el("span.corr", { html: "Correct: " + A.esc(corrText) })]),
            el("div.rationale", null, [el("span.lbl", { text: "Why" }), el("span", { html: q.explain })]),
            el("div.robj", { text: ((S.exam && S.exam.code) || "") + " Domain " + q.domain + " · Objective " + q.obj })
          ]));
        });
        box.appendChild(rl);

        box.appendChild(el("div.btnrow", { style: "margin-top:22px;justify-content:center" }, [
          el("button.btn.primary", { text: "Try another set", onclick: function () { r.retry(); } }),
          el("button.btn", { text: "View analytics", onclick: function () { A.openAnalytics(); } }),
          el("button.btn.ghost", { text: "Back to dashboard", onclick: function () { A.dashboard(); A.renderDashboard(); } })
        ]));
        host.appendChild(box);
      }
    });
  }

  /* ===========================================================================
     TIMED MOCK EXAM  (90 weighted questions, timer, flagging, palette)
     =========================================================================== */
  function buildMockSet() {
    var total = (S.exam && S.exam.maxQuestions) || 100, picks = [];
    var meta = S.domainMeta.slice();
    var alloc = meta.map(function (d) { return { d: d.id, n: Math.round(total * d.weight / 100) }; });
    var sum = alloc.reduce(function (a, x) { return a + x.n; }, 0);
    alloc[3].n += (total - sum); // correct rounding drift onto the largest domain (D4)
    alloc.forEach(function (x) {
      var pool = byDomain(x.d);
      picks = picks.concat(sample(pool, Math.min(x.n, pool.length)));
    });
    return shuffle(picks).map(prepare);
  }

  function startMock() {
    ready();
    if (S.questions.length < ((S.exam && S.exam.maxQuestions) || 100)) { A.toast("Question bank still loading…"); return; }
    var items = buildMockSet();
    var picks = new Array(items.length).fill(null);
    var flags = new Array(items.length).fill(false);
    var idx = 0;
    var DURATION = ((S.exam && S.exam.minutes) || 120) * 60; // seconds
    var remaining = DURATION;
    var ticker = null, paneRef = null, ended = false;

    A.open({
      tag: "Mock exam", render: function (host) {
        host.appendChild(A.crumb("Mock exam in progress", { onBack: function () {
          A.confirm("Abandon the mock exam?", "You are mid-exam. Leaving discards this attempt and it will not be scored.", "Abandon exam", function () { stop(); A.dashboard(); A.renderDashboard(); });
        } }));
        host.appendChild(el("div.phead", null, [el("h1", { text: "Full-Length Mock Exam" }), el("span.sub", { text: (((S.exam && S.exam.maxQuestions) || 100)) + " questions · weighted to " + ((S.exam && S.exam.code) || "") + " domains" })]));
        paneRef = el("div"); host.appendChild(paneRef);
        draw();
        ticker = setInterval(tick, 1000);
      }
    });

    function tick() {
      remaining--; updateTimer();
      if (remaining <= 0) { stop(); A.toast("Time! Submitting your exam."); submit(); }
    }
    function stop() { if (ticker) clearInterval(ticker); ticker = null; }
    function fmt(s) { var m = Math.floor(s / 60), ss = s % 60; return (m < 10 ? "0" : "") + m + ":" + (ss < 10 ? "0" : "") + ss; }
    function updateTimer() {
      var t = paneRef && paneRef.querySelector("#mockTimer"); if (!t) return;
      t.textContent = "⏱ " + fmt(remaining);
      t.className = "timer" + (remaining <= 60 ? " crit" : remaining <= 300 ? " warn" : "");
    }

    function draw() {
      if (ended) return;
      paneRef.innerHTML = "";
      var wrap = el("div.quizwrap");
      var answeredCount = picks.filter(function (p) { return p != null; }).length;

      var meta = el("div.qmeta", null, [
        el("div.timer#mockTimer", { text: "⏱ " + fmt(remaining) }),
        el("div.progressbar", null, el("i", { style: "width:" + (answeredCount / items.length * 100) + "%" })),
        el("div.qcount", { text: answeredCount + " / " + items.length + " answered" })
      ]);
      wrap.appendChild(meta);
      updateTimer();

      /* palette */
      var pal = el("div.palette");
      items.forEach(function (_, i) {
        var c = "palette";
        var b = el("button", { text: String(i + 1), onclick: function () { idx = i; draw(); } });
        if (picks[i] != null) b.classList.add("answered");
        if (flags[i]) b.classList.add("flagged");
        if (i === idx) b.classList.add("current");
        pal.appendChild(b);
      });
      wrap.appendChild(pal);

      var it = items[idx], q = it.ref;
      var qc = el("div.qcard-full");
      qc.appendChild(el("div.qhead", null, [
        el("span.qdombadge.d" + q.domain, { text: "DOMAIN " + q.domain }),
        el("span.qobj", { text: "Question " + (idx + 1) + " of " + items.length }),
        el("button.qflag" + (flags[idx] ? ".on" : ""), { text: flags[idx] ? "Flagged" : "Flag for review", onclick: function () { flags[idx] = !flags[idx]; draw(); } })
      ]));
      qc.appendChild(el("div.qtext", { html: q.q }));
      it.opts.forEach(function (text, i) {
        var b = el("button.opt" + (picks[idx] === i ? ".sel" : ""), { type: "button" });
        b.appendChild(el("span.key", { text: LETTERS[i] }));
        b.appendChild(el("span", { html: text }));
        b.addEventListener("click", function () { picks[idx] = (picks[idx] === i ? null : i); draw(); });
        qc.appendChild(b);
      });

      var nav = el("div.qnav", null, [
        el("button.btn.ghost", { text: "← Previous", disabled: idx === 0 ? "disabled" : null, onclick: function () { if (idx > 0) { idx--; draw(); } } }),
        el("div.btnrow", null, [
          idx === items.length - 1
            ? el("button.btn.primary", { text: "Review & submit", onclick: reviewSubmit })
            : el("button.btn.primary", { text: "Next →", onclick: function () { idx++; draw(); } })
        ])
      ]);
      qc.appendChild(nav);
      wrap.appendChild(qc);
      paneRef.appendChild(wrap);
    }

    function reviewSubmit() {
      var unanswered = picks.filter(function (p) { return p == null; }).length;
      var flagged = flags.filter(Boolean).length;
      A.confirm("Submit exam?",
        (unanswered ? unanswered + " question(s) are unanswered and will be marked wrong. " : "All questions answered. ") +
        (flagged ? flagged + " are flagged for review. " : "") + "Submit for scoring?",
        "Submit exam", function () { stop(); submit(); });
    }

    function submit() {
      if (ended) return; ended = true; stop();
      var stats = blankStats(), correct = 0, wrongList = [];
      items.forEach(function (it, i) {
        var ok = picks[i] === it.answer;
        stats[it.ref.domain].total++; if (ok) { stats[it.ref.domain].correct++; correct++; }
        if (!ok) wrongList.push({ it: it, pick: picks[i] });
      });
      var pct = Math.round(correct / items.length * 100);
      var _lo=(S.exam&&S.exam.scaleLow)||100,_hi=(S.exam&&S.exam.scaleHigh)||1000; var scaled = Math.max(_lo, Math.min(_hi, Math.round(_lo + pct / 100 * (_hi-_lo))));
      QS.record(items, picks); // feed adaptive engine + missed-question queue
      A.store.record({ mode: "mock", modeLabel: "Mock exam", detail: correct + "/" + items.length + " · used " + Math.round((DURATION - remaining) / 60) + " min", pct: pct, scaled: scaled, correct: correct, total: items.length, domainStats: stats });
      showResults({ tag: "Results", title: "Mock Exam", mode: "mock", correct: correct, total: items.length, pct: pct, scaled: scaled, stats: stats, wrongList: wrongList, retry: startMock });
    }
  }

  /* ===========================================================================
     PBQ SIMULATOR  (exhibit + dropdown fields, graded with rationale)
     =========================================================================== */
  function openPBQFormat(fid) {
    ready();
    var fmt = (S.pbqFormats || []).filter(function (f) { return f.id === fid; })[0] || {};
    var list = S.pbqs.filter(function (p) { return p.format === fid; });
    var done = A.store.get("pbqDone", []) || [];

    A.open({
      tag: "PBQ · " + (fmt.badge || ("Format " + fid)), render: function (host) {
        host.appendChild(A.crumb(fmt.title));
        host.appendChild(el("div.phead", null, [el("h1", { text: fmt.title }), el("span.sub", { text: (fmt.badge || ("Format " + fid)) + " · " + list.length + " simulations · objective " + fmt.obj })]));
        host.appendChild(el("p.sectsub", { html: fmt.long || fmt.desc }));
        var grid = el("div.grid");
        list.forEach(function (p, i) {
          var isDone = done.indexOf(p.id) >= 0;
          grid.appendChild((function () {
            var c = el("button.card" + (isDone ? ".domain.d" + p.domain : ""), { type: "button", onclick: function () { runPBQ(list, i, fid); } });
            c.appendChild(el("div.kome", null, [
              el("span.ico", { text: fmt.icon }),
              el("span.tag.d" + p.domain, { text: isDone ? "✓ DONE" : "PBQ " + (i + 1) })
            ]));
            c.appendChild(el("h3", { text: p.title }));
            c.appendChild(el("div.desc", { html: (p.brief || "").slice(0, 120) + ((p.brief || "").length > 120 ? "…" : "") }));
            c.appendChild(el("div.foot", null, [el("span", { text: p.fields.length + " decisions · D" + p.domain }), el("span.go", { text: "Open →" })]));
            return c;
          })());
        });
        host.appendChild(grid);
        if (A.backBar) host.appendChild(A.backBar());
      }
    });
  }

  function runPBQ(list, i, fid) {
    var p = list[i];
    var fmt = (S.pbqFormats || []).filter(function (f) { return f.id === fid; })[0] || {};
    var graded = false;
    var selects = [];

    A.open({
      tag: "PBQ " + p.id, render: function (host) {
        host.appendChild(A.crumb(p.id, { onBack: function () { openPBQFormat(fid); } }));
        host.appendChild(el("div.phead", null, [el("h1", { text: p.title }), el("span.sub", { text: "Domain " + p.domain + " · " + fmt.title })]));
        var wrap = el("div.pbqwrap");
        wrap.appendChild(el("p.pbq-brief", { html: p.brief }));

        if (p.exhibit) {
          wrap.appendChild(el("div.terminal", null, [
            el("div.tbar", null, [el("span.dots", null, [el("i"), el("i"), el("i")]), el("span.ttl", { text: p.exhibitTitle || "exhibit" })]),
            el("pre", { html: p.exhibit })
          ]));
        }

        var fieldsHost = el("div.pbq-fields");
        p.fields.forEach(function (f, fi) {
          var fld = el("div.field");
          fld.appendChild(el("div.flabel", { text: (fi + 1) + ". " + f.label }));
          if (f.hint) fld.appendChild(el("div.fhint", { html: f.hint }));
          var sel = el("select");
          sel.appendChild(el("option", { value: "", text: "— choose —" }));
          f.options.forEach(function (o, oi) { sel.appendChild(el("option", { value: String(oi), text: o })); });
          fld.appendChild(sel);
          fld.appendChild(el("div.fexplain", { html: "<span class='ans'>Correct: " + A.esc(f.options[f.answer]) + ".</span> " + f.explain }));
          fieldsHost.appendChild(fld);
          selects.push({ sel: sel, fld: fld, f: f });
        });
        wrap.appendChild(fieldsHost);

        var summary = el("div", { style: "margin-top:8px" });
        var actions = el("div.qnav", null, [
          el("button.btn.ghost", { text: "← All " + fmt.title.split(" ")[0] + " PBQs", onclick: function () { openPBQFormat(fid); } }),
          el("div.btnrow", null, [
            el("button.btn.primary#pbqGrade", { text: "Submit & grade", onclick: grade }),
            i < list.length - 1 ? el("button.btn", { text: "Next PBQ →", onclick: function () { runPBQ(list, i + 1, fid); } }) : null
          ])
        ]);
        wrap.appendChild(summary);
        wrap.appendChild(actions);
        host.appendChild(wrap);

        function grade() {
          if (graded) { // already graded → act as reset
            selects.forEach(function (s) { s.sel.value = ""; s.sel.disabled = false; s.fld.classList.remove("graded", "correct", "wrong"); });
            graded = false; summary.innerHTML = ""; $set("Submit & grade"); return;
          }
          var miss = selects.some(function (s) { return s.sel.value === ""; });
          if (miss && !confirmProceed()) return;
          var correct = 0;
          selects.forEach(function (s) {
            var val = s.sel.value === "" ? -1 : parseInt(s.sel.value, 10);
            var ok = val === s.f.answer;
            if (ok) correct++;
            s.fld.classList.add("graded"); s.fld.classList.toggle("correct", ok); s.fld.classList.toggle("wrong", !ok);
            s.sel.disabled = true;
          });
          graded = true; $set("Reset");
          var pct = Math.round(correct / selects.length * 100);
          var pass = pct >= 70;
          summary.innerHTML = "";
          summary.appendChild(el("div.rationale" + (pass ? "" : ".bad"), null, [
            el("span.lbl", { text: pass ? "Well configured" : "Needs work" }),
            el("span", { html: "<b>" + correct + " of " + selects.length + "</b> decisions correct (" + pct + "%). " + (p.summary || "") })
          ]));
          /* mark complete */
          var done = A.store.get("pbqDone", []) || [];
          if (done.indexOf(p.id) < 0) { done.push(p.id); A.store.set("pbqDone", done); }
          A.store.record({ mode: "pbq", modeLabel: "PBQ", detail: p.id + " · " + fmt.title.split(" ")[0], pct: pct, correct: correct, total: selects.length, domainStats: (function () { var st = blankStats(); st[p.domain] = { correct: correct, total: selects.length }; return st; })() });
          summary.scrollIntoView({ behavior: "smooth", block: "nearest" });
        }
        function $set(t) { var b = host.querySelector("#pbqGrade"); if (b) b.textContent = t; }
        var proceeded = false;
        function confirmProceed() { return window.confirm("Some fields are unset and will be marked incorrect. Grade anyway?"); }
      }
    });
  }

  /* ===========================================================================
     PUBLIC ENGINE SURFACE
     =========================================================================== */
  window.QUIZ = {
    startDomainQuiz: function (d) {
      ready();
      var meta = A.domainMeta(d);
      var pool = byDomain(d);
      if (pool.length < 1) { A.toast("No questions for this domain yet."); return; }
      runLinearQuiz({
        tag: "D" + d + " Quiz", mode: "domain", modeLabel: "Domain quiz",
        title: "Domain " + d + " Quiz", sub: meta.title + " · 10 questions",
        detail: "Domain " + d, items: sample(pool, Math.min(10, pool.length)),
        retry: function () { window.QUIZ.startDomainQuiz(d); }
      });
    },
    startQuickQuiz: function () {
      runLinearQuiz({
        tag: "Quick Quiz", mode: "quick", modeLabel: "Quick quiz",
        title: "Randomized Quick Quiz", sub: "10 questions · all five domains",
        detail: "Mixed", items: sample(S.questions, 10),
        retry: function () { window.QUIZ.startQuickQuiz(); }
      });
    },
    /* Adaptive: 10 questions weighted toward your weakest objectives + prior misses. */
    startAdaptive: function () {
      ready();
      var items = adaptiveSet(10);
      if (!items.length) { A.toast("No questions available."); return; }
      var weak = QS.weakestDomain();
      runLinearQuiz({
        tag: "Adaptive", mode: "adaptive", modeLabel: "Adaptive practice",
        title: "Adaptive Practice",
        sub: "10 questions weighted to your weak areas" + (weak ? " · focus: " + weak : ""),
        detail: weak ? "Weighted · " + weak : "Adaptive", items: items,
        retry: function () { window.QUIZ.startAdaptive(); }
      });
    },
    /* Missed queue: re-serve only previously-wrong questions (answering one
       correctly removes it from the queue via QS.record). */
    startMissed: function () {
      ready();
      var missed = QS.getMissed();
      var pool = S.questions.filter(function (q) { return missed[q.id]; });
      if (!pool.length) { A.toast("No missed questions yet — take a quiz first."); return; }
      runLinearQuiz({
        tag: "Missed", mode: "missed", modeLabel: "Missed questions",
        title: "Missed Questions", sub: pool.length + " in your retry queue",
        detail: "Retry", items: sample(pool, Math.min(15, pool.length)),
        retry: function () { window.QUIZ.startMissed(); }
      });
    },
    missedCount: function () { return QS.missedCount(); },
    weakestDomain: function () { return QS.weakestDomain(); },
    startMock: startMock,
    openPBQFormat: openPBQFormat
  };
})();